import React, { useState, useRef, useEffect, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from '@google/genai';
import type { Client, Item, Invoice } from '../types';

interface VoiceAssistantProps {
    onNavigate: (view: string) => void;
    currentView: string;
    onAddClient: (client: Omit<Client, 'id'>) => void;
    onAddItem: (item: Omit<Item, 'id'>) => void;
    onUpdateStock: (itemName: string, quantity: number) => { success: boolean; message: string };
    dataContext: {
        clients: Client[];
        items: Item[];
        invoices: Invoice[];
    };
    onOpenEmailModal: (invoiceNumber: string) => { success: boolean; message: string };
    // Drafting Actions
    onDraftInvoice: (clientName: string) => { success: boolean; message: string };
    onAddDraftItem: (itemName: string, quantity: number) => { success: boolean; message: string };

    // Optional props need checks before calling
    onCreateInvoice?: (clientName: string, itemName: string, quantity: number) => { success: boolean; message: string };
    onDeleteClient?: (clientName: string) => { success: boolean; message: string };
    onDeleteInvoice?: (invoiceNumber: string) => { success: boolean; message: string };
    onDeleteItem?: (itemName: string) => { success: boolean; message: string };
    onUpdateInvoiceStatus?: (invoiceNumber: string, status: string) => { success: boolean; message: string };
    onUpdateCompanyInfo?: (field: string, value: string) => { success: boolean; message: string };
}

const MicrophoneIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
    </svg>
);

const StopIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
    </svg>
);

const ActionIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" clipRule="evenodd" />
    </svg>
);

// --- Audio Visualizer Component ---
const AudioWaveform = () => (
    <div className="flex items-center justify-center gap-1 h-8">
        {[0, 1, 2, 3, 4].map((i) => (
            <div
                key={i}
                className="w-1 bg-accent rounded-full animate-music-bar"
                style={{
                    animationDelay: `${i * 0.15}s`
                }}
            />
        ))}
         <style>{`
            @keyframes music-bar {
                0%, 100% { height: 30%; opacity: 0.5; }
                50% { height: 80%; opacity: 1; }
            }
            .animate-music-bar {
                animation: music-bar 1s ease-in-out infinite;
            }
        `}</style>
    </div>
);

// --- Audio Helpers ---

function encode(bytes: Uint8Array) {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
        binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
}

function decode(base64: string) {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
}

async function decodeAudioData(
    data: Uint8Array,
    ctx: AudioContext,
    sampleRate: number,
    numChannels: number,
): Promise<AudioBuffer> {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

    for (let channel = 0; channel < numChannels; channel++) {
        const channelData = buffer.getChannelData(channel);
        for (let i = 0; i < frameCount; i++) {
            channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
        }
    }
    return buffer;
}

function createBlob(data: Float32Array): { data: string; mimeType: string } {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
        const s = Math.max(-1, Math.min(1, data[i]));
        int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
    }
    return {
        data: encode(new Uint8Array(int16.buffer)),
        mimeType: 'audio/pcm;rate=16000',
    };
}

// --- Component ---

const VoiceAssistant: React.FC<VoiceAssistantProps> = (props) => {
    const [isActive, setIsActive] = useState(false);
    const [statusText, setStatusText] = useState('Idle');
    const [currentAction, setCurrentAction] = useState<string | null>(null);

    // Refs for audio context and session management
    const aiRef = useRef<GoogleGenAI | null>(null);
    const sessionPromiseRef = useRef<Promise<any> | null>(null);
    const inputAudioCtxRef = useRef<AudioContext | null>(null);
    const outputAudioCtxRef = useRef<AudioContext | null>(null);
    const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
    const mediaStreamRef = useRef<MediaStream | null>(null);
    const outputNodeRef = useRef<GainNode | null>(null);
    const nextStartTimeRef = useRef<number>(0);
    const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

    // Props ref to access fresh props in callbacks
    const propsRef = useRef(props);
    useEffect(() => {
        propsRef.current = props;
    }, [props]);

    const navigateToView = useCallback((viewName: string) => {
        const validViews: {[key: string]: string} = {
            'dashboard': 'Dashboard',
            'home': 'Dashboard',
            'overview': 'Dashboard',
            'new invoice': 'NewInvoice',
            'create invoice': 'NewInvoice',
            'draft': 'NewInvoice',
            'make bill': 'NewInvoice',
            'invoices': 'Invoices',
            'list invoices': 'Invoices',
            'history': 'Invoices',
            'clients': 'Clients',
            'customers': 'Clients',
            'parties': 'Clients',
            'items': 'Items',
            'products': 'Items',
            'services': 'Items',
            'inventory': 'Inventory',
            'stock': 'Inventory',
            'transporters': 'Transporters',
            'settings': 'Settings',
            'profile': 'Settings',
            'config': 'Settings'
        };
        const normalizedInput = viewName.toLowerCase();
        let target = validViews[normalizedInput];

        if (!target) {
            const key = Object.keys(validViews).find(k => normalizedInput.includes(k));
            if (key) target = validViews[key];
        }

        if (target) {
            setCurrentAction(`Navigating to ${target}`);
            propsRef.current.onNavigate(target);
            return { success: true, message: `Navigated to ${target}` };
        }
        return { success: false, message: `View ${viewName} not found` };
    }, []);

    const getDashboardStats = useCallback(() => {
        const { dataContext } = propsRef.current;
        const totalRevenue = dataContext.invoices.filter(i => i.status === 'Paid').reduce((sum, i) => sum + i.grandTotal, 0);
        const totalOverdue = dataContext.invoices.filter(i => i.status === 'Overdue').reduce((sum, i) => sum + i.grandTotal, 0);
        const lowStockCount = dataContext.items.filter(i => i.quantityInStock <= 5).length;
        return {
            totalRevenue,
            totalOverdue,
            totalInvoices: dataContext.invoices.length,
            lowStockCount
        };
    }, []);

    // Tool Definitions
    const toolDeclarations: FunctionDeclaration[] = [
        {
            name: 'navigate',
            description: 'Navigate to a specific view/page in the application.',
            parameters: {
                type: Type.OBJECT,
                properties: {
                    viewName: { type: Type.STRING, description: 'The name of the view (Dashboard, Invoices, Clients, Items, Inventory, Transporters, Settings).' }
                },
                required: ['viewName']
            }
        },
        {
            name: 'getDashboardStats',
            description: 'Get key dashboard statistics like revenue, overdue invoices, and low stock count.',
            parameters: {
                type: Type.OBJECT,
                properties: {
                    detailed: { type: Type.BOOLEAN, description: 'Whether to return detailed stats.' }
                }
            }
        },
        {
            name: 'addClient',
            description: 'Open form to add a new client with provided details.',
            parameters: {
                type: Type.OBJECT,
                properties: {
                    name: { type: Type.STRING },
                    email: { type: Type.STRING },
                    phone: { type: Type.STRING }
                },
                required: ['name']
            }
        },
        {
            name: 'addItem',
            description: 'Open form to add a new item/product to inventory.',
            parameters: {
                type: Type.OBJECT,
                properties: {
                    name: { type: Type.STRING },
                    price: { type: Type.NUMBER },
                    gstRate: { type: Type.NUMBER }
                },
                required: ['name', 'price']
            }
        },
        {
            name: 'updateStock',
            description: 'Update stock quantity for a specific item.',
            parameters: {
                type: Type.OBJECT,
                properties: {
                    itemName: { type: Type.STRING },
                    quantity: { type: Type.NUMBER }
                },
                required: ['itemName', 'quantity']
            }
        },
        {
            name: 'draftInvoice',
            description: 'Start a new invoice draft for a specific client. Opens the New Invoice page.',
            parameters: {
                type: Type.OBJECT,
                properties: {
                    clientName: { type: Type.STRING }
                },
                required: ['clientName']
            }
        },
        {
            name: 'addInvoiceItem',
            description: 'Add an item to the currently active invoice draft.',
            parameters: {
                type: Type.OBJECT,
                properties: {
                    itemName: { type: Type.STRING },
                    quantity: { type: Type.NUMBER }
                },
                required: ['itemName', 'quantity']
            }
        },
        {
            name: 'emailInvoice',
            description: 'Open the email modal for a specific invoice number.',
            parameters: {
                type: Type.OBJECT,
                properties: {
                    invoiceNumber: { type: Type.STRING }
                },
                required: ['invoiceNumber']
            }
        },
        {
            name: 'deleteClient',
            description: 'Delete a client by name.',
            parameters: {
                type: Type.OBJECT,
                properties: { clientName: { type: Type.STRING } },
                required: ['clientName']
            }
        },
        {
            name: 'deleteInvoice',
            description: 'Delete an invoice by invoice number.',
            parameters: {
                type: Type.OBJECT,
                properties: { invoiceNumber: { type: Type.STRING } },
                required: ['invoiceNumber']
            }
        },
        {
            name: 'deleteItem',
            description: 'Delete an item by name.',
            parameters: {
                type: Type.OBJECT,
                properties: { itemName: { type: Type.STRING } },
                required: ['itemName']
            }
        },
        {
            name: 'updateInvoiceStatus',
            description: 'Update the payment status of an invoice (Paid, Unpaid, Overdue).',
            parameters: {
                type: Type.OBJECT,
                properties: {
                    invoiceNumber: { type: Type.STRING },
                    status: { type: Type.STRING }
                },
                required: ['invoiceNumber', 'status']
            }
        },
        {
            name: 'updateCompanyInfo',
            description: 'Update company details like name, phone, email, address, etc.',
            parameters: {
                type: Type.OBJECT,
                properties: {
                    field: { type: Type.STRING },
                    value: { type: Type.STRING }
                },
                required: ['field', 'value']
            }
        }
    ];

    const connect = async () => {
        if (!process.env.API_KEY) {
            console.error("API Key is missing.");
            return;
        }

        setStatusText("Requesting Mic...");
        try {
            // Setup Audio Contexts and Stream first
            const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
            inputAudioCtxRef.current = new AudioContextClass({ sampleRate: 16000 });
            outputAudioCtxRef.current = new AudioContextClass({ sampleRate: 24000 });

            // Get user media
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            mediaStreamRef.current = stream;

            outputNodeRef.current = outputAudioCtxRef.current.createGain();
            outputNodeRef.current.connect(outputAudioCtxRef.current.destination);

        } catch (err) {
            console.error("Microphone access denied:", err);
            setStatusText("Mic Denied");
            return;
        }

        setStatusText("Connecting...");

        try {
            aiRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY });

            // Context Construction
            const { clients, items } = propsRef.current.dataContext;
            const clientList = clients.map(c => c.name).slice(0, 100).join(", ");
            const itemList = items.map(i => i.name).slice(0, 100).join(", ");

            const systemInstruction = `You are a smart voice assistant for 'InvoicePro'.

YOUR CAPABILITIES:
1. Navigation: Move between pages (Dashboard, Invoices, Clients, Inventory, etc.).
2. Data Entry: Add clients, items, or draft invoices.
3. Management: Update stock, changing status, delete records.

CONTEXT DATA (Use this for Entity Matching):
- Clients: ${clientList || 'No clients found'}
- Items: ${itemList || 'No items found'}

RULES:
- **Entity Matching**: If a user says "Invoice for Reliance", match "Reliance" to the closest name in the Clients list. Correct matching is critical.
- **Variations**: 
  - "Bill", "Challan", "Receipt" = Invoice. 
  - "Customer", "Party" = Client. 
  - "Product", "Stock" = Item.
- **Drafting**: To create an invoice, first call 'draftInvoice' with the client name. Then, if the user mentioned items (e.g., "with 2 widgets"), call 'addInvoiceItem'.
- **Responses**: Be concise. "Opening invoice for X", "Added Y to inventory", "Navigating to Z".

Keep the conversation professional and efficient.`;

            const sessionPromise = aiRef.current.live.connect({
                model: 'gemini-2.5-flash-native-audio-preview-09-2025',
                callbacks: {
                    onopen: async () => {
                        setStatusText("Listening");
                        setIsActive(true);

                        if (inputAudioCtxRef.current && mediaStreamRef.current) {
                            const source = inputAudioCtxRef.current.createMediaStreamSource(mediaStreamRef.current);
                            scriptProcessorRef.current = inputAudioCtxRef.current.createScriptProcessor(4096, 1, 1);

                            scriptProcessorRef.current.onaudioprocess = (e) => {
                                const inputData = e.inputBuffer.getChannelData(0);
                                const pcmBlob = createBlob(inputData);
                                sessionPromiseRef.current?.then(session => {
                                    session.sendRealtimeInput({ media: pcmBlob });
                                });
                            };

                            source.connect(scriptProcessorRef.current);
                            scriptProcessorRef.current.connect(inputAudioCtxRef.current.destination);
                        }
                    },
                    onmessage: async (message: LiveServerMessage) => {
                        // Handle Tool Calls
                        if (message.toolCall) {
                            for (const fc of message.toolCall.functionCalls) {
                                let result: any = { success: true };
                                const args = fc.args as any;

                                setCurrentAction(`Processing: ${fc.name}...`);

                                switch (fc.name) {
                                    case 'navigate':
                                        setCurrentAction(`Navigating to ${args.viewName}`);
                                        result = navigateToView(args.viewName);
                                        break;
                                    case 'getDashboardStats':
                                        setCurrentAction('Fetching stats...');
                                        result = getDashboardStats();
                                        break;
                                    case 'addClient':
                                        setCurrentAction(`Adding client: ${args.name}`);
                                        propsRef.current.onAddClient(args);
                                        result = { success: true, message: 'Client added form opened.' };
                                        break;
                                    case 'addItem':
                                        setCurrentAction(`Adding item: ${args.name}`);
                                        propsRef.current.onAddItem(args);
                                        result = { success: true, message: 'Item added.' };
                                        break;
                                    case 'updateStock':
                                        setCurrentAction(`Updating stock for ${args.itemName}`);
                                        result = propsRef.current.onUpdateStock(args.itemName, args.quantity);
                                        break;
                                    case 'draftInvoice':
                                        setCurrentAction(`Drafting invoice for ${args.clientName}`);
                                        result = propsRef.current.onDraftInvoice(args.clientName);
                                        break;
                                    case 'addInvoiceItem':
                                        setCurrentAction(`Adding ${args.quantity} ${args.itemName}(s)`);
                                        result = propsRef.current.onAddDraftItem(args.itemName, args.quantity);
                                        break;
                                    case 'emailInvoice':
                                        setCurrentAction(`Preparing email for ${args.invoiceNumber}`);
                                        result = propsRef.current.onOpenEmailModal(args.invoiceNumber);
                                        break;
                                    case 'deleteClient':
                                        setCurrentAction(`Deleting client ${args.clientName}`);
                                        result = propsRef.current.onDeleteClient ? propsRef.current.onDeleteClient(args.clientName) : { success: false, message: 'Not supported' };
                                        break;
                                    case 'deleteInvoice':
                                        setCurrentAction(`Deleting invoice ${args.invoiceNumber}`);
                                        result = propsRef.current.onDeleteInvoice ? propsRef.current.onDeleteInvoice(args.invoiceNumber) : { success: false, message: 'Not supported' };
                                        break;
                                    case 'deleteItem':
                                        setCurrentAction(`Deleting item ${args.itemName}`);
                                        result = propsRef.current.onDeleteItem ? propsRef.current.onDeleteItem(args.itemName) : { success: false, message: 'Not supported' };
                                        break;
                                    case 'updateInvoiceStatus':
                                        setCurrentAction(`Updating status to ${args.status}`);
                                        result = propsRef.current.onUpdateInvoiceStatus ? propsRef.current.onUpdateInvoiceStatus(args.invoiceNumber, args.status) : { success: false, message: 'Not supported' };
                                        break;
                                    case 'updateCompanyInfo':
                                        setCurrentAction(`Updating company ${args.field}`);
                                        result = propsRef.current.onUpdateCompanyInfo ? propsRef.current.onUpdateCompanyInfo(args.field, args.value) : { success: false, message: 'Not supported' };
                                        break;
                                }

                                sessionPromiseRef.current?.then(session => {
                                    session.sendToolResponse({
                                        functionResponses: {
                                            id: fc.id,
                                            name: fc.name,
                                            response: { result }
                                        }
                                    });
                                });
                                // Keep action visible for a moment
                                setTimeout(() => setCurrentAction(null), 3000);
                            }
                        }

                        // Handle Audio Output
                        const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
                        if (audioData && outputAudioCtxRef.current && outputNodeRef.current) {
                            try {
                                const audioBuffer = await decodeAudioData(
                                    decode(audioData),
                                    outputAudioCtxRef.current,
                                    24000,
                                    1
                                );

                                const source = outputAudioCtxRef.current.createBufferSource();
                                source.buffer = audioBuffer;
                                source.connect(outputNodeRef.current);

                                nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioCtxRef.current.currentTime);
                                source.start(nextStartTimeRef.current);
                                nextStartTimeRef.current += audioBuffer.duration;

                                source.onended = () => {
                                    sourcesRef.current.delete(source);
                                };
                                sourcesRef.current.add(source);
                            } catch (e) {
                                console.error("Audio decode error", e);
                            }
                        }
                    },
                    onclose: () => {
                        setStatusText("Disconnected");
                        setIsActive(false);
                    },
                    onerror: (e) => {
                        console.error("Gemini Live API Error:", e);
                        setStatusText("Error");
                        setIsActive(false);
                    }
                },
                config: {
                    responseModalities: [Modality.AUDIO],
                    speechConfig: {
                        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
                    },
                    tools: [{ functionDeclarations: toolDeclarations }],
                    systemInstruction: systemInstruction
                }
            });
            sessionPromiseRef.current = sessionPromise;

        } catch (error) {
            console.error("Connection failed", error);
            setStatusText("Failed");
            setIsActive(false);
        }
    };

    const disconnect = () => {
        if (mediaStreamRef.current) {
            mediaStreamRef.current.getTracks().forEach(track => track.stop());
            mediaStreamRef.current = null;
        }
        if (scriptProcessorRef.current) {
            scriptProcessorRef.current.disconnect();
            scriptProcessorRef.current = null;
        }
        if (inputAudioCtxRef.current) {
            inputAudioCtxRef.current.close();
            inputAudioCtxRef.current = null;
        }
        if (outputAudioCtxRef.current) {
            outputAudioCtxRef.current.close();
            outputAudioCtxRef.current = null;
        }
        if (sessionPromiseRef.current) {
             sessionPromiseRef.current.then(session => session.close());
             sessionPromiseRef.current = null;
        }
        setIsActive(false);
        setStatusText("Idle");
        setCurrentAction(null);
    };

    const toggleSession = () => {
        if (isActive) {
            disconnect();
        } else {
            connect();
        }
    };

    // Cleanup on unmount
    useEffect(() => {
        return () => {
            disconnect();
        };
    }, []);

    return (
        <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end gap-3">
            {/* Status Card */}
            <div className={`transition-all duration-300 transform origin-bottom-right ${isActive || currentAction ? 'scale-100 opacity-100 translate-y-0' : 'scale-90 opacity-0 translate-y-4 pointer-events-none'}`}>
                <div className="bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 shadow-2xl rounded-2xl p-5 w-72 backdrop-blur-xl bg-opacity-95 dark:bg-opacity-95">
                    <div className="flex items-center justify-between mb-3">
                        <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400 dark:text-slate-500">Gemini Assistant</span>
                        {isActive && !currentAction && (
                            <div className="flex items-center gap-2">
                                <span className="relative flex h-2 w-2">
                                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                                    <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                                </span>
                                <span className="text-[10px] font-medium text-green-600 dark:text-green-400">Live</span>
                            </div>
                        )}
                    </div>

                    <div className="min-h-[2.5rem] flex items-center">
                        {currentAction ? (
                            <div className="flex items-start gap-3 w-full animate-fade-in">
                                <div className="flex-shrink-0 p-1.5 bg-accent/10 rounded-lg text-accent mt-0.5">
                                    <ActionIcon />
                                </div>
                                <div className="flex-grow">
                                    <p className="text-sm font-bold text-slate-800 dark:text-white leading-snug">{currentAction}</p>
                                    <p className="text-[10px] text-slate-500 dark:text-slate-400 mt-0.5 font-medium">Processing request...</p>
                                </div>
                            </div>
                        ) : (
                            <div className="w-full">
                                 {statusText === 'Listening' ? (
                                     <div className="flex flex-col items-center justify-center space-y-2">
                                         <p className="text-sm font-semibold text-slate-700 dark:text-slate-200">Listening...</p>
                                         <AudioWaveform />
                                     </div>
                                 ) : (
                                     <div className="text-center py-1">
                                         <p className="text-sm font-medium text-slate-600 dark:text-slate-400">{statusText}</p>
                                         {statusText === 'Connecting...' && <div className="mt-2 h-1 w-full bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden"><div className="h-full bg-accent animate-progress w-1/2"></div></div>}
                                     </div>
                                 )}
                            </div>
                        )}
                    </div>
                </div>
            </div>

            <button
                onClick={toggleSession}
                className={`p-4 rounded-full shadow-xl transition-all duration-300 transform hover:scale-105 active:scale-95 flex items-center justify-center ${
                    isActive 
                        ? 'bg-red-500 hover:bg-red-600 ring-4 ring-red-100 dark:ring-red-900/30' 
                        : 'bg-accent hover:bg-accent-hover ring-4 ring-accent/20 dark:ring-accent/10'
                }`}
                title={isActive ? "Stop Voice Assistant" : "Start Voice Assistant"}
            >
                <div className="text-white">
                    {isActive ? <StopIcon /> : <MicrophoneIcon />}
                </div>
            </button>
        </div>
    );
};

export default VoiceAssistant;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Settings from './components/Settings';
import Clients from './components/Clients';
import Items from './components/Items';
import Transporters from './components/Transporters';
import Invoices, { InvoiceContent } from './components/Invoices';
import NewInvoice from './components/NewInvoice';
import Auth from './components/auth/Auth';
import CompanyManager from './components/CompanyManager';
import UserProfile from './components/UserProfile';
import { useLocalStorage } from './hooks/useLocalStorage';
import type { Company, Client, Item, Invoice, Transporter, User, CompanyDetails, BankAccount, RecurringInvoice, RecurringFrequency, DraftInvoice, InvoiceItem } from './types';
import Modal from './components/common/Modal';
import Input from './components/common/Input';
import Button from './components/common/Button';
import Inventory from './components/Inventory';
import VoiceAssistant from './components/VoiceAssistant';

const simpleHash = (s: string) => {
    let h = 0;
    for(let i = 0; i < s.length; i++) h = Math.imul(31, h) + s.charCodeAt(i) | 0;
    return h.toString();
};

const emptyCompanyDetails: CompanyDetails = { 
    logo: '', name: '', gstin: '', pan: '', phone: '', email: '', website: '',
    address: '', city: '', state: '', zip: '', udyam: '', signature: '',
    invoicePrefix: 'INV-', nextInvoiceNumber: 1
};

const defaultCompany: Omit<Company, 'id' | 'ownerId'> = {
    details: { ...emptyCompanyDetails, name: 'My First Company' },
    bankAccounts: [], clients: [], items: [], transporters: [], invoices: [], recurringInvoices: []
};

const emptyDraftInvoice: DraftInvoice = {
    invoiceNumber: '',
    clientId: '',
    items: [],
    issueDate: new Date().toISOString().split('T')[0],
    dueDate: new Date().toISOString().split('T')[0],
    notes: '',
    selectedBankAccountId: null,
    shippingDetails: { name: '', address: '', city: '', state: '', zip: '', gstin: '' },
    isShippingSameAsBilling: true,
    transporterId: '',
    vehicleNumber: '',
    ewayBillNumber: ''
};

const App: React.FC = () => {
  const [activeView, setActiveView] = useState('Dashboard');
  const [theme, setTheme] = useLocalStorage<'light' | 'dark'>('theme', 'dark');
  const [users, setUsers] = useLocalStorage<User[]>('invoicepro_users', []);
  const [companies, setCompanies] = useLocalStorage<Company[]>('invoicepro_companies', []);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeCompanyId, setActiveCompanyId] = useState<string | null>(null);
  const [invoiceToEdit, setInvoiceToEdit] = useState<Invoice | null>(null);
  const [isAddCompanyModalOpen, setIsAddCompanyModalOpen] = useState(false);
  const [newCompanyName, setNewCompanyName] = useState('');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [voiceInvoiceToEmail, setVoiceInvoiceToEmail] = useState<Invoice | null>(null);

  // Profile State
  const [isProfileOpen, setIsProfileOpen] = useState(false);

  // Lifted State for New Invoice Draft
  const [draftInvoice, setDraftInvoice] = useState<DraftInvoice>(emptyDraftInvoice);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', theme === 'dark');
  }, [theme]);

  const activeCompany = useMemo(() => companies.find(c => c.id === activeCompanyId) || null, [companies, activeCompanyId]);
  const userCompanies = useMemo(() => companies.filter(c => c.ownerId === currentUser?.id), [companies, currentUser]);

  // Initialize draft invoice number when active company changes
  useEffect(() => {
      if (activeCompany) {
          const nextNum = activeCompany.details.nextInvoiceNumber || 1;
          const prefix = activeCompany.details.invoicePrefix || 'INV-';
          const defaultBank = activeCompany.bankAccounts.find(b => b.isDefault)?.id || (activeCompany.bankAccounts[0]?.id || null);

          setDraftInvoice(prev => ({
              ...prev,
              invoiceNumber: `${prefix}${nextNum.toString().padStart(3, '0')}`,
              selectedBankAccountId: defaultBank
          }));
      }
  }, [activeCompany?.id, activeCompany?.details.nextInvoiceNumber]);

  // --- Auth Handlers ---
  const handleLogin = (email: string, pass: string): boolean => {
    const user = users.find(u => u.email === email && u.passwordHash === simpleHash(pass));
    if (user) {
        setCurrentUser(user);
        const firstCompany = companies.find(c => c.ownerId === user.id);
        setActiveCompanyId(firstCompany?.id || null);
        return true;
    }
    return false;
  };

  const handleGoogleLogin = () => {
      const googleEmail = "user@gmail.com";
      let user = users.find(u => u.email === googleEmail);
      if (!user) {
          user = { id: `google_${Date.now()}`, email: googleEmail, passwordHash: 'google-auth', name: 'Google User' };
          setUsers([...users, user]);
      }
      setCurrentUser(user);
      const firstCompany = companies.find(c => c.ownerId === user!.id);
      setActiveCompanyId(firstCompany?.id || null);
  };

  const handleSignup = (email: string, pass: string, name: string): boolean => {
    if(users.some(u => u.email === email)) return false;
    const newUser: User = { id: Date.now().toString(), email, name, passwordHash: simpleHash(pass) };
    setUsers([...users, newUser]);
    setCurrentUser(newUser);
    setActiveCompanyId(null);
    return true;
  };

  const handleLogout = () => {
      setCurrentUser(null);
      setActiveCompanyId(null);
  };

  const handleCheckUser = (email: string): boolean => users.some(u => u.email === email);

  const handleResetPassword = (email: string, newPass: string): boolean => {
      if (!users.some(u => u.email === email)) return false;
      const updatedUsers = users.map(user => user.email === email ? { ...user, passwordHash: simpleHash(newPass) } : user);
      setUsers(updatedUsers);
      return true;
  };

  const handleUpdateProfile = (updatedUser: User) => {
      setUsers(users.map(u => u.id === updatedUser.id ? updatedUser : u));
      setCurrentUser(updatedUser);
  };

  // --- Company Handlers ---
  const handleAddCompany = (companyDetails: CompanyDetails) => {
      if(!currentUser) return;
      const newCompany: Company = {
          id: `comp_${Date.now()}`,
          ownerId: currentUser.id,
          details: companyDetails,
          bankAccounts: [], clients: [], items: [], transporters: [], invoices: [], recurringInvoices: []
      };
      setCompanies([...companies, newCompany]);
      setActiveCompanyId(newCompany.id);
      setActiveView('Dashboard');
  };

  const handleCreateNewCompany = () => {
    if (newCompanyName.trim()) {
        handleAddCompany({ ...emptyCompanyDetails, name: newCompanyName.trim() });
        setIsAddCompanyModalOpen(false);
        setNewCompanyName('');
    }
  };

  const handleUpdateCompany = (updatedCompany: Company) => {
      setCompanies(companies.map(c => c.id === updatedCompany.id ? updatedCompany : c));
  };

  const handleSwitchCompany = (companyId: string) => {
      setActiveCompanyId(companyId);
      setActiveView('Dashboard');
  };

  // --- Voice Assistant Handlers ---
  const handleVoiceAddClient = (client: Omit<Client, 'id'>) => {
      if (!activeCompany) return;
      const newClient: Client = { 
          gstin: '', email: '', phone: '', address: '', city: '', state: '', zip: '', tags: [],
          ...client,
          id: `c_${Date.now()}` 
      };
      handleUpdateCompany({
          ...activeCompany,
          clients: [...activeCompany.clients, newClient]
      });
  };

  const handleVoiceAddItem = (item: Omit<Item, 'id'>) => {
      if (!activeCompany) return;
      const newItem: Item = { 
          hsn: '', unit: 'pcs', quantityInStock: 0,
          ...item,
          id: `i_${Date.now()}` 
      };
      handleUpdateCompany({
          ...activeCompany,
          items: [...activeCompany.items, newItem]
      });
  };

  const handleVoiceUpdateStock = (itemName: string, quantity: number) => {
      if (!activeCompany) return { success: false, message: 'No company active' };
      const itemIndex = activeCompany.items.findIndex(i => i.name.toLowerCase() === itemName.toLowerCase());
      if (itemIndex > -1) {
          const updatedItems = [...activeCompany.items];
          updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: quantity };
          handleUpdateCompany({ ...activeCompany, items: updatedItems });
          return { success: true, message: `Stock for ${itemName} updated to ${quantity}` };
      }
      return { success: false, message: `Item ${itemName} not found` };
  };

  const handleVoiceOpenEmailModal = (invoiceNumberQuery: string) => {
      if(!activeCompany) return { success: false, message: 'No company' };
      const invoice = activeCompany.invoices.find(inv => 
          inv.invoiceNumber.toLowerCase().includes(invoiceNumberQuery.toLowerCase())
      );
      if(invoice) {
          setVoiceInvoiceToEmail(invoice);
          return { success: true, message: `Opening email for ${invoice.invoiceNumber}` };
      }
      return { success: false, message: `Invoice ${invoiceNumberQuery} not found` };
  };

  // Voice Drafting Logic
  const handleVoiceDraftInvoice = (clientName: string) => {
      if (!activeCompany) return { success: false, message: 'No active company' };
      const client = activeCompany.clients.find(c => c.name.toLowerCase().includes(clientName.toLowerCase()));

      // Update draft state
      setDraftInvoice(prev => ({
          ...prev,
          clientId: client ? client.id : prev.clientId,
          // Reset other fields if starting new, or keep them if intended? 
          // For a "Draft Invoice" command, we usually mean "Start New".
          items: [],
          shippingDetails: client ? {
              name: client.name,
              address: client.address,
              city: client.city,
              state: client.state,
              zip: client.zip,
              gstin: client.gstin
          } : prev.shippingDetails,
          isShippingSameAsBilling: true
      }));

      // Switch view
      setActiveView('NewInvoice');

      if (!client) return { success: false, message: `Opened New Invoice page. Client ${clientName} not found.` };
      return { success: true, message: `Started invoice for ${client.name}.` };
  };

  const handleVoiceAddDraftItem = (itemName: string, quantity: number) => {
      if (!activeCompany) return { success: false, message: 'No active company' };
      const item = activeCompany.items.find(i => i.name.toLowerCase().includes(itemName.toLowerCase()));

      if (!item) return { success: false, message: `Item ${itemName} not found.` };

      const newItem: InvoiceItem = { ...item, quantity };

      setDraftInvoice(prev => ({
          ...prev,
          items: [...prev.items, newItem]
      }));

      // Ensure user is on the right page
      if (activeView !== 'NewInvoice') setActiveView('NewInvoice');

      return { success: true, message: `Added ${quantity} ${item.name}(s) to invoice.` };
  };

  const handleVoiceDeleteClient = (clientName: string) => {
      if(!activeCompany) return { success: false, message: 'No active company' };
      const client = activeCompany.clients.find(c => c.name.toLowerCase().includes(clientName.toLowerCase()));
      if(client) {
          setActiveView('Clients');
          const updatedClients = activeCompany.clients.filter(c => c.id !== client.id);
          handleUpdateCompany({ ...activeCompany, clients: updatedClients });
          return { success: true, message: `Client ${client.name} deleted.` };
      }
      return { success: false, message: `Client ${clientName} not found` };
  };

  const handleVoiceDeleteInvoice = (invoiceNumber: string) => {
      if(!activeCompany) return { success: false, message: 'No active company' };
      const invoice = activeCompany.invoices.find(i => i.invoiceNumber.toLowerCase().includes(invoiceNumber.toLowerCase()));
      if(invoice) {
          setActiveView('Invoices');
          handleBulkDeleteInvoices([invoice.id]);
          return { success: true, message: `Invoice ${invoice.invoiceNumber} deleted.` };
      }
      return { success: false, message: `Invoice ${invoiceNumber} not found` };
  };

  const handleVoiceDeleteItem = (itemName: string) => {
      if(!activeCompany) return { success: false, message: 'No active company' };
      const item = activeCompany.items.find(i => i.name.toLowerCase().includes(itemName.toLowerCase()));
      if(item) {
          setActiveView('Items');
          handleBulkDeleteItems([item.id]);
          return { success: true, message: `Item ${item.name} deleted.` };
      }
      return { success: false, message: `Item ${itemName} not found` };
  };

  const handleVoiceUpdateInvoiceStatus = (invoiceNumber: string, status: string) => {
      if (!activeCompany) return { success: false, message: 'No company active' };
      const inv = activeCompany.invoices.find(i => i.invoiceNumber.toLowerCase().includes(invoiceNumber.toLowerCase()));
      if (inv) {
          const validStatus = ['Paid', 'Unpaid', 'Overdue'].find(s => s.toLowerCase() === status.toLowerCase());
          if (validStatus) {
              handleBulkStatusChange([inv.id], validStatus as Invoice['status']);
              return { success: true, message: `Invoice ${inv.invoiceNumber} marked as ${validStatus}` };
          }
          return { success: false, message: 'Invalid status. Use Paid, Unpaid, or Overdue.' };
      }
      return { success: false, message: 'Invoice not found' };
  };

  const handleVoiceUpdateCompanyInfo = (field: string, value: string) => {
      if (!activeCompany) return { success: false, message: 'No company active' };
      const validFields = ['name', 'phone', 'email', 'address', 'city', 'state', 'zip', 'gstin'];
      if (validFields.includes(field)) {
         const newDetails = { ...activeCompany.details, [field]: value };
         handleUpdateCompany({ ...activeCompany, details: newDetails });
         return { success: true, message: `Company ${field} updated.` };
      }
      return { success: false, message: `Cannot update field ${field}. Allowed: name, phone, email, address, etc.` };
  };

  // --- Recurring Invoice Generation Logic ---
  useEffect(() => {
      if (!activeCompany || !activeCompany.recurringInvoices) return;

      const today = new Date().toISOString().split('T')[0];
      let updatedInvoices = [...activeCompany.invoices];
      let updatedRecurring = [...(activeCompany.recurringInvoices || [])];
      let updatedItems = [...activeCompany.items];
      let updatedDetails = { ...activeCompany.details };
      let hasChanges = false;
      let nextInvoiceNum = updatedDetails.nextInvoiceNumber;

      const getNextDate = (current: string, freq: RecurringFrequency): string => {
          const date = new Date(current);
          if (freq === 'Daily') date.setDate(date.getDate() + 1);
          if (freq === 'Weekly') date.setDate(date.getDate() + 7);
          if (freq === 'Monthly') date.setMonth(date.getMonth() + 1);
          if (freq === 'Quarterly') date.setMonth(date.getMonth() + 3);
          if (freq === 'Yearly') date.setFullYear(date.getFullYear() + 1);
          return date.toISOString().split('T')[0];
      };

      updatedRecurring = updatedRecurring.map(rec => {
          if (rec.status === 'Active' && rec.nextRunDate <= today) {
              if (rec.endDate && rec.nextRunDate > rec.endDate) {
                  return { ...rec, status: 'Completed' };
              }
              const client = activeCompany.clients.find(c => c.id === rec.clientId);
              if (client) {
                  hasChanges = true;
                  const invoiceNumber = `${updatedDetails.invoicePrefix}${nextInvoiceNum.toString().padStart(3, '0')}`;
                  nextInvoiceNum++;

                  let subTotal = 0, cgst = 0, sgst = 0, igst = 0;
                  const isIntraState = client.state === activeCompany.details.state;

                  const items = rec.items.map(i => {
                      const taxable = i.price * i.quantity;
                      subTotal += taxable;
                      const tax = (taxable * i.gstRate) / 100;
                      if (isIntraState) { cgst += tax / 2; sgst += tax / 2; } else { igst += tax; }

                      const itemIndex = updatedItems.findIndex(invItem => invItem.id === i.id);
                      if (itemIndex > -1) {
                        const currentStock = Number(updatedItems[itemIndex].quantityInStock) || 0;
                        updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: currentStock - i.quantity };
                      }
                      return i;
                  });

                  const grandTotal = subTotal + cgst + sgst + igst;
                  const newInvoice: Invoice = {
                      id: `inv_rec_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
                      invoiceNumber, client, items, issueDate: rec.nextRunDate, dueDate: rec.nextRunDate,
                      notes: rec.notes || 'Recurring Invoice', subTotal, cgst, sgst, igst, grandTotal,
                      status: 'Unpaid', selectedBankAccountId: activeCompany.bankAccounts.find(b => b.isDefault)?.id || null,
                      shippingName: client.name, shippingAddress: client.shippingAddress || client.address,
                      shippingCity: client.shippingCity || client.city, shippingState: client.shippingState || client.state,
                      shippingZip: client.shippingZip || client.zip, shippingGstin: client.gstin
                  };
                  updatedInvoices.push(newInvoice);
                  return { ...rec, lastRunDate: rec.nextRunDate, nextRunDate: getNextDate(rec.nextRunDate, rec.frequency) };
              }
          }
          return rec;
      });

      if (hasChanges) {
          updatedDetails.nextInvoiceNumber = nextInvoiceNum;
          handleUpdateCompany({ ...activeCompany, details: updatedDetails, invoices: updatedInvoices.sort((a,b) => b.invoiceNumber.localeCompare(a.invoiceNumber, undefined, {numeric: true})), recurringInvoices: updatedRecurring, items: updatedItems });
      }
  }, [activeCompanyId]);

  const handleAddRecurring = (profile: Omit<RecurringInvoice, 'id'>) => {
      if (!activeCompany) return;
      handleUpdateCompany({ ...activeCompany, recurringInvoices: [...(activeCompany.recurringInvoices || []), { ...profile, id: `rec_${Date.now()}` }] });
  };

  const handleUpdateRecurring = (updatedProfile: RecurringInvoice) => {
      if (!activeCompany) return;
      handleUpdateCompany({ ...activeCompany, recurringInvoices: activeCompany.recurringInvoices.map(r => r.id === updatedProfile.id ? updatedProfile : r) });
  };

  const handleDeleteRecurring = (id: string) => {
      if (!activeCompany) return;
      handleUpdateCompany({ ...activeCompany, recurringInvoices: activeCompany.recurringInvoices.filter(r => r.id !== id) });
  };

  const createCompanyDataUpdater = <T,>(dataType: keyof Omit<Company, 'id' | 'ownerId' | 'details' | 'invoices' | 'recurringInvoices'>) => (data: T[]) => {
      if(!activeCompany) return;
      const updatedCompany = { ...activeCompany, [dataType]: data };
      handleUpdateCompany(updatedCompany as Company);
  };

  const setClients = createCompanyDataUpdater<Client>('clients');
  const setItems = createCompanyDataUpdater<Item>('items');
  const setTransporters = createCompanyDataUpdater<Transporter>('transporters');

  const handleSaveInvoice = (invoiceData: Invoice | Omit<Invoice, 'id' | 'status'>) => {
        if (!activeCompany) return;
        let updatedItems = [...activeCompany.items];
        let updatedInvoices = [...activeCompany.invoices];
        let updatedDetails = { ...activeCompany.details };

        if ('id' in invoiceData) {
            const updatedInvoice = invoiceData as Invoice;
            const originalInvoice = activeCompany.invoices.find(inv => inv.id === updatedInvoice.id);
            if (!originalInvoice) return; 
            const originalItemsMap = new Map<string, number>(originalInvoice.items.map(item => [item.id, item.quantity] as [string, number]));
            const updatedItemsMap = new Map<string, number>(updatedInvoice.items.map(item => [item.id, item.quantity] as [string, number]));
            const allItemIds = new Set([...originalItemsMap.keys(), ...updatedItemsMap.keys()]);

            allItemIds.forEach(itemId => {
                const originalQty = originalItemsMap.get(itemId) || 0;
                const updatedQty = updatedItemsMap.get(itemId) || 0;
                const diff = originalQty - updatedQty;
                const itemIndex = updatedItems.findIndex(i => i.id === itemId);
                if (itemIndex > -1) {
                    const currentStock = Number(updatedItems[itemIndex].quantityInStock) || 0;
                    updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: currentStock + diff };
                }
            });
            updatedInvoices = updatedInvoices.map(inv => inv.id === updatedInvoice.id ? updatedInvoice : inv);
        } else {
            const newInvoiceData = invoiceData as Omit<Invoice, 'id' | 'status'>;
            const nextNumber = Number(activeCompany.details.nextInvoiceNumber || 1);
            const expectedInvoiceNumber = `${activeCompany.details.invoicePrefix || 'INV-'}${nextNumber.toString().padStart(3, '0')}`;
            newInvoiceData.items.forEach(soldItem => {
                const itemIndex = updatedItems.findIndex(i => i.id === soldItem.id);
                if (itemIndex > -1) {
                    const currentStock = Number(updatedItems[itemIndex].quantityInStock) || 0;
                    updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: currentStock - soldItem.quantity };
                }
            });
            const newInvoice: Invoice = { ...newInvoiceData, id: `inv_${Date.now()}`, status: 'Unpaid' };
            updatedInvoices.push(newInvoice);
            if (newInvoiceData.invoiceNumber === expectedInvoiceNumber) updatedDetails.nextInvoiceNumber = nextNumber + 1;
        }

        handleUpdateCompany({ ...activeCompany, items: updatedItems, invoices: updatedInvoices.sort((a,b) => b.invoiceNumber.localeCompare(a.invoiceNumber, undefined, {numeric: true})), details: updatedDetails });
        // Reset Draft
        setDraftInvoice(emptyDraftInvoice);
  };

    const handleDeleteInvoice = (invoiceId: string) => handleBulkDeleteInvoices([invoiceId]);

    const handleBulkDeleteInvoices = (ids: string[]) => {
        if (!activeCompany) return;
        let updatedItems = [...activeCompany.items];
        const invoicesToDelete = activeCompany.invoices.filter(inv => ids.includes(inv.id));
        invoicesToDelete.forEach(invoice => {
             invoice.items.forEach(soldItem => {
                const itemIndex = updatedItems.findIndex(i => i.id === soldItem.id);
                if (itemIndex > -1) {
                    const currentStock = Number(updatedItems[itemIndex].quantityInStock) || 0;
                    updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: currentStock + soldItem.quantity }
                }
             });
        });
        const updatedInvoices = activeCompany.invoices.filter(inv => !ids.includes(inv.id));
        handleUpdateCompany({ ...activeCompany, items: updatedItems, invoices: updatedInvoices });
    };

    const handleUpdateInvoiceStatus = (invoiceId: string, status: Invoice['status']) => handleBulkStatusChange([invoiceId], status);

    const handleBulkStatusChange = (ids: string[], status: Invoice['status']) => {
        if (!activeCompany) return;
        const updatedInvoices = activeCompany.invoices.map(inv => ids.includes(inv.id) ? { ...inv, status } : inv);
        handleUpdateCompany({ ...activeCompany, invoices: updatedInvoices });
    };

    const handleBulkDeleteClients = (ids: string[]) => {
        if(!activeCompany) return;
        handleUpdateCompany({ ...activeCompany, clients: activeCompany.clients.filter(c => !ids.includes(c.id)) });
    };

    const handleBulkDeleteItems = (ids: string[]) => {
        if(!activeCompany) return;
        handleUpdateCompany({ ...activeCompany, items: activeCompany.items.filter(i => !ids.includes(i.id)) });
    };

  const handleEditInvoice = (invoiceId: string) => {
    const invoice = activeCompany?.invoices.find(inv => inv.id === invoiceId);
    if (invoice) {
      setInvoiceToEdit(invoice);
      setActiveView('NewInvoice');
    }
  };

  if (!currentUser) {
    return <div className="w-full h-screen bg-slate-100 dark:bg-secondary-dark flex items-center justify-center"><Auth onLogin={handleLogin} onSignup={handleSignup} onGoogleLogin={handleGoogleLogin} onCheckUserExists={handleCheckUser} onResetPassword={handleResetPassword} /></div>;
  }

  if (!activeCompany) {
    return <CompanyManager onAddCompany={handleAddCompany} onLogout={handleLogout}/>;
  }

  const renderView = () => {
    switch (activeView) {
      case 'Dashboard': return <Dashboard invoices={activeCompany.invoices} items={activeCompany.items} company={activeCompany} setActiveView={setActiveView} />;
      case 'NewInvoice': return <NewInvoice company={activeCompany} saveInvoice={handleSaveInvoice} setActiveView={setActiveView} invoiceToEdit={invoiceToEdit} clearEditingInvoice={() => setInvoiceToEdit(null)} onUpdateCompany={handleUpdateCompany} draftInvoice={draftInvoice} setDraftInvoice={setDraftInvoice} />;
      case 'Invoices': return <Invoices invoices={activeCompany.invoices} company={activeCompany} setActiveView={setActiveView} onEdit={handleEditInvoice} onDelete={handleDeleteInvoice} onStatusChange={handleUpdateInvoiceStatus} onBulkDelete={handleBulkDeleteInvoices} onBulkStatusChange={handleBulkStatusChange} onAddRecurring={handleAddRecurring} onUpdateRecurring={handleUpdateRecurring} onDeleteRecurring={handleDeleteRecurring} />;
      case 'Clients': return <Clients clients={activeCompany.clients} setClients={setClients} invoices={activeCompany.invoices} company={activeCompany} onEditInvoice={handleEditInvoice} onDeleteInvoice={handleDeleteInvoice} onStatusChange={handleUpdateInvoiceStatus} onBulkDelete={handleBulkDeleteClients} />;
      case 'Items': return <Items items={activeCompany.items} setItems={setItems} company={activeCompany} onBulkDelete={handleBulkDeleteItems} />;
      case 'Inventory': return <Inventory items={activeCompany.items} setItems={setItems} />;
      case 'Transporters': return <Transporters transporters={activeCompany.transporters} setTransporters={setTransporters} />;
      case 'Settings': return <Settings activeCompany={activeCompany} updateCompany={handleUpdateCompany} />;
      default: return <Dashboard invoices={activeCompany.invoices} items={activeCompany.items} company={activeCompany} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-100 dark:bg-secondary-dark font-sans transition-colors relative">
      <Sidebar 
        activeView={activeView} setActiveView={setActiveView} theme={theme} setTheme={setTheme} 
        userCompanies={userCompanies} activeCompany={activeCompany} 
        onSwitchCompany={handleSwitchCompany}
        onAddCompany={() => setIsAddCompanyModalOpen(true)}
        onLogout={handleLogout}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
        currentUser={currentUser}
        onOpenProfile={() => setIsProfileOpen(true)}
      />
      <main className="flex-1 p-8 overflow-y-auto">
        <div className="md:hidden mb-4">
            <button onClick={() => setIsSidebarOpen(true)} className="p-2 rounded-md text-slate-600 dark:text-light-text hover:bg-slate-200 dark:hover:bg-tertiary-dark">
