        const totalOverdue = dataContext.invoices.filter(i => i.status === 'Overdue').reduce((sum, i) => sum + i.grandTotal, 0);
        const lowStockCount = dataContext.items.filter(i => i.quantityInStock <= 5).length;
        return {
            totalRevenue,
            totalOverdue,
            totalInvoices: dataContext.invoices.length,
            lowStockCount
        };
    }, []);

    // Tool Definitions
    const toolDeclarations: FunctionDeclaration[] = [
        {
            name: 'navigate',
