            parameters: {
                type: Type.OBJECT,
                properties: {
                    itemName: { type: Type.STRING },
                    quantity: { type: Type.NUMBER }
                },
                required: ['itemName', 'quantity']
            }
        },
        // --- NEW TOOLS FOR FULL INVOICE CONTROL ---
        {
            name: 'updateInvoiceDetails',
            description: 'Update invoice details like date, due date, notes, vehicle number, transporter.',
            parameters: {
                type: Type.OBJECT,
                properties: {
