            parameters: {
                type: Type.OBJECT,
                properties: {
                    field: { type: Type.STRING },
                    value: { type: Type.STRING }
                },
                required: ['field', 'value']
            }
        }
    ];

    const connect = async () => {
        if (!process.env.API_KEY) {
            console.error("API Key is missing.");
            return;
        }

        setStatusText("Requesting Mic...");
        try {
            // Setup Audio Contexts and Stream first
            const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
            inputAudioCtxRef.current = new AudioContextClass({ sampleRate: 16000 });
            outputAudioCtxRef.current = new AudioContextClass({ sampleRate: 24000 });

            // Get user media
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            mediaStreamRef.current = stream;

            outputNodeRef.current = outputAudioCtxRef.current.createGain();
            outputNodeRef.current.connect(outputAudioCtxRef.current.destination);

        } catch (err) {
            console.error("Microphone access denied:", err);
            setStatusText("Mic Denied");
            return;
        }

        setStatusText("Connecting...");

        try {
            aiRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY });

            // Context Construction
            const { clients, items } = propsRef.current.dataContext;
            const clientList = clients.map(c => c.name).slice(0, 100).join(", ");
            const itemList = items.map(i => i.name).slice(0, 100).join(", ");

            const systemInstruction = `You are a smart voice assistant for 'InvoicePro'.

YOUR CAPABILITIES:
1. Navigation: Move between pages (Dashboard, Invoices, Clients, Inventory, etc.).
2. Data Entry: Add clients, items, or draft invoices.
3. Management: Update stock, changing status, delete records.
4. **Full Invoice Control**: Set dates, notes, vehicle numbers, shipping addresses, add/remove items, and SAVE invoices.

CONTEXT DATA (Use this for Entity Matching):
- Existing Clients: ${clientList || 'No clients'}
- Existing Items: ${itemList || 'No items'}

CRITICAL RULES:
- **DUPLICATE CHECK**: Before adding a new client or item, CHECK the Existing Clients/Items lists. 
  - If a user says "Add client Acme", and "Acme Corp" exists, ask: "Did you mean the existing Acme Corp?".
  - If the tool returns a failure message about duplicates, report that to the user clearly.
- **Invoice Creation**: 
  - Use 'draftInvoice' to start.
  - Use 'updateInvoiceDetails' for dates, notes, vehicle numbers.
  - Use 'updateShippingDetails' for shipping address.
  - Use 'saveDraftInvoice' when the user says "Save" or "Finish".
- **Responses**: Be concise. "Invoice saved", "Added item", "Navigating to settings".

Keep the conversation professional and efficient.`;

            const sessionPromise = aiRef.current.live.connect({
                model: 'gemini-2.5-flash-native-audio-preview-09-2025',
                callbacks: {
                    onopen: async () => {
                        setStatusText("Listening");
                        setIsActive(true);

                        if (inputAudioCtxRef.current && mediaStreamRef.current) {
                            const source = inputAudioCtxRef.current.createMediaStreamSource(mediaStreamRef.current);
                            scriptProcessorRef.current = inputAudioCtxRef.current.createScriptProcessor(4096, 1, 1);

                            scriptProcessorRef.current.onaudioprocess = (e) => {
                                const inputData = e.inputBuffer.getChannelData(0);
                                const pcmBlob = createBlob(inputData);
                                sessionPromiseRef.current?.then(session => {
                                    session.sendRealtimeInput({ media: pcmBlob });
                                });
                            };

                            source.connect(scriptProcessorRef.current);
                            scriptProcessorRef.current.connect(inputAudioCtxRef.current.destination);
                        }
                    },
                    onmessage: async (message: LiveServerMessage) => {
                        // Handle Tool Calls
                        if (message.toolCall) {
                            for (const fc of message.toolCall.functionCalls) {
                                let result: any = { success: true };
                                const args = fc.args as any;

                                setCurrentAction(`Processing: ${fc.name}...`);

                                switch (fc.name) {
                                    case 'navigate':
                                        setCurrentAction(`Navigating to ${args.viewName}`);
                                        result = navigateToView(args.viewName);
                                        break;
                                    case 'getDashboardStats':
                                        setCurrentAction('Fetching stats...');
                                        result = getDashboardStats();
                                        break;
                                    case 'addClient':
                                        setCurrentAction(`Adding client: ${args.name}`);
                                        result = propsRef.current.onAddClient(args);
                                        break;
                                    case 'addItem':
                                        setCurrentAction(`Adding item: ${args.name}`);
                                        result = propsRef.current.onAddItem(args);
                                        break;
                                    case 'updateStock':
                                        setCurrentAction(`Updating stock for ${args.itemName}`);
                                        result = propsRef.current.onUpdateStock(args.itemName, args.quantity);
                                        break;
                                    case 'draftInvoice':
                                        setCurrentAction(`Drafting invoice for ${args.clientName}`);
                                        result = propsRef.current.onDraftInvoice(args.clientName);
                                        break;
                                    case 'addInvoiceItem':
                                        setCurrentAction(`Adding ${args.quantity} ${args.itemName}(s)`);
                                        result = propsRef.current.onAddDraftItem(args.itemName, args.quantity);
                                        break;
                                    // New Invoice Tools
                                    case 'updateInvoiceDetails':
                                        setCurrentAction('Updating invoice details...');
                                        result = propsRef.current.onUpdateInvoiceDetails(args);
                                        break;
                                    case 'updateShippingDetails':
                                        setCurrentAction('Updating shipping details...');
                                        result = propsRef.current.onUpdateShippingDetails(args);
                                        break;
                                    case 'removeInvoiceItem':
                                        setCurrentAction(`Removing item ${args.itemName}`);
                                        result = propsRef.current.onRemoveInvoiceItem(args.itemName);
                                        break;
                                    case 'saveDraftInvoice':
                                        setCurrentAction('Saving invoice...');
                                        result = propsRef.current.onSaveDraftInvoice();
                                        break;
                                    // ----------------
                                    case 'emailInvoice':
                                        setCurrentAction(`Preparing email for ${args.invoiceNumber}`);
                                        result = propsRef.current.onOpenEmailModal(args.invoiceNumber);
                                        break;
                                    case 'deleteClient':
                                        setCurrentAction(`Deleting client ${args.clientName}`);
                                        result = propsRef.current.onDeleteClient ? propsRef.current.onDeleteClient(args.clientName) : { success: false, message: 'Not supported' };
                                        break;
                                    case 'deleteInvoice':
                                        setCurrentAction(`Deleting invoice ${args.invoiceNumber}`);
                                        result = propsRef.current.onDeleteInvoice ? propsRef.current.onDeleteInvoice(args.invoiceNumber) : { success: false, message: 'Not supported' };
                                        break;
                                    case 'deleteItem':
                                        setCurrentAction(`Deleting item ${args.itemName}`);
                                        result = propsRef.current.onDeleteItem ? propsRef.current.onDeleteItem(args.itemName) : { success: false, message: 'Not supported' };
                                        break;
                                    case 'updateInvoiceStatus':
                                        setCurrentAction(`Updating status to ${args.status}`);
                                        result = propsRef.current.onUpdateInvoiceStatus ? propsRef.current.onUpdateInvoiceStatus(args.invoiceNumber, args.status) : { success: false, message: 'Not supported' };
                                        break;
                                    case 'updateCompanyInfo':
                                        setCurrentAction(`Updating company ${args.field}`);
                                        result = propsRef.current.onUpdateCompanyInfo ? propsRef.current.onUpdateCompanyInfo(args.field, args.value) : { success: false, message: 'Not supported' };
                                        break;
                                }

                                sessionPromiseRef.current?.then(session => {
                                    session.sendToolResponse({
                                        functionResponses: {
                                            id: fc.id,
                                            name: fc.name,
                                            response: { result }
                                        }
                                    });
                                });
                                // Keep action visible for a moment
                                setTimeout(() => setCurrentAction(null), 3000);
                            }
                        }

                        // Handle Audio Output
                        const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
                        if (audioData && outputAudioCtxRef.current && outputNodeRef.current) {
                            try {
                                const audioBuffer = await decodeAudioData(
                                    decode(audioData),
                                    outputAudioCtxRef.current,
                                    24000,
                                    1
                                );

                                const source = outputAudioCtxRef.current.createBufferSource();
                                source.buffer = audioBuffer;
                                source.connect(outputNodeRef.current);

                                nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioCtxRef.current.currentTime);
                                source.start(nextStartTimeRef.current);
                                nextStartTimeRef.current += audioBuffer.duration;

                                source.onended = () => {
                                    sourcesRef.current.delete(source);
                                };
                                sourcesRef.current.add(source);
                            } catch (e) {
                                console.error("Audio decode error", e);
                            }
                        }
                    },
                    onclose: () => {
                        setStatusText("Disconnected");
                        setIsActive(false);
                    },
                    onerror: (e) => {
                        console.error("Gemini Live API Error:", e);
                        setStatusText("Error");
                        setIsActive(false);
                    }
                },
                config: {
                    responseModalities: [Modality.AUDIO],
                    speechConfig: {
                        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
                    },
                    tools: [{ functionDeclarations: toolDeclarations }],
                    systemInstruction: systemInstruction
                }
            });
            sessionPromiseRef.current = sessionPromise;

        } catch (error) {
            console.error("Connection failed", error);
            setStatusText("Failed");
            setIsActive(false);
        }
    };

    const disconnect = () => {
        if (mediaStreamRef.current) {
            mediaStreamRef.current.getTracks().forEach(track => track.stop());
            mediaStreamRef.current = null;
        }
        if (scriptProcessorRef.current) {
            scriptProcessorRef.current.disconnect();
            scriptProcessorRef.current = null;
        }
        if (inputAudioCtxRef.current) {
            inputAudioCtxRef.current.close();
            inputAudioCtxRef.current = null;
        }
        if (outputAudioCtxRef.current) {
            outputAudioCtxRef.current.close();
            outputAudioCtxRef.current = null;
        }
        if (sessionPromiseRef.current) {
             sessionPromiseRef.current.then(session => session.close());
             sessionPromiseRef.current = null;
        }
        setIsActive(false);
        setStatusText("Idle");
        setCurrentAction(null);
    };

    const toggleSession = () => {
        if (isActive) {
            disconnect();
        } else {
            connect();
        }
    };

    // Cleanup on unmount
    useEffect(() => {
        return () => {
            disconnect();
        };
    }, []);

    return (
        <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end gap-3">
            {/* Status Card */}
            <div className={`transition-all duration-300 transform origin-bottom-right ${isActive || currentAction ? 'scale-100 opacity-100 translate-y-0' : 'scale-90 opacity-0 translate-y-4 pointer-events-none'}`}>
                <div className="bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 shadow-2xl rounded-2xl p-5 w-72 backdrop-blur-xl bg-opacity-95 dark:bg-opacity-95">
                    <div className="flex items-center justify-between mb-3">
                        <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400 dark:text-slate-500">Gemini Assistant</span>
                        {isActive && !currentAction && (
                            <div className="flex items-center gap-2">
                                <span className="relative flex h-2 w-2">
                                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                                    <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                                </span>
                                <span className="text-[10px] font-medium text-green-600 dark:text-green-400">Live</span>
                            </div>
                        )}
                    </div>

                    <div className="min-h-[2.5rem] flex items-center">
                        {currentAction ? (
                            <div className="flex items-start gap-3 w-full animate-fade-in">
                                <div className="flex-shrink-0 p-1.5 bg-accent/10 rounded-lg text-accent mt-0.5">
                                    <ActionIcon />
                                </div>
                                <div className="flex-grow">
                                    <p className="text-sm font-bold text-slate-800 dark:text-white leading-snug">{currentAction}</p>
                                    <p className="text-[10px] text-slate-500 dark:text-slate-400 mt-0.5 font-medium">Processing request...</p>
                                </div>
                            </div>
                        ) : (
                            <div className="w-full">
                                 {statusText === 'Listening' ? (
                                     <div className="flex flex-col items-center justify-center space-y-2">
                                         <p className="text-sm font-semibold text-slate-700 dark:text-slate-200">Listening...</p>
                                         <AudioWaveform />
                                     </div>
                                 ) : (
                                     <div className="text-center py-1">
                                         <p className="text-sm font-medium text-slate-600 dark:text-slate-400">{statusText}</p>
                                         {statusText === 'Connecting...' && <div className="mt-2 h-1 w-full bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden"><div className="h-full bg-accent animate-progress w-1/2"></div></div>}
                                     </div>
                                 )}
                            </div>
                        )}
                    </div>
                </div>
            </div>

            <button
                onClick={toggleSession}
                className={`p-4 rounded-full shadow-xl transition-all duration-300 transform hover:scale-105 active:scale-95 flex items-center justify-center ${
                    isActive 
                        ? 'bg-red-500 hover:bg-red-600 ring-4 ring-red-100 dark:ring-red-900/30' 
                        : 'bg-accent hover:bg-accent-hover ring-4 ring-accent/20 dark:ring-accent/10'
                }`}
                title={isActive ? "Stop Voice Assistant" : "Start Voice Assistant"}
            >
                <div className="text-white">
                    {isActive ? <StopIcon /> : <MicrophoneIcon />}
                </div>
            </button>
        </div>
    );
};

