const Auth: React.FC<AuthProps> = ({ onLogin, onSignup, onGoogleLogin, onCheckUserExists, onResetPassword }) => {
    const [authView, setAuthView] = useState<AuthView>('login');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [name, setName] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [formError, setFormError] = useState('');
    const [fieldErrors, setFieldErrors] = useState<{ email?: string, password?: string, confirmPassword?: string, name?: string }>({});
    const [emailToReset, setEmailToReset] = useState('');

    const resetFormState = (view: AuthView) => {
        setAuthView(view);
        setFormError('');
        setFieldErrors({});
        setEmail('');
        setPassword('');
        setName('');
        setConfirmPassword('');
    };

    const validateAndSetField = useCallback((
        fieldName: 'email' | 'password' | 'confirmPassword' | 'name', 
        value: string, 
        isSignupOrReset: boolean = false
    ) => {
        let error: string | null = null;
        if (fieldName === 'email') {
            error = validateRequired(value) || validateEmail(value);
        } else if (fieldName === 'password') {
            error = validateRequired(value);
            if (!error && isSignupOrReset) {
                error = validatePasswordStrength(value);
            }
        } else if (fieldName === 'confirmPassword') {
            error = validateRequired(value);
            if (!error && value !== password) {
                error = "Passwords do not match.";
            }
        } else if (fieldName === 'name') {
            error = validateRequired(value);
        }
        setFieldErrors(prev => ({ ...prev, [fieldName]: error || undefined }));
        return !error;
    }, [password]);

    const handleLoginSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        setFormError('');
        const isEmailValid = validateAndSetField('email', email);
        const isPasswordValid = validateAndSetField('password', password);
        if (!isEmailValid || !isPasswordValid) return;

        if (!onLogin(email, password)) {
            setFormError('Invalid email or password.');
        }
    };

    const handleSignupSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        setFormError('');
        const isNameValid = validateAndSetField('name', name);
        const isEmailValid = validateAndSetField('email', email);
        const isPasswordValid = validateAndSetField('password', password, true);
        if (!isNameValid || !isEmailValid || !isPasswordValid) return;

        if (!onSignup(email, password, name)) {
            setFormError('Could not sign up. The email might already be in use.');
        }
    };

    const handleForgotPasswordSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        setFormError('');
        const isEmailValid = validateAndSetField('email', email);
        if(!isEmailValid) return;

        if(onCheckUserExists(email)) {
            setEmailToReset(email);
            resetFormState('resetPassword');
        } else {
            setFormError("No account found with that email address.");
        }
    };

    const handleResetPasswordSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        setFormError('');
        const isPasswordValid = validateAndSetField('password', password, true);
        const isConfirmPasswordValid = validateAndSetField('confirmPassword', confirmPassword);

        if (!isPasswordValid || !isConfirmPasswordValid) return;

        if(onResetPassword(emailToReset, password)) {
            resetFormState('resetSuccess');
        } else {
            setFormError("Could not reset password. Please try again.");
        }
    };

    // --- VIEW RENDERERS ---

    const renderLogin = () => (
        <div className="animate-fade-in space-y-6">
            <div className="text-center lg:text-left">
                <h1 className="text-4xl font-extrabold text-slate-900 dark:text-white tracking-tight mb-2">Welcome Back</h1>
                <p className="text-slate-500 dark:text-slate-400 text-lg">Enter your details to access your workspace.</p>
            </div>

            <form onSubmit={handleLoginSubmit} className="space-y-5">
                <Input 
                    label="Email" 
                    id="email" 
                    type="email" 
                    value={email} 
                    onChange={(e) => { setEmail(e.target.value); validateAndSetField('email', e.target.value); }} 
                    required 
                    placeholder="name@company.com" 
                    error={fieldErrors.email}
                    className="!bg-white dark:!bg-slate-800/50"
                />
                <div className="space-y-1">
                    <Input 
                        label="Password" 
                        id="password" 
                        type="password" 
                        value={password} 
                        onChange={(e) => { setPassword(e.target.value); validateAndSetField('password', e.target.value);}} 
                        required 
                        placeholder="••••••••" 
                        error={fieldErrors.password}
                        className="!bg-white dark:!bg-slate-800/50"
                    />
                    <div className="text-right">
                        <button type="button" onClick={() => resetFormState('forgotPassword')} className="text-sm font-semibold text-indigo-600 hover:text-indigo-500 dark:text-indigo-400 dark:hover:text-indigo-300 transition-colors">
                            Forgot Password?
                        </button>
                    </div>
                </div>

                {formError && (
                    <div className="p-4 rounded-xl bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 text-sm font-medium border border-red-100 dark:border-red-900/30 flex items-center gap-2 animate-shake">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                        {formError}
                    </div>
                )}

                <Button type="submit" className="w-full !py-4 !text-lg !rounded-xl shadow-lg shadow-indigo-500/30 hover:shadow-indigo-500/40 transition-all transform hover:-translate-y-0.5 active:translate-y-0 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 border-0 animate-gradient-x text-white">
                    Sign In
                </Button>
            </form>

            <Divider />
            <GoogleButton onClick={onGoogleLogin} text="Sign in with Google" />

            <p className="text-center mt-8 text-slate-600 dark:text-slate-400">
                Don't have an account? <button onClick={() => resetFormState('signup')} className="font-bold text-indigo-600 hover:text-indigo-500 dark:text-indigo-400 transition-colors hover:underline decoration-2 underline-offset-2">Create an account</button>
            </p>
        </div>
    );

    const renderSignup = () => (
        <div className="animate-fade-in space-y-6">
            <div className="text-center lg:text-left">
                <h1 className="text-4xl font-extrabold text-slate-900 dark:text-white tracking-tight mb-2">Create Account</h1>
                <p className="text-slate-500 dark:text-slate-400 text-lg">Start automating your invoices today.</p>
            </div>

            <form onSubmit={handleSignupSubmit} className="space-y-5">
                <Input label="Full Name" id="name" type="text" value={name} onChange={(e) => { setName(e.target.value); validateAndSetField('name', e.target.value); }} required placeholder="John Doe" error={fieldErrors.name} className="!bg-white dark:!bg-slate-800/50"/>
                <Input label="Email" id="email" type="email" value={email} onChange={(e) => { setEmail(e.target.value); validateAndSetField('email', e.target.value); }} required placeholder="name@company.com" error={fieldErrors.email} className="!bg-white dark:!bg-slate-800/50"/>
                <Input label="Password" id="password" type="password" value={password} onChange={(e) => { setPassword(e.target.value); validateAndSetField('password', e.target.value, true); }} required placeholder="Create a strong password" error={fieldErrors.password} className="!bg-white dark:!bg-slate-800/50"/>

                {formError && (
                    <div className="p-4 rounded-xl bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 text-sm font-medium border border-red-100 dark:border-red-900/30 flex items-center gap-2 animate-shake">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                        {formError}
                    </div>
                )}

                <Button type="submit" className="w-full !py-4 !text-lg !rounded-xl shadow-lg shadow-indigo-500/30 hover:shadow-indigo-500/40 transition-all transform hover:-translate-y-0.5 active:translate-y-0 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 border-0 animate-gradient-x text-white">
                    Create Account
                </Button>
            </form>

            <Divider />
            <GoogleButton onClick={onGoogleLogin} text="Sign up with Google" />

            <p className="text-center mt-8 text-slate-600 dark:text-slate-400">
                Already have an account? <button onClick={() => resetFormState('login')} className="font-bold text-indigo-600 hover:text-indigo-500 dark:text-indigo-400 transition-colors hover:underline decoration-2 underline-offset-2">Sign in</button>
            </p>
        </div>
    );

    const renderForgotPassword = () => (
        <div className="animate-fade-in space-y-6">
            <button onClick={() => resetFormState('login')} className="flex items-center gap-2 text-sm font-semibold text-slate-500 hover:text-slate-800 dark:text-slate-400 dark:hover:text-white transition-colors mb-4 group">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 transition-transform group-hover:-translate-x-1" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                Back to Sign In
            </button>

            <div className="text-center lg:text-left">
                <div className="inline-flex p-3 rounded-full bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 mb-4">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 14l-1 1-1 1H6v-2l2-2 2-2 6.344-6.344A2 2 0 0115 7zm7 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>
                </div>
                <h1 className="text-3xl font-extrabold text-slate-900 dark:text-white tracking-tight mb-2">Forgot Password?</h1>
                <p className="text-slate-500 dark:text-slate-400">Enter your email and we'll send you a link to reset your password.</p>
            </div>

            <form onSubmit={handleForgotPasswordSubmit} className="space-y-6">
                <Input label="Email Address" id="email" type="email" value={email} onChange={(e) => {setEmail(e.target.value); validateAndSetField('email', e.target.value);}} required placeholder="you@company.com" error={fieldErrors.email} className="!bg-white dark:!bg-slate-800/50"/>
                {formError && <div className="p-4 rounded-xl bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 text-sm font-medium border border-red-100 dark:border-red-900/30">{formError}</div>}
                <Button type="submit" className="w-full !py-4 !text-lg !rounded-xl shadow-lg shadow-indigo-500/20 bg-indigo-600 hover:bg-indigo-500 border-0">Send Reset Link</Button>
            </form>
        </div>
    );

    const renderResetPassword = () => (
        <div className="animate-fade-in space-y-6">
            <div className="text-center lg:text-left">
                <h1 className="text-3xl font-extrabold text-slate-900 dark:text-white tracking-tight mb-2">Reset Password</h1>
                <p className="text-slate-500 dark:text-slate-400">Create a new strong password for your account.</p>
            </div>
            <form onSubmit={handleResetPasswordSubmit} className="space-y-6">
                <Input label="New Password" id="password" type="password" value={password} onChange={(e) => { setPassword(e.target.value); validateAndSetField('password', e.target.value, true); }} required placeholder="New password" error={fieldErrors.password} className="!bg-white dark:!bg-slate-800/50"/>
                <Input label="Confirm New Password" id="confirmPassword" type="password" value={confirmPassword} onChange={(e) => { setConfirmPassword(e.target.value); validateAndSetField('confirmPassword', e.target.value); }} required placeholder="Confirm new password" error={fieldErrors.confirmPassword} className="!bg-white dark:!bg-slate-800/50"/>
                {formError && <div className="p-4 rounded-xl bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 text-sm font-medium border border-red-100 dark:border-red-900/30">{formError}</div>}
                <Button type="submit" className="w-full !py-4 !text-lg !rounded-xl shadow-lg shadow-indigo-500/20 bg-indigo-600 hover:bg-indigo-500 border-0">Set New Password</Button>
            </form>
        </div>
    );

    const renderResetSuccess = () => (
        <div className="animate-fade-in text-center py-8">
             <div className="w-20 h-20 bg-green-100 dark:bg-green-900/30 rounded-full flex items-center justify-center mx-auto mb-6 shadow-sm">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-green-600 dark:text-green-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
