// --- Helper to convert number to words (Indian format) ---
export const numberToWords = (num: number): string => {
    const a = ['', 'one ', 'two ', 'three ', 'four ', 'five ', 'six ', 'seven ', 'eight ', 'nine ', 'ten ', 'eleven ', 'twelve ', 'thirteen ', 'fourteen ', 'fifteen ', 'sixteen ', 'seventeen ', 'eighteen ', 'nineteen '];
    const b = ['', '', 'twenty', 'thirty', 'forty', 'fifty', 'sixty', 'seventy', 'eighty', 'ninety'];
    const g = ['', 'thousand', 'lakh', 'crore'];

    const inWords = (n: number): string => {
        if (n > 999999999) return 'overflow';
        let nStr = n.toString();
        if (nStr.length > 9) {
            nStr = nStr.substring(nStr.length - 9); // support up to 999 crores
        }
        let res = '';
        const lakhCrore = (num: number, divisor: number, word: string) => {
            const quotient = Math.floor(num / divisor);
            if (quotient > 0) {
                res += inWords(quotient) + word;
                num %= divisor;
            }
            return num;
        };
        n = lakhCrore(n, 10000000, 'crore ');
        n = lakhCrore(n, 100000, 'lakh ');
        n = lakhCrore(n, 1000, 'thousand ');

        const hundreds = Math.floor(n / 100);
        if (hundreds > 0) {
            res += a[hundreds] + 'hundred ';
            n %= 100;
        }

        if (n > 0) {
            if (res !== '') res += 'and ';
            if (n < 20) {
                res += a[n];
            } else {
                res += b[Math.floor(n / 10)] + a[n % 10];
            }
        }
        return res;
    };

    if (typeof num !== 'number') return '';
    let numStr = num.toFixed(2).toString();
    const [rupeesStr, paiseStr] = numStr.split('.');
    let rupees = parseInt(rupeesStr);
    let paise = parseInt(paiseStr);

    let output = inWords(rupees);
    if (output.trim() === '') output = 'Zero ';

    let finalOutput = output.trim().split(' ').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' ') + ' Rupees';

    if (paise > 0) {
        finalOutput += ' and ' + inWords(paise).trim().split(' ').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' ') + ' Paise';
    }

    return finalOutput + ' Only';
};

