// --- InvoiceView Component for Modal ---
interface InvoiceViewProps {
  invoice: Invoice;
  company: Company;
  onClose: () => void;
}

export const InvoiceView: React.FC<InvoiceViewProps> = ({ invoice, company, onClose }) => {
  const printRef = useRef<HTMLDivElement>(null);

  const generatePdf = async () => {
    if (!printRef.current) return null;
    try {
        const canvas = await (window as any).html2canvas(printRef.current, { 
            scale: 2,
            backgroundColor: '#ffffff'
        });

        const imgData = canvas.toDataURL('image/png');
        const pdf = new (window as any).jspdf.jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });

        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();
        const canvasWidth = canvas.width;
        const canvasHeight = canvas.height;

        // Calculate scaling
        const imgHeight = canvasHeight * pdfWidth / canvasWidth;

        // If content fits on one page (with small margin), scale it to fit height if necessary to force single page
        // as per user request to avoid blank/multiple pages if close.
        let renderHeight = imgHeight;
        let renderWidth = pdfWidth;

        if (imgHeight > pdfHeight) {
            // Content is taller than one page. Scale down to fit one page.
            const ratio = pdfHeight / imgHeight;
            renderHeight = pdfHeight - 10; // 10mm margin bottom
            renderWidth = pdfWidth * ratio;
        }

        pdf.addImage(imgData, 'PNG', (pdfWidth - renderWidth) / 2, 0, renderWidth, renderHeight);

        return pdf;
    } catch(error) {
        console.error("Error generating PDF:", error);
        alert("Failed to generate PDF. Please try again.");
        return null;
    }
  };

  const handleDownloadPdf = async () => {
    const pdf = await generatePdf();
    if (pdf) {
        pdf.save(`Invoice-${invoice.invoiceNumber}.pdf`);
    }
  };

  const handlePrint = async () => {
    const pdf = await generatePdf();
    if (pdf) {
        pdf.autoPrint();
        window.open(pdf.output('bloburl'), '_blank');
    }
  };

  const handleShareWhatsApp = () => {
      const text = `*Invoice from ${company.details.name}*%0A%0AHello ${invoice.client.name},%0A%0AHere are the details for *Invoice ${invoice.invoiceNumber}*:%0A%0A*Total Amount:* ₹${invoice.grandTotal.toFixed(2)}%0A*Issue Date:* ${invoice.issueDate}%0A*Due Date:* ${invoice.dueDate}%0A%0APlease arrange for payment at your earliest convenience.%0A%0AThank you.`;
      window.open(`https://wa.me/?text=${text}`, '_blank');
  };

  return (
    <>
      <div className="max-h-[80vh] overflow-y-auto bg-slate-200 dark:bg-tertiary-dark p-4 flex justify-center">
        {/* Render invoice without fixed height to let content flow naturally, but min-h for A4 look */}
        <div ref={printRef} className="w-[210mm] bg-white min-h-[297mm] shadow-lg"> 
          <InvoiceContent invoice={invoice} company={company} />
        </div>
      </div>
      <div className="p-6 bg-white dark:bg-primary-dark flex justify-end gap-4 rounded-b-lg border-t border-slate-100 dark:border-slate-800 sticky bottom-0 z-10">
        <Button variant="secondary" onClick={onClose}>Close</Button>
        <button onClick={handleShareWhatsApp} className="px-4 py-2 text-sm font-semibold rounded-md shadow-sm focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 bg-green-500 text-white hover:bg-green-600 flex items-center gap-2">
            <WhatsAppIcon /> Share via WhatsApp
        </button>
        <Button onClick={handleDownloadPdf}>Download PDF</Button>
        <Button onClick={handlePrint}>Print</Button>
      </div>
    </>
  );
};


