    }
  }, [invoiceToEmail, company.details.name]);


  const filteredInvoices = useMemo(() => {
    let result = [...invoices];
    const lowercasedQuery = searchQuery.toLowerCase();

    if (lowercasedQuery) {
        result = result.filter(invoice => 
            invoice.invoiceNumber.toLowerCase().includes(lowercasedQuery) ||
            invoice.client.name.toLowerCase().includes(lowercasedQuery) ||
            (invoice.notes && invoice.notes.toLowerCase().includes(lowercasedQuery))
        );
    }
    if (filterClient) result = result.filter(invoice => invoice.client.id === filterClient);
    if (filterStatus) result = result.filter(invoice => invoice.status === filterStatus);
    if (filterStartDate) result = result.filter(invoice => invoice.issueDate >= filterStartDate);
    if (filterEndDate) result = result.filter(invoice => invoice.issueDate <= filterEndDate);
    if (filterMinAmount) result = result.filter(inv => inv.grandTotal >= parseFloat(filterMinAmount));
    if (filterMaxAmount) result = result.filter(inv => inv.grandTotal <= parseFloat(filterMaxAmount));

    return result;
  }, [invoices, searchQuery, filterClient, filterStatus, filterStartDate, filterEndDate, filterMinAmount, filterMaxAmount]);

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.checked) setSelectedIds(filteredInvoices.map(inv => inv.id));
      else setSelectedIds([]);
  };

  const handleSelectOne = (id: string) => {
      if (selectedIds.includes(id)) setSelectedIds(selectedIds.filter(sid => sid !== id));
      else setSelectedIds([...selectedIds, id]);
  };

  const handleBulkDelete = () => {
      if (window.confirm(`Are you sure you want to delete ${selectedIds.length} invoices?`)) {
          onBulkDelete(selectedIds);
          setSelectedIds([]);
      }
  };

  const handleBulkStatusUpdate = (status: Invoice['status']) => {
      onBulkStatusChange(selectedIds, status);
      setSelectedIds([]);
  };

  const handleExport = async (exportAll: boolean = false) => {
    setIsExporting(true);

    // Small delay to allow UI to update
    await new Promise(resolve => setTimeout(resolve, 50));

    try {
        let dataToExport = exportAll ? invoices : filteredInvoices.filter(inv => selectedIds.length === 0 || selectedIds.includes(inv.id));
        if (isExportModalOpen) {
            const { startDate, endDate, status } = exportFilters;
            if (startDate) dataToExport = dataToExport.filter(inv => inv.issueDate >= startDate);
            if (endDate) dataToExport = dataToExport.filter(inv => inv.issueDate <= endDate);
            if (status && status !== 'All') dataToExport = dataToExport.filter(inv => inv.status === status);
        }

        if (exportType === 'gstr1') {
            const csvData = generateGSTR1CSV(dataToExport);
            downloadCSV(csvData, `GSTR1_Export_${new Date().toISOString().split('T')[0]}.csv`);
        } else if (exportType === 'gstr3b') {
            const csvData = generateGSTR3BCSV(dataToExport);
            downloadCSV(csvData, `GSTR3B_Summary_${new Date().toISOString().split('T')[0]}.csv`);
        } else {
            const csvData = arrayToCSV(dataToExport, [
                { key: 'invoiceNumber', label: 'Invoice Number' },
                { key: 'issueDate', label: 'Issue Date' },
                { key: 'dueDate', label: 'Due Date' },
                { key: 'client.name', label: 'Client Name', formatter: (inv) => inv.client.name },
                { key: 'client.gstin', label: 'Client GSTIN', formatter: (inv) => inv.client.gstin },
                { key: 'grandTotal', label: 'Total Amount', formatter: (inv) => inv.grandTotal.toFixed(2) },
                { key: 'status', label: 'Status' },
            ]);
            downloadCSV(csvData, `invoices_export_${new Date().toISOString().split('T')[0]}.csv`);
        }
        setIsExportModalOpen(false);
    } catch (e) {
        console.error("Export failed", e);
        alert("Export failed. Please check the console for details.");
    } finally {
        setIsExporting(false);
    }
  };

  const handleDeleteInvoice = (id: string) => {
    setInvoiceToDelete(id);
    setIsConfirmOpen(true);
  };

  const confirmDelete = () => {
    if (invoiceToDelete) onDelete(invoiceToDelete);
    setIsConfirmOpen(false);
    setInvoiceToDelete(null);
  };

  const handleStatusChange = (id: string, status: Invoice['status']) => {
      onStatusChange(id, status);
      setActiveStatusMenu(null);
  };

  const handleSendEmail = async () => {
    if (!invoiceToEmail || !emailPrintRef.current) return;
    setIsSending(true);
    try {
        const canvas = await (window as any).html2canvas(emailPrintRef.current, { 
            scale: 2,
            backgroundColor: '#ffffff'
        });
        const imgData = canvas.toDataURL('image/png');
        const pdf = new (window as any).jspdf.jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();
        const canvasWidth = canvas.width;
        const canvasHeight = canvas.height;
        const ratio = canvasWidth / pdfWidth;
        const scaledCanvasHeight = canvasHeight / ratio;
        let position = 0;
        pdf.addImage(imgData, 'PNG', 0, position, pdfWidth, scaledCanvasHeight);
        let heightLeft = scaledCanvasHeight - pdfHeight;
        while (heightLeft > 0) {
            position = -heightLeft;
            pdf.addPage();
            pdf.addImage(imgData, 'PNG', 0, position, pdfWidth, scaledCanvasHeight);
            heightLeft -= pdfHeight;
        }
        await new Promise(resolve => setTimeout(resolve, 2000));
        alert(`Email sent successfully to ${recipient} with Invoice-${invoiceToEmail.invoiceNumber}.pdf attached!`);
        setIsSending(false);
        setInvoiceToEmail(null);
    } catch (e) {
        console.error("Error generating PDF or sending email", e);
        setIsSending(false);
        alert("Failed to send email. Please try again.");
    }
  };

  const getStatusBadge = (status: Invoice['status']) => {
    switch (status) {
        case 'Paid': return 'bg-green-100 text-green-700 ring-1 ring-green-600/20 dark:bg-green-900/30 dark:text-green-400 dark:ring-green-400/30';
        case 'Unpaid': return 'bg-yellow-100 text-yellow-700 ring-1 ring-yellow-600/20 dark:bg-yellow-900/30 dark:text-yellow-400 dark:ring-yellow-400/30';
        case 'Overdue': return 'bg-red-100 text-red-700 ring-1 ring-red-600/20 dark:bg-red-900/30 dark:text-red-400 dark:ring-red-400/30';
        default: return 'bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-400';
    }
  };

  const statusOptions: Invoice['status'][] = ['Paid', 'Unpaid', 'Overdue'];

  const handleOpenRecurringModal = (profile?: RecurringInvoice) => {
    if (profile) {
        setEditingRecurringId(profile.id);
        setRecurringProfile({ ...profile });
    } else {
        setEditingRecurringId(null);
        setRecurringProfile({ frequency: 'Monthly', startDate: new Date().toISOString().split('T')[0], items: [], status: 'Active' });
    }
    setIsRecurringModalOpen(true);
  };

  const handleTogglePause = (profile: RecurringInvoice) => {
      onUpdateRecurring({ ...profile, status: profile.status === 'Active' ? 'Paused' : 'Active' });
  };

  const handleRecurringItemChange = (index: number, field: keyof InvoiceItem, value: any) => {
      const updatedItems = [...(recurringProfile.items || [])];
      const currentItem = { ...updatedItems[index] };
      if (field === 'id' && value) {
          const selectedItem = company.items.find(i => i.id === value);
          if (selectedItem) updatedItems[index] = { ...currentItem, ...selectedItem, quantity: 1 };
      } else {
          const newValue = (field === 'quantity' || field === 'price' || field === 'gstRate') ? parseFloat(value) || 0 : value;
          updatedItems[index] = { ...currentItem, [field]: newValue };
      }
      setRecurringProfile({ ...recurringProfile, items: updatedItems });
  };

  const addRecurringItem = () => {
      const newItems = [...(recurringProfile.items || []), { id: '', name: '', hsn: '', price: 0, gstRate: 18, quantity: 1, unit: 'pcs', quantityInStock: 0 }];
      setRecurringProfile({ ...recurringProfile, items: newItems });
  };

  const removeRecurringItem = (index: number) => {
      const newItems = (recurringProfile.items || []).filter((_, i) => i !== index);
      setRecurringProfile({ ...recurringProfile, items: newItems });
  };

  const saveRecurringProfile = () => {
      if (recurringProfile.clientId && recurringProfile.startDate && recurringProfile.frequency && recurringProfile.items?.length) {
          if (editingRecurringId) {
              onUpdateRecurring({ ...(recurringProfile as RecurringInvoice), id: editingRecurringId });
          } else {
              onAddRecurring({
                  clientId: recurringProfile.clientId,
                  startDate: recurringProfile.startDate,
                  frequency: recurringProfile.frequency as RecurringFrequency,
                  items: recurringProfile.items,
                  status: 'Active',
                  nextRunDate: recurringProfile.startDate,
                  endDate: recurringProfile.endDate || undefined
              });
          }
          setIsRecurringModalOpen(false);
          setRecurringProfile({ frequency: 'Monthly', startDate: new Date().toISOString().split('T')[0], items: [] });
          setEditingRecurringId(null);
      }
  };


  return (
    <div>
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold text-slate-900 dark:text-light-text tracking-tight">Invoices</h1>
        <div className="flex gap-4">
             {activeTab === 'invoices' && <Button variant="secondary" onClick={() => setIsExportModalOpen(true)}>Export</Button>}
             {activeTab === 'recurring' && <Button onClick={() => handleOpenRecurringModal()}>New Recurring Profile</Button>}
             {activeTab === 'invoices' && <Button onClick={() => setActiveView('NewInvoice')}>+ Create Invoice</Button>}
        </div>
      </div>

      <div className="mb-6 flex space-x-1 p-1 bg-slate-200 dark:bg-slate-800 rounded-lg w-fit">
          <button className={`px-5 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'invoices' ? 'bg-white dark:bg-primary-dark text-slate-900 dark:text-white shadow-sm' : 'text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white'}`} onClick={() => setActiveTab('invoices')}>All Invoices</button>
          <button className={`px-5 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'recurring' ? 'bg-white dark:bg-primary-dark text-slate-900 dark:text-white shadow-sm' : 'text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white'}`} onClick={() => setActiveTab('recurring')}>Recurring Profiles</button>
      </div>

      {activeTab === 'invoices' && (
        <>
            <div className="mb-6 space-y-4">
                <div className="flex gap-4">
                    <div className="flex-grow">
                        <Input label="" id="search-invoices" placeholder="Search Invoice #, Client, or Notes..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="!py-2.5"/>
                    </div>
                    <Button variant="secondary" onClick={() => setShowFilters(!showFilters)} className="h-[42px] mt-0.5 whitespace-nowrap">
                         {showFilters ? 'Hide Filters' : 'Filters'}
                    </Button>
                </div>

                {showFilters && (
                    <div className="bg-white dark:bg-primary-dark p-6 rounded-xl shadow-sm border border-slate-200 dark:border-slate-800 grid grid-cols-1 md:grid-cols-4 gap-6 animate-fade-in">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1.5">Filter Client</label>
                            <select value={filterClient} onChange={e => setFilterClient(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-300 dark:border-slate-600 text-slate-900 dark:text-light-text rounded-lg shadow-sm px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-accent">
                                <option value="">All Clients</option>
                                {company.clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1.5">Status</label>
                            <select value={filterStatus} onChange={e => setFilterStatus(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-300 dark:border-slate-600 text-slate-900 dark:text-light-text rounded-lg shadow-sm px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-accent">
                                <option value="">All Statuses</option>
                                <option value="Paid">Paid</option>
                                <option value="Unpaid">Unpaid</option>
                                <option value="Overdue">Overdue</option>
                            </select>
                        </div>
                        <div className="grid grid-cols-2 gap-2">
                            <Input label="From Date" type="date" value={filterStartDate} onChange={e => setFilterStartDate(e.target.value)} />
                            <Input label="To Date" type="date" value={filterEndDate} onChange={e => setFilterEndDate(e.target.value)} />
                        </div>
                        <div className="grid grid-cols-2 gap-2">
                            <Input label="Min Amount" type="number" value={filterMinAmount} onChange={e => setFilterMinAmount(e.target.value)} placeholder="0" />
                            <Input label="Max Amount" type="number" value={filterMaxAmount} onChange={e => setFilterMaxAmount(e.target.value)} placeholder="∞" />
                        </div>
                        <div className="md:col-span-4 flex justify-end">
                             <Button variant="secondary" onClick={() => { setFilterClient(''); setFilterStatus(''); setFilterStartDate(''); setFilterEndDate(''); setFilterMinAmount(''); setFilterMaxAmount(''); }} className="text-sm">Clear Filters</Button>
                        </div>
                    </div>
                )}
            </div>

            {selectedIds.length > 0 && (
                <div className="bg-accent/10 dark:bg-accent/20 border border-accent/20 p-4 rounded-lg flex items-center justify-between mb-6 animate-fade-in shadow-sm">
                    <span className="text-sm font-semibold text-accent dark:text-indigo-300 flex items-center gap-2">
                         <span className="w-2 h-2 rounded-full bg-accent animate-pulse"></span>
                         {selectedIds.length} invoices selected
                    </span>
                    <div className="flex gap-2">
                        <Button variant="secondary" className="!py-1.5 !text-xs !bg-white dark:!bg-slate-800 shadow-sm" onClick={() => handleBulkStatusUpdate('Paid')}>Mark Paid</Button>
                        <Button variant="secondary" className="!py-1.5 !text-xs !bg-white dark:!bg-slate-800 shadow-sm" onClick={() => handleBulkStatusUpdate('Unpaid')}>Mark Unpaid</Button>
                        <Button variant="secondary" className="!py-1.5 !text-xs !bg-white dark:!bg-slate-800 shadow-sm" onClick={() => handleExport(false)}>Export Selected</Button>
                        <Button variant="secondary" className="!py-1.5 !text-xs bg-red-50 hover:bg-red-100 !text-red-600 dark:bg-red-900/30 dark:hover:bg-red-900/50 dark:!text-red-300" onClick={handleBulkDelete}>Delete Selected</Button>
                    </div>
                </div>
            )}

            <div className="bg-white dark:bg-primary-dark shadow-sm border border-slate-200 dark:border-slate-800 rounded-xl overflow-hidden">
                <div className="overflow-x-auto">
                <table className="w-full text-sm text-left text-slate-600 dark:text-slate-400">
                    <thead className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800">
                    <tr>
                        <th scope="col" className="px-6 py-4 w-10">
                            <input type="checkbox" checked={filteredInvoices.length > 0 && selectedIds.length === filteredInvoices.length} onChange={handleSelectAll} className="w-4 h-4 rounded border-slate-300 text-accent focus:ring-accent transition-all" />
                        </th>
                        <th scope="col" className="px-6 py-4">Invoice #</th>
                        <th scope="col" className="px-6 py-4">Client</th>
                        <th scope="col" className="px-6 py-4">Issue Date</th>
                        <th scope="col" className="px-6 py-4 text-right">Amount</th>
                        <th scope="col" className="px-6 py-4 text-center">Status</th>
                        <th scope="col" className="px-6 py-4 text-right">Actions</th>
                    </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                    {filteredInvoices.map(invoice => (
                        <tr key={invoice.id} className={`group hover:bg-slate-50 dark:hover:bg-slate-800/30 transition-colors ${selectedIds.includes(invoice.id) ? 'bg-accent/5 dark:bg-accent/10' : ''}`}>
                        <td className="px-6 py-4">
                            <input type="checkbox" checked={selectedIds.includes(invoice.id)} onChange={() => handleSelectOne(invoice.id)} className="w-4 h-4 rounded border-slate-300 text-accent focus:ring-accent transition-all" />
                        </td>
                        <td className="px-6 py-4 font-medium text-slate-900 dark:text-white whitespace-nowrap">{invoice.invoiceNumber}</td>
                        <td className="px-6 py-4">
                            <div className="font-medium text-slate-800 dark:text-slate-200">{invoice.client.name}</div>
                            <div className="text-xs text-slate-500 truncate max-w-[150px]">{invoice.client.email}</div>
                        </td>
                        <td className="px-6 py-4">{invoice.issueDate}</td>
                        <td className="px-6 py-4 text-right font-semibold text-slate-900 dark:text-white">{currency}{invoice.grandTotal.toFixed(2)}</td>
                        <td className="px-6 py-4 text-center">
                            <div className="relative inline-block">
                                <button onClick={() => setActiveStatusMenu(activeStatusMenu === invoice.id ? null : invoice.id)} className={`px-2.5 py-1 rounded-full text-xs font-bold tracking-wide transition-all ${getStatusBadge(invoice.status)} hover:ring-2`}>
                                    {invoice.status}
                                </button>
                                {activeStatusMenu === invoice.id && (
                                    <div className="absolute z-50 top-full mt-2 w-36 left-1/2 -translate-x-1/2 bg-white dark:bg-slate-800 rounded-lg shadow-xl border border-slate-200 dark:border-slate-700 py-1" onMouseLeave={() => setActiveStatusMenu(null)}>
                                        {statusOptions.filter(s => s !== invoice.status).map(status => (
                                            <button key={status} onClick={() => handleStatusChange(invoice.id, status)} className="w-full text-left px-4 py-2 text-sm text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">
                                                Mark as {status}
                                            </button>
                                        ))}
                                    </div>
                                )}
                            </div>
                        </td>
                        <td className="px-6 py-4 text-right space-x-2 whitespace-nowrap">
                             <button onClick={() => setSelectedInvoice(invoice)} className="text-slate-400 hover:text-accent transition-colors" title="View"><svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg></button>
                             <button onClick={() => {
                                 const text = `*Invoice ${invoice.invoiceNumber}* from ${company.details.name}%0AAmount: ₹${invoice.grandTotal.toFixed(2)}%0ADue: ${invoice.dueDate}`;
                                 window.open(`https://wa.me/?text=${text}`, '_blank');
                             }} className="text-slate-400 hover:text-green-500 transition-colors" title="Share WhatsApp"><WhatsAppIcon /></button>
                             <button onClick={() => onEdit(invoice.id)} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors" title="Edit"><svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg></button>
                             <button onClick={() => setInvoiceToEmail(invoice)} className="text-slate-400 hover:text-blue-500 transition-colors" title="Email"><svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" /></svg></button>
                             <button onClick={() => handleDeleteInvoice(invoice.id)} className="text-slate-400 hover:text-red-500 transition-colors" title="Delete"><svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                        </td>
                        </tr>
                    ))}
                    {filteredInvoices.length === 0 && ( <tr><td colSpan={7} className="text-center py-12 text-slate-500 dark:text-slate-400"><div className="flex flex-col items-center"><svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-slate-300 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg><p className="text-lg font-medium text-slate-900 dark:text-white">No invoices found</p><p className="text-sm">Try adjusting your search or filters.</p></div></td></tr>)}
                    </tbody>
                </table>
                </div>
            </div>
        </>
      )}

      {activeTab === 'recurring' && (
          <div className="bg-white dark:bg-primary-dark shadow-sm border border-slate-200 dark:border-slate-800 rounded-xl overflow-hidden">
              <div className="overflow-x-auto">
                  <table className="w-full text-sm text-left text-slate-600 dark:text-slate-400">
                      <thead className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800">
                          <tr>
                              <th className="px-6 py-4">Client</th>
                              <th className="px-6 py-4">Frequency</th>
                              <th className="px-6 py-4">Status</th>
                              <th className="px-6 py-4">Next Run</th>
                              <th className="px-6 py-4">Items</th>
                              <th className="px-6 py-4 text-right">Actions</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                          {company.recurringInvoices?.map(recurring => {
                              const clientName = company.clients.find(c => c.id === recurring.clientId)?.name || 'Unknown Client';
                              const statusColor = recurring.status === 'Active' ? 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-300' : recurring.status === 'Paused' ? 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-300' : 'bg-slate-100 text-slate-800 dark:bg-slate-800 dark:text-slate-300';

                              return (
                                  <tr key={recurring.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/30 transition-colors">
                                      <td className="px-6 py-4 font-medium text-slate-900 dark:text-white">{clientName}</td>
                                      <td className="px-6 py-4"><span className="bg-purple-100 dark:bg-purple-900/30 text-purple-800 dark:text-purple-300 px-2 py-1 rounded text-xs font-bold">{recurring.frequency}</span></td>
                                      <td className="px-6 py-4"><span className={`px-2 py-1 rounded text-xs font-bold ${statusColor}`}>{recurring.status}</span></td>
                                      <td className="px-6 py-4 font-bold text-slate-800 dark:text-slate-200">{recurring.nextRunDate}</td>
                                      <td className="px-6 py-4">{recurring.items.length} Items</td>
                                      <td className="px-6 py-4 text-right space-x-2">
                                          {recurring.status !== 'Completed' && (
