                        <Button onClick={() => switchView('login')} className="w-full py-3 text-base shadow-lg shadow-accent/25 hover:shadow-accent/40 transition-all">Back to Sign In</Button>
                    </div>
                );
        }
    };

    return (
        <div className="flex min-h-screen bg-slate-50 dark:bg-slate-950 font-sans selection:bg-accent selection:text-white overflow-hidden">
