const Auth: React.FC<AuthProps> = ({ onLogin, onSignup, onGoogleLogin, onCheckUserExists, onResetPassword }) => {
    const [authView, setAuthView] = useState<AuthView>('login');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [name, setName] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [formError, setFormError] = useState('');
    const [fieldErrors, setFieldErrors] = useState<{ email?: string, password?: string, confirmPassword?: string, name?: string }>({});
    const [emailToReset, setEmailToReset] = useState('');
    const [isAnimating, setIsAnimating] = useState(false);

    // Transition helper
    const switchView = (view: AuthView) => {
        setIsAnimating(true);
        setTimeout(() => {
            setAuthView(view);
            setFormError('');
            setFieldErrors({});
            setIsAnimating(false);
        }, 300); // Wait for fade out
    };

    const validateAndSetField = useCallback((
        fieldName: 'email' | 'password' | 'confirmPassword' | 'name', 
        value: string, 
        isSignupOrReset: boolean = false
    ) => {
        let error: string | null = null;
        if (fieldName === 'email') {
            error = validateRequired(value) || validateEmail(value);
        } else if (fieldName === 'password') {
            error = validateRequired(value);
            if (!error && isSignupOrReset) {
                error = validatePasswordStrength(value);
            }
        } else if (fieldName === 'confirmPassword') {
            error = validateRequired(value);
            if (!error && value !== password) {
                error = "Passwords do not match.";
            }
        } else if (fieldName === 'name') {
            error = validateRequired(value);
        }
        setFieldErrors(prev => ({ ...prev, [fieldName]: error || undefined }));
        return !error;
    }, [password]);

    const handleLoginSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        setFormError('');
        const isEmailValid = validateAndSetField('email', email);
        const isPasswordValid = validateAndSetField('password', password);
        if (!isEmailValid || !isPasswordValid) return;

        if (!onLogin(email, password)) {
            setFormError('Invalid email or password.');
        }
    };

    const handleSignupSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        setFormError('');
        const isNameValid = validateAndSetField('name', name);
        const isEmailValid = validateAndSetField('email', email);
        const isPasswordValid = validateAndSetField('password', password, true);
        if (!isNameValid || !isEmailValid || !isPasswordValid) return;

        if (!onSignup(email, password, name)) {
            setFormError('Could not sign up. The email might already be in use.');
        }
    };

    const handleForgotPasswordSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        setFormError('');
        const isEmailValid = validateAndSetField('email', email);
        if(!isEmailValid) return;

        if(onCheckUserExists(email)) {
            setEmailToReset(email);
            switchView('resetPassword');
        } else {
            setFormError("No account found with that email address.");
        }
    };

    const handleResetPasswordSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        setFormError('');
        const isPasswordValid = validateAndSetField('password', password, true);
        const isConfirmPasswordValid = validateAndSetField('confirmPassword', confirmPassword);

        if (!isPasswordValid || !isConfirmPasswordValid) return;

        if(onResetPassword(emailToReset, password)) {
            switchView('resetSuccess');
        } else {
            setFormError("Could not reset password. Please try again.");
        }
    };

    // Renderers
    const renderFormContent = () => {
        switch (authView) {
            case 'login':
                return (
                    <form onSubmit={handleLoginSubmit} className="space-y-5 animate-fade-in">
                        <div className="text-center">
                            <h2 className="text-3xl font-bold text-slate-900 dark:text-white mb-2">Welcome back</h2>
                            <p className="text-slate-500 dark:text-slate-400 text-sm">Please enter your details to sign in.</p>
                        </div>

                        <div className="space-y-4 mt-6">
                            <Button type="button" variant="secondary" className="w-full !bg-white dark:!bg-slate-800 border border-slate-200 dark:border-slate-600 hover:bg-slate-50 dark:hover:bg-slate-700 !text-slate-700 dark:!text-slate-200 flex items-center justify-center gap-3 py-2.5 shadow-sm transition-all" onClick={onGoogleLogin}>
                                <svg className="w-5 h-5" viewBox="0 0 24 24"><path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/><path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/><path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/><path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/></svg>
                                <span>Sign in with Google</span>
                            </Button>

                            <div className="relative flex items-center justify-center text-sm text-slate-400">
                                <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-slate-200 dark:border-slate-700"></div></div>
                                <span className="relative bg-white dark:bg-slate-800 px-2 uppercase text-[10px] font-bold tracking-widest text-slate-400">Or continue with</span>
                            </div>

                            <Input label="Email" id="email" type="email" value={email} onChange={(e) => { setEmail(e.target.value); validateAndSetField('email', e.target.value); }} required placeholder="Enter your email" error={fieldErrors.email} className="!bg-slate-50 dark:!bg-slate-900 border-slate-300 dark:border-slate-600 focus:border-accent"/>
                            <div>
                                <Input label="Password" id="password" type="password" value={password} onChange={(e) => { setPassword(e.target.value); validateAndSetField('password', e.target.value); }} required placeholder="••••••••" error={fieldErrors.password} className="!bg-slate-50 dark:!bg-slate-900 border-slate-300 dark:border-slate-600 focus:border-accent"/>
                                <div className="flex justify-end mt-2">
                                    <button type="button" onClick={() => switchView('forgotPassword')} className="text-xs font-semibold text-accent hover:text-accent-hover dark:text-indigo-400 transition-colors">Forgot password?</button>
                                </div>
                            </div>
                        </div>

                        {formError && <div className="p-3 rounded-lg bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-300 text-sm font-medium border border-red-100 dark:border-red-900/30 text-center animate-shake">{formError}</div>}

                        <Button type="submit" className="w-full py-3 text-base shadow-lg shadow-accent/25 hover:shadow-accent/40 transition-all font-bold tracking-wide mt-2">Sign In</Button>

                        <p className="text-center text-sm text-slate-500 dark:text-slate-400 mt-6">
                            Don't have an account? <button type="button" onClick={() => switchView('signup')} className="font-bold text-accent hover:text-accent-hover dark:text-indigo-400 transition-colors ml-1">Sign up</button>
                        </p>
                    </form>
                );
            case 'signup':
                return (
                    <form onSubmit={handleSignupSubmit} className="space-y-5 animate-fade-in">
                        <div className="text-center">
                            <h2 className="text-3xl font-bold text-slate-900 dark:text-white mb-2">Create Account</h2>
                            <p className="text-slate-500 dark:text-slate-400 text-sm">Start your 14-day free trial.</p>
                        </div>

                        <div className="space-y-4 mt-6">
                            <Input label="Full Name" id="name" type="text" value={name} onChange={(e) => { setName(e.target.value); validateAndSetField('name', e.target.value); }} required placeholder="John Doe" error={fieldErrors.name} className="!bg-slate-50 dark:!bg-slate-900 border-slate-300 dark:border-slate-600"/>
                            <Input label="Email" id="email" type="email" value={email} onChange={(e) => { setEmail(e.target.value); validateAndSetField('email', e.target.value); }} required placeholder="name@company.com" error={fieldErrors.email} className="!bg-slate-50 dark:!bg-slate-900 border-slate-300 dark:border-slate-600"/>
                            <Input label="Password" id="password" type="password" value={password} onChange={(e) => { setPassword(e.target.value); validateAndSetField('password', e.target.value, true); }} required placeholder="Create a strong password" error={fieldErrors.password} className="!bg-slate-50 dark:!bg-slate-900 border-slate-300 dark:border-slate-600"/>
                        </div>

                        {formError && <div className="p-3 rounded-lg bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-300 text-sm font-medium border border-red-100 dark:border-red-900/30 text-center animate-shake">{formError}</div>}

                        <Button type="submit" className="w-full py-3 text-base shadow-lg shadow-accent/25 hover:shadow-accent/40 transition-all font-bold tracking-wide mt-2">Create Account</Button>

                        <p className="text-center text-sm text-slate-500 dark:text-slate-400 mt-6">
                            Already have an account? <button type="button" onClick={() => switchView('login')} className="font-bold text-accent hover:text-accent-hover dark:text-indigo-400 transition-colors ml-1">Log in</button>
                        </p>
                    </form>
                );
            case 'forgotPassword':
                return (
                    <form onSubmit={handleForgotPasswordSubmit} className="space-y-6 animate-fade-in">
                        <button type="button" onClick={() => switchView('login')} className="flex items-center gap-2 text-sm text-slate-500 hover:text-slate-800 dark:text-slate-400 dark:hover:text-slate-200 transition-colors mb-2">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                            Back to Login
                        </button>
                        <div className="text-center">
                            <div className="w-12 h-12 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-xl flex items-center justify-center mb-4 mx-auto">
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 14l-1 1-1 1H6v-2l2-2 2-2 6.344-6.344A2 2 0 0115 7zm7 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>
                            </div>
