                        </div>
                        <Input label="Email" id="email" type="email" value={email} onChange={(e) => { setEmail(e.target.value); validateAndSetField('email', e.target.value); }} required placeholder="Enter your email" error={fieldErrors.email} className="!bg-slate-50 dark:!bg-slate-900 border-slate-300 dark:border-slate-600"/>
                        {formError && <div className="p-3 rounded-lg bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-300 text-sm font-medium border border-red-100 dark:border-red-900/30 text-center animate-shake">{formError}</div>}
                        <Button type="submit" className="w-full py-3 text-base shadow-lg shadow-accent/25 hover:shadow-accent/40 transition-all font-bold">Send Reset Link</Button>
                    </form>
                );
            case 'resetPassword':
                return (
                    <form onSubmit={handleResetPasswordSubmit} className="space-y-6 animate-fade-in">
                        <div className="text-center">
                            <h2 className="text-2xl font-bold text-slate-900 dark:text-white mb-2">Reset Password</h2>
                            <p className="text-slate-500 dark:text-slate-400 text-sm">Enter a new password for <br/><strong className="text-slate-700 dark:text-slate-300">{emailToReset}</strong></p>
                        </div>
                        <div className="space-y-4">
                            <Input label="New Password" id="password" type="password" value={password} onChange={(e) => { setPassword(e.target.value); validateAndSetField('password', e.target.value, true); }} required placeholder="••••••••" error={fieldErrors.password} className="!bg-slate-50 dark:!bg-slate-900 border-slate-300 dark:border-slate-600"/>
                            <Input label="Confirm Password" id="confirmPassword" type="password" value={confirmPassword} onChange={(e) => { setConfirmPassword(e.target.value); validateAndSetField('confirmPassword', e.target.value); }} required placeholder="••••••••" error={fieldErrors.confirmPassword} className="!bg-slate-50 dark:!bg-slate-900 border-slate-300 dark:border-slate-600"/>
                        </div>
                        {formError && <div className="p-3 rounded-lg bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-300 text-sm font-medium border border-red-100 dark:border-red-900/30 text-center animate-shake">{formError}</div>}
                        <Button type="submit" className="w-full py-3 text-base shadow-lg shadow-accent/25 hover:shadow-accent/40 transition-all font-bold">Reset Password</Button>
                    </form>
                );
            case 'resetSuccess':
                return (
                    <div className="text-center space-y-6 animate-fade-in py-8">
                        <div className="w-20 h-20 bg-green-100 dark:bg-green-900/30 rounded-full flex items-center justify-center mx-auto shadow-sm">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-green-600 dark:text-green-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                        </div>
                        <div>
                            <h2 className="text-2xl font-bold text-slate-900 dark:text-white mb-2">Password Reset</h2>
                            <p className="text-slate-500 dark:text-slate-400 max-w-xs mx-auto text-sm">Your password has been successfully updated. You can now sign in with your new password.</p>
                        </div>
                        <Button onClick={() => switchView('login')} className="w-full py-3 text-base shadow-lg shadow-accent/25 hover:shadow-accent/40 transition-all font-bold">Back to Sign In</Button>
                    </div>
                );
        }
    };

    return (
        <div className="flex min-h-screen bg-slate-100 dark:bg-slate-950 font-sans selection:bg-accent selection:text-white overflow-hidden">
            <style>{styles}</style>

            {/* Left Hero Section (Desktop) */}
            <div className="hidden lg:flex lg:w-1/2 relative bg-slate-900 overflow-hidden flex-col justify-between p-12 xl:p-16 text-white">
                {/* Background Effects */}
                <div className="absolute inset-0 bg-slate-900">
                    <div className="absolute inset-0 bg-gradient-to-br from-indigo-900/40 via-slate-900 to-slate-900 z-0"></div>
                    <div className="absolute inset-0 bg-grid-animated opacity-20 z-0"></div>
                    {/* Glowing Orbs */}
                    <div className="absolute top-[-10%] right-[-10%] w-[500px] h-[500px] bg-indigo-600/30 rounded-full blur-[120px]"></div>
                    <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-purple-600/20 rounded-full blur-[100px]"></div>
                </div>

                {/* Brand Header */}
