import React, { useState, useMemo } from 'react';
import type { Item, StockHistoryEntry } from '../types';
import Button from './common/Button';
import Input from './common/Input';
import Modal from './common/Modal';

interface InventoryProps {
  items: Item[];
  setItems: (items: Item[]) => void;
  onBulkStockUpdate?: (updates: { itemId: string, newQuantity: number }[], action: StockHistoryEntry['action']) => void;
  stockHistory: StockHistoryEntry[];
}

// Helper for fuzzy search (Subsequence matching)
const fuzzyMatch = (text: string, query: string): boolean => {
    const t = text.toLowerCase();
    const q = query.toLowerCase();
    if (t.includes(q)) return true;
    let qIdx = 0;
    let tIdx = 0;
    while (qIdx < q.length && tIdx < t.length) {
        if (q[qIdx] === t[tIdx]) {
            qIdx++;
        }
        tIdx++;
    }
    return qIdx === q.length;
};

// Icons
const WarningIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-orange-600 dark:text-orange-400" viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
    </svg>
);

const AlertIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-red-600 dark:text-red-400" viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
    </svg>
);

const Inventory: React.FC<InventoryProps> = ({ items, setItems, onBulkStockUpdate, stockHistory }) => {
    const [searchQuery, setSearchQuery] = useState('');
    const [stockFilter, setStockFilter] = useState<'all' | 'in' | 'low' | 'out'>('all');
    const [editingItemId, setEditingItemId] = useState<string | null>(null);
    const [stockValue, setStockValue] = useState<number>(0);
    const [stockError, setStockError] = useState<string|null>(null);

    // Bulk Selection State
    const [selectedIds, setSelectedIds] = useState<string[]>([]);
    const [isBulkModalOpen, setIsBulkModalOpen] = useState(false);
    const [bulkUpdates, setBulkUpdates] = useState<Record<string, number>>({});

    // History Modal State
    const [isHistoryModalOpen, setIsHistoryModalOpen] = useState(false);

    const filteredItems = useMemo(() => {
        let result = items;

        // 1. Filter by Stock Status
        if (stockFilter === 'low') {
            result = result.filter(i => i.quantityInStock > 0 && i.quantityInStock <= 5);
        } else if (stockFilter === 'out') {
            result = result.filter(i => i.quantityInStock === 0);
        } else if (stockFilter === 'in') {
            result = result.filter(i => i.quantityInStock > 0);
        }

        // 2. Fuzzy Search
        const query = searchQuery.trim();
        if (query) {
            result = result.filter(item =>
                fuzzyMatch(item.name, query) ||
                fuzzyMatch(item.hsn, query) ||
                (item.id.includes(query))
            );
        }

        return result;
    }, [items, searchQuery, stockFilter]);

    const sortedHistory = useMemo(() => {
        return [...stockHistory].sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
    }, [stockHistory]);

    // Single Edit Handlers
    const handleEditClick = (item: Item) => {
        setEditingItemId(item.id);
        setStockValue(item.quantityInStock);
        setStockError(null);
    };

    const handleCancelClick = () => {
        setEditingItemId(null);
        setStockError(null);
    };

    const handleSaveClick = (item: Item) => {
        if(stockValue < 0) {
            setStockError("Stock cannot be negative.");
            return;
        }

        if (onBulkStockUpdate) {
            onBulkStockUpdate([{ itemId: item.id, newQuantity: stockValue }], 'Manual Update');
        } else {
            const updatedItems = items.map(i =>
                i.id === item.id ? { ...i, quantityInStock: stockValue } : i
            );
            setItems(updatedItems);
        }

        setEditingItemId(null);
        setStockError(null);
    };

    // Bulk Handlers
    const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.checked) setSelectedIds(filteredItems.map(i => i.id));
        else setSelectedIds([]);
    };

    const handleSelectOne = (id: string) => {
        if (selectedIds.includes(id)) setSelectedIds(selectedIds.filter(sid => sid !== id));
        else setSelectedIds([...selectedIds, id]);
    };

    const openBulkModal = () => {
        const initialUpdates: Record<string, number> = {};
        selectedIds.forEach(id => {
            const item = items.find(i => i.id === id);
            if (item) initialUpdates[id] = item.quantityInStock;
        });
        setBulkUpdates(initialUpdates);
        setIsBulkModalOpen(true);
    };

    const handleBulkUpdateChange = (id: string, value: string) => {
        const num = parseInt(value) || 0;
        setBulkUpdates(prev => ({ ...prev, [id]: num }));
    };

    const saveBulkUpdates = () => {
        if (onBulkStockUpdate) {
            const updatesArray = Object.entries(bulkUpdates).map(([itemId, newQuantity]) => ({ itemId, newQuantity }));
            onBulkStockUpdate(updatesArray, 'Bulk Update');
        }
        setIsBulkModalOpen(false);
        setSelectedIds([]);
    };

    const inputClasses = "w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 text-slate-900 dark:text-white rounded-lg shadow-sm px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-accent";

    return (
        <div className="animate-fade-in">
            <div className="flex flex-col md:flex-row justify-between md:items-center mb-6 gap-4">
                <div>
                    <h1 className="text-3xl font-bold text-slate-900 dark:text-light-text">Inventory Management</h1>
                    <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">Manage stock levels and track history</p>
                </div>
                <div className="flex gap-3">
                    <Button variant="secondary" onClick={() => setIsHistoryModalOpen(true)}>View Stock History</Button>
                    {selectedIds.length > 0 && (
                        <Button onClick={openBulkModal}>Update Selected ({selectedIds.length})</Button>
                    )}
                </div>
            </div>

            <div className="flex flex-col md:flex-row gap-4 mb-6">
                <div className="flex-grow">
                    <Input 
                        label=""
                        id="search-inventory"
                        placeholder="Search items (e.g. 'iphn' for iPhone)..."
                        value={searchQuery}
                        onChange={e => setSearchQuery(e.target.value)}
                        className="!py-2.5"
                    />
                </div>
                <div className="w-full md:w-64">
                    <select 
                        value={stockFilter} 
                        onChange={(e) => setStockFilter(e.target.value as any)}
                        className={`${inputClasses} h-[42px] mt-0.5 cursor-pointer`}
                        aria-label="Filter Stock"
                    >
                        <option value="all">All Items</option>
                        <option value="in">In Stock (&gt; 0)</option>
                        <option value="low">Low Stock (&le; 5)</option>
                        <option value="out">Out of Stock (0)</option>
                    </select>
                </div>
            </div>

            <div className="bg-white dark:bg-primary-dark shadow-lg rounded-lg overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left text-slate-600 dark:text-medium-text">
                        <thead className="text-xs text-slate-700 dark:text-light-text uppercase bg-slate-100 dark:bg-tertiary-dark">
                            <tr>
                                <th scope="col" className="px-6 py-3 w-10">
                                    <input type="checkbox" checked={filteredItems.length > 0 && selectedIds.length === filteredItems.length} onChange={handleSelectAll} className="rounded border-slate-300 text-accent focus:ring-accent" />
                                </th>
                                <th scope="col" className="px-6 py-3">Item Name</th>
                                <th scope="col" className="px-6 py-3">HSN/SAC</th>
                                <th scope="col" className="px-6 py-3 text-center">Unit</th>
                                <th scope="col" className="px-6 py-3">Current Stock</th>
                                <th scope="col" className="px-6 py-3 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filteredItems.map((item) => {
                                const isLowStock = item.quantityInStock <= 5 && item.quantityInStock > 0;
                                const isOutOfStock = item.quantityInStock === 0;
                                const isSelected = selectedIds.includes(item.id);

                                // Determine Row Styling
                                let rowClass = "bg-white dark:bg-primary-dark";
                                if (isSelected) {
                                    rowClass = "bg-blue-50 dark:bg-blue-900/20";
                                } else if (isOutOfStock) {
                                    rowClass = "bg-red-50 dark:bg-red-900/20";
                                } else if (isLowStock) {
                                    rowClass = "bg-orange-50 dark:bg-orange-900/20";
                                }

                                return (
                                <tr key={item.id} className={`${rowClass} border-b border-slate-200 dark:border-tertiary-dark hover:brightness-95 dark:hover:brightness-110 transition-colors`}>
                                    <td className="px-6 py-4">
                                        <input type="checkbox" checked={isSelected} onChange={() => handleSelectOne(item.id)} className="rounded border-slate-300 text-accent focus:ring-accent" />
                                    </td>
                                    <td className="px-6 py-4 font-medium text-slate-900 dark:text-light-text whitespace-nowrap">
                                        <div className="flex items-center gap-2">
                                            {isOutOfStock && <AlertIcon />}
                                            {isLowStock && <WarningIcon />}
                                            <span className={isOutOfStock ? 'text-red-700 dark:text-red-300 font-semibold' : ''}>{item.name}</span>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4">{item.hsn}</td>
                                    <td className="px-6 py-4 text-center uppercase">{item.unit}</td>
                                    <td className="px-6 py-4">
                                        {editingItemId === item.id ? (
                                            <div className="relative">
                                                <Input 
                                                    label=""
                                                    type="number" 
                                                    value={stockValue} 
                                                    onChange={e => setStockValue(parseInt(e.target.value) || 0)}
                                                    className="!py-1 w-24"
                                                    error={stockError || undefined}
                                                />
                                            </div>
                                        ) : (
                                            <div className="flex items-center gap-2">
                                                <span className={`inline-flex items-center px-3 py-1 rounded-full text-xs font-bold shadow-sm
                                                    ${isOutOfStock ? 'bg-white text-red-700 border border-red-200 dark:bg-red-900/50 dark:text-red-200 dark:border-red-800' : 
                                                      isLowStock ? 'bg-white text-orange-700 border border-orange-200 dark:bg-orange-900/50 dark:text-orange-200 dark:border-orange-800' : 
                                                      'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400'}`}>
                                                    {item.quantityInStock}
                                                </span>
                                                {isLowStock && <span className="text-xs text-orange-700 dark:text-orange-300 font-medium">Low</span>}
                                                {isOutOfStock && <span className="text-xs text-red-700 dark:text-red-300 font-medium">Empty</span>}
                                            </div>
                                        )}
                                    </td>
                                    <td className="px-6 py-4 text-right space-x-2">
                                        {editingItemId === item.id ? (
                                            <>
                                                <Button variant="secondary" onClick={() => handleSaveClick(item)}>Save</Button>
                                                <Button variant="secondary" onClick={handleCancelClick}>Cancel</Button>
                                            </>
                                        ) : (
                                            <Button variant="secondary" onClick={() => handleEditClick(item)}>Update</Button>
                                        )}
                                    </td>
                                </tr>
                            )})}
                            {filteredItems.length === 0 && (
                                <tr>
                                    <td colSpan={6} className="text-center py-8 text-slate-500 dark:text-medium-text">
                                        {items.length > 0 ? 'No items match your search or filters.' : 'No items found. Add items in the "Items" section to manage their inventory.'}
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Bulk Update Modal */}
            <Modal isOpen={isBulkModalOpen} onClose={() => setIsBulkModalOpen(false)} title="Bulk Stock Update">
                <div className="p-6 max-h-[60vh] overflow-y-auto">
                    <p className="text-sm text-slate-600 dark:text-slate-400 mb-4">Set new stock quantities for selected items:</p>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {selectedIds.map(id => {
                            const item = items.find(i => i.id === id);
                            if (!item) return null;
                            return (
                                <div key={id} className="flex items-center justify-between p-3 bg-slate-50 dark:bg-slate-800 rounded-lg border border-slate-200 dark:border-slate-700">
                                    <span className="text-sm font-medium text-slate-800 dark:text-slate-200 truncate pr-4">{item.name}</span>
                                    <input 
                                        type="number" 
                                        className="w-20 rounded border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-900 px-2 py-1 text-sm focus:ring-accent focus:border-accent"
                                        value={bulkUpdates[id] ?? item.quantityInStock}
                                        onChange={(e) => handleBulkUpdateChange(id, e.target.value)}
                                        min="0"
                                    />
                                </div>
                            );
                        })}
                    </div>
                </div>
                <div className="p-6 pt-0 flex justify-end gap-3">
                    <Button variant="secondary" onClick={() => setIsBulkModalOpen(false)}>Cancel</Button>
                    <Button onClick={saveBulkUpdates}>Update All</Button>
                </div>
            </Modal>

            {/* History Modal */}
            <Modal isOpen={isHistoryModalOpen} onClose={() => setIsHistoryModalOpen(false)} title="Stock Movement Log">
                <div className="p-0 max-h-[70vh] overflow-y-auto">
                    {sortedHistory.length > 0 ? (
                        <table className="w-full text-sm text-left text-slate-600 dark:text-slate-400">
                            <thead className="text-xs text-slate-700 dark:text-light-text uppercase bg-slate-100 dark:bg-slate-800 sticky top-0">
                                <tr>
                                    <th className="px-6 py-3">Date</th>
                                    <th className="px-6 py-3">Item</th>
                                    <th className="px-6 py-3 text-right">Change</th>
                                    <th className="px-6 py-3">Action</th>
                                    <th className="px-6 py-3">Ref</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                                {sortedHistory.map(entry => {
                                    const change = entry.newQuantity - entry.previousQuantity;
                                    const isPositive = change > 0;
                                    return (
                                        <tr key={entry.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50">
                                            <td className="px-6 py-3 whitespace-nowrap">
                                                {new Date(entry.timestamp).toLocaleDateString()} <span className="text-xs text-slate-400">{new Date(entry.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                                            </td>
                                            <td className="px-6 py-3 font-medium text-slate-900 dark:text-white">{entry.itemName}</td>
                                            <td className="px-6 py-3 text-right">
                                                <div className="flex flex-col items-end">
                                                    <span className={`font-bold ${isPositive ? 'text-green-600' : change < 0 ? 'text-red-600' : 'text-slate-500'}`}>
                                                        {isPositive ? '+' : ''}{change}
                                                    </span>
                                                    <span className="text-xs text-slate-400">{entry.previousQuantity} → {entry.newQuantity}</span>
                                                </div>
                                            </td>
                                            <td className="px-6 py-3">
                                                <span className={`px-2 py-1 rounded-full text-xs font-medium 
                                                    ${entry.action.includes('Invoice') ? 'bg-purple-100 text-purple-800 dark:bg-purple-900/30 dark:text-purple-300' : 
                                                      entry.action.includes('Voice') ? 'bg-indigo-100 text-indigo-800 dark:bg-indigo-900/30 dark:text-indigo-300' :
                                                      'bg-slate-100 text-slate-800 dark:bg-slate-700 dark:text-slate-300'}`}>
                                                    {entry.action}
                                                </span>
                                            </td>
                                            <td className="px-6 py-3 text-xs font-mono text-slate-500">{entry.referenceId || '-'}</td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    ) : (
                        <div className="p-8 text-center text-slate-500">No stock history recorded yet.</div>
                    )}
                </div>
                <div className="p-6 border-t border-slate-100 dark:border-slate-800 flex justify-end">
                    <Button variant="secondary" onClick={() => setIsHistoryModalOpen(false)}>Close</Button>
                </div>
            </Modal>
        </div>
    );
};

