const Dashboard: React.FC<DashboardProps> = ({ invoices, items, company, setActiveView }) => {
    const currency = '₹';

    // Metrics Calculation
    const metrics = useMemo(() => {
        // Total Stats
        const totalRevenue = invoices.filter(inv => inv.status === 'Paid').reduce((acc, inv) => acc + inv.grandTotal, 0);
        const totalOutstanding = invoices.filter(inv => inv.status === 'Unpaid').reduce((acc, inv) => acc + inv.grandTotal, 0);
        const totalOverdue = invoices.filter(inv => inv.status === 'Overdue').reduce((acc, inv) => acc + inv.grandTotal, 0);
        const totalReceivables = totalOutstanding + totalOverdue;
        const totalClients = new Set(invoices.map(i => i.client.id)).size;
        const lowStockItems = items.filter(i => i.quantityInStock <= 5).length;

        // --- Monthly Trend Calculation ---
        const today = new Date();
        // Create buckets for the last 6 months including current month
        const last6Months = Array.from({ length: 6 }, (_, i) => {
            const d = new Date(today.getFullYear(), today.getMonth() - (5 - i), 1);
            return {
                month: d.getMonth(),
                year: d.getFullYear(),
                label: d.toLocaleString('default', { month: 'short' }),
                revenue: 0,
                outstanding: 0,
                activeClients: new Set<string>()
            };
        });

        invoices.forEach(inv => {
            // Robust date parsing to avoid timezone shifts
            const [y, m] = inv.issueDate.split('-').map(Number);
            // In split, month is 1-indexed (01..12), Date is 0-indexed.
            const invYear = y;
            const invMonth = m - 1;

            const monthIndex = last6Months.findIndex(b => b.month === invMonth && b.year === invYear);

            if (monthIndex !== -1) {
                if (inv.status === 'Paid') {
                    last6Months[monthIndex].revenue += inv.grandTotal;
                } else if (inv.status === 'Unpaid' || inv.status === 'Overdue') {
                    last6Months[monthIndex].outstanding += inv.grandTotal;
                }
                last6Months[monthIndex].activeClients.add(inv.client.id);
            }
        });

        const revenueData = last6Months.map(m => m.revenue);
        const outstandingData = last6Months.map(m => m.outstanding);
        const chartLabels = last6Months.map(m => m.label);

        // Trend Calculation (Current vs Previous Month)
        const currentIdx = 5;
        const prevIdx = 4;

        const calcTrend = (curr: number, prev: number) => {
            if (prev === 0) return curr > 0 ? 100 : 0;
            return ((curr - prev) / prev) * 100;
        };

        const revenueTrend = calcTrend(revenueData[currentIdx], revenueData[prevIdx]);
        const outstandingTrend = calcTrend(outstandingData[currentIdx], outstandingData[prevIdx]);
        const clientTrend = calcTrend(last6Months[currentIdx].activeClients.size, last6Months[prevIdx].activeClients.size);

        return { 
            totalRevenue, 
            totalReceivables,
            totalOverdue, 
            totalClients,
            lowStockItems,
            revenueData, 
            outstandingData, 
            chartLabels,
            trends: {
                revenue: revenueTrend,
                outstanding: outstandingTrend,
                clients: clientTrend
            }
        };
    }, [invoices, items]);

    const revenueChartData = useMemo(() => {
        return metrics.chartLabels.map((label, i) => ({
            label,
            value: metrics.revenueData[i]
        }));
    }, [metrics]);

    const invoiceStatusCounts = useMemo(() => {
        const paid = invoices.filter(i => i.status === 'Paid').length;
        const pending = invoices.filter(i => i.status === 'Unpaid').length;
        const overdue = invoices.filter(i => i.status === 'Overdue').length;
        const total = invoices.length || 1; // avoid division by zero for circles
        return { paid, pending, overdue, total };
    }, [invoices]);

    const dashArray = (count: number) => {
        const total = invoiceStatusCounts.total;
        const percentage = (count / total) * 100;
        return `${percentage}, 100`;
    };

    const dashOffset = (prevCounts: number[]) => {
        const total = invoiceStatusCounts.total;
        const prevSum = prevCounts.reduce((a, b) => a + b, 0);
        return -((prevSum / total) * 100);
    };

    const navigateToInvoices = () => setActiveView && setActiveView('Invoices');
    const navigateToInventory = () => setActiveView && setActiveView('Inventory');

