import React, { useState, useEffect, useMemo } from 'react';
import type { Invoice, Client, Item, InvoiceItem, Company, Transporter, BankAccount, DraftInvoice } from '../types';
import Input from './common/Input';
import Button from './common/Button';
import Modal from './common/Modal';
import { INDIAN_STATES } from '../constants';
import { fetchLocationByPincode, validateGstin, validateIfsc } from '../utils/validation';

interface NewInvoiceProps {
  company: Company;
  saveInvoice: (invoice: Omit<Invoice, 'id' | 'status'> | Invoice) => void;
  setActiveView: (view: string) => void;
  invoiceToEdit?: Invoice | null;
  clearEditingInvoice: () => void;
  onUpdateCompany: (updatedCompany: Company) => void;

  draftInvoice: DraftInvoice;
  setDraftInvoice: (invoice: DraftInvoice) => void;
}

const ITEM_UNITS = ['pcs', 'kgs', 'ltr', 'nos', 'box', 'pkt', 'gram'];

const SectionCard: React.FC<{ title: string; children: React.ReactNode; className?: string }> = ({ title, children, className = "" }) => (
    <div className={`bg-white dark:bg-primary-dark rounded-xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden ${className}`}>
        <div className="px-6 py-4 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/50">
            <h3 className="text-sm font-bold uppercase tracking-wide text-slate-700 dark:text-slate-200">{title}</h3>
        </div>
        <div className="p-6">
            {children}
        </div>
    </div>
);

const NewInvoice: React.FC<NewInvoiceProps> = ({ 
    company, saveInvoice, setActiveView, 
    invoiceToEdit, clearEditingInvoice, onUpdateCompany,
    draftInvoice, setDraftInvoice
}) => {
    const isEditing = !!invoiceToEdit;
    const currency = '₹';

    // Derived state for validations
    const [vehicleNumberError, setVehicleNumberError] = useState<string | null>(null);
    const [formError, setFormError] = useState<string | null>(null);
    const [isPincodeLoading, setIsPincodeLoading] = useState(false);
    const [pincodeError, setPincodeError] = useState<string|null>(null);
    const [itemErrors, setItemErrors] = useState<Record<string, string>>({});

    // Bank Account Modal State
    const [isAddBankModalOpen, setIsAddBankModalOpen] = useState(false);
    const [newBank, setNewBank] = useState<Omit<BankAccount, 'id' | 'isDefault'>>({ bankName: '', accountNumber: '', ifsc: '' });
    const [newBankErrors, setNewBankErrors] = useState<Partial<Record<keyof typeof newBank, string>>>({});

    const selectedClient = useMemo(() => company.clients.find(c => c.id === draftInvoice.clientId), [draftInvoice.clientId, company.clients]);

    const handleClientChange = (clientId: string) => {
        const client = company.clients.find(c => c.id === clientId);
        if (client) {
            setDraftInvoice({
                ...draftInvoice,
                clientId: clientId,
                isShippingSameAsBilling: true,
                shippingDetails: {
                    name: client.name,
                    address: client.address,
                    city: client.city,
                    state: client.state,
                    zip: client.zip,
                    gstin: client.gstin
                }
            });
        } else {
            setDraftInvoice({ ...draftInvoice, clientId: clientId });
        }
    };

    const handleSameAsBillingToggle = (e: React.ChangeEvent<HTMLInputElement>) => {
        const isChecked = e.target.checked;
        const updates: Partial<DraftInvoice> = { isShippingSameAsBilling: isChecked };

        if (!isChecked && selectedClient) {
            updates.shippingDetails = {
                name: selectedClient.name,
                address: selectedClient.shippingAddress || selectedClient.address,
                city: selectedClient.shippingCity || selectedClient.city,
                state: selectedClient.shippingState || selectedClient.state,
                zip: selectedClient.shippingZip || selectedClient.zip,
                gstin: selectedClient.gstin,
            };
        }
        setDraftInvoice({ ...draftInvoice, ...updates });
    };

    // Auto-update shipping details if client changes and same-as-billing is checked
    useEffect(() => {
        if(draftInvoice.isShippingSameAsBilling) return;
        let isMounted = true;
        const pincode = draftInvoice.shippingDetails.zip;
        if (pincode && pincode.length === 6) {
          const timer = setTimeout(async () => {
            if (!isMounted) return;
            setIsPincodeLoading(true);
            setPincodeError(null);
            const location = await fetchLocationByPincode(pincode);
            if (isMounted) {
                if (location) {
                    setDraftInvoice(prev => ({
                        ...prev,
                        shippingDetails: {
                            ...prev.shippingDetails,
                            city: location.city,
                            state: location.state
                        }
                    }));
                } else if (location === null) {
                    setPincodeError('Invalid Pincode');
                } else {
                    setPincodeError('Lookup failed. Enter manually.');
                }
                setIsPincodeLoading(false);
            }
          }, 500);
          return () => { isMounted = false; clearTimeout(timer); };
        } else {
            setPincodeError(null);
        }
    }, [draftInvoice.shippingDetails.zip, draftInvoice.isShippingSameAsBilling]);

    const handleVehicleNumberChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setVehicleNumberError(null);
        const value = e.target.value;
        const parts = value.split(/ (.*)/s);
        const rtoPart = (parts[0] || '').toUpperCase();
        let finalValue = rtoPart;

        if (parts.length > 1) {
            let numberPart = parts[1] || '';
            numberPart = numberPart.replace(/[^0-9]/g, '');
            if (numberPart.length > 4) {
                numberPart = numberPart.slice(0, 4);
                setVehicleNumberError('Numeric part must be 4 digits.');
                setTimeout(() => setVehicleNumberError(null), 3000);
            }
            finalValue = `${rtoPart} ${numberPart}`;
        }
        setDraftInvoice({ ...draftInvoice, vehicleNumber: finalValue });
    };

    const handleShippingChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        setDraftInvoice({
            ...draftInvoice,
            shippingDetails: {
                ...draftInvoice.shippingDetails,
                [e.target.name]: e.target.value
            }
        });
    };

    const transporterDetails = useMemo(() => {
        if (draftInvoice.transporterId === 'self') {
            return { name: 'Self', gstin: company.details.gstin };
        }
        return company.transporters.find(t => t.id === draftInvoice.transporterId);
    }, [draftInvoice.transporterId, company.transporters, company.details.gstin]);

    const handleAddItem = () => {
        setDraftInvoice({
            ...draftInvoice,
            items: [...draftInvoice.items, { id: '', name: '', hsn: '', price: 0, gstRate: 18, quantity: 1, unit: 'pcs', quantityInStock: 0 }]
        });
    };

    const handleRemoveItem = (index: number) => {
        setDraftInvoice({
            ...draftInvoice,
            items: draftInvoice.items.filter((_, i) => i !== index)
        });

        // Clean up errors
        setItemErrors(prev => {
            const newErrs: Record<string, string> = {};
            Object.keys(prev).forEach(key => {
                const parts = key.split('-');
                const idx = parseInt(parts[0]);
                const field = parts.slice(1).join('-');
                if (idx < index) newErrs[key] = prev[key];
                else if (idx > index) newErrs[`${idx - 1}-${field}`] = prev[key];
            });
            return newErrs;
        });
    };

    const handleItemChange = (index: number, field: keyof InvoiceItem, value: any) => {
        const updatedItems = [...draftInvoice.items];
        const currentItem = { ...updatedItems[index] };
        let newItemErrors = { ...itemErrors };

        if (field === 'id' && value) {
            const selectedItem = company.items.find(i => i.id === value);
            if (selectedItem) updatedItems[index] = { ...currentItem, ...selectedItem, quantity: 1 };
            // Clear errors for this row if selecting a valid item
            delete newItemErrors[`${index}-name`];
            delete newItemErrors[`${index}-price`];
            delete newItemErrors[`${index}-quantity`];
        } else {
            const newValue = (field === 'quantity' || field === 'price' || field === 'gstRate') ? parseFloat(value) || 0 : value;
            updatedItems[index] = { ...currentItem, [field]: newValue };

            // Real-time Validation Logic
            if (field === 'quantity') {
                if (newValue <= 0) newItemErrors[`${index}-quantity`] = 'Qty > 0';
                else delete newItemErrors[`${index}-quantity`];
            }
            if (field === 'price') {
                if (newValue < 0) newItemErrors[`${index}-price`] = 'No negative';
                else delete newItemErrors[`${index}-price`];
            }
            if (field === 'name' && !value) {
                newItemErrors[`${index}-name`] = 'Required';
            } else if (field === 'name') {
                delete newItemErrors[`${index}-name`];
            }
        }

        setItemErrors(newItemErrors);
        setDraftInvoice({ ...draftInvoice, items: updatedItems });
    };

    // Calculations
    const calculateTotals = () => {
        let subTotal = 0;
        let cgst = 0;
        let sgst = 0;
        let igst = 0;

        const posState = draftInvoice.shippingDetails.state || (selectedClient ? selectedClient.state : '');
        const isIntraState = !posState || posState.toLowerCase() === company.details.state.toLowerCase();

        draftInvoice.items.forEach(item => {
            const taxable = item.price * item.quantity;
            subTotal += taxable;
            const taxAmount = (taxable * item.gstRate) / 100;

            if (isIntraState) {
                cgst += taxAmount / 2;
                sgst += taxAmount / 2;
            } else {
                igst += taxAmount;
            }
        });

        return { subTotal, cgst, sgst, igst, grandTotal: subTotal + cgst + sgst + igst };
    };

    const totals = calculateTotals();

    const handleSave = () => {
        // Validation logic
        const newFormErrors: string[] = [];
        if (!draftInvoice.clientId) newFormErrors.push("Please select a client.");
        if (draftInvoice.items.length === 0) newFormErrors.push("Please add at least one item.");

        // Item validations check
        const newItemErrors: Record<string, string> = {};
        draftInvoice.items.forEach((item, idx) => {
             if (!item.name) newItemErrors[`${idx}-name`] = "Required";
             if (item.price < 0) newItemErrors[`${idx}-price`] = "Invalid";
             if (item.quantity <= 0) newItemErrors[`${idx}-quantity`] = "Invalid";
        });

        if (newFormErrors.length > 0) {
            setFormError(newFormErrors.join(" "));
            return;
        }

        if (Object.keys(newItemErrors).length > 0 || Object.keys(itemErrors).length > 0) {
            setItemErrors({ ...itemErrors, ...newItemErrors });
            setFormError("Please fix invalid items.");
            return;
        }

        const selectedClient = company.clients.find(c => c.id === draftInvoice.clientId);
        if(!selectedClient) return;

        // Construct Invoice Object
        const finalInvoice: Omit<Invoice, 'id' | 'status'> | Invoice = {
            ...(isEditing && invoiceToEdit ? { id: invoiceToEdit.id, status: invoiceToEdit.status } : {}),
            invoiceNumber: draftInvoice.invoiceNumber,
            client: selectedClient,
            items: draftInvoice.items,
            issueDate: draftInvoice.issueDate,
            dueDate: draftInvoice.dueDate,
            notes: draftInvoice.notes,
            selectedBankAccountId: draftInvoice.selectedBankAccountId,

            // Snapshot details
            shippingName: draftInvoice.shippingDetails.name,
            shippingAddress: draftInvoice.shippingDetails.address,
            shippingCity: draftInvoice.shippingDetails.city,
            shippingState: draftInvoice.shippingDetails.state,
            shippingZip: draftInvoice.shippingDetails.zip,
            shippingGstin: draftInvoice.shippingDetails.gstin,

            transporterName: transporterDetails?.name,
            transporterGstin: transporterDetails?.gstin,
            vehicleNumber: draftInvoice.vehicleNumber,
            ewayBillNumber: draftInvoice.ewayBillNumber,

            ...totals
        };

        saveInvoice(finalInvoice);
        setActiveView('Invoices');
        clearEditingInvoice(); 
    };

    // Load invoice to edit
    useEffect(() => {
        if (invoiceToEdit) {
            setDraftInvoice({
                invoiceNumber: invoiceToEdit.invoiceNumber,
                clientId: invoiceToEdit.client.id,
                items: invoiceToEdit.items,
                issueDate: invoiceToEdit.issueDate,
                dueDate: invoiceToEdit.dueDate,
                notes: invoiceToEdit.notes,
                selectedBankAccountId: invoiceToEdit.selectedBankAccountId,
                shippingDetails: {
                    name: invoiceToEdit.shippingName || '',
                    address: invoiceToEdit.shippingAddress || '',
                    city: invoiceToEdit.shippingCity || '',
                    state: invoiceToEdit.shippingState || '',
                    zip: invoiceToEdit.shippingZip || '',
                    gstin: invoiceToEdit.shippingGstin || ''
                },
                isShippingSameAsBilling: false, 
                transporterId: '', 
                vehicleNumber: invoiceToEdit.vehicleNumber || '',
                ewayBillNumber: invoiceToEdit.ewayBillNumber || ''
            });

             const tId = company.transporters.find(t => t.name === invoiceToEdit.transporterName)?.id;
             if(tId) setDraftInvoice(prev => ({...prev, transporterId: tId}));
             else if(invoiceToEdit.transporterName === 'Self') setDraftInvoice(prev => ({...prev, transporterId: 'self'}));
        }
    }, [invoiceToEdit]);

    return (
        <div>
             {/* Header */}
             <div className="flex justify-between items-center mb-6">
                <div className="flex items-center gap-4">
                     <button onClick={() => { setActiveView('Invoices'); clearEditingInvoice(); }} className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors">
                        <svg className="w-6 h-6 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                     </button>
                     <h1 className="text-3xl font-bold text-slate-900 dark:text-light-text">{isEditing ? 'Edit Invoice' : 'New Invoice'}</h1>
                </div>
                <div className="flex gap-3">
                    <Button variant="secondary" onClick={() => { setActiveView('Invoices'); clearEditingInvoice(); }}>Cancel</Button>
                    <Button onClick={handleSave}>Save Invoice</Button>
                </div>
             </div>

             {formError && <div className="mb-6 p-4 bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300 rounded-lg border border-red-200 dark:border-red-800 font-medium animate-fade-in flex items-center gap-2">
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                 {formError}
             </div>}

             <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                 {/* Left Column */}
                 <div className="lg:col-span-2 space-y-6">

                     {/* Client & Invoice Info */}
                     <SectionCard title="Client & Invoice Details">
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                             <div>
                                 <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1.5">Select Client</label>
                                 <select 
                                    className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 text-slate-900 dark:text-white rounded-lg px-4 py-3 focus:ring-2 focus:ring-accent focus:outline-none transition-shadow"
                                    value={draftInvoice.clientId}
                                    onChange={(e) => handleClientChange(e.target.value)}
                                 >
                                     <option value="">-- Choose Client --</option>
                                     {company.clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                                 </select>
                                 <p className="text-xs text-slate-500 mt-1">Or add a new client in Clients section.</p>
                             </div>
                             <Input label="Invoice Number" value={draftInvoice.invoiceNumber} onChange={e => setDraftInvoice({...draftInvoice, invoiceNumber: e.target.value})} />
                             <Input label="Issue Date" type="date" value={draftInvoice.issueDate} onChange={e => setDraftInvoice({...draftInvoice, issueDate: e.target.value})} />
                             <Input label="Due Date" type="date" value={draftInvoice.dueDate} onChange={e => setDraftInvoice({...draftInvoice, dueDate: e.target.value})} />
                         </div>
                     </SectionCard>

                     {/* Items Table */}
                     <SectionCard title="Items" className="overflow-visible">
                         <div className="overflow-x-auto">
                            <table className="w-full text-sm text-left text-slate-600 dark:text-slate-400">
                                <thead className="text-xs text-slate-700 dark:text-slate-300 uppercase bg-slate-100 dark:bg-slate-800">
                                    <tr>
                                        <th className="px-4 py-3 rounded-l-lg w-1/3">Item Details</th>
                                        <th className="px-2 py-3 w-20">Qty</th>
                                        <th className="px-2 py-3 w-24">Unit</th>
                                        <th className="px-2 py-3 w-28">Price</th>
                                        <th className="px-2 py-3 w-20">GST %</th>
                                        <th className="px-4 py-3 w-28 text-right">Amount</th>
                                        <th className="px-2 py-3 w-10 rounded-r-lg"></th>
                                    </tr>
                                </thead>
                                <tbody className="space-y-1">
                                    {draftInvoice.items.map((item, index) => {
                                        const qtyError = itemErrors[`${index}-quantity`];
                                        const priceError = itemErrors[`${index}-price`];

                                        return (
                                        <tr key={index} className="bg-white dark:bg-primary-dark group">
                                            <td className="px-2 py-2 align-top">
                                                <input 
                                                    list="company-items"
                                                    value={item.name}
                                                    onChange={e => {
                                                        const val = e.target.value;
                                                        const existing = company.items.find(i => i.name === val);
                                                        if(existing) {
                                                            handleItemChange(index, 'id', existing.id);
                                                        } else {
                                                            handleItemChange(index, 'name', val);
                                                        }
                                                    }}
                                                    className={`w-full bg-slate-50 dark:bg-slate-900 border ${itemErrors[`${index}-name`] ? 'border-red-500 focus:ring-red-500' : 'border-slate-300 dark:border-slate-700 hover:border-slate-400 focus:border-accent'} rounded-lg px-3 py-2 focus:ring-2 focus:ring-accent/20 focus:outline-none transition-all font-medium`}
                                                    placeholder="Search Item"
                                                />
                                            </td>
                                            <td className="px-2 py-2 align-top relative">
                                                <input type="number" min="0" value={item.quantity} onChange={e => handleItemChange(index, 'quantity', e.target.value)} className={`w-full bg-slate-50 dark:bg-slate-900 border ${qtyError ? 'border-red-500 focus:ring-red-500' : 'border-slate-300 dark:border-slate-700 hover:border-slate-400 focus:border-accent'} rounded-lg px-2 py-2 text-center focus:ring-2 focus:ring-accent/20 focus:outline-none transition-all`} />
                                                {qtyError && <div className="absolute top-full left-0 w-full text-[10px] text-red-500 text-center font-bold mt-0.5">{qtyError}</div>}
                                            </td>
                                             <td className="px-2 py-2 align-top">
                                                <select value={item.unit} onChange={e => handleItemChange(index, 'unit', e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 rounded-lg px-2 py-2 text-xs focus:ring-2 focus:ring-accent/20 focus:border-accent outline-none">
                                                    {ITEM_UNITS.map(u => <option key={u} value={u}>{u}</option>)}
                                                </select>
                                            </td>
                                            <td className="px-2 py-2 align-top relative">
                                                <input type="number" min="0" value={item.price} onChange={e => handleItemChange(index, 'price', e.target.value)} className={`w-full bg-slate-50 dark:bg-slate-900 border ${priceError ? 'border-red-500 focus:ring-red-500' : 'border-slate-300 dark:border-slate-700 hover:border-slate-400 focus:border-accent'} rounded-lg px-2 py-2 text-right focus:ring-2 focus:ring-accent/20 focus:outline-none transition-all`} />
                                                {priceError && <div className="absolute top-full right-0 text-[10px] text-red-500 font-bold mt-0.5">{priceError}</div>}
                                            </td>
                                            <td className="px-2 py-2 align-top">
                                                <input type="number" min="0" value={item.gstRate} onChange={e => handleItemChange(index, 'gstRate', e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 rounded-lg px-2 py-2 text-center focus:ring-2 focus:ring-accent/20 focus:border-accent outline-none" />
                                            </td>
                                            <td className="px-4 py-3 align-top text-right font-bold text-slate-900 dark:text-white">
                                                {currency}{((item.price * item.quantity)).toFixed(2)}
                                            </td>
                                            <td className="px-2 py-2 align-top text-center">
                                                <button onClick={() => handleRemoveItem(index)} className="text-slate-400 hover:text-red-500 transition-colors p-2 rounded-lg hover:bg-red-50 dark:hover:bg-red-900/20">
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                                                </button>
                                            </td>
                                        </tr>
                                    )})}
                                </tbody>
                            </table>
                            <datalist id="company-items">
                                {company.items.map(i => <option key={i.id} value={i.name} />)}
                            </datalist>
                         </div>

                         {/* Item Summary Footer within card */}
                         <div className="mt-4 pt-4 border-t border-slate-100 dark:border-slate-800 flex justify-between items-center">
                            <Button variant="secondary" onClick={handleAddItem} className="border-dashed border-2 border-slate-300 dark:border-slate-700 hover:border-accent dark:hover:border-accent flex items-center gap-2 px-4">
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 5a1 1 0 011 1v3h3a1 1 0 110 2h-3v3a1 1 0 11-2 0v-3H6a1 1 0 110-2h3V6a1 1 0 011-1z" clipRule="evenodd" /></svg>
                                Add New Item
                            </Button>
                            <div className="text-right text-xs text-slate-500">
                                Total Items: <span className="font-bold text-slate-900 dark:text-white">{draftInvoice.items.length}</span>
                            </div>
                         </div>
                     </SectionCard>
                 </div>

                 {/* Right Column */}
                 <div className="space-y-6">

                     {/* Summary */}
                     <SectionCard title="Payment Summary">
                         <div className="space-y-3 text-sm">
                             <div className="flex justify-between text-slate-600 dark:text-slate-400">
                                 <span>Subtotal</span>
                                 <span>{currency}{totals.subTotal.toFixed(2)}</span>
                             </div>
                             <div className="flex justify-between text-slate-600 dark:text-slate-400">
                                 <span>CGST</span>
                                 <span>{currency}{totals.cgst.toFixed(2)}</span>
                             </div>
                             <div className="flex justify-between text-slate-600 dark:text-slate-400">
                                 <span>SGST</span>
                                 <span>{currency}{totals.sgst.toFixed(2)}</span>
                             </div>
                             <div className="flex justify-between text-slate-600 dark:text-slate-400">
                                 <span>IGST</span>
                                 <span>{currency}{totals.igst.toFixed(2)}</span>
                             </div>
                             <div className="border-t border-slate-200 dark:border-slate-700 pt-3 flex justify-between font-bold text-lg text-slate-900 dark:text-white">
                                 <span>Total</span>
                                 <span>{currency}{totals.grandTotal.toFixed(2)}</span>
                             </div>
                         </div>
                     </SectionCard>

                     {/* Bank Account */}
                     <SectionCard title="Bank Details">
                         <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Select Bank Account</label>
                         <select 
                            className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 text-slate-900 dark:text-white rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-accent focus:outline-none"
                            value={draftInvoice.selectedBankAccountId || ''}
                            onChange={(e) => setDraftInvoice({...draftInvoice, selectedBankAccountId: e.target.value})}
                         >
                             <option value="">-- No Bank Account --</option>
                             {company.bankAccounts.map(b => <option key={b.id} value={b.id}>{b.bankName} - {b.accountNumber.slice(-4)}</option>)}
                         </select>
                         <div className="mt-2 text-right">
                            <button className="text-xs text-accent font-semibold hover:underline" onClick={() => setIsAddBankModalOpen(true)}>+ Add New Bank</button>
                         </div>
                     </SectionCard>

                     {/* Shipping & Transport */}
                     <SectionCard title="Shipping & Transport">
                         <div className="space-y-4">
                             <div className="flex items-center gap-2 mb-2">
                                <input type="checkbox" id="sameAsBilling" checked={draftInvoice.isShippingSameAsBilling} onChange={handleSameAsBillingToggle} className="rounded border-slate-300 text-accent focus:ring-accent" />
                                <label htmlFor="sameAsBilling" className="text-sm text-slate-700 dark:text-slate-300">Same as Billing Address</label>
                             </div>

                             {!draftInvoice.isShippingSameAsBilling && (
                                 <div className="space-y-3 bg-slate-50 dark:bg-slate-800 p-3 rounded-lg border border-slate-200 dark:border-slate-700">
                                     <Input label="Shipping Name" name="name" value={draftInvoice.shippingDetails.name} onChange={handleShippingChange} className="!py-1.5 !text-xs" />
                                     <textarea name="address" rows={2} value={draftInvoice.shippingDetails.address} onChange={(e) => handleShippingChange(e as any)} placeholder="Address" className="w-full bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded px-2 py-1 text-xs" />
                                     <div className="grid grid-cols-2 gap-2">
                                         <div className="relative">
                                             <Input label="Zip" name="zip" value={draftInvoice.shippingDetails.zip} onChange={handleShippingChange} className="!py-1.5 !text-xs" error={pincodeError || undefined}/>
                                             {isPincodeLoading && <div className="absolute top-7 right-2 h-3 w-3 border border-slate-400 border-t-transparent rounded-full animate-spin"></div>}
                                         </div>
                                         <Input label="City" name="city" value={draftInvoice.shippingDetails.city} onChange={handleShippingChange} className="!py-1.5 !text-xs" />
                                     </div>
                                      <select name="state" value={draftInvoice.shippingDetails.state} onChange={handleShippingChange} className="w-full bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded px-2 py-1 text-xs">
                                        <option value="">Select State</option>
                                        {INDIAN_STATES.map(s => <option key={s} value={s}>{s}</option>)}
                                     </select>
                                     <Input label="GSTIN" name="gstin" value={draftInvoice.shippingDetails.gstin} onChange={handleShippingChange} className="!py-1.5 !text-xs" />
                                 </div>
                             )}

                             <div className="pt-2 border-t border-slate-100 dark:border-slate-700">
                                 <label className="block text-xs font-semibold text-slate-500 uppercase mb-2">Logistics</label>
                                 <select value={draftInvoice.transporterId} onChange={(e) => setDraftInvoice({...draftInvoice, transporterId: e.target.value})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 rounded-lg px-3 py-2 text-sm mb-3">
                                     <option value="">-- Select Transporter --</option>
                                     <option value="self">Self Transport</option>
                                     {company.transporters.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                                 </select>
                                 <Input label="Vehicle Number" value={draftInvoice.vehicleNumber} onChange={handleVehicleNumberChange} error={vehicleNumberError || undefined} placeholder="MH 01 AB 1234" />
                                 <Input label="E-Way Bill No." value={draftInvoice.ewayBillNumber} onChange={e => setDraftInvoice({...draftInvoice, ewayBillNumber: e.target.value})} className="mt-3" />
                             </div>
                         </div>
                     </SectionCard>

                     <SectionCard title="Notes">
                         <textarea 
                            rows={3} 
                            className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 rounded-lg p-3 text-sm focus:ring-accent focus:border-accent"
                            placeholder="Add terms, conditions, or payment instructions..."
                            value={draftInvoice.notes}
                            onChange={e => setDraftInvoice({...draftInvoice, notes: e.target.value})}
                         />
                     </SectionCard>

                 </div>
             </div>

             {/* Add Bank Modal */}
             <Modal isOpen={isAddBankModalOpen} onClose={() => setIsAddBankModalOpen(false)} title="Add Bank Account">
                 <div className="p-6 space-y-4">
                     <Input label="Bank Name" value={newBank.bankName} onChange={e => setNewBank({...newBank, bankName: e.target.value})} error={newBankErrors.bankName} />
                     <Input label="Account Number" value={newBank.accountNumber} onChange={e => setNewBank({...newBank, accountNumber: e.target.value})} error={newBankErrors.accountNumber} />
                     <Input label="IFSC Code" value={newBank.ifsc} onChange={e => setNewBank({...newBank, ifsc: e.target.value})} error={newBankErrors.ifsc} />
                 </div>
                 <div className="p-6 pt-0 flex justify-end gap-3">
                     <Button variant="secondary" onClick={() => setIsAddBankModalOpen(false)}>Cancel</Button>
                     <Button onClick={() => {
                         // Simple validation for modal
                         if(!newBank.bankName) { setNewBankErrors({...newBankErrors, bankName: 'Required'}); return; }
                         if(!newBank.accountNumber) { setNewBankErrors({...newBankErrors, accountNumber: 'Required'}); return; }
                         if(!newBank.ifsc) { setNewBankErrors({...newBankErrors, ifsc: 'Required'}); return; }

                         const newAccount: BankAccount = { ...newBank, id: Date.now().toString(), isDefault: company.bankAccounts.length === 0 } as BankAccount;
                         onUpdateCompany({ ...company, bankAccounts: [...company.bankAccounts, newAccount] });
                         setDraftInvoice({...draftInvoice, selectedBankAccountId: newAccount.id});
                         setIsAddBankModalOpen(false);
                         setNewBank({ bankName: '', accountNumber: '', ifsc: '' });
                         setNewBankErrors({});
                     }}>Save Account</Button>
                 </div>
             </Modal>
        </div>
    );
};

