                            No invoice history found for this client.
                        </div>
                    )}
                </div>
            )}

            {/* Timeline Tab */}
            {activeTab === 'timeline' && (
                <div className="bg-white dark:bg-primary-dark p-6 rounded-xl border border-slate-200 dark:border-slate-700">
                    <div className="relative pl-4">
                        {/* Vertical Line */}
                        <div className="absolute top-0 bottom-0 left-[21px] w-px bg-slate-200 dark:bg-slate-700"></div>

                        <div className="space-y-8">
                            {timelineEvents.map((event, idx) => (
                                <div key={idx} className="relative flex gap-6 group">
                                    {/* Icon/Dot */}
                                    <div className={`absolute left-0 mt-1.5 w-11 h-11 rounded-full border-4 border-white dark:border-primary-dark flex items-center justify-center z-10 shadow-sm
                                        ${event.type === 'created' ? 'bg-indigo-100 text-indigo-600' : 'bg-red-100 text-red-600'}`}>
                                        {event.type === 'created' ? (
                                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M4 4a2 2 0 012-2h4.586A2 2 0 0112 2.586L15.414 6A2 2 0 0116 7.414V16a2 2 0 01-2 2H6a2 2 0 01-2-2V4zm2 6a1 1 0 011-1h6a1 1 0 110 2H7a1 1 0 01-1-1zm1 3a1 1 0 100 2h6a1 1 0 100-2H7z" clipRule="evenodd" /></svg>
                                        ) : (
                                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                                        )}
                                    </div>

                                    <div className="flex-1 ml-12 pt-1">
                                        <div className="flex justify-between items-start mb-1">
                                            <h4 className="text-sm font-bold text-slate-900 dark:text-white group-hover:text-accent transition-colors">{event.title}</h4>
                                            <span className="text-xs font-mono font-medium text-slate-400 bg-slate-100 dark:bg-slate-800 px-2 py-1 rounded">{event.date}</span>
                                        </div>
                                        <p className="text-sm text-slate-600 dark:text-slate-400">{event.description}</p>
                                        {event.status && (
                                            <span className={`inline-block mt-2 px-2 py-0.5 text-[10px] font-bold uppercase rounded ${getStatusBadge(event.status)}`}>
                                                {event.status}
                                            </span>
                                        )}
                                    </div>
                                </div>
                            ))}
                            {timelineEvents.length === 0 && (
                                <p className="text-sm text-slate-500 italic pl-12">No activity recorded yet.</p>
                            )}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

const Clients: React.FC<ClientsProps> = ({ clients, setClients, invoices, company, onEditInvoice, onDeleteInvoice, onStatusChange, onBulkDelete }) => {
  const [isClientModalOpen, setIsClientModalOpen] = useState(false);
  const [editingClient, setEditingClient] = useState<Client>(emptyClient);
  const [clientFormErrors, setClientFormErrors] = useState<ClientFormErrors>({});
  const [isClientConfirmOpen, setIsClientConfirmOpen] = useState(false);
  const [clientToDelete, setClientToDelete] = useState<string | null>(null);
  const [expandedClientId, setExpandedClientId] = useState<string | null>(null);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  // Search & Filter State
  const [searchQuery, setSearchQuery] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [filterState, setFilterState] = useState('');
  const [filterTags, setFilterTags] = useState<string[]>([]);
  const [filterCity, setFilterCity] = useState('');
  const [filterBalanceStatus, setFilterBalanceStatus] = useState<'All' | 'Outstanding' | 'Settled' | 'Overdue'>('All');
  const [filterMinBalance, setFilterMinBalance] = useState('');
  const [filterMaxBalance, setFilterMaxBalance] = useState('');
  const [sortOption, setSortOption] = useState('name-asc');

  const [selectedInvoice, setSelectedInvoice] = useState<Invoice | null>(null);
  const [invoiceToEmail, setInvoiceToEmail] = useState<Invoice | null>(null);
  const [isInvoiceConfirmOpen, setIsInvoiceConfirmOpen] = useState(false);
  const [invoiceToDeleteId, setInvoiceToDeleteId] = useState<string | null>(null);
  const [isExporting, setIsExporting] = useState(false);

  const [recipient, setRecipient] = useState('');
  const [subject, setSubject] = useState('');
  const [body, setBody] = useState('');
  const [isSending, setIsSending] = useState(false);
  const emailPrintRef = useRef<HTMLDivElement>(null);
  const currency = '₹';

  // Extract unique tags and cities for filter dropdowns
  const { allTags, allCities } = useMemo(() => {
      const tags = new Set<string>();
      const cities = new Set<string>();
      clients.forEach(c => {
          c.tags?.forEach(t => tags.add(t));
          if(c.city) cities.add(c.city);
      });
      return { 
          allTags: Array.from(tags).sort(),
          allCities: Array.from(cities).sort()
      };
  }, [clients]);

  // Calculate balances for filtering (memoized)
  const clientBalances = useMemo(() => {
      const balances: Record<string, number> = {};
      clients.forEach(c => {
          const clientInvoices = invoices.filter(inv => inv.client.id === c.id && inv.status !== 'Paid');
          balances[c.id] = clientInvoices.reduce((sum, inv) => sum + inv.grandTotal, 0);
      });
      return balances;
  }, [clients, invoices]);

  // Calculate invoice counts for each client
  const clientInvoiceCounts = useMemo(() => {
      const counts: Record<string, number> = {};
      invoices.forEach(inv => {
          counts[inv.client.id] = (counts[inv.client.id] || 0) + 1;
      });
      return counts;
  }, [invoices]);

  // Identify clients with Overdue invoices
  const clientOverdueStatus = useMemo(() => {
      const overdueSet = new Set<string>();
      invoices.forEach(inv => {
          if (inv.status === 'Overdue') overdueSet.add(inv.client.id);
      });
      return overdueSet;
  }, [invoices]);

  useEffect(() => {
    if (invoiceToEmail) {
        setRecipient(invoiceToEmail.client.email);
        setSubject(`Invoice #${invoiceToEmail.invoiceNumber} from ${company.details.name || 'InvoicePro'}`);
        setBody(`Dear ${invoiceToEmail.client.name},

Please find attached Invoice #${invoiceToEmail.invoiceNumber} for ${currency}${invoiceToEmail.grandTotal.toFixed(2)}, issued on ${invoiceToEmail.issueDate}.

The amount is due by ${invoiceToEmail.dueDate}.

Thank you for your business.

Best regards,
${company.details.name || 'The Team'}`);
    }
  }, [invoiceToEmail, company.details.name]);


  const handleOpenClientModal = (client?: Client) => {
    setClientFormErrors({});
    setEditingClient(client || emptyClient);
    setIsClientModalOpen(true);
  };

  const handleCloseClientModal = () => setIsClientModalOpen(false);

  const validateClientForm = (client: Client): boolean => {
      const errors: ClientFormErrors = {};
      const nameError = validateRequired(client.name);
      if(nameError) errors.name = nameError;

      const emailError = validateEmail(client.email);
      if(emailError) errors.email = emailError;

      const gstinError = validateGstin(client.gstin);
      if (gstinError) errors.gstin = gstinError;

      setClientFormErrors(errors);
      return Object.values(errors).every(e => !e);
  }

  const handleSaveClient = () => {
    if(!validateClientForm(editingClient)) return;

    if (editingClient.id) {
      setClients(clients.map(c => c.id === editingClient.id ? editingClient : c));
    } else {
      setClients([...clients, { ...editingClient, id: Date.now().toString() }]);
    }
    handleCloseClientModal();
  };

  const handleDeleteClient = (id: string) => {
    setClientToDelete(id);
    setIsClientConfirmOpen(true);
  };

  const confirmDeleteClient = () => {
    if (clientToDelete) {
      setClients(clients.filter(c => c.id !== clientToDelete));
    }
    setIsClientConfirmOpen(false);
    setClientToDelete(null);
  };

  const toggleFilterTag = (tag: string) => {
      setFilterTags(prev => prev.includes(tag) ? prev.filter(t => t !== tag) : [...prev, tag]);
  };

  const processedClients = useMemo(() => {
    let result = [...clients];
    const lowercasedQuery = searchQuery.toLowerCase();

    if (lowercasedQuery) {
        result = result.filter(client =>
            client.name.toLowerCase().includes(lowercasedQuery) ||
            client.gstin.toLowerCase().includes(lowercasedQuery) ||
            client.email.toLowerCase().includes(lowercasedQuery) ||
            client.phone.toLowerCase().includes(lowercasedQuery) ||
            (client.address && client.address.toLowerCase().includes(lowercasedQuery)) ||
            (client.city && client.city.toLowerCase().includes(lowercasedQuery)) ||
            (client.zip && client.zip.includes(lowercasedQuery))
        );
    }

    if (filterState) result = result.filter(client => client.state === filterState);

    // Multi-select tag filter (OR logic: client must have at least one of the selected tags)
    if (filterTags.length > 0) {
        result = result.filter(client => client.tags?.some(t => filterTags.includes(t)));
    }

    if (filterCity) result = result.filter(client => client.city === filterCity);

    if (filterBalanceStatus !== 'All') {
        if (filterBalanceStatus === 'Overdue') {
             result = result.filter(c => clientOverdueStatus.has(c.id));
        } else {
            result = result.filter(c => {
                const balance = clientBalances[c.id] || 0;
                return filterBalanceStatus === 'Outstanding' ? balance > 0 : balance === 0;
            });
        }
    }

    if (filterMinBalance || filterMaxBalance) {
        result = result.filter(c => {
            const balance = clientBalances[c.id] || 0;
            const min = filterMinBalance ? parseFloat(filterMinBalance) : -Infinity;
            const max = filterMaxBalance ? parseFloat(filterMaxBalance) : Infinity;
            return balance >= min && balance <= max;
        });
    }

    switch (sortOption) {
        case 'name-asc': result.sort((a, b) => a.name.localeCompare(b.name)); break;
        case 'name-desc': result.sort((a, b) => b.name.localeCompare(a.name)); break;
        case 'gstin-asc': result.sort((a, b) => a.gstin.localeCompare(b.gstin)); break;
        case 'newest': result.sort((a, b) => parseInt(b.id) - parseInt(a.id)); break;
        case 'oldest': result.sort((a, b) => parseInt(a.id) - parseInt(b.id)); break;
        case 'balance-desc': result.sort((a, b) => (clientBalances[b.id] || 0) - (clientBalances[a.id] || 0)); break;
        default: break;
    }
    return result;
  }, [clients, searchQuery, filterState, filterTags, filterCity, filterBalanceStatus, filterMinBalance, filterMaxBalance, sortOption, clientBalances, clientOverdueStatus]);

  // Bulk Actions
  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.checked) {
          setSelectedIds(processedClients.map(c => c.id));
      } else {
          setSelectedIds([]);
      }
  };

  const handleSelectOne = (id: string) => {
      if (selectedIds.includes(id)) {
          setSelectedIds(selectedIds.filter(sid => sid !== id));
      } else {
          setSelectedIds([...selectedIds, id]);
      }
  };

  const handleBulkDelete = () => {
      if(window.confirm(`Are you sure you want to delete ${selectedIds.length} clients?`)) {
          onBulkDelete(selectedIds);
          setSelectedIds([]);
      }
  };

  const handleExport = async (exportAll: boolean = false) => {
      setIsExporting(true);
      await new Promise(resolve => setTimeout(resolve, 50)); // Allow UI update
      try {
          const dataToExport = exportAll ? clients : processedClients.filter(c => selectedIds.length === 0 || selectedIds.includes(c.id));
          const csvData = arrayToCSV(dataToExport, [
              { key: 'name', label: 'Name' },
              { key: 'gstin', label: 'GSTIN' },
              { key: 'email', label: 'Email' },
              { key: 'phone', label: 'Phone' },
              { key: 'address', label: 'Address' },
              { key: 'city', label: 'City' },
              { key: 'state', label: 'State' },
              { key: 'zip', label: 'Zip' },
              { key: 'tags', label: 'Tags', formatter: (c) => c.tags?.join(', ') || '' }
          ]);
          downloadCSV(csvData, `clients_export_${new Date().toISOString().split('T')[0]}.csv`);
      } catch (e) {
          console.error("Export error", e);
          alert("Export failed.");
      } finally {
          setIsExporting(false);
      }
  };

  const handleDeleteInvoice = (id: string) => {
    setInvoiceToDeleteId(id);
    setIsInvoiceConfirmOpen(true);
  };

  const confirmDeleteInvoice = () => {
    if (invoiceToDeleteId) {
      onDeleteInvoice(invoiceToDeleteId);
    }
    setIsInvoiceConfirmOpen(false);
    setInvoiceToDeleteId(null);
  };

  const handleSendEmail = async () => {
    if (!invoiceToEmail || !emailPrintRef.current) return;
    setIsSending(true);

    try {
        // Generate PDF
        const canvas = await (window as any).html2canvas(emailPrintRef.current, { 
            scale: 2,
            backgroundColor: '#ffffff' // FORCE WHITE BACKGROUND
        });
        const imgData = canvas.toDataURL('image/png');
        const pdf = new (window as any).jspdf.jsPDF({ orientation: 'portrait', unit: 'pt', format: 'a4' });

        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();
        const canvasWidth = canvas.width;
        const canvasHeight = canvas.height;
        const ratio = canvasWidth / pdfWidth;
        const scaledCanvasHeight = canvasHeight / ratio;

        let position = 0;
        pdf.addImage(imgData, 'PNG', 0, position, pdfWidth, scaledCanvasHeight);
        let heightLeft = scaledCanvasHeight - pdfHeight;

        while (heightLeft > 0) {
            position = -heightLeft;
            pdf.addPage();
            pdf.addImage(imgData, 'PNG', 0, position, pdfWidth, scaledCanvasHeight);
            heightLeft -= pdfHeight;
        }

        const pdfBlob = pdf.output('blob');
        console.log(`Generated Invoice PDF (${pdfBlob.size} bytes) for ${invoiceToEmail.invoiceNumber}`);

        // Simulate sending with attachment
        await new Promise(resolve => setTimeout(resolve, 2000));

        alert(`Email sent successfully to ${recipient} with Invoice-${invoiceToEmail.invoiceNumber}.pdf attached!`);
        setIsSending(false);
        setInvoiceToEmail(null);
