        </div>

        {showFilters && (
            <div className="bg-white dark:bg-primary-dark p-4 rounded-lg shadow-sm border border-slate-200 dark:border-tertiary-dark grid grid-cols-1 md:grid-cols-4 gap-4 items-start animate-fade-in">
                <div>
                    <label htmlFor="filterState" className="block text-sm font-medium text-slate-600 dark:text-medium-text mb-1">State</label>
                    <select id="filterState" value={filterState} onChange={e => setFilterState(e.target.value)} className={`${inputClasses} !py-2 text-sm`}>
                        <option value="">All States</option>
                        {INDIAN_STATES.map(state => <option key={state} value={state}>{state}</option>)}
                    </select>
                </div>
                 <div>
                    <label htmlFor="filterCity" className="block text-sm font-medium text-slate-600 dark:text-medium-text mb-1">City</label>
                    <select id="filterCity" value={filterCity} onChange={e => setFilterCity(e.target.value)} className={`${inputClasses} !py-2 text-sm`}>
                        <option value="">All Cities</option>
                        {allCities.map(city => <option key={city} value={city}>{city}</option>)}
                    </select>
                </div>
                <div>
                     <label className="block text-sm font-medium text-slate-600 dark:text-medium-text mb-1">Filter by Tags</label>
                     <div className="flex flex-wrap gap-1.5 min-h-[38px] p-1.5 bg-slate-50 dark:bg-tertiary-dark border border-slate-300 dark:border-slate-600 rounded-md">
