                    description: `Due Date Passed. Amount: ${currency}${inv.grandTotal.toFixed(2)}`,
                    type: 'due'
                });
            }
        });

        return events.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    }, [clientInvoices, currency]);

