const ClientHistoryPanel: React.FC<{
    client: Client;
    invoices: Invoice[];
    currency: string;
    onEditInvoice: (id: string) => void;
    onViewInvoice: (inv: Invoice) => void;
    onDeleteInvoice: (id: string) => void;
    onEmailInvoice: (inv: Invoice) => void;
}> = ({ client, invoices, currency, onEditInvoice, onViewInvoice, onDeleteInvoice, onEmailInvoice }) => {
    const [activeTab, setActiveTab] = useState<'invoices' | 'timeline'>('invoices');

    const clientInvoices = useMemo(() => 
        invoices.filter(inv => inv.client.id === client.id).sort((a, b) => new Date(b.issueDate).getTime() - new Date(a.issueDate).getTime())
    , [invoices, client.id]);

    const stats = useMemo(() => {
        const totalInvoiced = clientInvoices.reduce((acc, inv) => acc + inv.grandTotal, 0);
        const totalPaid = clientInvoices.filter(inv => inv.status === 'Paid').reduce((acc, inv) => acc + inv.grandTotal, 0);
        const totalOutstanding = clientInvoices.filter(inv => inv.status !== 'Paid').reduce((acc, inv) => acc + inv.grandTotal, 0);
        return { totalInvoiced, totalPaid, totalOutstanding, count: clientInvoices.length };
    }, [clientInvoices]);

    const timelineEvents = useMemo(() => {
        const events: { date: string, title: string, description: string, type: 'created' | 'due' | 'paid', status?: string }[] = [];

        clientInvoices.forEach(inv => {
            events.push({
                date: inv.issueDate,
                title: `Invoice #${inv.invoiceNumber} Created`,
                description: `Amount: ${currency}${inv.grandTotal.toFixed(2)}`,
                type: 'created',
                status: inv.status
            });

            if (inv.status === 'Overdue') {
                 events.push({
                    date: inv.dueDate,
                    title: `Payment Overdue #${inv.invoiceNumber}`,
                    description: `Due Date Passed. Amount: ${currency}${inv.grandTotal.toFixed(2)}`,
                    type: 'due'
                });
            }
        });

        return events.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    }, [clientInvoices, currency]);

    const getStatusBadge = (status: string) => {
        switch (status) {
            case 'Paid': return 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400';
            case 'Unpaid': return 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400';
            case 'Overdue': return 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400';
            default: return 'bg-slate-100 text-slate-800';
        }
    };

    return (
        <div className="animate-fade-in bg-slate-50/50 dark:bg-slate-800/20 p-4 rounded-xl border border-slate-200 dark:border-slate-700">
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-bold text-slate-800 dark:text-white flex items-center gap-2">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-accent" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm1-12a1 1 0 10-2 0v4a1 1 0 00.293.707l2.828 2.829a1 1 0 101.415-1.415L11 9.586V6z" clipRule="evenodd" /></svg>
                    Client History & Analytics
                </h3>
            </div>

            {/* Stats Overview */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
                <div className="bg-white dark:bg-primary-dark p-4 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm relative overflow-hidden group">
                    <div className="absolute right-0 top-0 p-3 opacity-10 group-hover:opacity-20 transition-opacity"><svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg></div>
                    <p className="text-xs text-slate-500 uppercase tracking-wider font-semibold">Total Invoiced</p>
                    <p className="text-2xl font-black text-slate-900 dark:text-white mt-1">{currency}{stats.totalInvoiced.toLocaleString()}</p>
                </div>
                <div className="bg-white dark:bg-primary-dark p-4 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm relative overflow-hidden">
                    <div className="absolute right-0 top-0 p-3 opacity-10 text-green-500"><svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg></div>
