);

const NewInvoice: React.FC<NewInvoiceProps> = ({ 
    company, saveInvoice, setActiveView, 
    invoiceToEdit, clearEditingInvoice, onUpdateCompany,
    draftInvoice, setDraftInvoice
}) => {
    const isEditing = !!invoiceToEdit;
    const currency = '₹';

    // Derived state for validations
    const [vehicleNumberError, setVehicleNumberError] = useState<string | null>(null);
    const [formError, setFormError] = useState<string | null>(null);
    const [isPincodeLoading, setIsPincodeLoading] = useState(false);
    const [pincodeError, setPincodeError] = useState<string|null>(null);
    const [itemErrors, setItemErrors] = useState<Record<string, string>>({});

    // Bank Account Modal State
    const [isAddBankModalOpen, setIsAddBankModalOpen] = useState(false);
    const [newBank, setNewBank] = useState<Omit<BankAccount, 'id' | 'isDefault'>>({ bankName: '', accountNumber: '', ifsc: '' });
    const [newBankErrors, setNewBankErrors] = useState<Partial<Record<keyof typeof newBank, string>>>({});

    // Item Creation & Selection State
    const [activeDropdownIndex, setActiveDropdownIndex] = useState<number | null>(null);
    const dropdownRef = useRef<HTMLDivElement>(null);
    const [isCreateItemModalOpen, setIsCreateItemModalOpen] = useState(false);
    const [creatingItemRowIndex, setCreatingItemRowIndex] = useState<number | null>(null);
    const [newItemData, setNewItemData] = useState<Partial<Item>>({ name: '', price: 0, gstRate: 18, unit: 'pcs', quantityInStock: 0, hsn: '' });

    // Item Detail View State
    const [viewItemModalOpen, setViewItemModalOpen] = useState(false);
    const [viewingItem, setViewingItem] = useState<Item | null>(null);

    const selectedClient = useMemo(() => company.clients.find(c => c.id === draftInvoice.clientId), [draftInvoice.clientId, company.clients]);

    // Close dropdown when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setActiveDropdownIndex(null);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const handleClientChange = (clientId: string) => {
        const client = company.clients.find(c => c.id === clientId);
        if (client) {
            setDraftInvoice({
                ...draftInvoice,
                clientId: clientId,
                isShippingSameAsBilling: true,
                shippingDetails: {
                    name: client.name,
                    address: client.address,
                    city: client.city,
                    state: client.state,
                    zip: client.zip,
                    gstin: client.gstin
                }
            });
        } else {
            setDraftInvoice({ ...draftInvoice, clientId: clientId });
        }
    };

    const handleSameAsBillingToggle = (e: React.ChangeEvent<HTMLInputElement>) => {
        const isChecked = e.target.checked;
        const updates: Partial<DraftInvoice> = { isShippingSameAsBilling: isChecked };

        if (!isChecked && selectedClient) {
            updates.shippingDetails = {
                name: selectedClient.name,
                address: selectedClient.shippingAddress || selectedClient.address,
                city: selectedClient.shippingCity || selectedClient.city,
                state: selectedClient.shippingState || selectedClient.state,
                zip: selectedClient.shippingZip || selectedClient.zip,
                gstin: selectedClient.gstin,
            };
        }
        setDraftInvoice({ ...draftInvoice, ...updates });
    };

    // Auto-update shipping details
    useEffect(() => {
        if(draftInvoice.isShippingSameAsBilling) return;
        let isMounted = true;
        const pincode = draftInvoice.shippingDetails.zip;
        if (pincode && pincode.length === 6) {
          const timer = setTimeout(async () => {
            if (!isMounted) return;
            setIsPincodeLoading(true);
            setPincodeError(null);
            const location = await fetchLocationByPincode(pincode);
            if (isMounted) {
                if (location) {
                    setDraftInvoice(prev => ({
                        ...prev,
                        shippingDetails: {
                            ...prev.shippingDetails,
                            city: location.city,
                            state: location.state
                        }
                    }));
                } else if (location === null) {
                    setPincodeError('Invalid Pincode');
                } else {
                    setPincodeError('Lookup failed. Enter manually.');
                }
                setIsPincodeLoading(false);
            }
          }, 500);
          return () => { isMounted = false; clearTimeout(timer); };
        } else {
            setPincodeError(null);
        }
    }, [draftInvoice.shippingDetails.zip, draftInvoice.isShippingSameAsBilling]);

    const handleVehicleNumberChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setVehicleNumberError(null);
        const value = e.target.value;
        const parts = value.split(/ (.*)/s);
        const rtoPart = (parts[0] || '').toUpperCase();
        let finalValue = rtoPart;

        if (parts.length > 1) {
            let numberPart = parts[1] || '';
            numberPart = numberPart.replace(/[^0-9]/g, '');
            if (numberPart.length > 4) {
                numberPart = numberPart.slice(0, 4);
                setVehicleNumberError('Numeric part must be 4 digits.');
                setTimeout(() => setVehicleNumberError(null), 3000);
            }
            finalValue = `${rtoPart} ${numberPart}`;
        }
        setDraftInvoice({ ...draftInvoice, vehicleNumber: finalValue });
    };

    const handleShippingChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        setDraftInvoice({
            ...draftInvoice,
            shippingDetails: {
                ...draftInvoice.shippingDetails,
                [e.target.name]: e.target.value
            }
        });
    };

    const transporterDetails = useMemo(() => {
        if (draftInvoice.transporterId === 'self') {
            return { name: 'Self', gstin: company.details.gstin };
        }
        return company.transporters.find(t => t.id === draftInvoice.transporterId);
    }, [draftInvoice.transporterId, company.transporters, company.details.gstin]);

    const handleAddItem = () => {
        setDraftInvoice({
            ...draftInvoice,
            items: [...draftInvoice.items, { id: '', name: '', hsn: '', price: 0, gstRate: 18, quantity: 1, unit: 'pcs', quantityInStock: 0 }]
        });
    };

    const handleRemoveItem = (index: number) => {
        setDraftInvoice({
            ...draftInvoice,
            items: draftInvoice.items.filter((_, i) => i !== index)
        });

        // Clean up errors
        setItemErrors(prev => {
            const newErrs: Record<string, string> = {};
            Object.keys(prev).forEach(key => {
                const parts = key.split('-');
                const idx = parseInt(parts[0]);
                const field = parts.slice(1).join('-');
                if (idx < index) newErrs[key] = prev[key];
                else if (idx > index) newErrs[`${idx - 1}-${field}`] = prev[key];
            });
            return newErrs;
        });
    };

    const handleItemChange = (index: number, field: keyof InvoiceItem, value: any) => {
        const updatedItems = [...draftInvoice.items];
        const currentItem = { ...updatedItems[index] };
        let newItemErrors = { ...itemErrors };

        if (field === 'id' && value) {
            const selectedItem = company.items.find(i => i.id === value);
            if (selectedItem) updatedItems[index] = { ...currentItem, ...selectedItem, quantity: 1 };
            // Clear errors for this row if selecting a valid item
            delete newItemErrors[`${index}-name`];
            delete newItemErrors[`${index}-price`];
            delete newItemErrors[`${index}-quantity`];
        } else {
            const newValue = (field === 'quantity' || field === 'price' || field === 'gstRate') ? parseFloat(value) || 0 : value;
            updatedItems[index] = { ...currentItem, [field]: newValue };

            // Real-time Validation Logic
            if (field === 'quantity') {
                if (newValue <= 0) newItemErrors[`${index}-quantity`] = 'Qty > 0';
                else delete newItemErrors[`${index}-quantity`];
            }
            if (field === 'price') {
                if (newValue <= 0) newItemErrors[`${index}-price`] = 'Price > 0';
                else delete newItemErrors[`${index}-price`];
            }
            if (field === 'name' && !value) {
                newItemErrors[`${index}-name`] = 'Required';
            } else if (field === 'name') {
                delete newItemErrors[`${index}-name`];
            }
        }

        setItemErrors(newItemErrors);
        setDraftInvoice({ ...draftInvoice, items: updatedItems });
    };

    // Item creation flow
    const openCreateItemModal = (name: string, rowIndex: number) => {
        setNewItemData({ ...newItemData, name, price: 0, gstRate: 18, quantityInStock: 0, hsn: '' });
        setCreatingItemRowIndex(rowIndex);
        setIsCreateItemModalOpen(true);
        setActiveDropdownIndex(null);
    };

    const handleCreateNewItem = () => {
        if (!newItemData.name || (newItemData.price || 0) < 0) return;

        const newItem: Item = {
            id: `item_${Date.now()}`,
            name: newItemData.name!,
            price: Number(newItemData.price) || 0,
            gstRate: Number(newItemData.gstRate) || 0,
            unit: newItemData.unit || 'pcs',
            hsn: newItemData.hsn || '',
            quantityInStock: Number(newItemData.quantityInStock) || 0
        };

        // Add to company items
        onUpdateCompany({
            ...company,
            items: [...company.items, newItem]
        });

        // Update the active row in draft invoice
        if (creatingItemRowIndex !== null) {
            handleItemChange(creatingItemRowIndex, 'id', newItem.id);
        }

        setIsCreateItemModalOpen(false);
        setCreatingItemRowIndex(null);
    };

    // Calculations
    const calculateTotals = () => {
        let subTotal = 0;
        let cgst = 0;
        let sgst = 0;
        let igst = 0;

        const posState = draftInvoice.shippingDetails.state || (selectedClient ? selectedClient.state : '');
        const isIntraState = !posState || posState.toLowerCase() === company.details.state.toLowerCase();

        draftInvoice.items.forEach(item => {
            const taxable = item.price * item.quantity;
            subTotal += taxable;
            const taxAmount = (taxable * item.gstRate) / 100;

            if (isIntraState) {
                cgst += taxAmount / 2;
                sgst += taxAmount / 2;
            } else {
                igst += taxAmount;
            }
        });

        return { subTotal, cgst, sgst, igst, grandTotal: subTotal + cgst + sgst + igst };
    };

    const totals = calculateTotals();

    const handleSave = () => {
        // Validation logic
        const newFormErrors: string[] = [];
        if (!draftInvoice.clientId) newFormErrors.push("Please select a client.");
        if (draftInvoice.items.length === 0) newFormErrors.push("Please add at least one item.");

        // Item validations check
        const newItemErrors: Record<string, string> = {};
        draftInvoice.items.forEach((item, idx) => {
             if (!item.name) newItemErrors[`${idx}-name`] = "Required";
             if (item.price <= 0) newItemErrors[`${idx}-price`] = "Invalid";
             if (item.quantity <= 0) newItemErrors[`${idx}-quantity`] = "Invalid";
        });

        if (newFormErrors.length > 0) {
            setFormError(newFormErrors.join(" "));
            return;
        }

        if (Object.keys(newItemErrors).length > 0 || Object.keys(itemErrors).length > 0) {
            setItemErrors({ ...itemErrors, ...newItemErrors });
            setFormError("Please fix invalid items.");
            return;
        }

        const selectedClient = company.clients.find(c => c.id === draftInvoice.clientId);
        if(!selectedClient) return;

        // Construct Invoice Object
        const finalInvoice: Omit<Invoice, 'id' | 'status'> | Invoice = {
            ...(isEditing && invoiceToEdit ? { id: invoiceToEdit.id, status: invoiceToEdit.status } : {}),
            invoiceNumber: draftInvoice.invoiceNumber,
            client: selectedClient,
            items: draftInvoice.items,
            issueDate: draftInvoice.issueDate,
            dueDate: draftInvoice.dueDate,
            notes: draftInvoice.notes,
            selectedBankAccountId: draftInvoice.selectedBankAccountId,

            // Snapshot details
            shippingName: draftInvoice.shippingDetails.name,
            shippingAddress: draftInvoice.shippingDetails.address,
            shippingCity: draftInvoice.shippingDetails.city,
            shippingState: draftInvoice.shippingDetails.state,
            shippingZip: draftInvoice.shippingDetails.zip,
            shippingGstin: draftInvoice.shippingDetails.gstin,

            transporterName: transporterDetails?.name,
            transporterGstin: transporterDetails?.gstin,
            vehicleNumber: draftInvoice.vehicleNumber,
            ewayBillNumber: draftInvoice.ewayBillNumber,

            ...totals
        };

        saveInvoice(finalInvoice);
        setActiveView('Invoices');
        clearEditingInvoice(); 
    };

    // Load invoice to edit
    useEffect(() => {
        if (invoiceToEdit) {
            setDraftInvoice({
                invoiceNumber: invoiceToEdit.invoiceNumber,
                clientId: invoiceToEdit.client.id,
                items: invoiceToEdit.items,
                issueDate: invoiceToEdit.issueDate,
                dueDate: invoiceToEdit.dueDate,
                notes: invoiceToEdit.notes,
                selectedBankAccountId: invoiceToEdit.selectedBankAccountId,
                shippingDetails: {
                    name: invoiceToEdit.shippingName || '',
                    address: invoiceToEdit.shippingAddress || '',
                    city: invoiceToEdit.shippingCity || '',
                    state: invoiceToEdit.shippingState || '',
                    zip: invoiceToEdit.shippingZip || '',
                    gstin: invoiceToEdit.shippingGstin || ''
                },
                isShippingSameAsBilling: false, 
                transporterId: '', 
                vehicleNumber: invoiceToEdit.vehicleNumber || '',
                ewayBillNumber: invoiceToEdit.ewayBillNumber || ''
            });

             const tId = company.transporters.find(t => t.name === invoiceToEdit.transporterName)?.id;
             if(tId) setDraftInvoice(prev => ({...prev, transporterId: tId}));
             else if(invoiceToEdit.transporterName === 'Self') setDraftInvoice(prev => ({...prev, transporterId: 'self'}));
        }
    }, [invoiceToEdit]);

    // View Item Modal Handler
    const handleViewItemDetails = (itemRow: InvoiceItem) => {
        // Find the full item object from inventory to get latest stock data, fallback to row data
        const inventoryItem = company.items.find(i => i.id === itemRow.id) || itemRow;
        setViewingItem(inventoryItem);
        setViewItemModalOpen(true);
    };

    return (
        <div>
             {/* Header */}
             <div className="flex justify-between items-center mb-6">
                <div className="flex items-center gap-4">
                     <button onClick={() => { setActiveView('Invoices'); clearEditingInvoice(); }} className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors">
                        <svg className="w-6 h-6 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                     </button>
                     <h1 className="text-3xl font-bold text-slate-900 dark:text-light-text">{isEditing ? 'Edit Invoice' : 'New Invoice'}</h1>
                </div>
                <div className="flex gap-3">
                    <Button variant="secondary" onClick={() => { setActiveView('Invoices'); clearEditingInvoice(); }}>Cancel</Button>
                    <Button onClick={handleSave}>Save Invoice</Button>
                </div>
             </div>

             {formError && <div className="mb-6 p-4 bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300 rounded-lg border border-red-200 dark:border-red-800 font-medium animate-fade-in flex items-center gap-2">
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                 {formError}
             </div>}

             <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                 {/* Left Column */}
                 <div className="lg:col-span-2 space-y-6">

                     {/* Client & Invoice Info */}
                     <SectionCard title="Client & Invoice Details">
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                             <div>
                                 <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1.5">Select Client</label>
                                 <select 
                                    className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 text-slate-900 dark:text-white rounded-lg px-4 py-3 focus:ring-2 focus:ring-accent focus:outline-none transition-shadow"
                                    value={draftInvoice.clientId}
                                    onChange={(e) => handleClientChange(e.target.value)}
                                 >
                                     <option value="">-- Choose Client --</option>
                                     {company.clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                                 </select>
                                 <p className="text-xs text-slate-500 mt-1">Or add a new client in Clients section.</p>
                             </div>
                             <Input label="Invoice Number" value={draftInvoice.invoiceNumber} onChange={e => setDraftInvoice({...draftInvoice, invoiceNumber: e.target.value})} />
                             <Input label="Issue Date" type="date" value={draftInvoice.issueDate} onChange={e => setDraftInvoice({...draftInvoice, issueDate: e.target.value})} />
                             <Input label="Due Date" type="date" value={draftInvoice.dueDate} onChange={e => setDraftInvoice({...draftInvoice, dueDate: e.target.value})} />
                         </div>
                     </SectionCard>

                     {/* Items Table */}
                     <SectionCard title="Items" className="overflow-visible">
                         <div className="overflow-visible"> 
                            <table className="w-full text-sm text-left text-slate-600 dark:text-slate-400">
                                <thead className="text-xs text-slate-700 dark:text-slate-300 uppercase bg-slate-100 dark:bg-slate-800">
                                    <tr>
                                        <th className="px-4 py-3 rounded-l-lg w-1/3">Item Details</th>
                                        <th className="px-2 py-3 w-20">Qty</th>
                                        <th className="px-2 py-3 w-24">Unit</th>
                                        <th className="px-2 py-3 w-28">Price</th>
                                        <th className="px-2 py-3 w-20">GST %</th>
                                        <th className="px-4 py-3 w-28 text-right">Amount</th>
                                        <th className="px-2 py-3 w-16 text-center rounded-r-lg">Actions</th>
                                    </tr>
                                </thead>
                                <tbody className="space-y-1">
                                    {draftInvoice.items.map((item, index) => {
                                        const qtyError = itemErrors[`${index}-quantity`];
                                        const priceError = itemErrors[`${index}-price`];
                                        const filteredItems = company.items.filter(i => i.name.toLowerCase().includes(item.name.toLowerCase()));

                                        return (
                                        <tr 
                                            key={index} 
                                            className="bg-white dark:bg-primary-dark group relative"
                                            onClick={(e) => {
                                                // If clicking the row background (not inputs), select or view details could trigger here if desired
                                            }}
                                        >
                                            <td className="px-2 py-2 align-top relative">
                                                <div className="relative">
                                                    <input 
                                                        value={item.name}
                                                        onChange={e => {
                                                            handleItemChange(index, 'name', e.target.value);
                                                            setActiveDropdownIndex(index);
                                                        }}
                                                        onFocus={() => setActiveDropdownIndex(index)}
                                                        onClick={(e) => e.stopPropagation()}
                                                        className={`w-full bg-slate-50 dark:bg-slate-900 border ${itemErrors[`${index}-name`] ? 'border-red-500 focus:ring-red-500' : 'border-slate-300 dark:border-slate-700 hover:border-slate-400 focus:border-accent'} rounded-lg px-3 py-2 focus:ring-2 focus:ring-accent/20 focus:outline-none transition-all font-medium`}
                                                        placeholder="Search or Create Item"
                                                    />

                                                    {/* Custom Dropdown */}
                                                    {activeDropdownIndex === index && (
                                                        <div ref={dropdownRef} className="absolute z-50 left-0 top-full mt-1 w-full bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg shadow-xl max-h-60 overflow-y-auto">
                                                            {filteredItems.length > 0 ? (
                                                                filteredItems.map(suggestion => (
                                                                    <div 
                                                                        key={suggestion.id}
                                                                        className="px-4 py-2 hover:bg-slate-50 dark:hover:bg-slate-700 cursor-pointer text-sm text-slate-700 dark:text-slate-200"
                                                                        onClick={(e) => {
                                                                            e.stopPropagation();
                                                                            handleItemChange(index, 'id', suggestion.id);
                                                                            setActiveDropdownIndex(null);
                                                                        }}
                                                                    >
                                                                        <div className="font-medium">{suggestion.name}</div>
                                                                        <div className="text-xs text-slate-500 flex justify-between">
                                                                            <span>Stock: {suggestion.quantityInStock}</span>
                                                                            <span>{currency}{suggestion.price}</span>
                                                                        </div>
                                                                    </div>
                                                                ))
                                                            ) : (
                                                                <div className="px-4 py-2 text-sm text-slate-500 italic">No existing items found</div>
                                                            )}
                                                            {/* Create New Option */}
                                                            {item.name && !company.items.some(i => i.name.toLowerCase() === item.name.toLowerCase()) && (
                                                                <div 
                                                                    className="px-4 py-2 bg-accent/5 hover:bg-accent/10 cursor-pointer border-t border-slate-100 dark:border-slate-700 text-accent dark:text-indigo-400 font-semibold text-sm flex items-center gap-2"
                                                                    onClick={(e) => {
                                                                        e.stopPropagation();
                                                                        openCreateItemModal(item.name, index);
                                                                    }}
                                                                >
                                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 3a1 1 0 011 1v5h5a1 1 0 110 2h-5v5a1 1 0 11-2 0v-5H4a1 1 0 110-2h5V4a1 1 0 011-1z" clipRule="evenodd" /></svg>
                                                                    Create "{item.name}"
                                                                </div>
                                                            )}
                                                        </div>
                                                    )}
                                                </div>
                                            </td>
                                            <td className="px-2 py-2 align-top relative">
                                                <input onClick={(e) => e.stopPropagation()} type="number" min="0" value={item.quantity} onChange={e => handleItemChange(index, 'quantity', e.target.value)} className={`w-full bg-slate-50 dark:bg-slate-900 border ${qtyError ? 'border-red-500 focus:ring-red-500' : 'border-slate-300 dark:border-slate-700 hover:border-slate-400 focus:border-accent'} rounded-lg px-2 py-2 text-center focus:ring-2 focus:ring-accent/20 focus:outline-none transition-all`} />
                                                {qtyError && <div className="absolute top-full left-0 w-full text-[10px] text-red-500 text-center font-bold mt-0.5">{qtyError}</div>}
                                            </td>
                                             <td className="px-2 py-2 align-top">
                                                <select onClick={(e) => e.stopPropagation()} value={item.unit} onChange={e => handleItemChange(index, 'unit', e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 rounded-lg px-2 py-2 text-xs focus:ring-2 focus:ring-accent/20 focus:border-accent outline-none">
                                                    {ITEM_UNITS.map(u => <option key={u} value={u}>{u}</option>)}
                                                </select>
                                            </td>
                                            <td className="px-2 py-2 align-top relative">
                                                <input onClick={(e) => e.stopPropagation()} type="number" min="0" value={item.price} onChange={e => handleItemChange(index, 'price', e.target.value)} className={`w-full bg-slate-50 dark:bg-slate-900 border ${priceError ? 'border-red-500 focus:ring-red-500' : 'border-slate-300 dark:border-slate-700 hover:border-slate-400 focus:border-accent'} rounded-lg px-2 py-2 text-right focus:ring-2 focus:ring-accent/20 focus:outline-none transition-all`} />
                                                {priceError && <div className="absolute top-full right-0 text-[10px] text-red-500 font-bold mt-0.5">{priceError}</div>}
                                            </td>
                                            <td className="px-2 py-2 align-top">
                                                <input onClick={(e) => e.stopPropagation()} type="number" min="0" value={item.gstRate} onChange={e => handleItemChange(index, 'gstRate', e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 rounded-lg px-2 py-2 text-center focus:ring-2 focus:ring-accent/20 focus:border-accent outline-none" />
                                            </td>
                                            <td className="px-4 py-3 align-top text-right font-bold text-slate-900 dark:text-white">
                                                {currency}{((item.price * item.quantity)).toFixed(2)}
                                            </td>
                                            <td className="px-2 py-2 align-top text-center flex justify-center gap-1">
                                                <button onClick={(e) => { e.stopPropagation(); handleViewItemDetails(item); }} className="text-slate-400 hover:text-blue-500 transition-colors p-2 rounded-lg hover:bg-blue-50 dark:hover:bg-blue-900/20" title="Item Details">
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                                </button>
                                                <button onClick={(e) => { e.stopPropagation(); handleRemoveItem(index); }} className="text-slate-400 hover:text-red-500 transition-colors p-2 rounded-lg hover:bg-red-50 dark:hover:bg-red-900/20" title="Remove Item">
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                                                </button>
                                            </td>
                                        </tr>
                                    )})}
                                </tbody>
                            </table>
                         </div>

                         {/* Item Summary Footer within card */}
                         <div className="mt-4 pt-4 border-t border-slate-100 dark:border-slate-800 flex justify-between items-center">
                            <Button variant="secondary" onClick={handleAddItem} className="border-dashed border-2 border-slate-300 dark:border-slate-700 hover:border-accent dark:hover:border-accent flex items-center gap-2 px-4">
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 5a1 1 0 011 1v3h3a1 1 0 110 2h-3v3a1 1 0 11-2 0v-3H6a1 1 0 110-2h3V6a1 1 0 011-1z" clipRule="evenodd" /></svg>
                                Add New Item
                            </Button>
                            <div className="text-right text-xs text-slate-500">
                                Total Items: <span className="font-bold text-slate-900 dark:text-white">{draftInvoice.items.length}</span>
                            </div>
                         </div>
                     </SectionCard>
                 </div>

                 {/* Right Column */}
                 <div className="space-y-6">

                     {/* Summary */}
                     <SectionCard title="Payment Summary">
                         <div className="space-y-3 text-sm">
                             <div className="flex justify-between text-slate-600 dark:text-slate-400">
                                 <span>Subtotal</span>
                                 <span>{currency}{totals.subTotal.toFixed(2)}</span>
                             </div>
                             <div className="flex justify-between text-slate-600 dark:text-slate-400">
                                 <span>CGST</span>
                                 <span>{currency}{totals.cgst.toFixed(2)}</span>
                             </div>
                             <div className="flex justify-between text-slate-600 dark:text-slate-400">
                                 <span>SGST</span>
                                 <span>{currency}{totals.sgst.toFixed(2)}</span>
                             </div>
                             <div className="flex justify-between text-slate-600 dark:text-slate-400">
                                 <span>IGST</span>
                                 <span>{currency}{totals.igst.toFixed(2)}</span>
                             </div>
                             <div className="border-t border-slate-200 dark:border-slate-700 pt-3 flex justify-between font-bold text-lg text-slate-900 dark:text-white">
                                 <span>Total</span>
                                 <span>{currency}{totals.grandTotal.toFixed(2)}</span>
                             </div>
                         </div>
                     </SectionCard>

                     {/* Bank Account */}
                     <SectionCard title="Bank Details">
                         <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Select Bank Account</label>
                         <select 
                            className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 text-slate-900 dark:text-white rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-accent focus:outline-none"
                            value={draftInvoice.selectedBankAccountId || ''}
                            onChange={(e) => setDraftInvoice({...draftInvoice, selectedBankAccountId: e.target.value})}
                         >
                             <option value="">-- No Bank Account --</option>
                             {company.bankAccounts.map(b => <option key={b.id} value={b.id}>{b.bankName} - {b.accountNumber.slice(-4)}</option>)}
                         </select>
                         <div className="mt-2 text-right">
                            <button className="text-xs text-accent font-semibold hover:underline" onClick={() => setIsAddBankModalOpen(true)}>+ Add New Bank</button>
                         </div>
                     </SectionCard>

                     {/* Shipping & Transport */}
                     <SectionCard title="Shipping & Transport">
                         <div className="space-y-4">
                             <div className="flex items-center gap-2 mb-2">
                                <input type="checkbox" id="sameAsBilling" checked={draftInvoice.isShippingSameAsBilling} onChange={handleSameAsBillingToggle} className="rounded border-slate-300 text-accent focus:ring-accent" />
                                <label htmlFor="sameAsBilling" className="text-sm text-slate-700 dark:text-slate-300">Same as Billing Address</label>
                             </div>

                             {!draftInvoice.isShippingSameAsBilling && (
                                 <div className="space-y-3 bg-slate-50 dark:bg-slate-800 p-3 rounded-lg border border-slate-200 dark:border-slate-700">
                                     <Input label="Shipping Name" name="name" value={draftInvoice.shippingDetails.name} onChange={handleShippingChange} className="!py-1.5 !text-xs" />
                                     <textarea name="address" rows={2} value={draftInvoice.shippingDetails.address} onChange={(e) => handleShippingChange(e as any)} placeholder="Address" className="w-full bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded px-2 py-1 text-xs" />
                                     <div className="grid grid-cols-2 gap-2">
                                         <div className="relative">
                                             <Input label="Zip" name="zip" value={draftInvoice.shippingDetails.zip} onChange={handleShippingChange} className="!py-1.5 !text-xs" error={pincodeError || undefined}/>
                                             {isPincodeLoading && <div className="absolute top-7 right-2 h-3 w-3 border border-slate-400 border-t-transparent rounded-full animate-spin"></div>}
                                         </div>
                                         <Input label="City" name="city" value={draftInvoice.shippingDetails.city} onChange={handleShippingChange} className="!py-1.5 !text-xs" />
                                     </div>
                                      <select name="state" value={draftInvoice.shippingDetails.state} onChange={handleShippingChange} className="w-full bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded px-2 py-1 text-xs">
                                        <option value="">Select State</option>
                                        {INDIAN_STATES.map(s => <option key={s} value={s}>{s}</option>)}
                                     </select>
                                     <Input label="GSTIN" name="gstin" value={draftInvoice.shippingDetails.gstin} onChange={handleShippingChange} className="!py-1.5 !text-xs" />
                                 </div>
                             )}

                             <div className="pt-2 border-t border-slate-100 dark:border-slate-700">
                                 <label className="block text-xs font-semibold text-slate-500 uppercase mb-2">Logistics</label>
                                 <select value={draftInvoice.transporterId} onChange={(e) => setDraftInvoice({...draftInvoice, transporterId: e.target.value})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 rounded-lg px-3 py-2 text-sm mb-3">
                                     <option value="">-- Select Transporter --</option>
                                     <option value="self">Self Transport</option>
                                     {company.transporters.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                                 </select>
                                 <Input label="Vehicle Number" value={draftInvoice.vehicleNumber} onChange={handleVehicleNumberChange} error={vehicleNumberError || undefined} placeholder="MH 01 AB 1234" />
                                 <Input label="E-Way Bill No." value={draftInvoice.ewayBillNumber} onChange={e => setDraftInvoice({...draftInvoice, ewayBillNumber: e.target.value})} className="mt-3" />
                             </div>
                         </div>
                     </SectionCard>

                     <SectionCard title="Notes">
                         <textarea 
                            rows={3} 
                            className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 rounded-lg p-3 text-sm focus:ring-accent focus:border-accent"
                            placeholder="Add terms, conditions, or payment instructions..."
                            value={draftInvoice.notes}
                            onChange={e => setDraftInvoice({...draftInvoice, notes: e.target.value})}
                         />
                     </SectionCard>

                 </div>
             </div>

             {/* Add Bank Modal */}
             <Modal isOpen={isAddBankModalOpen} onClose={() => setIsAddBankModalOpen(false)} title="Add Bank Account">
                 <div className="p-6 space-y-4">
                     <Input label="Bank Name" value={newBank.bankName} onChange={e => setNewBank({...newBank, bankName: e.target.value})} error={newBankErrors.bankName} />
                     <Input label="Account Number" value={newBank.accountNumber} onChange={e => setNewBank({...newBank, accountNumber: e.target.value})} error={newBankErrors.accountNumber} />
                     <Input label="IFSC Code" value={newBank.ifsc} onChange={e => setNewBank({...newBank, ifsc: e.target.value})} error={newBankErrors.ifsc} />
                 </div>
                 <div className="p-6 pt-0 flex justify-end gap-3">
                     <Button variant="secondary" onClick={() => setIsAddBankModalOpen(false)}>Cancel</Button>
                     <Button onClick={() => {
                         if(!newBank.bankName) { setNewBankErrors({...newBankErrors, bankName: 'Required'}); return; }
                         if(!newBank.accountNumber) { setNewBankErrors({...newBankErrors, accountNumber: 'Required'}); return; }
                         if(!newBank.ifsc) { setNewBankErrors({...newBankErrors, ifsc: 'Required'}); return; }

                         const newAccount: BankAccount = { ...newBank, id: Date.now().toString(), isDefault: company.bankAccounts.length === 0 } as BankAccount;
                         onUpdateCompany({ ...company, bankAccounts: [...company.bankAccounts, newAccount] });
                         setDraftInvoice({...draftInvoice, selectedBankAccountId: newAccount.id});
                         setIsAddBankModalOpen(false);
                         setNewBank({ bankName: '', accountNumber: '', ifsc: '' });
                         setNewBankErrors({});
                     }}>Save Account</Button>
                 </div>
             </Modal>

             {/* Create Item Modal */}
             <Modal isOpen={isCreateItemModalOpen} onClose={() => setIsCreateItemModalOpen(false)} title="Create New Item">
                 <div className="p-6 space-y-4">
                     <div className="p-3 bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-300 text-sm rounded-lg">
                         Creating item: <strong>{newItemData.name}</strong>. This item will be added to your inventory.
                     </div>
                     <Input label="Name" value={newItemData.name || ''} onChange={e => setNewItemData({...newItemData, name: e.target.value})} required />
                     <div className="grid grid-cols-2 gap-4">
                         <Input label="Price (₹)" type="number" min="0" value={newItemData.price} onChange={e => setNewItemData({...newItemData, price: parseFloat(e.target.value) || 0})} required />
                         <Input label="GST Rate (%)" type="number" min="0" value={newItemData.gstRate} onChange={e => setNewItemData({...newItemData, gstRate: parseFloat(e.target.value) || 0})} required />
                     </div>
                     <div className="grid grid-cols-2 gap-4">
                         <div className="flex flex-col">
                             <label className="text-sm font-semibold mb-1.5 text-slate-700 dark:text-slate-300">Unit</label>
                             <select 
                                value={newItemData.unit} 
                                onChange={e => setNewItemData({...newItemData, unit: e.target.value})} 
                                className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 text-slate-900 dark:text-white rounded-lg px-4 py-3 focus:ring-2 focus:ring-accent focus:outline-none"
                             >
                                {ITEM_UNITS.map(u => <option key={u} value={u}>{u}</option>)}
                             </select>
                         </div>
                         <Input label="HSN Code" value={newItemData.hsn || ''} onChange={e => setNewItemData({...newItemData, hsn: e.target.value})} />
                     </div>
                     <Input label="Initial Stock" type="number" min="0" value={newItemData.quantityInStock} onChange={e => setNewItemData({...newItemData, quantityInStock: parseFloat(e.target.value) || 0})} />
                 </div>
                 <div className="p-6 pt-0 flex justify-end gap-3">
                     <Button variant="secondary" onClick={() => setIsCreateItemModalOpen(false)}>Cancel</Button>
                     <Button onClick={handleCreateNewItem}>Create Item</Button>
                 </div>
             </Modal>

             {/* Item Details Modal */}
             <Modal isOpen={viewItemModalOpen} onClose={() => setViewItemModalOpen(false)} title="Item Details">
                 {viewingItem && (
                     <div className="p-6">
                         <div className="flex justify-between items-start mb-6">
                             <div>
                                 <h2 className="text-2xl font-bold text-slate-900 dark:text-white">{viewingItem.name}</h2>
                                 {viewingItem.hsn && <p className="text-slate-500 dark:text-slate-400 text-sm">HSN: {viewingItem.hsn}</p>}
                             </div>
                             <div className={`px-3 py-1 rounded-full text-xs font-bold ${viewingItem.quantityInStock > 5 ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'}`}>
                                 {viewingItem.quantityInStock > 0 ? 'In Stock' : 'Out of Stock'}
                             </div>
                         </div>

                         <div className="grid grid-cols-2 gap-4 mb-6">
                             <div className="p-4 bg-slate-50 dark:bg-slate-800 rounded-lg">
                                 <p className="text-xs text-slate-500 uppercase font-semibold">Selling Price</p>
                                 <p className="text-xl font-bold text-slate-900 dark:text-white">{currency}{viewingItem.price.toFixed(2)}</p>
                             </div>
                             <div className="p-4 bg-slate-50 dark:bg-slate-800 rounded-lg">
                                 <p className="text-xs text-slate-500 uppercase font-semibold">Available Stock</p>
                                 <p className="text-xl font-bold text-slate-900 dark:text-white">{viewingItem.quantityInStock} <span className="text-sm font-normal text-slate-500">{viewingItem.unit}</span></p>
                             </div>
                             <div className="p-4 bg-slate-50 dark:bg-slate-800 rounded-lg">
                                 <p className="text-xs text-slate-500 uppercase font-semibold">GST Rate</p>
                                 <p className="text-xl font-bold text-slate-900 dark:text-white">{viewingItem.gstRate}%</p>
                             </div>
                             <div className="p-4 bg-slate-50 dark:bg-slate-800 rounded-lg">
                                 <p className="text-xs text-slate-500 uppercase font-semibold">Unit Type</p>
                                 <p className="text-xl font-bold text-slate-900 dark:text-white capitalize">{viewingItem.unit}</p>
                             </div>
                         </div>

                         <div className="flex justify-end">
                             <Button variant="secondary" onClick={() => setViewItemModalOpen(false)}>Close</Button>
                         </div>
                     </div>
                 )}
             </Modal>
        </div>
    );
};

export default NewInvoice;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import type { Invoice, Client, Item, InvoiceItem, Company, Transporter, BankAccount, DraftInvoice } from '../types';
import Input from './common/Input';
import Button from './common/Button';
import Modal from './common/Modal';
import { INDIAN_STATES } from '../constants';
import { fetchLocationByPincode, validateGstin, validateIfsc } from '../utils/validation';

interface NewInvoiceProps {
  company: Company;
  saveInvoice: (invoice: Omit<Invoice, 'id' | 'status'> | Invoice) => void;
  setActiveView: (view: string) => void;
  invoiceToEdit?: Invoice | null;
  clearEditingInvoice: () => void;
  onUpdateCompany: (updatedCompany: Company) => void;

  draftInvoice: DraftInvoice;
  setDraftInvoice: (invoice: DraftInvoice) => void;
}

const ITEM_UNITS = ['pcs', 'kgs', 'ltr', 'nos', 'box', 'pkt', 'gram', 'set', 'pair', 'm', 'cm', 'ft', 'sqft'];

const SectionCard: React.FC<{ title: string; children: React.ReactNode; className?: string }> = ({ title, children, className = "" }) => (
    <div className={`bg-white dark:bg-primary-dark rounded-xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden ${className}`}>
        <div className="px-6 py-4 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/50">
            <h3 className="text-sm font-bold uppercase tracking-wide text-slate-700 dark:text-slate-200">{title}</h3>
        </div>
        <div className="p-6">
            {children}
        </div>
    </div>
);

const NewInvoice: React.FC<NewInvoiceProps> = ({ 
    company, saveInvoice, setActiveView, 
    invoiceToEdit, clearEditingInvoice, onUpdateCompany,
    draftInvoice, setDraftInvoice
}) => {
    const isEditing = !!invoiceToEdit;
    const currency = '₹';

    // Derived state for validations
    const [vehicleNumberError, setVehicleNumberError] = useState<string | null>(null);
    const [formError, setFormError] = useState<string | null>(null);
    const [isPincodeLoading, setIsPincodeLoading] = useState(false);
    const [pincodeError, setPincodeError] = useState<string|null>(null);
    const [itemErrors, setItemErrors] = useState<Record<string, string>>({});

    // Bank Account Modal State
    const [isAddBankModalOpen, setIsAddBankModalOpen] = useState(false);
    const [newBank, setNewBank] = useState<Omit<BankAccount, 'id' | 'isDefault'>>({ bankName: '', accountNumber: '', ifsc: '' });
    const [newBankErrors, setNewBankErrors] = useState<Partial<Record<keyof typeof newBank, string>>>({});

    // Item Creation & Selection State
    const [activeDropdownIndex, setActiveDropdownIndex] = useState<number | null>(null);
    const dropdownRef = useRef<HTMLDivElement>(null);
    const [isCreateItemModalOpen, setIsCreateItemModalOpen] = useState(false);
    const [creatingItemRowIndex, setCreatingItemRowIndex] = useState<number | null>(null);
    const [newItemData, setNewItemData] = useState<Partial<Item>>({ name: '', price: 0, gstRate: 18, unit: 'pcs', quantityInStock: 0, hsn: '' });

    // Item Detail View State
    const [viewItemModalOpen, setViewItemModalOpen] = useState(false);
    const [viewingItem, setViewingItem] = useState<Item | null>(null);

    const selectedClient = useMemo(() => company.clients.find(c => c.id === draftInvoice.clientId), [draftInvoice.clientId, company.clients]);

    // Close dropdown when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setActiveDropdownIndex(null);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const handleClientChange = (clientId: string) => {
        const client = company.clients.find(c => c.id === clientId);
        if (client) {
            setDraftInvoice({
                ...draftInvoice,
                clientId: clientId,
                isShippingSameAsBilling: true,
                shippingDetails: {
                    name: client.name,
                    address: client.address,
                    city: client.city,
                    state: client.state,
                    zip: client.zip,
                    gstin: client.gstin
                }
            });
        } else {
            setDraftInvoice({ ...draftInvoice, clientId: clientId });
        }
    };

    const handleSameAsBillingToggle = (e: React.ChangeEvent<HTMLInputElement>) => {
        const isChecked = e.target.checked;
        const updates: Partial<DraftInvoice> = { isShippingSameAsBilling: isChecked };

        if (!isChecked && selectedClient) {
            updates.shippingDetails = {
                name: selectedClient.name,
                address: selectedClient.shippingAddress || selectedClient.address,
                city: selectedClient.shippingCity || selectedClient.city,
                state: selectedClient.shippingState || selectedClient.state,
                zip: selectedClient.shippingZip || selectedClient.zip,
                gstin: selectedClient.gstin,
            };
        }
        setDraftInvoice({ ...draftInvoice, ...updates });
    };

    // Auto-update shipping details
    useEffect(() => {
        if(draftInvoice.isShippingSameAsBilling) return;
        let isMounted = true;
        const pincode = draftInvoice.shippingDetails.zip;
        if (pincode && pincode.length === 6) {
          const timer = setTimeout(async () => {
            if (!isMounted) return;
            setIsPincodeLoading(true);
            setPincodeError(null);
            const location = await fetchLocationByPincode(pincode);
            if (isMounted) {
                if (location) {
                    setDraftInvoice(prev => ({
                        ...prev,
                        shippingDetails: {
                            ...prev.shippingDetails,
                            city: location.city,
                            state: location.state
                        }
                    }));
                } else if (location === null) {
                    setPincodeError('Invalid Pincode');
                } else {
                    setPincodeError('Lookup failed. Enter manually.');
                }
                setIsPincodeLoading(false);
            }
          }, 500);
          return () => { isMounted = false; clearTimeout(timer); };
        } else {
            setPincodeError(null);
        }
    }, [draftInvoice.shippingDetails.zip, draftInvoice.isShippingSameAsBilling]);

    const handleVehicleNumberChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setVehicleNumberError(null);
        const value = e.target.value;
        const parts = value.split(/ (.*)/s);
        const rtoPart = (parts[0] || '').toUpperCase();
        let finalValue = rtoPart;

        if (parts.length > 1) {
            let numberPart = parts[1] || '';
            numberPart = numberPart.replace(/[^0-9]/g, '');
            if (numberPart.length > 4) {
                numberPart = numberPart.slice(0, 4);
                setVehicleNumberError('Numeric part must be 4 digits.');
                setTimeout(() => setVehicleNumberError(null), 3000);
            }
            finalValue = `${rtoPart} ${numberPart}`;
        }
        setDraftInvoice({ ...draftInvoice, vehicleNumber: finalValue });
    };

    const handleShippingChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        setDraftInvoice({
            ...draftInvoice,
            shippingDetails: {
                ...draftInvoice.shippingDetails,
                [e.target.name]: e.target.value
            }
        });
    };

    const transporterDetails = useMemo(() => {
        if (draftInvoice.transporterId === 'self') {
            return { name: 'Self', gstin: company.details.gstin };
        }
        return company.transporters.find(t => t.id === draftInvoice.transporterId);
    }, [draftInvoice.transporterId, company.transporters, company.details.gstin]);

    const handleAddItem = () => {
        setDraftInvoice({
            ...draftInvoice,
            items: [...draftInvoice.items, { id: '', name: '', hsn: '', price: 0, gstRate: 18, quantity: 1, unit: 'pcs', quantityInStock: 0 }]
        });
    };

    const handleRemoveItem = (index: number) => {
        setDraftInvoice({
            ...draftInvoice,
            items: draftInvoice.items.filter((_, i) => i !== index)
        });

        // Clean up errors
        setItemErrors(prev => {
            const newErrs: Record<string, string> = {};
            Object.keys(prev).forEach(key => {
                const parts = key.split('-');
                const idx = parseInt(parts[0]);
                const field = parts.slice(1).join('-');
                if (idx < index) newErrs[key] = prev[key];
                else if (idx > index) newErrs[`${idx - 1}-${field}`] = prev[key];
            });
            return newErrs;
        });
    };

    const handleItemChange = (index: number, field: keyof InvoiceItem, value: any) => {
        const updatedItems = [...draftInvoice.items];
        const currentItem = { ...updatedItems[index] };
        let newItemErrors = { ...itemErrors };

        if (field === 'id' && value) {
            const selectedItem = company.items.find(i => i.id === value);
            if (selectedItem) updatedItems[index] = { ...currentItem, ...selectedItem, quantity: 1 };
            // Clear errors for this row if selecting a valid item
            delete newItemErrors[`${index}-name`];
            delete newItemErrors[`${index}-price`];
            delete newItemErrors[`${index}-quantity`];
        } else {
            const newValue = (field === 'quantity' || field === 'price' || field === 'gstRate') ? parseFloat(value) || 0 : value;
            updatedItems[index] = { ...currentItem, [field]: newValue };

            // Real-time Validation Logic
            if (field === 'quantity') {
                if (newValue <= 0) newItemErrors[`${index}-quantity`] = 'Qty > 0';
                else delete newItemErrors[`${index}-quantity`];
            }
            if (field === 'price') {
                if (newValue <= 0) newItemErrors[`${index}-price`] = 'Price > 0';
                else delete newItemErrors[`${index}-price`];
            }
            if (field === 'name' && !value) {
                newItemErrors[`${index}-name`] = 'Required';
            } else if (field === 'name') {
                delete newItemErrors[`${index}-name`];
            }
        }

        setItemErrors(newItemErrors);
        setDraftInvoice({ ...draftInvoice, items: updatedItems });
    };

    // Item creation flow
    const openCreateItemModal = (name: string, rowIndex: number) => {
        setNewItemData({ ...newItemData, name, price: 0, gstRate: 18, quantityInStock: 0, hsn: '' });
        setCreatingItemRowIndex(rowIndex);
        setIsCreateItemModalOpen(true);
        setActiveDropdownIndex(null);
    };

    const handleCreateNewItem = () => {
        if (!newItemData.name || (newItemData.price || 0) < 0) return;

        const newItem: Item = {
            id: `item_${Date.now()}`,
            name: newItemData.name!,
            price: Number(newItemData.price) || 0,
            gstRate: Number(newItemData.gstRate) || 0,
            unit: newItemData.unit || 'pcs',
            hsn: newItemData.hsn || '',
            quantityInStock: Number(newItemData.quantityInStock) || 0
        };

        // Add to company items
        onUpdateCompany({
            ...company,
            items: [...company.items, newItem]
        });

        // Update the active row in draft invoice
        if (creatingItemRowIndex !== null) {
            handleItemChange(creatingItemRowIndex, 'id', newItem.id);
        }

        setIsCreateItemModalOpen(false);
        setCreatingItemRowIndex(null);
    };

    // Calculations
    const calculateTotals = () => {
        let subTotal = 0;
        let cgst = 0;
        let sgst = 0;
        let igst = 0;

        const posState = draftInvoice.shippingDetails.state || (selectedClient ? selectedClient.state : '');
        const isIntraState = !posState || posState.toLowerCase() === company.details.state.toLowerCase();

        draftInvoice.items.forEach(item => {
            const taxable = item.price * item.quantity;
            subTotal += taxable;
            const taxAmount = (taxable * item.gstRate) / 100;

            if (isIntraState) {
                cgst += taxAmount / 2;
                sgst += taxAmount / 2;
            } else {
                igst += taxAmount;
            }
        });

        return { subTotal, cgst, sgst, igst, grandTotal: subTotal + cgst + sgst + igst };
    };

    const totals = calculateTotals();

    const handleSave = () => {
        // Validation logic
        const newFormErrors: string[] = [];
        if (!draftInvoice.clientId) newFormErrors.push("Please select a client.");
        if (draftInvoice.items.length === 0) newFormErrors.push("Please add at least one item.");

        // Item validations check
        const newItemErrors: Record<string, string> = {};
        draftInvoice.items.forEach((item, idx) => {
             if (!item.name) newItemErrors[`${idx}-name`] = "Required";
             if (item.price <= 0) newItemErrors[`${idx}-price`] = "Invalid";
             if (item.quantity <= 0) newItemErrors[`${idx}-quantity`] = "Invalid";
        });

        if (newFormErrors.length > 0) {
            setFormError(newFormErrors.join(" "));
            return;
        }

        if (Object.keys(newItemErrors).length > 0 || Object.keys(itemErrors).length > 0) {
            setItemErrors({ ...itemErrors, ...newItemErrors });
            setFormError("Please fix invalid items.");
            return;
        }

        const selectedClient = company.clients.find(c => c.id === draftInvoice.clientId);
        if(!selectedClient) return;

        // Construct Invoice Object
        const finalInvoice: Omit<Invoice, 'id' | 'status'> | Invoice = {
            ...(isEditing && invoiceToEdit ? { id: invoiceToEdit.id, status: invoiceToEdit.status } : {}),
            invoiceNumber: draftInvoice.invoiceNumber,
            client: selectedClient,
            items: draftInvoice.items,
            issueDate: draftInvoice.issueDate,
            dueDate: draftInvoice.dueDate,
            notes: draftInvoice.notes,
            selectedBankAccountId: draftInvoice.selectedBankAccountId,

            // Snapshot details
            shippingName: draftInvoice.shippingDetails.name,
            shippingAddress: draftInvoice.shippingDetails.address,
            shippingCity: draftInvoice.shippingDetails.city,
            shippingState: draftInvoice.shippingDetails.state,
            shippingZip: draftInvoice.shippingDetails.zip,
            shippingGstin: draftInvoice.shippingDetails.gstin,

            transporterName: transporterDetails?.name,
            transporterGstin: transporterDetails?.gstin,
            vehicleNumber: draftInvoice.vehicleNumber,
            ewayBillNumber: draftInvoice.ewayBillNumber,

            ...totals
        };

        saveInvoice(finalInvoice);
        setActiveView('Invoices');
        clearEditingInvoice(); 
    };

    // Load invoice to edit
    useEffect(() => {
        if (invoiceToEdit) {
            setDraftInvoice({
                invoiceNumber: invoiceToEdit.invoiceNumber,
                clientId: invoiceToEdit.client.id,
                items: invoiceToEdit.items,
                issueDate: invoiceToEdit.issueDate,
                dueDate: invoiceToEdit.dueDate,
                notes: invoiceToEdit.notes,
                selectedBankAccountId: invoiceToEdit.selectedBankAccountId,
                shippingDetails: {
                    name: invoiceToEdit.shippingName || '',
                    address: invoiceToEdit.shippingAddress || '',
                    city: invoiceToEdit.shippingCity || '',
                    state: invoiceToEdit.shippingState || '',
                    zip: invoiceToEdit.shippingZip || '',
                    gstin: invoiceToEdit.shippingGstin || ''
                },
                isShippingSameAsBilling: false, 
                transporterId: '', 
                vehicleNumber: invoiceToEdit.vehicleNumber || '',
                ewayBillNumber: invoiceToEdit.ewayBillNumber || ''
            });

             const tId = company.transporters.find(t => t.name === invoiceToEdit.transporterName)?.id;
             if(tId) setDraftInvoice(prev => ({...prev, transporterId: tId}));
             else if(invoiceToEdit.transporterName === 'Self') setDraftInvoice(prev => ({...prev, transporterId: 'self'}));
        }
    }, [invoiceToEdit]);

    // View Item Modal Handler
    const handleViewItemDetails = (itemRow: InvoiceItem) => {
        // Find the full item object from inventory to get latest stock data, fallback to row data
        const inventoryItem = company.items.find(i => i.id === itemRow.id) || itemRow;
        setViewingItem(inventoryItem);
        setViewItemModalOpen(true);
    };

    return (
        <div>
             {/* Header */}
             <div className="flex justify-between items-center mb-6">
                <div className="flex items-center gap-4">
                     <button onClick={() => { setActiveView('Invoices'); clearEditingInvoice(); }} className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors">
                        <svg className="w-6 h-6 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                     </button>
                     <h1 className="text-3xl font-bold text-slate-900 dark:text-light-text">{isEditing ? 'Edit Invoice' : 'New Invoice'}</h1>
                </div>
                <div className="flex gap-3">
                    <Button variant="secondary" onClick={() => { setActiveView('Invoices'); clearEditingInvoice(); }}>Cancel</Button>
                    <Button onClick={handleSave}>Save Invoice</Button>
                </div>
             </div>

             {formError && <div className="mb-6 p-4 bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300 rounded-lg border border-red-200 dark:border-red-800 font-medium animate-fade-in flex items-center gap-2">
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                 {formError}
             </div>}

             <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                 {/* Left Column */}
                 <div className="lg:col-span-2 space-y-6">

                     {/* Client & Invoice Info */}
                     <SectionCard title="Client & Invoice Details">
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                             <div>
                                 <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1.5">Select Client</label>
                                 <select 
                                    className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 text-slate-900 dark:text-white rounded-lg px-4 py-3 focus:ring-2 focus:ring-accent focus:outline-none transition-shadow"
                                    value={draftInvoice.clientId}
                                    onChange={(e) => handleClientChange(e.target.value)}
                                 >
                                     <option value="">-- Choose Client --</option>
                                     {company.clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                                 </select>
                                 <p className="text-xs text-slate-500 mt-1">Or add a new client in Clients section.</p>
                             </div>
                             <Input label="Invoice Number" value={draftInvoice.invoiceNumber} onChange={e => setDraftInvoice({...draftInvoice, invoiceNumber: e.target.value})} />
                             <Input label="Issue Date" type="date" value={draftInvoice.issueDate} onChange={e => setDraftInvoice({...draftInvoice, issueDate: e.target.value})} />
                             <Input label="Due Date" type="date" value={draftInvoice.dueDate} onChange={e => setDraftInvoice({...draftInvoice, dueDate: e.target.value})} />
                         </div>
                     </SectionCard>

                     {/* Items Table */}
                     <SectionCard title="Items" className="overflow-visible">
                         <div className="overflow-visible"> 
                            <table className="w-full text-sm text-left text-slate-600 dark:text-slate-400">
                                <thead className="text-xs text-slate-700 dark:text-slate-300 uppercase bg-slate-100 dark:bg-slate-800">
                                    <tr>
                                        <th className="px-4 py-3 rounded-l-lg w-1/3">Item Details</th>
                                        <th className="px-2 py-3 w-20">Qty</th>
                                        <th className="px-2 py-3 w-24">Unit</th>
                                        <th className="px-2 py-3 w-28">Price</th>
                                        <th className="px-2 py-3 w-20">GST %</th>
                                        <th className="px-4 py-3 w-28 text-right">Amount</th>
                                        <th className="px-2 py-3 w-16 text-center rounded-r-lg">Actions</th>
                                    </tr>
                                </thead>
                                <tbody className="space-y-1">
                                    {draftInvoice.items.map((item, index) => {
                                        const qtyError = itemErrors[`${index}-quantity`];
                                        const priceError = itemErrors[`${index}-price`];
                                        const filteredItems = company.items.filter(i => i.name.toLowerCase().includes(item.name.toLowerCase()));

                                        return (
                                        <tr 
                                            key={index} 
                                            className="bg-white dark:bg-primary-dark group relative"
                                            onClick={(e) => {
                                                // If clicking the row background (not inputs), select or view details could trigger here if desired
                                            }}
                                        >
                                            <td className="px-2 py-2 align-top relative">
                                                <div className="relative">
                                                    <input 
                                                        value={item.name}
                                                        onChange={e => {
                                                            handleItemChange(index, 'name', e.target.value);
                                                            setActiveDropdownIndex(index);
                                                        }}
                                                        onFocus={() => setActiveDropdownIndex(index)}
                                                        onClick={(e) => e.stopPropagation()}
                                                        className={`w-full bg-slate-50 dark:bg-slate-900 border ${itemErrors[`${index}-name`] ? 'border-red-500 focus:ring-red-500' : 'border-slate-300 dark:border-slate-700 hover:border-slate-400 focus:border-accent'} rounded-lg px-3 py-2 focus:ring-2 focus:ring-accent/20 focus:outline-none transition-all font-medium`}
                                                        placeholder="Search or Create Item"
                                                    />

                                                    {/* Custom Dropdown */}
                                                    {activeDropdownIndex === index && (
                                                        <div ref={dropdownRef} className="absolute z-50 left-0 top-full mt-1 w-full bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg shadow-xl max-h-60 overflow-y-auto">
                                                            {filteredItems.length > 0 ? (
                                                                filteredItems.map(suggestion => (
                                                                    <div 
                                                                        key={suggestion.id}
                                                                        className="px-4 py-2 hover:bg-slate-50 dark:hover:bg-slate-700 cursor-pointer text-sm text-slate-700 dark:text-slate-200"
                                                                        onClick={(e) => {
                                                                            e.stopPropagation();
                                                                            handleItemChange(index, 'id', suggestion.id);
                                                                            setActiveDropdownIndex(null);
                                                                        }}
                                                                    >
                                                                        <div className="font-medium">{suggestion.name}</div>
                                                                        <div className="text-xs text-slate-500 flex justify-between">
                                                                            <span>Stock: {suggestion.quantityInStock}</span>
                                                                            <span>{currency}{suggestion.price}</span>
                                                                        </div>
                                                                    </div>
                                                                ))
                                                            ) : (
                                                                <div className="px-4 py-2 text-sm text-slate-500 italic">No existing items found</div>
                                                            )}
                                                            {/* Create New Option */}
                                                            {item.name && !company.items.some(i => i.name.toLowerCase() === item.name.toLowerCase()) && (
                                                                <div 
                                                                    className="px-4 py-2 bg-accent/5 hover:bg-accent/10 cursor-pointer border-t border-slate-100 dark:border-slate-700 text-accent dark:text-indigo-400 font-semibold text-sm flex items-center gap-2"
                                                                    onClick={(e) => {
                                                                        e.stopPropagation();
                                                                        openCreateItemModal(item.name, index);
                                                                    }}
                                                                >
                                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 3a1 1 0 011 1v5h5a1 1 0 110 2h-5v5a1 1 0 11-2 0v-5H4a1 1 0 110-2h5V4a1 1 0 011-1z" clipRule="evenodd" /></svg>
                                                                    Create "{item.name}"
                                                                </div>
                                                            )}
                                                        </div>
                                                    )}
                                                </div>
                                            </td>
                                            <td className="px-2 py-2 align-top relative">
                                                <input onClick={(e) => e.stopPropagation()} type="number" min="0" value={item.quantity} onChange={e => handleItemChange(index, 'quantity', e.target.value)} className={`w-full bg-slate-50 dark:bg-slate-900 border ${qtyError ? 'border-red-500 focus:ring-red-500' : 'border-slate-300 dark:border-slate-700 hover:border-slate-400 focus:border-accent'} rounded-lg px-2 py-2 text-center focus:ring-2 focus:ring-accent/20 focus:outline-none transition-all`} />
                                                {qtyError && <div className="absolute top-full left-0 w-full text-[10px] text-red-500 text-center font-bold mt-0.5">{qtyError}</div>}
                                            </td>
                                             <td className="px-2 py-2 align-top">
                                                <select onClick={(e) => e.stopPropagation()} value={item.unit} onChange={e => handleItemChange(index, 'unit', e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 rounded-lg px-2 py-2 text-xs focus:ring-2 focus:ring-accent/20 focus:border-accent outline-none">
                                                    {ITEM_UNITS.map(u => <option key={u} value={u}>{u}</option>)}
                                                </select>
                                            </td>
                                            <td className="px-2 py-2 align-top relative">
                                                <input onClick={(e) => e.stopPropagation()} type="number" min="0" value={item.price} onChange={e => handleItemChange(index, 'price', e.target.value)} className={`w-full bg-slate-50 dark:bg-slate-900 border ${priceError ? 'border-red-500 focus:ring-red-500' : 'border-slate-300 dark:border-slate-700 hover:border-slate-400 focus:border-accent'} rounded-lg px-2 py-2 text-right focus:ring-2 focus:ring-accent/20 focus:outline-none transition-all`} />
                                                {priceError && <div className="absolute top-full right-0 text-[10px] text-red-500 font-bold mt-0.5">{priceError}</div>}
                                            </td>
                                            <td className="px-2 py-2 align-top">
                                                <input onClick={(e) => e.stopPropagation()} type="number" min="0" value={item.gstRate} onChange={e => handleItemChange(index, 'gstRate', e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 rounded-lg px-2 py-2 text-center focus:ring-2 focus:ring-accent/20 focus:border-accent outline-none" />
                                            </td>
                                            <td className="px-4 py-3 align-top text-right font-bold text-slate-900 dark:text-white">
                                                {currency}{((item.price * item.quantity)).toFixed(2)}
                                            </td>
                                            <td className="px-2 py-2 align-top text-center flex justify-center gap-1">
                                                <button onClick={(e) => { e.stopPropagation(); handleViewItemDetails(item); }} className="text-slate-400 hover:text-blue-500 transition-colors p-2 rounded-lg hover:bg-blue-50 dark:hover:bg-blue-900/20" title="Item Details">
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                                </button>
                                                <button onClick={(e) => { e.stopPropagation(); handleRemoveItem(index); }} className="text-slate-400 hover:text-red-500 transition-colors p-2 rounded-lg hover:bg-red-50 dark:hover:bg-red-900/20" title="Remove Item">
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                                                </button>
                                            </td>
                                        </tr>
                                    )})}
                                </tbody>
                            </table>
                         </div>

                         {/* Item Summary Footer within card */}
                         <div className="mt-4 pt-4 border-t border-slate-100 dark:border-slate-800 flex justify-between items-center">
                            <Button variant="secondary" onClick={handleAddItem} className="border-dashed border-2 border-slate-300 dark:border-slate-700 hover:border-accent dark:hover:border-accent flex items-center gap-2 px-4">
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 5a1 1 0 011 1v3h3a1 1 0 110 2h-3v3a1 1 0 11-2 0v-3H6a1 1 0 110-2h3V6a1 1 0 011-1z" clipRule="evenodd" /></svg>
                                Add New Item
                            </Button>
                            <div className="text-right text-xs text-slate-500">
                                Total Items: <span className="font-bold text-slate-900 dark:text-white">{draftInvoice.items.length}</span>
                            </div>
                         </div>
                     </SectionCard>
                 </div>

                 {/* Right Column */}
                 <div className="space-y-6">

                     {/* Summary */}
                     <SectionCard title="Payment Summary">
                         <div className="space-y-3 text-sm">
                             <div className="flex justify-between text-slate-600 dark:text-slate-400">
                                 <span>Subtotal</span>
                                 <span>{currency}{totals.subTotal.toFixed(2)}</span>
                             </div>
                             <div className="flex justify-between text-slate-600 dark:text-slate-400">
                                 <span>CGST</span>
                                 <span>{currency}{totals.cgst.toFixed(2)}</span>
                             </div>
                             <div className="flex justify-between text-slate-600 dark:text-slate-400">
                                 <span>SGST</span>
                                 <span>{currency}{totals.sgst.toFixed(2)}</span>
                             </div>
                             <div className="flex justify-between text-slate-600 dark:text-slate-400">
                                 <span>IGST</span>
                                 <span>{currency}{totals.igst.toFixed(2)}</span>
                             </div>
                             <div className="border-t border-slate-200 dark:border-slate-700 pt-3 flex justify-between font-bold text-lg text-slate-900 dark:text-white">
                                 <span>Total</span>
                                 <span>{currency}{totals.grandTotal.toFixed(2)}</span>
                             </div>
                         </div>
                     </SectionCard>

                     {/* Bank Account */}
                     <SectionCard title="Bank Details">
                         <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Select Bank Account</label>
                         <select 
                            className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 text-slate-900 dark:text-white rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-accent focus:outline-none"
                            value={draftInvoice.selectedBankAccountId || ''}
                            onChange={(e) => setDraftInvoice({...draftInvoice, selectedBankAccountId: e.target.value})}
                         >
                             <option value="">-- No Bank Account --</option>
                             {company.bankAccounts.map(b => <option key={b.id} value={b.id}>{b.bankName} - {b.accountNumber.slice(-4)}</option>)}
                         </select>
                         <div className="mt-2 text-right">
                            <button className="text-xs text-accent font-semibold hover:underline" onClick={() => setIsAddBankModalOpen(true)}>+ Add New Bank</button>
                         </div>
                     </SectionCard>

                     {/* Shipping & Transport */}
                     <SectionCard title="Shipping & Transport">
                         <div className="space-y-4">
                             <div className="flex items-center gap-2 mb-2">
                                <input type="checkbox" id="sameAsBilling" checked={draftInvoice.isShippingSameAsBilling} onChange={handleSameAsBillingToggle} className="rounded border-slate-300 text-accent focus:ring-accent" />
                                <label htmlFor="sameAsBilling" className="text-sm text-slate-700 dark:text-slate-300">Same as Billing Address</label>
                             </div>

                             {!draftInvoice.isShippingSameAsBilling && (
                                 <div className="space-y-3 bg-slate-50 dark:bg-slate-800 p-3 rounded-lg border border-slate-200 dark:border-slate-700">
                                     <Input label="Shipping Name" name="name" value={draftInvoice.shippingDetails.name} onChange={handleShippingChange} className="!py-1.5 !text-xs" />
                                     <textarea name="address" rows={2} value={draftInvoice.shippingDetails.address} onChange={(e) => handleShippingChange(e as any)} placeholder="Address" className="w-full bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded px-2 py-1 text-xs" />
                                     <div className="grid grid-cols-2 gap-2">
                                         <div className="relative">
                                             <Input label="Zip" name="zip" value={draftInvoice.shippingDetails.zip} onChange={handleShippingChange} className="!py-1.5 !text-xs" error={pincodeError || undefined}/>
                                             {isPincodeLoading && <div className="absolute top-7 right-2 h-3 w-3 border border-slate-400 border-t-transparent rounded-full animate-spin"></div>}
                                         </div>
                                         <Input label="City" name="city" value={draftInvoice.shippingDetails.city} onChange={handleShippingChange} className="!py-1.5 !text-xs" />
                                     </div>
                                      <select name="state" value={draftInvoice.shippingDetails.state} onChange={handleShippingChange} className="w-full bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded px-2 py-1 text-xs">
                                        <option value="">Select State</option>
                                        {INDIAN_STATES.map(s => <option key={s} value={s}>{s}</option>)}
                                     </select>
                                     <Input label="GSTIN" name="gstin" value={draftInvoice.shippingDetails.gstin} onChange={handleShippingChange} className="!py-1.5 !text-xs" />
                                 </div>
                             )}

                             <div className="pt-2 border-t border-slate-100 dark:border-slate-700">
                                 <label className="block text-xs font-semibold text-slate-500 uppercase mb-2">Logistics</label>
                                 <select value={draftInvoice.transporterId} onChange={(e) => setDraftInvoice({...draftInvoice, transporterId: e.target.value})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 rounded-lg px-3 py-2 text-sm mb-3">
                                     <option value="">-- Select Transporter --</option>
                                     <option value="self">Self Transport</option>
                                     {company.transporters.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                                 </select>
                                 <Input label="Vehicle Number" value={draftInvoice.vehicleNumber} onChange={handleVehicleNumberChange} error={vehicleNumberError || undefined} placeholder="MH 01 AB 1234" />
                                 <Input label="E-Way Bill No." value={draftInvoice.ewayBillNumber} onChange={e => setDraftInvoice({...draftInvoice, ewayBillNumber: e.target.value})} className="mt-3" />
                             </div>
                         </div>
                     </SectionCard>

                     <SectionCard title="Notes">
                         <textarea 
                            rows={3} 
                            className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 rounded-lg p-3 text-sm focus:ring-accent focus:border-accent"
                            placeholder="Add terms, conditions, or payment instructions..."
                            value={draftInvoice.notes}
                            onChange={e => setDraftInvoice({...draftInvoice, notes: e.target.value})}
                         />
                     </SectionCard>

                 </div>
             </div>

             {/* Add Bank Modal */}
             <Modal isOpen={isAddBankModalOpen} onClose={() => setIsAddBankModalOpen(false)} title="Add Bank Account">
                 <div className="p-6 space-y-4">
                     <Input label="Bank Name" value={newBank.bankName} onChange={e => setNewBank({...newBank, bankName: e.target.value})} error={newBankErrors.bankName} />
                     <Input label="Account Number" value={newBank.accountNumber} onChange={e => setNewBank({...newBank, accountNumber: e.target.value})} error={newBankErrors.accountNumber} />
                     <Input label="IFSC Code" value={newBank.ifsc} onChange={e => setNewBank({...newBank, ifsc: e.target.value})} error={newBankErrors.ifsc} />
                 </div>
                 <div className="p-6 pt-0 flex justify-end gap-3">
                     <Button variant="secondary" onClick={() => setIsAddBankModalOpen(false)}>Cancel</Button>
                     <Button onClick={() => {
                         if(!newBank.bankName) { setNewBankErrors({...newBankErrors, bankName: 'Required'}); return; }
                         if(!newBank.accountNumber) { setNewBankErrors({...newBankErrors, accountNumber: 'Required'}); return; }
                         if(!newBank.ifsc) { setNewBankErrors({...newBankErrors, ifsc: 'Required'}); return; }

                         const newAccount: BankAccount = { ...newBank, id: Date.now().toString(), isDefault: company.bankAccounts.length === 0 } as BankAccount;
                         onUpdateCompany({ ...company, bankAccounts: [...company.bankAccounts, newAccount] });
                         setDraftInvoice({...draftInvoice, selectedBankAccountId: newAccount.id});
                         setIsAddBankModalOpen(false);
                         setNewBank({ bankName: '', accountNumber: '', ifsc: '' });
                         setNewBankErrors({});
                     }}>Save Account</Button>
                 </div>
             </Modal>

             {/* Create Item Modal */}
             <Modal isOpen={isCreateItemModalOpen} onClose={() => setIsCreateItemModalOpen(false)} title="Create New Item">
                 <div className="p-6 space-y-4">
                     <div className="p-3 bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-300 text-sm rounded-lg">
                         Creating item: <strong>{newItemData.name}</strong>. This item will be added to your inventory.
                     </div>
                     <Input label="Name" value={newItemData.name || ''} onChange={e => setNewItemData({...newItemData, name: e.target.value})} required />
                     <div className="grid grid-cols-2 gap-4">
                         <Input label="Price (₹)" type="number" min="0" value={newItemData.price} onChange={e => setNewItemData({...newItemData, price: parseFloat(e.target.value) || 0})} required />
                         <Input label="GST Rate (%)" type="number" min="0" value={newItemData.gstRate} onChange={e => setNewItemData({...newItemData, gstRate: parseFloat(e.target.value) || 0})} required />
                     </div>
                     <div className="grid grid-cols-2 gap-4">
                         <div className="flex flex-col">
                             <label className="text-sm font-semibold mb-1.5 text-slate-700 dark:text-slate-300">Unit</label>
                             <select 
                                value={newItemData.unit} 
                                onChange={e => setNewItemData({...newItemData, unit: e.target.value})} 
                                className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 text-slate-900 dark:text-white rounded-lg px-4 py-3 focus:ring-2 focus:ring-accent focus:outline-none"
                             >
                                {ITEM_UNITS.map(u => <option key={u} value={u}>{u}</option>)}
                             </select>
                         </div>
                         <Input label="HSN Code" value={newItemData.hsn || ''} onChange={e => setNewItemData({...newItemData, hsn: e.target.value})} />
                     </div>
                     <Input label="Initial Stock" type="number" min="0" value={newItemData.quantityInStock} onChange={e => setNewItemData({...newItemData, quantityInStock: parseFloat(e.target.value) || 0})} />
                 </div>
                 <div className="p-6 pt-0 flex justify-end gap-3">
                     <Button variant="secondary" onClick={() => setIsCreateItemModalOpen(false)}>Cancel</Button>
                     <Button onClick={handleCreateNewItem}>Create Item</Button>
                 </div>
             </Modal>

             {/* Item Details Modal */}
             <Modal isOpen={viewItemModalOpen} onClose={() => setViewItemModalOpen(false)} title="Item Details">
                 {viewingItem && (
                     <div className="p-6">
                         <div className="flex justify-between items-start mb-6">
                             <div>
                                 <h2 className="text-2xl font-bold text-slate-900 dark:text-white">{viewingItem.name}</h2>
                                 {viewingItem.hsn && <p className="text-slate-500 dark:text-slate-400 text-sm">HSN: {viewingItem.hsn}</p>}
                             </div>
                             <div className={`px-3 py-1 rounded-full text-xs font-bold ${viewingItem.quantityInStock > 5 ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'}`}>
                                 {viewingItem.quantityInStock > 0 ? 'In Stock' : 'Out of Stock'}
                             </div>
                         </div>

                         <div className="grid grid-cols-2 gap-4 mb-6">
                             <div className="p-4 bg-slate-50 dark:bg-slate-800 rounded-lg">
                                 <p className="text-xs text-slate-500 uppercase font-semibold">Selling Price</p>
                                 <p className="text-xl font-bold text-slate-900 dark:text-white">{currency}{viewingItem.price.toFixed(2)}</p>
                             </div>
                             <div className="p-4 bg-slate-50 dark:bg-slate-800 rounded-lg">
                                 <p className="text-xs text-slate-500 uppercase font-semibold">Available Stock</p>
                                 <p className="text-xl font-bold text-slate-900 dark:text-white">{viewingItem.quantityInStock} <span className="text-sm font-normal text-slate-500">{viewingItem.unit}</span></p>
                             </div>
                             <div className="p-4 bg-slate-50 dark:bg-slate-800 rounded-lg">
                                 <p className="text-xs text-slate-500 uppercase font-semibold">GST Rate</p>
                                 <p className="text-xl font-bold text-slate-900 dark:text-white">{viewingItem.gstRate}%</p>
                             </div>
                             <div className="p-4 bg-slate-50 dark:bg-slate-800 rounded-lg">
                                 <p className="text-xs text-slate-500 uppercase font-semibold">Unit Type</p>
                                 <p className="text-xl font-bold text-slate-900 dark:text-white capitalize">{viewingItem.unit}</p>
                             </div>
                         </div>

                         <div className="flex justify-end">
                             <Button variant="secondary" onClick={() => setViewItemModalOpen(false)}>Close</Button>
                         </div>
                     </div>
                 )}
             </Modal>
        </div>
    );
};

export default NewInvoice;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Settings from './components/Settings';
import Clients from './components/Clients';
import Items from './components/Items';
import Transporters from './components/Transporters';
import Invoices, { InvoiceContent } from './components/Invoices';
import NewInvoice from './components/NewInvoice';
import Auth from './components/auth/Auth';
import CompanyManager from './components/CompanyManager';
import UserProfile from './components/UserProfile';
import { useLocalStorage } from './hooks/useLocalStorage';
import type { Company, Client, Item, Invoice, Transporter, User, CompanyDetails, BankAccount, RecurringInvoice, RecurringFrequency, DraftInvoice, InvoiceItem, StockHistoryEntry } from './types';
import Modal from './components/common/Modal';
import Input from './components/common/Input';
import Button from './components/common/Button';
import Inventory from './components/Inventory';
import VoiceAssistant from './components/VoiceAssistant';

const simpleHash = (s: string) => {
    let h = 0;
    for(let i = 0; i < s.length; i++) h = Math.imul(31, h) + s.charCodeAt(i) | 0;
    return h.toString();
};

const emptyCompanyDetails: CompanyDetails = { 
    logo: '', name: '', gstin: '', pan: '', phone: '', email: '', website: '',
    address: '', city: '', state: '', zip: '', udyam: '', signature: '',
    invoicePrefix: 'INV-', nextInvoiceNumber: 1
};

const defaultCompany: Omit<Company, 'id' | 'ownerId'> = {
    details: { ...emptyCompanyDetails, name: 'My First Company' },
    bankAccounts: [], clients: [], items: [], transporters: [], invoices: [], recurringInvoices: [], stockHistory: []
};

const emptyDraftInvoice: DraftInvoice = {
    invoiceNumber: '',
    clientId: '',
    items: [],
    issueDate: new Date().toISOString().split('T')[0],
    dueDate: new Date().toISOString().split('T')[0],
    notes: '',
    selectedBankAccountId: null,
    shippingDetails: { name: '', address: '', city: '', state: '', zip: '', gstin: '' },
    isShippingSameAsBilling: true,
    transporterId: '',
    vehicleNumber: '',
    ewayBillNumber: ''
};

const App: React.FC = () => {
  const [activeView, setActiveView] = useState('Dashboard');
  const [theme, setTheme] = useLocalStorage<'light' | 'dark'>('theme', 'dark');
  const [users, setUsers] = useLocalStorage<User[]>('invoicepro_users', []);
  const [companies, setCompanies] = useLocalStorage<Company[]>('invoicepro_companies', []);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeCompanyId, setActiveCompanyId] = useState<string | null>(null);
  const [invoiceToEdit, setInvoiceToEdit] = useState<Invoice | null>(null);
  const [isAddCompanyModalOpen, setIsAddCompanyModalOpen] = useState(false);
  const [newCompanyName, setNewCompanyName] = useState('');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [voiceInvoiceToEmail, setVoiceInvoiceToEmail] = useState<Invoice | null>(null);

  // Profile State
  const [isProfileOpen, setIsProfileOpen] = useState(false);

  // Lifted State for New Invoice Draft
  const [draftInvoice, setDraftInvoice] = useState<DraftInvoice>(emptyDraftInvoice);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', theme === 'dark');
  }, [theme]);

  const activeCompany = useMemo(() => companies.find(c => c.id === activeCompanyId) || null, [companies, activeCompanyId]);
  const userCompanies = useMemo(() => companies.filter(c => c.ownerId === currentUser?.id), [companies, currentUser]);

  // Initialize draft invoice number when active company changes
  useEffect(() => {
      if (activeCompany) {
          const nextNum = activeCompany.details.nextInvoiceNumber || 1;
          const prefix = activeCompany.details.invoicePrefix || 'INV-';
          const defaultBank = activeCompany.bankAccounts.find(b => b.isDefault)?.id || (activeCompany.bankAccounts[0]?.id || null);

          setDraftInvoice(prev => ({
              ...prev,
              invoiceNumber: `${prefix}${nextNum.toString().padStart(3, '0')}`,
              selectedBankAccountId: defaultBank
          }));
      }
  }, [activeCompany?.id, activeCompany?.details.nextInvoiceNumber]);

  // --- Auto-Overdue Check ---
  useEffect(() => {
      if (!activeCompany) return;

      const today = new Date().toISOString().split('T')[0];
      let hasUpdates = false;

      const updatedInvoices = activeCompany.invoices.map(inv => {
          // Check if invoice is Unpaid and Due Date has passed
          if (inv.status === 'Unpaid' && inv.dueDate < today) {
              hasUpdates = true;
              return { ...inv, status: 'Overdue' as const };
          }
          return inv;
      });

      if (hasUpdates) {
          handleUpdateCompany({ ...activeCompany, invoices: updatedInvoices });
      }
  }, [activeCompanyId, activeCompany?.invoices]); // Depend on invoices array itself, not length, to catch edits

  // --- Auth Handlers ---
  const handleLogin = (email: string, pass: string): boolean => {
    const user = users.find(u => u.email === email && u.passwordHash === simpleHash(pass));
    if (user) {
        setCurrentUser(user);
        const firstCompany = companies.find(c => c.ownerId === user.id);
        setActiveCompanyId(firstCompany?.id || null);
        return true;
    }
    return false;
  };

  const handleGoogleLogin = () => {
      const googleEmail = "user@gmail.com";
      let user = users.find(u => u.email === googleEmail);
      if (!user) {
          user = { id: `google_${Date.now()}`, email: googleEmail, passwordHash: 'google-auth', name: 'Google User' };
          setUsers([...users, user]);
      }
      setCurrentUser(user);
      const firstCompany = companies.find(c => c.ownerId === user!.id);
      setActiveCompanyId(firstCompany?.id || null);
  };

  const handleSignup = (email: string, pass: string, name: string): boolean => {
    if(users.some(u => u.email === email)) return false;
    const newUser: User = { id: Date.now().toString(), email, name, passwordHash: simpleHash(pass) };
    setUsers([...users, newUser]);
    setCurrentUser(newUser);
    setActiveCompanyId(null);
    return true;
  };

  const handleLogout = () => {
      setCurrentUser(null);
      setActiveCompanyId(null);
  };

  const handleCheckUser = (email: string): boolean => users.some(u => u.email === email);

  const handleResetPassword = (email: string, newPass: string): boolean => {
      if (!users.some(u => u.email === email)) return false;
      const updatedUsers = users.map(user => user.email === email ? { ...user, passwordHash: simpleHash(newPass) } : user);
      setUsers(updatedUsers);
      return true;
  };

  const handleUpdateProfile = (updatedUser: User) => {
      setUsers(users.map(u => u.id === updatedUser.id ? updatedUser : u));
      setCurrentUser(updatedUser);
  };

  // --- Company Handlers ---
  const handleAddCompany = (companyDetails: CompanyDetails) => {
      if(!currentUser) return;
      const newCompany: Company = {
          id: `comp_${Date.now()}`,
          ownerId: currentUser.id,
          details: companyDetails,
          bankAccounts: [], clients: [], items: [], transporters: [], invoices: [], recurringInvoices: [], stockHistory: []
      };
      setCompanies([...companies, newCompany]);
      setActiveCompanyId(newCompany.id);
      setActiveView('Dashboard');
  };

  const handleCreateNewCompany = () => {
    if (newCompanyName.trim()) {
        handleAddCompany({ ...emptyCompanyDetails, name: newCompanyName.trim() });
        setIsAddCompanyModalOpen(false);
        setNewCompanyName('');
    }
  };

  const handleUpdateCompany = (updatedCompany: Company) => {
      setCompanies(companies.map(c => c.id === updatedCompany.id ? updatedCompany : c));
  };

  const handleSwitchCompany = (companyId: string) => {
      setActiveCompanyId(companyId);
      setActiveView('Dashboard');
  };

  // --- Stock Log Helper ---
  const createStockLog = (
      itemId: string, 
      itemName: string, 
      prevQty: number, 
      newQty: number, 
      action: StockHistoryEntry['action'], 
      refId?: string
  ): StockHistoryEntry => ({
      id: `log_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
      itemId,
      itemName,
      previousQuantity: prevQty,
      newQuantity: newQty,
      action,
      timestamp: new Date().toISOString(),
      referenceId: refId
  });

  // --- Voice Assistant Handlers ---
  const handleVoiceAddClient = (client: Omit<Client, 'id'>) => {
      if (!activeCompany) return { success: false, message: 'No active company' };

      const existing = activeCompany.clients.find(c => c.name.toLowerCase() === client.name.toLowerCase());
      if (existing) {
          return { success: false, message: `Client '${client.name}' already exists.` };
      }

      const newClient: Client = { 
          gstin: '', email: '', phone: '', address: '', city: '', state: '', zip: '', tags: [],
          ...client,
          id: `c_${Date.now()}` 
      };
      handleUpdateCompany({
          ...activeCompany,
          clients: [...activeCompany.clients, newClient]
      });
      return { success: true, message: `Client ${client.name} added successfully.` };
  };

  const handleVoiceAddItem = (item: Omit<Item, 'id'>) => {
      if (!activeCompany) return { success: false, message: 'No active company' };

      const existing = activeCompany.items.find(i => i.name.toLowerCase() === item.name.toLowerCase());
      if (existing) {
          return { success: false, message: `Item '${item.name}' already exists in inventory.` };
      }

      const newItem: Item = { 
          hsn: '', unit: 'pcs', quantityInStock: 0,
          ...item,
          id: `i_${Date.now()}` 
      };

      // Log initial stock
      const log = createStockLog(newItem.id, newItem.name, 0, newItem.quantityInStock, 'Initial');

      handleUpdateCompany({
          ...activeCompany,
          items: [...activeCompany.items, newItem],
          stockHistory: [...(activeCompany.stockHistory || []), log]
      });
      return { success: true, message: `Item ${item.name} added to inventory.` };
  };

  const handleVoiceUpdateStock = (itemName: string, quantity: number) => {
      if (!activeCompany) return { success: false, message: 'No company active' };
      const itemIndex = activeCompany.items.findIndex(i => i.name.toLowerCase() === itemName.toLowerCase());
      if (itemIndex > -1) {
          const updatedItems = [...activeCompany.items];
          const prevQty = updatedItems[itemIndex].quantityInStock;
          updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: quantity };

          const log = createStockLog(
              updatedItems[itemIndex].id, 
              updatedItems[itemIndex].name, 
              prevQty, 
              quantity, 
              'Voice Update'
          );

          handleUpdateCompany({ 
              ...activeCompany, 
              items: updatedItems,
              stockHistory: [...(activeCompany.stockHistory || []), log]
          });
          return { success: true, message: `Stock for ${itemName} updated to ${quantity}` };
      }
      return { success: false, message: `Item ${itemName} not found` };
  };

  const handleVoiceOpenEmailModal = (invoiceNumberQuery: string) => {
      if(!activeCompany) return { success: false, message: 'No company' };
      const invoice = activeCompany.invoices.find(inv => 
          inv.invoiceNumber.toLowerCase().includes(invoiceNumberQuery.toLowerCase())
      );
      if(invoice) {
          setVoiceInvoiceToEmail(invoice);
          return { success: true, message: `Opening email for ${invoice.invoiceNumber}` };
      }
      return { success: false, message: `Invoice ${invoiceNumberQuery} not found` };
  };

  // Voice Drafting Logic
  const handleVoiceDraftInvoice = (clientName: string) => {
      if (!activeCompany) return { success: false, message: 'No active company' };
      const client = activeCompany.clients.find(c => c.name.toLowerCase().includes(clientName.toLowerCase()));

      // Update draft state
      setDraftInvoice(prev => ({
          ...prev,
          clientId: client ? client.id : prev.clientId,
          items: [],
          shippingDetails: client ? {
              name: client.name,
              address: client.address,
              city: client.city,
              state: client.state,
              zip: client.zip,
              gstin: client.gstin
          } : prev.shippingDetails,
          isShippingSameAsBilling: true
      }));

      // Switch view
      setActiveView('NewInvoice');

      if (!client) return { success: false, message: `Opened New Invoice page. Client ${clientName} not found.` };
      return { success: true, message: `Started invoice for ${client.name}.` };
  };

  const handleVoiceAddDraftItem = (itemName: string, quantity: number) => {
      if (!activeCompany) return { success: false, message: 'No active company' };
      const item = activeCompany.items.find(i => i.name.toLowerCase().includes(itemName.toLowerCase()));

      if (!item) return { success: false, message: `Item ${itemName} not found.` };

      const newItem: InvoiceItem = { ...item, quantity };

      setDraftInvoice(prev => ({
          ...prev,
          items: [...prev.items, newItem]
      }));

      // Ensure user is on the right page
      if (activeView !== 'NewInvoice') setActiveView('NewInvoice');

      return { success: true, message: `Added ${quantity} ${item.name}(s) to invoice.` };
  };

  // --- NEW VOICE INVOICE CONTROL HANDLERS ---
  const handleVoiceUpdateInvoiceDetails = (details: { issueDate?: string, dueDate?: string, notes?: string, vehicleNumber?: string, transporterName?: string }) => {
      if (activeView !== 'NewInvoice') setActiveView('NewInvoice');

      const updates: any = {};
      if (details.issueDate) updates.issueDate = details.issueDate;
      if (details.dueDate) updates.dueDate = details.dueDate;
      if (details.notes) updates.notes = details.notes;
      if (details.vehicleNumber) updates.vehicleNumber = details.vehicleNumber;

      // Handle Transporter matching
      if (details.transporterName) {
          if (details.transporterName.toLowerCase() === 'self') {
              updates.transporterId = 'self';
          } else {
              const trans = activeCompany?.transporters.find(t => t.name.toLowerCase().includes(details.transporterName!.toLowerCase()));
              if (trans) updates.transporterId = trans.id;
          }
      }

      setDraftInvoice(prev => ({ ...prev, ...updates }));
      return { success: true, message: "Invoice details updated." };
  };

  const handleVoiceUpdateShippingDetails = (details: Partial<DraftInvoice['shippingDetails']>) => {
      if (activeView !== 'NewInvoice') setActiveView('NewInvoice');
      setDraftInvoice(prev => ({
          ...prev,
          isShippingSameAsBilling: false,
          shippingDetails: { ...prev.shippingDetails, ...details }
      }));
      return { success: true, message: "Shipping details updated." };
  };

  const handleVoiceRemoveInvoiceItem = (itemName: string) => {
      if (activeView !== 'NewInvoice') return { success: false, message: "Not on invoice page" };

      const index = draftInvoice.items.findIndex(i => i.name.toLowerCase().includes(itemName.toLowerCase()));
      if (index === -1) return { success: false, message: "Item not found in invoice" };

      const newItems = draftInvoice.items.filter((_, i) => i !== index);
      setDraftInvoice(prev => ({ ...prev, items: newItems }));
      return { success: true, message: `Removed ${itemName} from invoice.` };
  };

  const handleVoiceSaveInvoice = () => {
      if (activeView !== 'NewInvoice') return { success: false, message: "Not on invoice page" };
      if (!draftInvoice.clientId || draftInvoice.items.length === 0) {
          return { success: false, message: "Cannot save: Missing client or items." };
      }

      const client = activeCompany?.clients.find(c => c.id === draftInvoice.clientId);
      if(!client) return { success: false, message: "Client not found" };

      let subTotal = 0, cgst = 0, sgst = 0, igst = 0;
      const isIntraState = !draftInvoice.shippingDetails.state || draftInvoice.shippingDetails.state === activeCompany?.details.state;

      draftInvoice.items.forEach(item => {
          const t = item.price * item.quantity;
          subTotal += t;
          const tax = (t * item.gstRate) / 100;
          if (isIntraState) { cgst += tax/2; sgst += tax/2; } else { igst += tax; }
      });

      const inv: Omit<Invoice, 'id' | 'status'> = {
          invoiceNumber: draftInvoice.invoiceNumber,
          client: client,
          items: draftInvoice.items,
          issueDate: draftInvoice.issueDate,
          dueDate: draftInvoice.dueDate,
          notes: draftInvoice.notes,
          selectedBankAccountId: draftInvoice.selectedBankAccountId,
          shippingName: draftInvoice.shippingDetails.name,
          shippingAddress: draftInvoice.shippingDetails.address,
          shippingCity: draftInvoice.shippingDetails.city,
          shippingState: draftInvoice.shippingDetails.state,
          shippingZip: draftInvoice.shippingDetails.zip,
          shippingGstin: draftInvoice.shippingDetails.gstin,
          transporterName: '', 
          vehicleNumber: draftInvoice.vehicleNumber,
          ewayBillNumber: draftInvoice.ewayBillNumber,
          subTotal, cgst, sgst, igst, grandTotal: subTotal + cgst + sgst + igst
      };

      handleSaveInvoice(inv);
      setActiveView('Invoices');
      return { success: true, message: "Invoice saved successfully." };
  };

  const handleVoiceDeleteClient = (clientName: string) => {
      if(!activeCompany) return { success: false, message: 'No active company' };
      const client = activeCompany.clients.find(c => c.name.toLowerCase().includes(clientName.toLowerCase()));
      if(client) {
          setActiveView('Clients');
          const updatedClients = activeCompany.clients.filter(c => c.id !== client.id);
          handleUpdateCompany({ ...activeCompany, clients: updatedClients });
          return { success: true, message: `Client ${client.name} deleted.` };
      }
      return { success: false, message: `Client ${clientName} not found` };
  };

  const handleVoiceDeleteInvoice = (invoiceNumber: string) => {
      if(!activeCompany) return { success: false, message: 'No active company' };
      const invoice = activeCompany.invoices.find(i => i.invoiceNumber.toLowerCase().includes(invoiceNumber.toLowerCase()));
      if(invoice) {
          setActiveView('Invoices');
          handleBulkDeleteInvoices([invoice.id]);
          return { success: true, message: `Invoice ${invoice.invoiceNumber} deleted.` };
      }
      return { success: false, message: `Invoice ${invoiceNumber} not found` };
  };

  const handleVoiceDeleteItem = (itemName: string) => {
      if(!activeCompany) return { success: false, message: 'No active company' };
      const item = activeCompany.items.find(i => i.name.toLowerCase().includes(itemName.toLowerCase()));
      if(item) {
          setActiveView('Items');
          handleBulkDeleteItems([item.id]);
          return { success: true, message: `Item ${item.name} deleted.` };
      }
      return { success: false, message: `Item ${itemName} not found` };
  };

  const handleVoiceUpdateInvoiceStatus = (invoiceNumber: string, status: string) => {
      if (!activeCompany) return { success: false, message: 'No company active' };
      const inv = activeCompany.invoices.find(i => i.invoiceNumber.toLowerCase().includes(invoiceNumber.toLowerCase()));
      if (inv) {
          const validStatus = ['Paid', 'Unpaid', 'Overdue'].find(s => s.toLowerCase() === status.toLowerCase());
          if (validStatus) {
              handleBulkStatusChange([inv.id], validStatus as Invoice['status']);
              return { success: true, message: `Invoice ${inv.invoiceNumber} marked as ${validStatus}` };
          }
          return { success: false, message: 'Invalid status. Use Paid, Unpaid, or Overdue.' };
      }
      return { success: false, message: 'Invoice not found' };
  };

  const handleVoiceUpdateCompanyInfo = (field: string, value: string) => {
      if (!activeCompany) return { success: false, message: 'No company active' };
      const validFields = ['name', 'phone', 'email', 'address', 'city', 'state', 'zip', 'gstin'];
      if (validFields.includes(field)) {
         const newDetails = { ...activeCompany.details, [field]: value };
         handleUpdateCompany({ ...activeCompany, details: newDetails });
         return { success: true, message: `Company ${field} updated.` };
      }
      return { success: false, message: `Cannot update field ${field}. Allowed: name, phone, email, address, etc.` };
  };

  // --- Recurring Invoice Generation Logic ---
  useEffect(() => {
      if (!activeCompany || !activeCompany.recurringInvoices) return;

      const today = new Date().toISOString().split('T')[0];
      let updatedInvoices = [...activeCompany.invoices];
      let updatedRecurring = [...(activeCompany.recurringInvoices || [])];
      let updatedItems = [...activeCompany.items];
      let updatedDetails = { ...activeCompany.details };
      let newHistoryLogs: StockHistoryEntry[] = [];
      let hasChanges = false;
      let nextInvoiceNum = updatedDetails.nextInvoiceNumber;

      const getNextDate = (current: string, freq: RecurringFrequency): string => {
          const date = new Date(current);
          if (freq === 'Daily') date.setDate(date.getDate() + 1);
          if (freq === 'Weekly') date.setDate(date.getDate() + 7);
          if (freq === 'Monthly') date.setMonth(date.getMonth() + 1);
          if (freq === 'Quarterly') date.setMonth(date.getMonth() + 3);
          if (freq === 'Yearly') date.setFullYear(date.getFullYear() + 1);
          return date.toISOString().split('T')[0];
      };

      updatedRecurring = updatedRecurring.map(rec => {
          if (rec.status === 'Active' && rec.nextRunDate <= today) {
              if (rec.endDate && rec.nextRunDate > rec.endDate) {
                  return { ...rec, status: 'Completed' };
              }
              const client = activeCompany.clients.find(c => c.id === rec.clientId);
              if (client) {
                  hasChanges = true;
                  const invoiceNumber = `${updatedDetails.invoicePrefix}${nextInvoiceNum.toString().padStart(3, '0')}`;
                  nextInvoiceNum++;

                  let subTotal = 0, cgst = 0, sgst = 0, igst = 0;
                  const isIntraState = client.state === activeCompany.details.state;

                  const items = rec.items.map(i => {
                      const taxable = i.price * i.quantity;
                      subTotal += taxable;
                      const tax = (taxable * i.gstRate) / 100;
                      if (isIntraState) { cgst += tax / 2; sgst += tax / 2; } else { igst += tax; }

                      const itemIndex = updatedItems.findIndex(invItem => invItem.id === i.id);
                      if (itemIndex > -1) {
                        const prevQty = Number(updatedItems[itemIndex].quantityInStock) || 0;
                        const newQty = prevQty - i.quantity;
                        updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: newQty };

                        newHistoryLogs.push(createStockLog(
                            i.id, i.name, prevQty, newQty, 'Invoice Created', invoiceNumber
                        ));
                      }
                      return i;
                  });

                  const grandTotal = subTotal + cgst + sgst + igst;
                  const newInvoice: Invoice = {
                      id: `inv_rec_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
                      invoiceNumber, client, items, issueDate: rec.nextRunDate, dueDate: rec.nextRunDate,
                      notes: rec.notes || 'Recurring Invoice', subTotal, cgst, sgst, igst, grandTotal,
                      status: 'Unpaid', selectedBankAccountId: activeCompany.bankAccounts.find(b => b.isDefault)?.id || null,
                      shippingName: client.name, shippingAddress: client.shippingAddress || client.address,
                      shippingCity: client.shippingCity || client.city, shippingState: client.shippingState || client.state,
                      shippingZip: client.shippingZip || client.zip, shippingGstin: client.gstin
                  };
                  updatedInvoices.push(newInvoice);
                  return { ...rec, lastRunDate: rec.nextRunDate, nextRunDate: getNextDate(rec.nextRunDate, rec.frequency) };
              }
          }
          return rec;
      });

      if (hasChanges) {
          updatedDetails.nextInvoiceNumber = nextInvoiceNum;
          handleUpdateCompany({ 
              ...activeCompany, 
              details: updatedDetails, 
              invoices: updatedInvoices.sort((a,b) => b.invoiceNumber.localeCompare(a.invoiceNumber, undefined, {numeric: true})), 
              recurringInvoices: updatedRecurring, 
              items: updatedItems,
              stockHistory: [...(activeCompany.stockHistory || []), ...newHistoryLogs]
          });
      }
  }, [activeCompanyId]);

  const handleAddRecurring = (profile: Omit<RecurringInvoice, 'id'>) => {
      if (!activeCompany) return;
      handleUpdateCompany({ ...activeCompany, recurringInvoices: [...(activeCompany.recurringInvoices || []), { ...profile, id: `rec_${Date.now()}` }] });
  };

  const handleUpdateRecurring = (updatedProfile: RecurringInvoice) => {
      if (!activeCompany) return;
      handleUpdateCompany({ ...activeCompany, recurringInvoices: activeCompany.recurringInvoices.map(r => r.id === updatedProfile.id ? updatedProfile : r) });
  };

  const handleDeleteRecurring = (id: string) => {
      if (!activeCompany) return;
      handleUpdateCompany({ ...activeCompany, recurringInvoices: activeCompany.recurringInvoices.filter(r => r.id !== id) });
  };

  const createCompanyDataUpdater = <T,>(dataType: keyof Omit<Company, 'id' | 'ownerId' | 'details' | 'invoices' | 'recurringInvoices' | 'stockHistory'>) => (data: T[]) => {
      if(!activeCompany) return;
      const updatedCompany = { ...activeCompany, [dataType]: data };
      handleUpdateCompany(updatedCompany as Company);
  };

  const setClients = createCompanyDataUpdater<Client>('clients');
  // Replaced setItems with custom logic inside bulk updates, but keeping this for direct access if needed
  const setItems = createCompanyDataUpdater<Item>('items');
  const setTransporters = createCompanyDataUpdater<Transporter>('transporters');

  // New Bulk Update Logic for Inventory Page
  const handleBulkStockUpdate = (updates: { itemId: string, newQuantity: number }[], actionType: StockHistoryEntry['action'] = 'Bulk Update') => {
      if (!activeCompany) return;
      const updatedItems = [...activeCompany.items];
      const newHistoryLogs: StockHistoryEntry[] = [];

      updates.forEach(update => {
          const idx = updatedItems.findIndex(i => i.id === update.itemId);
          if (idx !== -1) {
              const prevQty = updatedItems[idx].quantityInStock;
              if (prevQty !== update.newQuantity) {
                  updatedItems[idx] = { ...updatedItems[idx], quantityInStock: update.newQuantity };
                  newHistoryLogs.push(createStockLog(
                      updatedItems[idx].id, 
                      updatedItems[idx].name, 
                      prevQty, 
                      update.newQuantity, 
                      actionType
                  ));
              }
          }
      });

      if (newHistoryLogs.length > 0) {
          handleUpdateCompany({
              ...activeCompany,
              items: updatedItems,
              stockHistory: [...(activeCompany.stockHistory || []), ...newHistoryLogs]
          });
      }
  };

  const handleSaveInvoice = (invoiceData: Invoice | Omit<Invoice, 'id' | 'status'>) => {
        if (!activeCompany) return;
        let updatedItems = [...activeCompany.items];
        let updatedInvoices = [...activeCompany.invoices];
        let updatedDetails = { ...activeCompany.details };
        let newHistoryLogs: StockHistoryEntry[] = [];

        if ('id' in invoiceData) {
            // Edit Mode
            const updatedInvoice = invoiceData as Invoice;
            const originalInvoice = activeCompany.invoices.find(inv => inv.id === updatedInvoice.id);
            if (!originalInvoice) return; 

            const originalItemsMap = new Map<string, number>(originalInvoice.items.map(item => [item.id, item.quantity] as [string, number]));
            const updatedItemsMap = new Map<string, number>(updatedInvoice.items.map(item => [item.id, item.quantity] as [string, number]));
            const allItemIds = new Set([...originalItemsMap.keys(), ...updatedItemsMap.keys()]);

            allItemIds.forEach(itemId => {
                const originalQty = originalItemsMap.get(itemId) || 0;
                const updatedQty = updatedItemsMap.get(itemId) || 0;
                const diff = originalQty - updatedQty; // +ve means item removed from invoice (stock increase), -ve means item added (stock decrease)

                if (diff !== 0) {
                    const itemIndex = updatedItems.findIndex(i => i.id === itemId);
                    if (itemIndex > -1) {
                        const prevStock = Number(updatedItems[itemIndex].quantityInStock) || 0;
                        const newStock = prevStock + diff;
                        updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: newStock };

                        newHistoryLogs.push(createStockLog(
                            updatedItems[itemIndex].id,
                            updatedItems[itemIndex].name,
                            prevStock,
                            newStock,
                            'Invoice Edited',
                            updatedInvoice.invoiceNumber
                        ));
                    }
                }
            });
            updatedInvoices = updatedInvoices.map(inv => inv.id === updatedInvoice.id ? updatedInvoice : inv);
        } else {
            // Create Mode
            const newInvoiceData = invoiceData as Omit<Invoice, 'id' | 'status'>;
            const nextNumber = Number(activeCompany.details.nextInvoiceNumber || 1);
            const expectedInvoiceNumber = `${activeCompany.details.invoicePrefix || 'INV-'}${nextNumber.toString().padStart(3, '0')}`;

            newInvoiceData.items.forEach(soldItem => {
                const itemIndex = updatedItems.findIndex(i => i.id === soldItem.id);
                if (itemIndex > -1) {
                    const prevStock = Number(updatedItems[itemIndex].quantityInStock) || 0;
                    const newStock = prevStock - soldItem.quantity;
                    updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: newStock };

                    newHistoryLogs.push(createStockLog(
                        updatedItems[itemIndex].id,
                        updatedItems[itemIndex].name,
                        prevStock,
                        newStock,
                        'Invoice Created',
                        newInvoiceData.invoiceNumber
                    ));
                }
            });
            const newInvoice: Invoice = { ...newInvoiceData, id: `inv_${Date.now()}`, status: 'Unpaid' };
            updatedInvoices.push(newInvoice);
            if (newInvoiceData.invoiceNumber === expectedInvoiceNumber) updatedDetails.nextInvoiceNumber = nextNumber + 1;
        }

        handleUpdateCompany({ 
            ...activeCompany, 
            items: updatedItems, 
            invoices: updatedInvoices.sort((a,b) => b.invoiceNumber.localeCompare(a.invoiceNumber, undefined, {numeric: true})), 
            details: updatedDetails,
            stockHistory: [...(activeCompany.stockHistory || []), ...newHistoryLogs]
        });

        setDraftInvoice(emptyDraftInvoice);
  };

    const handleDeleteInvoice = (invoiceId: string) => handleBulkDeleteInvoices([invoiceId]);

    const handleBulkDeleteInvoices = (ids: string[]) => {
        if (!activeCompany) return;
        let updatedItems = [...activeCompany.items];
        let newHistoryLogs: StockHistoryEntry[] = [];

        const invoicesToDelete = activeCompany.invoices.filter(inv => ids.includes(inv.id));
        invoicesToDelete.forEach(invoice => {
             invoice.items.forEach(soldItem => {
                const itemIndex = updatedItems.findIndex(i => i.id === soldItem.id);
                if (itemIndex > -1) {
                    const prevStock = Number(updatedItems[itemIndex].quantityInStock) || 0;
                    const newStock = prevStock + soldItem.quantity; // Restore stock
                    updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: newStock };

                    newHistoryLogs.push(createStockLog(
                        updatedItems[itemIndex].id,
                        updatedItems[itemIndex].name,
                        prevStock,
                        newStock,
                        'Invoice Deleted',
                        invoice.invoiceNumber
                    ));
                }
             });
        });
        const updatedInvoices = activeCompany.invoices.filter(inv => !ids.includes(inv.id));
        handleUpdateCompany({ 
            ...activeCompany, 
            items: updatedItems, 
            invoices: updatedInvoices,
            stockHistory: [...(activeCompany.stockHistory || []), ...newHistoryLogs]
        });
    };

    const handleUpdateInvoiceStatus = (invoiceId: string, status: Invoice['status']) => handleBulkStatusChange([invoiceId], status);

    const handleBulkStatusChange = (ids: string[], status: Invoice['status']) => {
        if (!activeCompany) return;
        const updatedInvoices = activeCompany.invoices.map(inv => ids.includes(inv.id) ? { ...inv, status } : inv);
        handleUpdateCompany({ ...activeCompany, invoices: updatedInvoices });
    };

    const handleBulkDeleteClients = (ids: string[]) => {
        if(!activeCompany) return;
        handleUpdateCompany({ ...activeCompany, clients: activeCompany.clients.filter(c => !ids.includes(c.id)) });
    };

    const handleBulkDeleteItems = (ids: string[]) => {
        if(!activeCompany) return;
        handleUpdateCompany({ ...activeCompany, items: activeCompany.items.filter(i => !ids.includes(i.id)) });
    };

  const handleEditInvoice = (invoiceId: string) => {
    const invoice = activeCompany?.invoices.find(inv => inv.id === invoiceId);
    if (invoice) {
      setInvoiceToEdit(invoice);
      setActiveView('NewInvoice');
    }
  };

  if (!currentUser) {
    return <div className="w-full h-screen bg-slate-100 dark:bg-secondary-dark flex items-center justify-center"><Auth onLogin={handleLogin} onSignup={handleSignup} onGoogleLogin={handleGoogleLogin} onCheckUserExists={handleCheckUser} onResetPassword={handleResetPassword} /></div>;
  }

  if (!activeCompany) {
    return <CompanyManager onAddCompany={handleAddCompany} onLogout={handleLogout}/>;
  }

  const renderView = () => {
    switch (activeView) {
      case 'Dashboard': return <Dashboard invoices={activeCompany.invoices} items={activeCompany.items} company={activeCompany} setActiveView={setActiveView} />;
      case 'NewInvoice': return <NewInvoice company={activeCompany} saveInvoice={handleSaveInvoice} setActiveView={setActiveView} invoiceToEdit={invoiceToEdit} clearEditingInvoice={() => setInvoiceToEdit(null)} onUpdateCompany={handleUpdateCompany} draftInvoice={draftInvoice} setDraftInvoice={setDraftInvoice} />;
      case 'Invoices': return <Invoices invoices={activeCompany.invoices} company={activeCompany} setActiveView={setActiveView} onEdit={handleEditInvoice} onDelete={handleDeleteInvoice} onStatusChange={handleUpdateInvoiceStatus} onBulkDelete={handleBulkDeleteInvoices} onBulkStatusChange={handleBulkStatusChange} onAddRecurring={handleAddRecurring} onUpdateRecurring={handleUpdateRecurring} onDeleteRecurring={handleDeleteRecurring} />;
      case 'Clients': return <Clients clients={activeCompany.clients} setClients={setClients} invoices={activeCompany.invoices} company={activeCompany} onEditInvoice={handleEditInvoice} onDeleteInvoice={handleDeleteInvoice} onStatusChange={handleUpdateInvoiceStatus} onBulkDelete={handleBulkDeleteClients} />;
      case 'Items': return <Items items={activeCompany.items} setItems={setItems} company={activeCompany} onBulkDelete={handleBulkDeleteItems} />;
      case 'Inventory': return <Inventory items={activeCompany.items} setItems={setItems} onBulkStockUpdate={handleBulkStockUpdate} stockHistory={activeCompany.stockHistory || []} />;
      case 'Transporters': return <Transporters transporters={activeCompany.transporters} setTransporters={setTransporters} />;
      case 'Settings': return <Settings activeCompany={activeCompany} updateCompany={handleUpdateCompany} />;
      default: return <Dashboard invoices={activeCompany.invoices} items={activeCompany.items} company={activeCompany} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-100 dark:bg-secondary-dark font-sans transition-colors relative">
      <Sidebar 
        activeView={activeView} setActiveView={setActiveView} theme={theme} setTheme={setTheme} 
        userCompanies={userCompanies} activeCompany={activeCompany} 
        onSwitchCompany={handleSwitchCompany}
        onAddCompany={() => setIsAddCompanyModalOpen(true)}
        onLogout={handleLogout}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
        currentUser={currentUser}
        onOpenProfile={() => setIsProfileOpen(true)}
      />
      <main className="flex-1 p-8 overflow-y-auto">
        <div className="md:hidden mb-4">
            <button onClick={() => setIsSidebarOpen(true)} className="p-2 rounded-md text-slate-600 dark:text-light-text hover:bg-slate-200 dark:hover:bg-tertiary-dark">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" /></svg>
            </button>
        </div>
        {renderView()}
      </main>

      <VoiceAssistant 
        onNavigate={setActiveView} 
        currentView={activeView}
        onAddClient={handleVoiceAddClient}
        onAddItem={handleVoiceAddItem}
        onUpdateStock={handleVoiceUpdateStock}
        dataContext={{
            clients: activeCompany.clients,
            items: activeCompany.items,
            invoices: activeCompany.invoices
        }}
        onOpenEmailModal={handleVoiceOpenEmailModal}
        onDraftInvoice={handleVoiceDraftInvoice}
        onAddDraftItem={handleVoiceAddDraftItem}
        onUpdateInvoiceDetails={handleVoiceUpdateInvoiceDetails}
        onUpdateShippingDetails={handleVoiceUpdateShippingDetails}
        onRemoveInvoiceItem={handleVoiceRemoveInvoiceItem}
        onSaveDraftInvoice={handleVoiceSaveInvoice}
        onDeleteClient={handleVoiceDeleteClient}
        onDeleteInvoice={handleVoiceDeleteInvoice}
        onDeleteItem={handleVoiceDeleteItem}
        onUpdateInvoiceStatus={handleVoiceUpdateInvoiceStatus}
        onUpdateCompanyInfo={handleVoiceUpdateCompanyInfo}
      />

       <Modal isOpen={isAddCompanyModalOpen} onClose={() => setIsAddCompanyModalOpen(false)} title="Create New Company">
          <div className="p-6 space-y-4">
            <Input label="Company Name" id="new-company-name" value={newCompanyName} onChange={(e) => setNewCompanyName(e.target.value)} placeholder="Enter your new company's name" required />
          </div>
          <div className="p-6 pt-0 flex justify-end gap-4">
            <Button variant="secondary" onClick={() => { setIsAddCompanyModalOpen(false); setNewCompanyName(''); }}>Cancel</Button>
            <Button onClick={handleCreateNewCompany} disabled={!newCompanyName.trim()}>Create Company</Button>
          </div>
        </Modal>

        {/* Profile Modal */}
        <Modal isOpen={isProfileOpen} onClose={() => setIsProfileOpen(false)} title="User Profile">
            {currentUser && <UserProfile user={currentUser} onUpdateProfile={handleUpdateProfile} onClose={() => setIsProfileOpen(false)} />}
        </Modal>

        {/* Hidden Invoice Content for Email Logic if needed by Voice */}
        {voiceInvoiceToEmail && (
            <Modal isOpen={true} onClose={() => setVoiceInvoiceToEmail(null)} title={`Email Invoice #${voiceInvoiceToEmail.invoiceNumber}`}>
                <div className="p-6 text-center">
                    <p className="text-slate-600 dark:text-slate-300 mb-4">The email functionality for <strong>{voiceInvoiceToEmail.invoiceNumber}</strong> has been triggered by your voice command.</p>
                    <p className="text-sm text-slate-500">(In a real app, this would pre-fill and send the email. For now, it opens this confirmation.)</p>
                    <div className="mt-6 flex justify-center gap-4">
                        <Button variant="secondary" onClick={() => setVoiceInvoiceToEmail(null)}>Close</Button>
                        <Button onClick={() => { alert(`Email sent to ${voiceInvoiceToEmail.client.email}`); setVoiceInvoiceToEmail(null); }}>Send Email Now</Button>
                    </div>
                </div>
            </Modal>
        )}
    </div>
  );
};

export default App;

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  children: React.ReactNode;
  variant?: 'primary' | 'secondary';
}

const Button: React.FC<ButtonProps> = ({ children, variant = 'primary', className = '', ...props }) => {
  const baseClasses = "px-5 py-2.5 text-sm font-semibold rounded-xl shadow-sm focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-white dark:focus:ring-offset-primary-dark transition-all duration-200 active:scale-95";
  const variantClasses = {
    primary: "bg-accent text-white hover:bg-accent-hover focus:ring-accent shadow-[0_4px_14px_0_rgba(79,70,229,0.39)] hover:shadow-[0_6px_20px_rgba(79,70,229,0.23)]",
    secondary: "bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-200 border border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-700 focus:ring-slate-400 hover:border-slate-300 dark:hover:border-slate-600",
  };

  return (
    <button
      {...props}
      className={`${baseClasses} ${variantClasses[variant]} ${className}`}
    >
      {children}
    </button>
  );
};

export default Button;

import React from 'react';

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label: string;
  error?: string;
}

const Input: React.FC<InputProps> = ({ label, id, error, className = '', ...props }) => {
  const errorClasses = "border-red-500 focus:border-red-500 focus:ring-red-200 dark:focus:ring-red-900/50";
  // Improved clarity: slightly off-white background to distinguish input area, better padding
  const defaultClasses = "bg-white dark:bg-slate-800/50 border-slate-200 dark:border-slate-700 text-slate-900 dark:text-white rounded-xl shadow-sm placeholder:text-slate-400 dark:placeholder:text-slate-500 focus:outline-none text-sm px-4 py-3 transition-all duration-200 ease-in-out border hover:border-slate-300 dark:hover:border-slate-600 focus:ring-2 focus:ring-accent/20 focus:border-accent";

  return (
    <div className="w-full group">
      {label && (
        <label 
          htmlFor={id} 
          className={`block text-xs font-semibold mb-1.5 uppercase tracking-wider transition-colors ${error ? 'text-red-600 dark:text-red-400' : 'text-slate-500 dark:text-slate-400'}`}
        >
          {label} {props.required && <span className="text-red-500">*</span>}
        </label>
      )}
      <input
        id={id}
        {...props}
        className={`w-full ${error ? errorClasses : defaultClasses} ${props.disabled ? 'opacity-60 cursor-not-allowed bg-slate-100 dark:bg-slate-800' : ''} ${className}`}
        aria-invalid={!!error}
        aria-describedby={error ? `${id}-error` : undefined}
      />
      {error && (
        <p id={`${id}-error`} className="mt-1.5 text-xs font-bold text-red-600 dark:text-red-400 flex items-center gap-1 animate-slide-in">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
          {error}
        </p>
      )}
    </div>
  );
};

export default Input;

import React, { useEffect, useState } from 'react';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
}

const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children }) => {
  const [show, setShow] = useState(false);

  useEffect(() => {
    if (isOpen) {
      setShow(true);
      document.body.style.overflow = 'hidden';
    } else {
      setTimeout(() => setShow(false), 200); // Wait for animation
      document.body.style.overflow = 'unset';
    }
    return () => { document.body.style.overflow = 'unset'; };
  }, [isOpen]);

  if (!show && !isOpen) return null;

  return (
    <div className={`fixed inset-0 z-50 flex justify-center items-center p-4 sm:p-6 transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
      <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={onClose}></div>
      <div className={`bg-white dark:bg-primary-dark rounded-2xl shadow-2xl w-full max-w-4xl max-h-[90vh] flex flex-col transform transition-all duration-300 ${isOpen ? 'scale-100 translate-y-0' : 'scale-95 translate-y-4'}`}>
