                <div className="absolute top-0 right-0 -mt-10 -mr-10 w-40 h-40 bg-accent/5 rounded-full blur-3xl"></div>
                <div className="relative z-10">
                    <h1 className="text-3xl font-bold text-slate-900 dark:text-white tracking-tight">
                        Good Morning, Team <span className="text-accent">{company.details.name}</span>
                    </h1>
                    <div className="flex flex-wrap items-center gap-3 mt-3">
                        <span className="text-sm text-slate-500 dark:text-slate-400 font-medium">Quick Actions:</span>
                        <VoiceSuggestion command="What is my revenue?" />
