                                        <td className="px-6 py-4 text-center"><span className={`px-3 py-1 rounded-full text-xs font-bold ${getStatusBadge(invoice.status)}`}>{invoice.status}</span></td>
                                        <td className="px-6 py-4 text-right space-x-2" onClick={e => e.stopPropagation()}>
                                            <button onClick={() => onEdit(invoice.id)} className="text-slate-400 hover:text-accent p-2 hover:bg-accent/10 rounded-lg transition-all">Edit</button>
                                            <button onClick={() => onDelete(invoice.id)} className="text-slate-400 hover:text-red-500 p-2 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-all">Delete</button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}
        </>
      )}

      {/* ... (Keep Recurring Tab Logic similar but wrap in card for mobile) ... */}

      <Modal isOpen={!!selectedInvoice} onClose={() => setSelectedInvoice(null)} title={`Invoice #${selectedInvoice?.invoiceNumber}`}>
          {selectedInvoice && <InvoiceView invoice={selectedInvoice} company={company} onClose={() => setSelectedInvoice(null)} />}
      </Modal>
    </div>
  );
};

