const CommandPalette: React.FC<{ 
    isOpen: boolean; 
    onClose: () => void; 
    onNavigate: (view: string) => void;
    toggleTheme: () => void;
    onNewInvoice: () => void;
}> = ({ isOpen, onClose, onNavigate, toggleTheme, onNewInvoice }) => {
    const [query, setQuery] = useState('');
    const inputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        if (isOpen) {
            setTimeout(() => inputRef.current?.focus(), 100);
        } else {
            setQuery('');
        }
    }, [isOpen]);

    const actions = [
        { id: 'new-inv', label: 'Create New Invoice', icon: '+', action: () => onNewInvoice() },
        { id: 'dash', label: 'Go to Dashboard', icon: '🏠', action: () => onNavigate('Dashboard') },
        { id: 'inv', label: 'View Invoices', icon: '📄', action: () => onNavigate('Invoices') },
        { id: 'cli', label: 'Manage Clients', icon: '👥', action: () => onNavigate('Clients') },
        { id: 'itm', label: 'Inventory Items', icon: '📦', action: () => onNavigate('Inventory') },
        { id: 'set', label: 'Settings', icon: '⚙️', action: () => onNavigate('Settings') },
        { id: 'theme', label: 'Toggle Dark Mode', icon: '🌗', action: () => toggleTheme() },
    ];

    const filteredActions = actions.filter(a => a.label.toLowerCase().includes(query.toLowerCase()));

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[100] flex items-start justify-center pt-[20vh] px-4" onClick={onClose}>
            <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm transition-opacity" />
            <div 
                className="relative w-full max-w-lg bg-white dark:bg-slate-800 rounded-xl shadow-2xl overflow-hidden transform transition-all animate-scale-in border border-slate-200 dark:border-slate-700" 
                onClick={e => e.stopPropagation()}
            >
                <div className="flex items-center px-4 py-3 border-b border-slate-100 dark:border-slate-700">
                    <svg className="w-5 h-5 text-slate-400 mr-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                    <input 
                        ref={inputRef}
                        className="w-full bg-transparent text-lg text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none" 
                        placeholder="Type a command or search..."
                        value={query}
                        onChange={e => setQuery(e.target.value)}
                    />
                    <div className="text-xs font-mono text-slate-400 border border-slate-200 dark:border-slate-600 px-1.5 py-0.5 rounded">ESC</div>
                </div>
                <div className="max-h-[60vh] overflow-y-auto py-2">
                    {filteredActions.length > 0 ? (
                        filteredActions.map(action => (
                            <button 
                                key={action.id}
                                onClick={() => { action.action(); onClose(); }}
                                className="w-full text-left px-4 py-3 flex items-center gap-3 hover:bg-slate-100 dark:hover:bg-slate-700/50 text-slate-700 dark:text-slate-200 transition-colors group"
                            >
                                <span className="flex items-center justify-center w-8 h-8 rounded-lg bg-slate-100 dark:bg-slate-700 text-lg group-hover:bg-white dark:group-hover:bg-slate-600 transition-colors shadow-sm">{action.icon}</span>
                                <span className="font-medium">{action.label}</span>
                            </button>
                        ))
                    ) : (
                        <div className="px-4 py-8 text-center text-slate-500">No matching commands found.</div>
                    )}
                </div>
            </div>
        </div>
    );
};

