      setActiveCompanyId(firstCompany?.id || null);
  };

  const handleSignup = (email: string, pass: string, name: string): boolean => {
    if(users.some(u => u.email === email)) return false;
    const newUser: User = { id: Date.now().toString(), email, name, passwordHash: simpleHash(pass) };
    setUsers([...users, newUser]);
    setCurrentUser(newUser);
    setActiveCompanyId(null);
    return true;
  };

  const handleLogout = () => {
      setCurrentUser(null);
      setActiveCompanyId(null);
  };

  const handleCheckUser = (email: string): boolean => users.some(u => u.email === email);

  const handleResetPassword = (email: string, newPass: string): boolean => {
      if (!users.some(u => u.email === email)) return false;
      const updatedUsers = users.map(user => user.email === email ? { ...user, passwordHash: simpleHash(newPass) } : user);
      setUsers(updatedUsers);
      return true;
  };

  const handleUpdateProfile = (updatedUser: User) => {
      setUsers(users.map(u => u.id === updatedUser.id ? updatedUser : u));
      setCurrentUser(updatedUser);
  };

  const handleAddCompany = (companyDetails: CompanyDetails) => {
      if(!currentUser) return;
      const newCompany: Company = {
          id: `comp_${Date.now()}`,
          ownerId: currentUser.id,
          details: companyDetails,
          bankAccounts: [], clients: [], items: [], transporters: [], invoices: [], recurringInvoices: [], stockHistory: []
      };
      setCompanies([...companies, newCompany]);
      setActiveCompanyId(newCompany.id);
      setActiveView('Dashboard');
  };

  const handleCreateNewCompany = () => {
    if (newCompanyName.trim()) {
        handleAddCompany({ ...emptyCompanyDetails, name: newCompanyName.trim() });
        setIsAddCompanyModalOpen(false);
        setNewCompanyName('');
    }
  };

  const handleUpdateCompany = (updatedCompany: Company) => {
      setCompanies(companies.map(c => c.id === updatedCompany.id ? updatedCompany : c));
  };

  const handleSwitchCompany = (companyId: string) => {
      setActiveCompanyId(companyId);
      setActiveView('Dashboard');
  };

  const createStockLog = (
      itemId: string, 
      itemName: string, 
      prevQty: number, 
      newQty: number, 
      action: StockHistoryEntry['action'], 
      refId?: string
  ): StockHistoryEntry => ({
      id: `log_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
      itemId,
      itemName,
      previousQuantity: prevQty,
      newQuantity: newQty,
      action,
      timestamp: new Date().toISOString(),
      referenceId: refId
  });

  // --- Voice Assistant Handlers ---
  const handleVoiceAddClient = (client: Omit<Client, 'id'>) => {
      if (!activeCompany) return { success: false, message: 'No active company' };
      const existing = activeCompany.clients.find(c => c.name.toLowerCase() === client.name.toLowerCase());
      if (existing) return { success: false, message: `Client '${client.name}' already exists.` };
      const newClient: Client = { gstin: '', email: '', phone: '', address: '', city: '', state: '', zip: '', tags: [], ...client, id: `c_${Date.now()}` };
      handleUpdateCompany({ ...activeCompany, clients: [...activeCompany.clients, newClient] });
      return { success: true, message: `Client ${client.name} added successfully.` };
  };

  const handleVoiceAddItem = (item: Omit<Item, 'id'>) => {
      if (!activeCompany) return { success: false, message: 'No active company' };
      const existing = activeCompany.items.find(i => i.name.toLowerCase() === item.name.toLowerCase());
      if (existing) return { success: false, message: `Item '${item.name}' already exists.` };
      const newItem: Item = { hsn: '', unit: 'pcs', quantityInStock: 0, ...item, id: `i_${Date.now()}` };
      const log = createStockLog(newItem.id, newItem.name, 0, newItem.quantityInStock, 'Initial');
      handleUpdateCompany({ ...activeCompany, items: [...activeCompany.items, newItem], stockHistory: [...(activeCompany.stockHistory || []), log] });
      return { success: true, message: `Item ${item.name} added.` };
  };

  const handleVoiceUpdateStock = (itemName: string, quantity: number) => {
      if (!activeCompany) return { success: false, message: 'No company active' };
      const itemIndex = activeCompany.items.findIndex(i => i.name.toLowerCase() === itemName.toLowerCase());
      if (itemIndex > -1) {
          const updatedItems = [...activeCompany.items];
          const prevQty = updatedItems[itemIndex].quantityInStock;
          updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: quantity };
          const log = createStockLog(updatedItems[itemIndex].id, updatedItems[itemIndex].name, prevQty, quantity, 'Voice Update');
          handleUpdateCompany({ ...activeCompany, items: updatedItems, stockHistory: [...(activeCompany.stockHistory || []), log] });
          return { success: true, message: `Stock for ${itemName} updated to ${quantity}` };
      }
      return { success: false, message: `Item ${itemName} not found` };
  };

  const handleVoiceOpenEmailModal = (invoiceNumberQuery: string) => {
      if(!activeCompany) return { success: false, message: 'No company' };
      const invoice = activeCompany.invoices.find(inv => inv.invoiceNumber.toLowerCase().includes(invoiceNumberQuery.toLowerCase()));
      if(invoice) { setVoiceInvoiceToEmail(invoice); return { success: true, message: `Opening email for ${invoice.invoiceNumber}` }; }
      return { success: false, message: `Invoice ${invoiceNumberQuery} not found` };
  };

  const handleVoiceDraftInvoice = (clientName: string) => {
      if (!activeCompany) return { success: false, message: 'No active company' };
      const client = activeCompany.clients.find(c => c.name.toLowerCase().includes(clientName.toLowerCase()));
      setDraftInvoice(prev => ({ ...prev, clientId: client ? client.id : prev.clientId, items: [], shippingDetails: client ? { name: client.name, address: client.address, city: client.city, state: client.state, zip: client.zip, gstin: client.gstin } : prev.shippingDetails, isShippingSameAsBilling: true }));
      setActiveView('NewInvoice');
      setInvoiceToEdit(null); 
      if (!client) return { success: false, message: `Opened New Invoice. Client ${clientName} not found.` };
      return { success: true, message: `Started invoice for ${client.name}.` };
  };

  const handleVoiceAddDraftItem = (itemName: string, quantity: number) => {
      if (!activeCompany) return { success: false, message: 'No active company' };
      const item = activeCompany.items.find(i => i.name.toLowerCase().includes(itemName.toLowerCase()));
      if (!item) return { success: false, message: `Item ${itemName} not found.` };
      const newItem: InvoiceItem = { ...item, quantity };
      setDraftInvoice(prev => ({ ...prev, items: [...prev.items, newItem] }));
      if (activeView !== 'NewInvoice') setActiveView('NewInvoice');
      return { success: true, message: `Added ${quantity} ${item.name}(s).` };
  };

  const handleVoiceUpdateInvoiceDetails = (details: any) => {
      if (activeView !== 'NewInvoice') setActiveView('NewInvoice');
      setDraftInvoice(prev => ({ ...prev, ...details }));
      return { success: true, message: "Invoice details updated." };
  };
  const handleVoiceUpdateShippingDetails = (details: any) => {
      if (activeView !== 'NewInvoice') setActiveView('NewInvoice');
      setDraftInvoice(prev => ({ ...prev, isShippingSameAsBilling: false, shippingDetails: { ...prev.shippingDetails, ...details } }));
      return { success: true, message: "Shipping details updated." };
  };
  const handleVoiceRemoveInvoiceItem = (itemName: string) => {
      if (activeView !== 'NewInvoice') return { success: false, message: "Not on invoice page" };
      const index = draftInvoice.items.findIndex(i => i.name.toLowerCase().includes(itemName.toLowerCase()));
      if (index === -1) return { success: false, message: "Item not found" };
      const newItems = draftInvoice.items.filter((_, i) => i !== index);
      setDraftInvoice(prev => ({ ...prev, items: newItems }));
      return { success: true, message: `Removed ${itemName}.` };
  };

  const handleVoiceSaveInvoice = () => {
      if (activeView !== 'NewInvoice') return { success: false, message: "Not on invoice page" };
      if (!draftInvoice.clientId || draftInvoice.items.length === 0) return { success: false, message: "Missing client or items." };
      const client = activeCompany?.clients.find(c => c.id === draftInvoice.clientId);
      if(!client) return { success: false, message: "Client not found" };
      let subTotal = 0, cgst = 0, sgst = 0, igst = 0;
      const isIntraState = !draftInvoice.shippingDetails.state || draftInvoice.shippingDetails.state === activeCompany?.details.state;
      draftInvoice.items.forEach(item => {
          const t = item.price * item.quantity;
          subTotal += t;
          const tax = (t * item.gstRate) / 100;
          if (isIntraState) { cgst += tax/2; sgst += tax/2; } else { igst += tax; }
      });
      const commonData = {
          invoiceNumber: draftInvoice.invoiceNumber,
          client,
          items: draftInvoice.items,
          issueDate: draftInvoice.issueDate,
          dueDate: draftInvoice.dueDate,
          notes: draftInvoice.notes,
          selectedBankAccountId: draftInvoice.selectedBankAccountId,
          shippingName: draftInvoice.shippingDetails.name,
          shippingAddress: draftInvoice.shippingDetails.address,
          shippingCity: draftInvoice.shippingDetails.city,
          shippingState: draftInvoice.shippingDetails.state,
          shippingZip: draftInvoice.shippingDetails.zip,
          shippingGstin: draftInvoice.shippingDetails.gstin,
          vehicleNumber: draftInvoice.vehicleNumber,
          ewayBillNumber: draftInvoice.ewayBillNumber,
          subTotal, cgst, sgst, igst, grandTotal: subTotal + cgst + sgst + igst
      };
      if (invoiceToEdit) {
          handleSaveInvoice({ ...commonData, id: invoiceToEdit.id, status: invoiceToEdit.status });
      } else {
          handleSaveInvoice(commonData);
      }
      setActiveView('Invoices');
      return { success: true, message: invoiceToEdit ? "Invoice updated." : "Invoice saved." };
  };

  const handleVoiceDeleteClient = (clientName: string) => {
      if(!activeCompany) return { success: false, message: 'No active company' };
      const client = activeCompany.clients.find(c => c.name.toLowerCase().includes(clientName.toLowerCase()));
      if(client) {
          setActiveView('Clients');
          const updatedClients = activeCompany.clients.filter(c => c.id !== client.id);
          handleUpdateCompany({ ...activeCompany, clients: updatedClients });
          return { success: true, message: `Client ${client.name} deleted.` };
      }
      return { success: false, message: `Client ${clientName} not found` };
  };

  const handleVoiceDeleteInvoice = (invoiceNumber: string) => {
      if(!activeCompany) return { success: false, message: 'No active company' };
      const invoice = activeCompany.invoices.find(i => i.invoiceNumber.toLowerCase().includes(invoiceNumber.toLowerCase()));
      if(invoice) {
          setActiveView('Invoices');
          handleBulkDeleteInvoices([invoice.id]);
          return { success: true, message: `Invoice ${invoice.invoiceNumber} deleted.` };
      }
      return { success: false, message: `Invoice ${invoiceNumber} not found` };
  };

  const handleVoiceDeleteItem = (itemName: string) => {
      if(!activeCompany) return { success: false, message: 'No active company' };
      const item = activeCompany.items.find(i => i.name.toLowerCase().includes(itemName.toLowerCase()));
      if(item) {
          setActiveView('Items');
          handleBulkDeleteItems([item.id]);
          return { success: true, message: `Item ${item.name} deleted.` };
      }
      return { success: false, message: `Item ${itemName} not found` };
  };

  const handleVoiceUpdateInvoiceStatus = (invoiceNumber: string, status: string) => {
      if (!activeCompany) return { success: false, message: 'No company active' };
      const inv = activeCompany.invoices.find(i => i.invoiceNumber.toLowerCase().includes(invoiceNumber.toLowerCase()));
      if (inv) {
          const validStatus = ['Paid', 'Unpaid', 'Overdue'].find(s => s.toLowerCase() === status.toLowerCase());
          if (validStatus) {
              handleBulkStatusChange([inv.id], validStatus as Invoice['status']);
              return { success: true, message: `Invoice ${inv.invoiceNumber} marked as ${validStatus}` };
          }
          return { success: false, message: 'Invalid status. Use Paid, Unpaid, or Overdue.' };
      }
      return { success: false, message: 'Invoice not found' };
  };

  const handleVoiceUpdateCompanyInfo = (field: string, value: string) => {
      if (!activeCompany) return { success: false, message: 'No company active' };
      const validFields = ['name', 'phone', 'email', 'address', 'city', 'state', 'zip', 'gstin'];
      if (validFields.includes(field)) {
         const newDetails = { ...activeCompany.details, [field]: value };
         handleUpdateCompany({ ...activeCompany, details: newDetails });
         return { success: true, message: `Company ${field} updated.` };
      }
      return { success: false, message: `Cannot update field ${field}. Allowed: name, phone, email, address, etc.` };
  };

  const handleSaveInvoice = (invoiceData: Invoice | Omit<Invoice, 'id' | 'status'>) => {
        if (!activeCompany) return;
        let updatedItems = [...activeCompany.items];
        let updatedInvoices = [...activeCompany.invoices];
        let updatedDetails = { ...activeCompany.details };
        let newHistoryLogs: StockHistoryEntry[] = [];

        if ('id' in invoiceData) {
            const updatedInvoice = invoiceData as Invoice;
            const originalInvoice = activeCompany.invoices.find(inv => inv.id === updatedInvoice.id);
            if (!originalInvoice) return; 

            const originalItemsMap = new Map<string, number>(originalInvoice.items.map(item => [item.id, item.quantity] as [string, number]));
            const updatedItemsMap = new Map<string, number>(updatedInvoice.items.map(item => [item.id, item.quantity] as [string, number]));
            const allItemIds = new Set([...originalItemsMap.keys(), ...updatedItemsMap.keys()]);

            allItemIds.forEach(itemId => {
                const originalQty = originalItemsMap.get(itemId) || 0;
                const updatedQty = updatedItemsMap.get(itemId) || 0;
                const diff = originalQty - updatedQty; 

                if (diff !== 0) {
                    const itemIndex = updatedItems.findIndex(i => i.id === itemId);
                    if (itemIndex > -1) {
                        const prevStock = Number(updatedItems[itemIndex].quantityInStock) || 0;
                        const newStock = prevStock + diff;
                        updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: newStock };

                        newHistoryLogs.push(createStockLog(updatedItems[itemIndex].id, updatedItems[itemIndex].name, prevStock, newStock, 'Invoice Edited', updatedInvoice.invoiceNumber));
                    }
                }
            });
            updatedInvoices = updatedInvoices.map(inv => inv.id === updatedInvoice.id ? updatedInvoice : inv);
        } else {
            const newInvoiceData = invoiceData as Omit<Invoice, 'id' | 'status'>;
            const nextNumber = Number(activeCompany.details.nextInvoiceNumber || 1);
            const expectedInvoiceNumber = `${activeCompany.details.invoicePrefix || 'INV-'}${nextNumber.toString().padStart(3, '0')}`;

            newInvoiceData.items.forEach(soldItem => {
                const itemIndex = updatedItems.findIndex(i => i.id === soldItem.id);
                if (itemIndex > -1) {
                    const prevStock = Number(updatedItems[itemIndex].quantityInStock) || 0;
                    const newStock = prevStock - soldItem.quantity;
                    updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: newStock };
                    newHistoryLogs.push(createStockLog(updatedItems[itemIndex].id, updatedItems[itemIndex].name, prevStock, newStock, 'Invoice Created', newInvoiceData.invoiceNumber));
                }
            });
            const newInvoice: Invoice = { ...newInvoiceData, id: `inv_${Date.now()}`, status: 'Unpaid' };
            updatedInvoices.push(newInvoice);
            if (newInvoiceData.invoiceNumber === expectedInvoiceNumber) updatedDetails.nextInvoiceNumber = nextNumber + 1;
        }

        handleUpdateCompany({ ...activeCompany, items: updatedItems, invoices: updatedInvoices.sort((a,b) => b.invoiceNumber.localeCompare(a.invoiceNumber, undefined, {numeric: true})), details: updatedDetails, stockHistory: [...(activeCompany.stockHistory || []), ...newHistoryLogs] });
        setDraftInvoice(emptyDraftInvoice);
  };

    // ... (rest of the file remains largely similar with updated props) ...
    const handleDeleteInvoice = (invoiceId: string) => handleBulkDeleteInvoices([invoiceId]);
    const handleBulkDeleteInvoices = (ids: string[]) => {
        if (!activeCompany) return;
        let updatedItems = [...activeCompany.items];
        let newHistoryLogs: StockHistoryEntry[] = [];

        const invoicesToDelete = activeCompany.invoices.filter(inv => ids.includes(inv.id));
        invoicesToDelete.forEach(invoice => {
             invoice.items.forEach(soldItem => {
                const itemIndex = updatedItems.findIndex(i => i.id === soldItem.id);
                if (itemIndex > -1) {
                    const prevStock = Number(updatedItems[itemIndex].quantityInStock) || 0;
                    const newStock = prevStock + soldItem.quantity; 
                    updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: newStock };
                    newHistoryLogs.push(createStockLog(updatedItems[itemIndex].id, updatedItems[itemIndex].name, prevStock, newStock, 'Invoice Deleted', invoice.invoiceNumber));
                }
             });
        });
        const updatedInvoices = activeCompany.invoices.filter(inv => !ids.includes(inv.id));
        handleUpdateCompany({ ...activeCompany, items: updatedItems, invoices: updatedInvoices, stockHistory: [...(activeCompany.stockHistory || []), ...newHistoryLogs] });
    };

    const handleUpdateInvoiceStatus = (invoiceId: string, status: Invoice['status']) => handleBulkStatusChange([invoiceId], status);
    const handleBulkStatusChange = (ids: string[], status: Invoice['status']) => {
        if (!activeCompany) return;
        const updatedInvoices = activeCompany.invoices.map(inv => ids.includes(inv.id) ? { ...inv, status } : inv);
        handleUpdateCompany({ ...activeCompany, invoices: updatedInvoices });
    };
    const handleAddRecurring = (profile: Omit<RecurringInvoice, 'id'>) => { if (!activeCompany) return; handleUpdateCompany({ ...activeCompany, recurringInvoices: [...(activeCompany.recurringInvoices || []), { ...profile, id: `rec_${Date.now()}` }] }); };
    const handleUpdateRecurring = (updatedProfile: RecurringInvoice) => { if (!activeCompany) return; handleUpdateCompany({ ...activeCompany, recurringInvoices: activeCompany.recurringInvoices.map(r => r.id === updatedProfile.id ? updatedProfile : r) }); };
    const handleDeleteRecurring = (id: string) => { if (!activeCompany) return; handleUpdateCompany({ ...activeCompany, recurringInvoices: activeCompany.recurringInvoices.filter(r => r.id !== id) }); };
    const createCompanyDataUpdater = <T,>(dataType: keyof Omit<Company, 'id' | 'ownerId' | 'details' | 'invoices' | 'recurringInvoices' | 'stockHistory'>) => (data: T[]) => { if(!activeCompany) return; const updatedCompany = { ...activeCompany, [dataType]: data }; handleUpdateCompany(updatedCompany as Company); };
    const setClients = createCompanyDataUpdater<Client>('clients');
    const setItems = createCompanyDataUpdater<Item>('items');
    const setTransporters = createCompanyDataUpdater<Transporter>('transporters');
    const handleBulkStockUpdate = (updates: { itemId: string, newQuantity: number }[], actionType: StockHistoryEntry['action'] = 'Bulk Update') => { if (!activeCompany) return; const updatedItems = [...activeCompany.items]; const newHistoryLogs: StockHistoryEntry[] = []; updates.forEach(update => { const idx = updatedItems.findIndex(i => i.id === update.itemId); if (idx !== -1) { const prevQty = updatedItems[idx].quantityInStock; if (prevQty !== update.newQuantity) { updatedItems[idx] = { ...updatedItems[idx], quantityInStock: update.newQuantity }; newHistoryLogs.push(createStockLog(updatedItems[idx].id, updatedItems[idx].name, prevQty, update.newQuantity, actionType)); } } }); if (newHistoryLogs.length > 0) { handleUpdateCompany({ ...activeCompany, items: updatedItems, stockHistory: [...(activeCompany.stockHistory || []), ...newHistoryLogs] }); } };
    const handleBulkDeleteClients = (ids: string[]) => { if(!activeCompany) return; handleUpdateCompany({ ...activeCompany, clients: activeCompany.clients.filter(c => !ids.includes(c.id)) }); };
    const handleBulkDeleteItems = (ids: string[]) => { if(!activeCompany) return; handleUpdateCompany({ ...activeCompany, items: activeCompany.items.filter(i => !ids.includes(i.id)) }); };

  const handleEditInvoice = (invoiceId: string) => {
    const invoice = activeCompany?.invoices.find(inv => inv.id === invoiceId);
    if (invoice) {
      setInvoiceToEdit(invoice);
      setActiveView('NewInvoice');
    }
  };

  if (!currentUser) return <div className="w-full h-screen bg-slate-100 dark:bg-secondary-dark flex items-center justify-center"><Auth onLogin={handleLogin} onSignup={handleSignup} onGoogleLogin={handleGoogleLogin} onCheckUserExists={handleCheckUser} onResetPassword={handleResetPassword} /></div>;
  if (!activeCompany) return <CompanyManager onAddCompany={handleAddCompany} onLogout={handleLogout}/>;

  const renderView = () => {
    switch (activeView) {
      case 'Dashboard': return <Dashboard invoices={activeCompany.invoices} items={activeCompany.items} company={activeCompany} setActiveView={handleNavigate} />;
      case 'NewInvoice': return <NewInvoice company={activeCompany} saveInvoice={handleSaveInvoice} setActiveView={handleNavigate} invoiceToEdit={invoiceToEdit} clearEditingInvoice={() => setInvoiceToEdit(null)} onUpdateCompany={handleUpdateCompany} draftInvoice={draftInvoice} setDraftInvoice={setDraftInvoice} />;
      case 'Invoices': return <Invoices invoices={activeCompany.invoices} company={activeCompany} setActiveView={handleNavigate} onEdit={handleEditInvoice} onDelete={handleDeleteInvoice} onStatusChange={handleUpdateInvoiceStatus} onBulkDelete={handleBulkDeleteInvoices} onBulkStatusChange={handleBulkStatusChange} onAddRecurring={handleAddRecurring} onUpdateRecurring={handleUpdateRecurring} onDeleteRecurring={handleDeleteRecurring} />;
      case 'Clients': return <Clients clients={activeCompany.clients} setClients={setClients} invoices={activeCompany.invoices} company={activeCompany} onEditInvoice={handleEditInvoice} onDeleteInvoice={handleDeleteInvoice} onStatusChange={handleUpdateInvoiceStatus} onBulkDelete={handleBulkDeleteClients} />;
      case 'Items': return <Items items={activeCompany.items} setItems={setItems} company={activeCompany} onBulkDelete={handleBulkDeleteItems} />;
      case 'Inventory': return <Inventory items={activeCompany.items} setItems={setItems} onBulkStockUpdate={handleBulkStockUpdate} stockHistory={activeCompany.stockHistory || []} />;
      case 'Transporters': return <Transporters transporters={activeCompany.transporters} setTransporters={setTransporters} />;
      case 'Settings': return <Settings activeCompany={activeCompany} updateCompany={handleUpdateCompany} />;
      default: return <Dashboard invoices={activeCompany.invoices} items={activeCompany.items} company={activeCompany} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-100 dark:bg-secondary-dark font-sans transition-colors relative">
      <Sidebar 
        activeView={activeView} setActiveView={handleNavigate} theme={theme} setTheme={setTheme} 
        userCompanies={userCompanies} activeCompany={activeCompany} 
        onSwitchCompany={handleSwitchCompany}
        onAddCompany={() => setIsAddCompanyModalOpen(true)}
        onLogout={handleLogout}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
        currentUser={currentUser}
        onOpenProfile={() => setIsProfileOpen(true)}
      />
      <main className="flex-1 p-4 lg:p-8 overflow-y-auto">
        <div className="md:hidden mb-4 flex justify-between items-center">
            <button onClick={() => setIsSidebarOpen(true)} className="p-2 rounded-xl text-slate-600 dark:text-light-text hover:bg-white dark:hover:bg-tertiary-dark shadow-sm">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" /></svg>
            </button>
            <div className="text-xs font-medium text-slate-400">Cmd+K</div>
        </div>
        {renderView()}
      </main>

      <CommandPalette 
        isOpen={isPaletteOpen} 
        onClose={() => setIsPaletteOpen(false)} 
        onNavigate={handleNavigate}
        toggleTheme={() => setTheme(theme === 'dark' ? 'light' : 'dark')}
        onNewInvoice={() => { handleNavigate('NewInvoice'); }}
      />

      <VoiceAssistant 
        onNavigate={handleNavigate} 
        currentView={activeView}
        onAddClient={handleVoiceAddClient}
        onAddItem={handleVoiceAddItem}
        onUpdateStock={handleVoiceUpdateStock}
        dataContext={{
            clients: activeCompany.clients,
            items: activeCompany.items,
            invoices: activeCompany.invoices
        }}
        onOpenEmailModal={handleVoiceOpenEmailModal}
        onDraftInvoice={handleVoiceDraftInvoice}
        onAddDraftItem={handleVoiceAddDraftItem}
        onUpdateInvoiceDetails={handleVoiceUpdateInvoiceDetails}
        onUpdateShippingDetails={handleVoiceUpdateShippingDetails}
        onRemoveInvoiceItem={handleVoiceRemoveInvoiceItem}
        onSaveDraftInvoice={handleVoiceSaveInvoice}
        onDeleteClient={handleVoiceDeleteClient}
        onDeleteInvoice={handleVoiceDeleteInvoice}
        onDeleteItem={handleVoiceDeleteItem}
        onUpdateInvoiceStatus={handleVoiceUpdateInvoiceStatus}
        onUpdateCompanyInfo={handleVoiceUpdateCompanyInfo}
      />

       <Modal isOpen={isAddCompanyModalOpen} onClose={() => setIsAddCompanyModalOpen(false)} title="Create New Company">
          <div className="p-6 space-y-4">
            <Input label="Company Name" id="new-company-name" value={newCompanyName} onChange={(e) => setNewCompanyName(e.target.value)} placeholder="Enter your new company's name" required />
          </div>
          <div className="p-6 pt-0 flex justify-end gap-4">
            <Button variant="secondary" onClick={() => { setIsAddCompanyModalOpen(false); setNewCompanyName(''); }}>Cancel</Button>
            <Button onClick={handleCreateNewCompany} disabled={!newCompanyName.trim()}>Create Company</Button>
          </div>
        </Modal>

        <Modal isOpen={isProfileOpen} onClose={() => setIsProfileOpen(false)} title="User Profile">
            {currentUser && <UserProfile user={currentUser} onUpdateProfile={handleUpdateProfile} onClose={() => setIsProfileOpen(false)} />}
        </Modal>

        {voiceInvoiceToEmail && (
            <Modal isOpen={true} onClose={() => setVoiceInvoiceToEmail(null)} title={`Email Invoice #${voiceInvoiceToEmail.invoiceNumber}`}>
                <div className="p-6 text-center">
                    <p className="text-slate-600 dark:text-slate-300 mb-4">The email functionality for <strong>{voiceInvoiceToEmail.invoiceNumber}</strong> has been triggered by your voice command.</p>
                    <p className="text-sm text-slate-500">(In a real app, this would pre-fill and send the email. For now, it opens this confirmation.)</p>
                    <div className="mt-6 flex justify-center gap-4">
                        <Button variant="secondary" onClick={() => setVoiceInvoiceToEmail(null)}>Close</Button>
                        <Button onClick={() => { alert(`Email sent to ${voiceInvoiceToEmail.client.email}`); setVoiceInvoiceToEmail(null); }}>Send Email Now</Button>
                    </div>
                </div>
            </Modal>
        )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import type { Invoice, Item, InvoiceItem, Company, DraftInvoice } from '../types';
import Input from './common/Input';
import Button from './common/Button';
import Modal from './common/Modal';
import { INDIAN_STATES } from '../constants';

interface NewInvoiceProps {
  company: Company;
  saveInvoice: (invoice: Omit<Invoice, 'id' | 'status'> | Invoice) => void;
  setActiveView: (view: string) => void;
  invoiceToEdit?: Invoice | null;
  clearEditingInvoice: () => void;
  onUpdateCompany: (updatedCompany: Company) => void;
  draftInvoice: DraftInvoice;
  setDraftInvoice: React.Dispatch<React.SetStateAction<DraftInvoice>>;
}

const ITEM_UNITS = ['pcs', 'kgs', 'ltr', 'nos', 'box', 'pkt', 'gram', 'set', 'pair', 'm', 'cm', 'ft', 'sqft'];

const NewInvoice: React.FC<NewInvoiceProps> = ({ 
    company, saveInvoice, setActiveView, 
    invoiceToEdit, clearEditingInvoice, onUpdateCompany,
    draftInvoice, setDraftInvoice
}) => {
    const isEditing = !!invoiceToEdit;
    const [isCreateItemModalOpen, setIsCreateItemModalOpen] = useState(false);
    const [newItemData, setNewItemData] = useState<Partial<Item>>({ name: '', price: 0, gstRate: 18, unit: 'pcs', quantityInStock: 0 });

    // Initialize editing state if needed
    useEffect(() => {
        if (invoiceToEdit) {
            const client = invoiceToEdit.client;
            setDraftInvoice({
                invoiceNumber: invoiceToEdit.invoiceNumber,
                clientId: client.id,
                items: invoiceToEdit.items,
                issueDate: invoiceToEdit.issueDate,
                dueDate: invoiceToEdit.dueDate,
                notes: invoiceToEdit.notes,
                selectedBankAccountId: invoiceToEdit.selectedBankAccountId,
                shippingDetails: {
                    name: invoiceToEdit.shippingName || client.name,
                    address: invoiceToEdit.shippingAddress || client.address,
                    city: invoiceToEdit.shippingCity || client.city,
                    state: invoiceToEdit.shippingState || client.state,
                    zip: invoiceToEdit.shippingZip || client.zip,
                    gstin: invoiceToEdit.shippingGstin || client.gstin
                },
                isShippingSameAsBilling: 
                    (invoiceToEdit.shippingAddress === client.address && 
                     invoiceToEdit.shippingState === client.state) || !invoiceToEdit.shippingAddress,
                transporterId: '', 
                vehicleNumber: invoiceToEdit.vehicleNumber || '',
                ewayBillNumber: invoiceToEdit.ewayBillNumber || ''
            });
        }
    }, [invoiceToEdit, setDraftInvoice]);

    // Handlers
    const handleClientChange = (clientId: string) => {
        const client = company.clients.find(c => c.id === clientId);
        setDraftInvoice(prev => ({
            ...prev,
            clientId: clientId,
            isShippingSameAsBilling: true, // Always reset to safe default when changing client
            shippingDetails: client ? {
                name: client.name,
                address: client.address,
                city: client.city,
                state: client.state,
                zip: client.zip,
                gstin: client.gstin
            } : prev.shippingDetails
        }));
    };

    const handleShippingChange = (field: string, value: string) => {
        setDraftInvoice(prev => ({
            ...prev,
            shippingDetails: { ...prev.shippingDetails, [field]: value }
        }));
    };

    const handleItemChange = (index: number, field: keyof InvoiceItem, value: any) => {
        const updatedItems = [...draftInvoice.items];
        const currentItem = { ...updatedItems[index] };

        if (field === 'id') {
            const selectedItem = company.items.find(i => i.id === value);
            if (selectedItem) {
                // Populate row with selected item details
                updatedItems[index] = { 
                    ...currentItem, 
                    ...selectedItem, 
                    id: selectedItem.id, // Ensure ID is linked
                    quantity: currentItem.quantity || 1 
                };
            } else {
                // Clear the row if "Select Item" is chosen (empty ID)
                // This allows the user to then type a custom item name
                updatedItems[index] = {
                    ...currentItem,
                    id: '', 
                    name: '', 
                    price: 0, 
                    gstRate: 18, 
                    hsn: '', 
                    unit: 'pcs'
                };
            }
        } else {
            updatedItems[index] = { ...currentItem, [field]: value };
        }
        setDraftInvoice(prev => ({ ...prev, items: updatedItems }));
    };

    const handleRemoveItem = (index: number) => {
        const updatedItems = draftInvoice.items.filter((_, i) => i !== index);
        setDraftInvoice(prev => ({ ...prev, items: updatedItems }));
    };

    const handleAddItem = () => {
        setDraftInvoice(prev => ({
            ...prev, 
            items: [...prev.items, { id: '', name: '', hsn: '', price: 0, gstRate: 18, quantity: 1, unit: 'pcs', quantityInStock: 0 }]
        }));
    };

    const handleCreateNewItem = () => {
        if (!newItemData.name) return;
        const newItem: Item = {
            id: `item_${Date.now()}`,
            name: newItemData.name,
            price: Number(newItemData.price) || 0,
            gstRate: Number(newItemData.gstRate) || 0,
            unit: newItemData.unit || 'pcs',
            hsn: newItemData.hsn || '',
            quantityInStock: Number(newItemData.quantityInStock) || 0
        };
        onUpdateCompany({ ...company, items: [...company.items, newItem] });
        setIsCreateItemModalOpen(false);
    };

    const calculateTotals = () => {
        let subTotal = 0, cgst = 0, sgst = 0, igst = 0;
        const client = company.clients.find(c => c.id === draftInvoice.clientId);

        const posState = !draftInvoice.isShippingSameAsBilling && draftInvoice.shippingDetails.state 
            ? draftInvoice.shippingDetails.state 
            : (client?.state || '');

        const companyState = company.details.state || '';
        const isIntraState = !posState || !companyState || posState.toLowerCase() === companyState.toLowerCase();

        draftInvoice.items.forEach(item => {
            const taxable = item.price * item.quantity;
            subTotal += taxable;
            const taxAmount = (taxable * item.gstRate) / 100;
            if (isIntraState) { 
                cgst += taxAmount / 2; 
                sgst += taxAmount / 2; 
            } else { 
                igst += taxAmount; 
            }
        });

        return { subTotal, cgst, sgst, igst, grandTotal: subTotal + cgst + sgst + igst };
    };

    const totals = calculateTotals();

    const handleSave = () => {
        // Strict Validation
        if (!draftInvoice.clientId) {
            alert("Please select a Client.");
            return;
        }
        if (draftInvoice.items.length === 0) {
            alert("Please add at least one item.");
            return;
        }

        // Validate incomplete items
        const invalidItem = draftInvoice.items.find(i => !i.name.trim() || i.quantity <= 0 || i.price < 0);
        if (invalidItem) {
            alert("One or more items have missing names, invalid quantity, or negative price.");
            return;
        }

        const client = company.clients.find(c => c.id === draftInvoice.clientId);
        if(!client) return;

        const shippingData = draftInvoice.isShippingSameAsBilling ? {
            name: client.name,
            address: client.address,
            city: client.city,
            state: client.state,
            zip: client.zip,
            gstin: client.gstin
        } : draftInvoice.shippingDetails;

        const finalInvoice: Omit<Invoice, 'id' | 'status'> | Invoice = {
            ...(isEditing && invoiceToEdit ? { id: invoiceToEdit.id, status: invoiceToEdit.status } : {}),
            invoiceNumber: draftInvoice.invoiceNumber,
            client: client,
            items: draftInvoice.items,
            issueDate: draftInvoice.issueDate,
            dueDate: draftInvoice.dueDate,
            notes: draftInvoice.notes,
            subTotal: totals.subTotal,
            cgst: totals.cgst,
            sgst: totals.sgst,
            igst: totals.igst,
            grandTotal: totals.grandTotal,
            selectedBankAccountId: draftInvoice.selectedBankAccountId,
            shippingName: shippingData.name,
            shippingAddress: shippingData.address,
            shippingCity: shippingData.city,
            shippingState: shippingData.state,
            shippingZip: shippingData.zip,
            shippingGstin: shippingData.gstin,
            transporterName: draftInvoice.transporterId === 'self' ? 'Self' : company.transporters.find(t => t.id === draftInvoice.transporterId)?.name,
            vehicleNumber: draftInvoice.vehicleNumber,
            ewayBillNumber: draftInvoice.ewayBillNumber
        };

        saveInvoice(finalInvoice);
        setActiveView('Invoices');
        clearEditingInvoice();
    };

    return (
        <div className="max-w-6xl mx-auto pb-20 animate-fade-in">
             <div className="flex justify-between items-center mb-6">
                <div className="flex items-center gap-4">
                     <button onClick={() => { setActiveView('Invoices'); clearEditingInvoice(); }} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 text-slate-500 transition-colors">
                        <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                     </button>
                     <h1 className="text-2xl font-bold text-slate-900 dark:text-light-text">{isEditing ? 'Edit Invoice' : 'New Invoice'}</h1>
                </div>
                <div className="flex gap-3">
                    <Button variant="secondary" onClick={() => { setActiveView('Invoices'); clearEditingInvoice(); }}>Cancel</Button>
                    <Button onClick={handleSave} className="shadow-lg shadow-accent/20">Save Invoice</Button>
                </div>
             </div>

             <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-6">
                 {/* Left Column: Client & Shipping */}
                 <div className="lg:col-span-2 space-y-6">
                     <div className="bg-white dark:bg-primary-dark p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800">
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                             {/* Bill To */}
                             <div>
                                 <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Bill To</label>
                                 <select 
                                    className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-900 dark:text-white rounded-xl px-4 py-3 focus:ring-2 focus:ring-accent focus:outline-none transition-shadow mb-4 cursor-pointer"
                                    value={draftInvoice.clientId}
                                    onChange={(e) => handleClientChange(e.target.value)}
                                 >
                                     <option value="">Select Client</option>
                                     {company.clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                                 </select>

                                 <div className="grid grid-cols-2 gap-4">
                                     <Input label="Invoice #" value={draftInvoice.invoiceNumber} onChange={e => setDraftInvoice({...draftInvoice, invoiceNumber: e.target.value})} />
                                     <Input label="Issue Date" type="date" value={draftInvoice.issueDate} onChange={e => setDraftInvoice({...draftInvoice, issueDate: e.target.value})} />
                                 </div>
                             </div>

                             {/* Ship To */}
                             <div className="border-l border-slate-100 dark:border-slate-700 pl-0 md:pl-6 pt-6 md:pt-0 border-t md:border-t-0">
                                 <div className="flex justify-between items-center mb-2">
                                     <label className="block text-xs font-bold text-slate-500 uppercase">Ship To</label>
                                     <div className="flex items-center gap-2">
                                         <input 
                                            type="checkbox" 
                                            id="sameAsBilling"
                                            className="rounded text-accent focus:ring-accent"
                                            checked={draftInvoice.isShippingSameAsBilling}
                                            onChange={(e) => setDraftInvoice(prev => ({ ...prev, isShippingSameAsBilling: e.target.checked }))}
                                         />
                                         <label htmlFor="sameAsBilling" className="text-xs text-slate-500 cursor-pointer">Same as Billing</label>
                                     </div>
                                 </div>

                                 {draftInvoice.isShippingSameAsBilling ? (
                                     <div className="p-4 bg-slate-50 dark:bg-slate-800/50 rounded-xl text-sm text-slate-500 dark:text-slate-400 italic text-center h-[120px] flex items-center justify-center border border-dashed border-slate-200 dark:border-slate-700">
                                         Shipping address same as billing.
                                     </div>
                                 ) : (
                                     <div className="space-y-3 animate-fade-in">
                                         <Input label="Shipping Name" value={draftInvoice.shippingDetails.name} onChange={e => handleShippingChange('name', e.target.value)} className="!py-2 !text-xs" />
                                         <Input label="Address" value={draftInvoice.shippingDetails.address} onChange={e => handleShippingChange('address', e.target.value)} className="!py-2 !text-xs" />
                                         <div className="grid grid-cols-2 gap-2">
                                             <Input label="City" value={draftInvoice.shippingDetails.city} onChange={e => handleShippingChange('city', e.target.value)} className="!py-2 !text-xs" />
                                             <Input label="Zip" value={draftInvoice.shippingDetails.zip} onChange={e => handleShippingChange('zip', e.target.value)} className="!py-2 !text-xs" />
                                         </div>
                                         <div className="grid grid-cols-2 gap-2">
                                             <div>
                                                 <select 
                                                    value={draftInvoice.shippingDetails.state} 
                                                    onChange={e => handleShippingChange('state', e.target.value)}
                                                    className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl px-3 py-2 text-xs focus:ring-1 focus:ring-accent"
                                                 >
                                                     <option value="">State</option>
                                                     {INDIAN_STATES.map(s => <option key={s} value={s}>{s}</option>)}
                                                 </select>
                                             </div>
                                             <Input label="GSTIN" value={draftInvoice.shippingDetails.gstin} onChange={e => handleShippingChange('gstin', e.target.value)} className="!py-2 !text-xs" />
                                         </div>
                                     </div>
                                 )}
                             </div>
                         </div>
                     </div>
                 </div>

                 {/* Right Column: Other Details */}
                 <div className="lg:col-span-1 space-y-6">
                     <div className="bg-white dark:bg-primary-dark p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800">
                         <h4 className="text-xs font-bold text-slate-500 uppercase mb-4">Payment & Transport</h4>
                         <div className="space-y-4">
                            <Input label="Due Date" type="date" value={draftInvoice.dueDate} onChange={e => setDraftInvoice({...draftInvoice, dueDate: e.target.value})} />
                            <div>
                                <label className="block text-xs font-bold text-slate-500 mb-1">Bank Account</label>
                                <select className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg px-3 py-2 text-sm" value={draftInvoice.selectedBankAccountId || ''} onChange={e => setDraftInvoice({...draftInvoice, selectedBankAccountId: e.target.value})}>
                                    <option value="">None (Cash/Cheque)</option>
                                    {company.bankAccounts.map(b => <option key={b.id} value={b.id}>{b.bankName} - {b.accountNumber}</option>)}
                                </select>
                            </div>
                            <div className="grid grid-cols-2 gap-2">
                                <Input label="Vehicle No." value={draftInvoice.vehicleNumber} onChange={e => setDraftInvoice({...draftInvoice, vehicleNumber: e.target.value})} placeholder="MH01AB1234" />
                                <Input label="E-Way Bill" value={draftInvoice.ewayBillNumber} onChange={e => setDraftInvoice({...draftInvoice, ewayBillNumber: e.target.value})} placeholder="Optional" />
                            </div>
                         </div>
                     </div>
                 </div>
             </div>

             {/* Items Section */}
             <div className="bg-white dark:bg-primary-dark p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden mb-6">
                 <div className="flex justify-between items-center mb-4">
                    <h3 className="text-lg font-bold text-slate-900 dark:text-white">Items</h3>
                    <Button variant="secondary" onClick={() => setIsCreateItemModalOpen(true)} className="text-xs">+ New Item</Button>
                 </div>

                 <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-slate-50 dark:bg-slate-800/50 text-xs text-slate-500 uppercase font-semibold">
                            <tr>
                                <th className="px-4 py-3 min-w-[200px]">Item Description</th>
                                <th className="px-4 py-3 w-24 text-center">Qty</th>
                                <th className="px-4 py-3 w-24 text-center">Unit</th>
                                <th className="px-4 py-3 w-32 text-right">Price</th>
                                <th className="px-4 py-3 w-20 text-center">GST%</th>
                                <th className="px-4 py-3 w-32 text-right">Amount</th>
                                <th className="px-4 py-3 w-10"></th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                            {draftInvoice.items.map((item, index) => (
                                <tr key={index} className="group hover:bg-slate-50 dark:hover:bg-slate-800/20">
                                    <td className="p-3">
                                        <select 
                                            className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg px-3 py-2 text-sm focus:ring-1 focus:ring-accent focus:outline-none cursor-pointer"
                                            value={item.id || ''}
                                            onChange={e => handleItemChange(index, 'id', e.target.value)}
                                        >
                                            <option value="">Select Item</option>
                                            {company.items.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
                                        </select>
                                        <div className="mt-1">
                                            {item.id ? (
                                                <div className="text-[10px] text-slate-400">HSN: {item.hsn || 'N/A'} | Stock: {item.quantityInStock}</div>
                                            ) : (
                                                <input 
                                                    className="w-full bg-transparent border-b border-dashed border-slate-300 dark:border-slate-700 text-xs py-1 focus:outline-none placeholder-slate-400 text-slate-600 dark:text-slate-300" 
                                                    placeholder="Type custom item name..."
                                                    value={item.name}
                                                    onChange={e => handleItemChange(index, 'name', e.target.value)}
                                                />
                                            )}
                                        </div>
                                    </td>
                                    <td className="p-3">
                                        <input type="number" min="0" className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg px-2 py-2 text-center focus:ring-1 focus:ring-accent focus:outline-none" value={item.quantity} onChange={e => handleItemChange(index, 'quantity', parseFloat(e.target.value) || 0)} />
                                    </td>
                                    <td className="p-3">
                                        <select className="w-full bg-transparent border-b border-transparent focus:border-accent focus:outline-none py-1 text-center" value={item.unit} onChange={e => handleItemChange(index, 'unit', e.target.value)}>
                                            {ITEM_UNITS.map(u => <option key={u} value={u}>{u}</option>)}
                                        </select>
                                    </td>
                                    <td className="p-3">
                                        <input type="number" min="0" className="w-full bg-transparent border-b border-transparent focus:border-accent focus:outline-none py-1 text-right" value={item.price} onChange={e => handleItemChange(index, 'price', parseFloat(e.target.value) || 0)} />
                                    </td>
                                    <td className="p-3">
                                        <input type="number" min="0" className="w-full bg-transparent border-b border-transparent focus:border-accent focus:outline-none py-1 text-center" value={item.gstRate} onChange={e => handleItemChange(index, 'gstRate', parseFloat(e.target.value) || 0)} />
                                    </td>
                                    <td className="p-3 text-right font-medium text-slate-900 dark:text-white">
                                        ₹{(item.price * item.quantity).toFixed(2)}
                                    </td>
                                    <td className="p-3 text-center">
                                        <button onClick={() => handleRemoveItem(index)} className="text-slate-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all">
                                            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                                        </button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                 </div>
                 <button onClick={handleAddItem} className="w-full py-3 text-center text-sm font-bold text-accent hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors border-t border-slate-100 dark:border-slate-800 mt-2">
                     + Add Another Item
                 </button>
             </div>

             <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                 <div className="space-y-4">
                    <label className="block text-xs font-bold text-slate-500 mb-1">Notes / Terms & Conditions</label>
                    <textarea className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg p-3 text-sm focus:ring-accent focus:border-accent outline-none" placeholder="e.g. Payment due within 15 days" rows={4} value={draftInvoice.notes} onChange={e => setDraftInvoice({...draftInvoice, notes: e.target.value})} />
                 </div>

                 <div className="bg-white dark:bg-primary-dark p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 h-fit">
                     <h4 className="text-sm font-bold text-slate-500 uppercase mb-4 border-b border-slate-100 dark:border-slate-700 pb-2">Amount Due</h4>
                     <div className="space-y-3 text-sm">
                         <div className="flex justify-between text-slate-600 dark:text-slate-400">
                             <span>Subtotal</span>
                             <span>₹{totals.subTotal.toFixed(2)}</span>
                         </div>
                         {(totals.cgst > 0 || totals.sgst > 0) && (
                             <>
                                <div className="flex justify-between text-slate-600 dark:text-slate-400">
                                    <span>CGST</span>
                                    <span>₹{totals.cgst.toFixed(2)}</span>
                                </div>
                                <div className="flex justify-between text-slate-600 dark:text-slate-400">
                                    <span>SGST</span>
                                    <span>₹{totals.sgst.toFixed(2)}</span>
                                </div>
                             </>
                         )}
                         {totals.igst > 0 && (
                             <div className="flex justify-between text-slate-600 dark:text-slate-400">
                                 <span>IGST</span>
                                 <span>₹{totals.igst.toFixed(2)}</span>
                             </div>
                         )}
                         <div className="border-t border-slate-100 dark:border-slate-800 my-3 pt-3 flex justify-between items-center">
                             <span className="text-lg font-bold text-slate-900 dark:text-white">Grand Total</span>
                             <span className="text-2xl font-black text-accent">₹{totals.grandTotal.toFixed(2)}</span>
                         </div>
                     </div>
                 </div>
             </div>

             <Modal isOpen={isCreateItemModalOpen} onClose={() => setIsCreateItemModalOpen(false)} title="Create New Item">
                 <div className="p-6 space-y-4">
                     <Input label="Name" value={newItemData.name || ''} onChange={e => setNewItemData({...newItemData, name: e.target.value})} required />
                     <div className="grid grid-cols-2 gap-4">
                         <Input label="Price (₹)" type="number" min="0" value={newItemData.price} onChange={e => setNewItemData({...newItemData, price: parseFloat(e.target.value) || 0})} required />
                         <Input label="GST Rate (%)" type="number" min="0" value={newItemData.gstRate} onChange={e => setNewItemData({...newItemData, gstRate: parseFloat(e.target.value) || 0})} required />
                     </div>
                 </div>
                 <div className="p-6 pt-0 flex justify-end gap-3">
                     <Button variant="secondary" onClick={() => setIsCreateItemModalOpen(false)}>Cancel</Button>
                     <Button onClick={handleCreateNewItem}>Create Item</Button>
                 </div>
             </Modal>
        </div>
    );
};

