          // Explicitly clear editing state when user clicks "New Invoice"
          setInvoiceToEdit(null);
          setDraftInvoice(prev => ({
              ...emptyDraftInvoice, 
              invoiceNumber: prev.invoiceNumber, // Preserve the correctly calculated next number
              selectedBankAccountId: prev.selectedBankAccountId // Preserve default bank
          }));
      }
      setActiveView(view);
      setIsSidebarOpen(false); 
  };

  // ... (Auth, Company, and most logic remains the same) ...
  const handleLogin = (email: string, pass: string): boolean => {
