      setActiveView('Dashboard');
  };

  const createStockLog = (
      itemId: string, 
      itemName: string, 
      prevQty: number, 
      newQty: number, 
      action: StockHistoryEntry['action'], 
      refId?: string
  ): StockHistoryEntry => ({
      id: `log_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
      itemId,
      itemName,
      previousQuantity: prevQty,
      newQuantity: newQty,
      action,
      timestamp: new Date().toISOString(),
      referenceId: refId
  });

  // --- Voice Assistant Handlers ---
  const handleVoiceAddClient = (client: Omit<Client, 'id'>) => {
      if (!activeCompany) return { success: false, message: 'No active company' };
      const existing = activeCompany.clients.find(c => c.name.toLowerCase() === client.name.toLowerCase());
      if (existing) return { success: false, message: `Client '${client.name}' already exists.` };
      const newClient: Client = { gstin: '', email: '', phone: '', address: '', city: '', state: '', zip: '', tags: [], ...client, id: `c_${Date.now()}` };
      handleUpdateCompany({ ...activeCompany, clients: [...activeCompany.clients, newClient] });
      return { success: true, message: `Client ${client.name} added successfully.` };
  };

  const handleVoiceAddItem = (item: Omit<Item, 'id'>) => {
      if (!activeCompany) return { success: false, message: 'No active company' };
      const existing = activeCompany.items.find(i => i.name.toLowerCase() === item.name.toLowerCase());
      if (existing) return { success: false, message: `Item '${item.name}' already exists.` };
      const newItem: Item = { hsn: '', unit: 'pcs', quantityInStock: 0, ...item, id: `i_${Date.now()}` };
      const log = createStockLog(newItem.id, newItem.name, 0, newItem.quantityInStock, 'Initial');
      handleUpdateCompany({ ...activeCompany, items: [...activeCompany.items, newItem], stockHistory: [...(activeCompany.stockHistory || []), log] });
      return { success: true, message: `Item ${item.name} added.` };
  };

  const handleVoiceUpdateStock = (itemName: string, quantity: number) => {
      if (!activeCompany) return { success: false, message: 'No company active' };
      const itemIndex = activeCompany.items.findIndex(i => i.name.toLowerCase() === itemName.toLowerCase());
      if (itemIndex > -1) {
          const updatedItems = [...activeCompany.items];
          const prevQty = updatedItems[itemIndex].quantityInStock;
          updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: quantity };
          const log = createStockLog(updatedItems[itemIndex].id, updatedItems[itemIndex].name, prevQty, quantity, 'Voice Update');
          handleUpdateCompany({ ...activeCompany, items: updatedItems, stockHistory: [...(activeCompany.stockHistory || []), log] });
          return { success: true, message: `Stock for ${itemName} updated to ${quantity}` };
      }
      return { success: false, message: `Item ${itemName} not found` };
  };

  const handleVoiceOpenEmailModal = (invoiceNumberQuery: string) => {
      if(!activeCompany) return { success: false, message: 'No company' };
      const invoice = activeCompany.invoices.find(inv => inv.invoiceNumber.toLowerCase().includes(invoiceNumberQuery.toLowerCase()));
      if(invoice) { setVoiceInvoiceToEmail(invoice); return { success: true, message: `Opening email for ${invoice.invoiceNumber}` }; }
      return { success: false, message: `Invoice ${invoiceNumberQuery} not found` };
  };

  const handleVoiceDraftInvoice = (clientName: string) => {
      if (!activeCompany) return { success: false, message: 'No active company' };
      const client = activeCompany.clients.find(c => c.name.toLowerCase().includes(clientName.toLowerCase()));
      setDraftInvoice(prev => ({ ...prev, clientId: client ? client.id : prev.clientId, items: [], shippingDetails: client ? { name: client.name, address: client.address, city: client.city, state: client.state, zip: client.zip, gstin: client.gstin } : prev.shippingDetails, isShippingSameAsBilling: true }));
      setActiveView('NewInvoice');
      setInvoiceToEdit(null); 
      if (!client) return { success: false, message: `Opened New Invoice. Client ${clientName} not found.` };
      return { success: true, message: `Started invoice for ${client.name}.` };
  };

  const handleVoiceAddDraftItem = (itemName: string, quantity: number) => {
      if (!activeCompany) return { success: false, message: 'No active company' };
      const item = activeCompany.items.find(i => i.name.toLowerCase().includes(itemName.toLowerCase()));
      if (!item) return { success: false, message: `Item ${itemName} not found.` };
      const newItem: InvoiceItem = { ...item, quantity };
      setDraftInvoice(prev => ({ ...prev, items: [...prev.items, newItem] }));
      if (activeView !== 'NewInvoice') setActiveView('NewInvoice');
      return { success: true, message: `Added ${quantity} ${item.name}(s).` };
  };

  const handleVoiceUpdateInvoiceDetails = (details: any) => {
      if (activeView !== 'NewInvoice') setActiveView('NewInvoice');
      setDraftInvoice(prev => ({ ...prev, ...details }));
      return { success: true, message: "Invoice details updated." };
  };
  const handleVoiceUpdateShippingDetails = (details: any) => {
      if (activeView !== 'NewInvoice') setActiveView('NewInvoice');
      setDraftInvoice(prev => ({ ...prev, isShippingSameAsBilling: false, shippingDetails: { ...prev.shippingDetails, ...details } }));
      return { success: true, message: "Shipping details updated." };
  };
  const handleVoiceRemoveInvoiceItem = (itemName: string) => {
      if (activeView !== 'NewInvoice') return { success: false, message: "Not on invoice page" };
      const index = draftInvoice.items.findIndex(i => i.name.toLowerCase().includes(itemName.toLowerCase()));
      if (index === -1) return { success: false, message: "Item not found" };
      const newItems = draftInvoice.items.filter((_, i) => i !== index);
      setDraftInvoice(prev => ({ ...prev, items: newItems }));
      return { success: true, message: `Removed ${itemName}.` };
  };

  const handleVoiceSaveInvoice = () => {
      if (activeView !== 'NewInvoice') return { success: false, message: "Not on invoice page" };
      if (!draftInvoice.clientId || draftInvoice.items.length === 0) return { success: false, message: "Missing client or items." };
      const client = activeCompany?.clients.find(c => c.id === draftInvoice.clientId);
      if(!client) return { success: false, message: "Client not found" };
      let subTotal = 0, cgst = 0, sgst = 0, igst = 0;
      const isIntraState = !draftInvoice.shippingDetails.state || draftInvoice.shippingDetails.state === activeCompany?.details.state;
      draftInvoice.items.forEach(item => {
          const t = item.price * item.quantity;
          subTotal += t;
          const tax = (t * item.gstRate) / 100;
          if (isIntraState) { cgst += tax/2; sgst += tax/2; } else { igst += tax; }
      });
      const commonData = {
          invoiceNumber: draftInvoice.invoiceNumber,
          client,
          items: draftInvoice.items,
          issueDate: draftInvoice.issueDate,
          dueDate: draftInvoice.dueDate,
          notes: draftInvoice.notes,
          selectedBankAccountId: draftInvoice.selectedBankAccountId,
          shippingName: draftInvoice.shippingDetails.name,
          shippingAddress: draftInvoice.shippingDetails.address,
          shippingCity: draftInvoice.shippingDetails.city,
          shippingState: draftInvoice.shippingDetails.state,
          shippingZip: draftInvoice.shippingDetails.zip,
          shippingGstin: draftInvoice.shippingDetails.gstin,
          vehicleNumber: draftInvoice.vehicleNumber,
          ewayBillNumber: draftInvoice.ewayBillNumber,
          subTotal, cgst, sgst, igst, grandTotal: subTotal + cgst + sgst + igst
      };
      if (invoiceToEdit) {
          handleSaveInvoice({ ...commonData, id: invoiceToEdit.id, status: invoiceToEdit.status });
      } else {
          handleSaveInvoice(commonData);
      }
      setActiveView('Invoices');
      return { success: true, message: invoiceToEdit ? "Invoice updated." : "Invoice saved." };
  };

  const handleVoiceDeleteClient = (clientName: string) => {
      if(!activeCompany) return { success: false, message: 'No active company' };
      const client = activeCompany.clients.find(c => c.name.toLowerCase().includes(clientName.toLowerCase()));
      if(client) {
          setActiveView('Clients');
          const updatedClients = activeCompany.clients.filter(c => c.id !== client.id);
          handleUpdateCompany({ ...activeCompany, clients: updatedClients });
          return { success: true, message: `Client ${client.name} deleted.` };
      }
      return { success: false, message: `Client ${clientName} not found` };
  };

  const handleVoiceDeleteInvoice = (invoiceNumber: string) => {
      if(!activeCompany) return { success: false, message: 'No active company' };
      const invoice = activeCompany.invoices.find(i => i.invoiceNumber.toLowerCase().includes(invoiceNumber.toLowerCase()));
      if(invoice) {
          setActiveView('Invoices');
          handleBulkDeleteInvoices([invoice.id]);
          return { success: true, message: `Invoice ${invoice.invoiceNumber} deleted.` };
      }
      return { success: false, message: `Invoice ${invoiceNumber} not found` };
  };

  const handleVoiceDeleteItem = (itemName: string) => {
      if(!activeCompany) return { success: false, message: 'No active company' };
      const item = activeCompany.items.find(i => i.name.toLowerCase().includes(itemName.toLowerCase()));
      if(item) {
          setActiveView('Items');
          handleBulkDeleteItems([item.id]);
          return { success: true, message: `Item ${item.name} deleted.` };
      }
      return { success: false, message: `Item ${itemName} not found` };
  };

  const handleVoiceUpdateInvoiceStatus = (invoiceNumber: string, status: string) => {
      if (!activeCompany) return { success: false, message: 'No company active' };
      const inv = activeCompany.invoices.find(i => i.invoiceNumber.toLowerCase().includes(invoiceNumber.toLowerCase()));
      if (inv) {
          const validStatus = ['Paid', 'Unpaid', 'Overdue'].find(s => s.toLowerCase() === status.toLowerCase());
          if (validStatus) {
              handleBulkStatusChange([inv.id], validStatus as Invoice['status']);
              return { success: true, message: `Invoice ${inv.invoiceNumber} marked as ${validStatus}` };
          }
          return { success: false, message: 'Invalid status. Use Paid, Unpaid, or Overdue.' };
      }
      return { success: false, message: 'Invoice not found' };
  };

  const handleVoiceUpdateCompanyInfo = (field: string, value: string) => {
      if (!activeCompany) return { success: false, message: 'No company active' };
      const validFields = ['name', 'phone', 'email', 'address', 'city', 'state', 'zip', 'gstin'];
      if (validFields.includes(field)) {
         const newDetails = { ...activeCompany.details, [field]: value };
         handleUpdateCompany({ ...activeCompany, details: newDetails });
         return { success: true, message: `Company ${field} updated.` };
      }
      return { success: false, message: `Cannot update field ${field}. Allowed: name, phone, email, address, etc.` };
  };

  const handleSaveInvoice = (invoiceData: Invoice | Omit<Invoice, 'id' | 'status'>) => {
        if (!activeCompany) return;
        let updatedItems = [...activeCompany.items];
        let updatedInvoices = [...activeCompany.invoices];
        let updatedDetails = { ...activeCompany.details };
        let newHistoryLogs: StockHistoryEntry[] = [];

        if ('id' in invoiceData) {
            const updatedInvoice = invoiceData as Invoice;
            const originalInvoice = activeCompany.invoices.find(inv => inv.id === updatedInvoice.id);
            if (!originalInvoice) return; 

            const originalItemsMap = new Map<string, number>(originalInvoice.items.map(item => [item.id, item.quantity] as [string, number]));
            const updatedItemsMap = new Map<string, number>(updatedInvoice.items.map(item => [item.id, item.quantity] as [string, number]));
            const allItemIds = new Set([...originalItemsMap.keys(), ...updatedItemsMap.keys()]);

            allItemIds.forEach(itemId => {
                const originalQty = originalItemsMap.get(itemId) || 0;
                const updatedQty = updatedItemsMap.get(itemId) || 0;
                const diff = originalQty - updatedQty; 

                if (diff !== 0) {
                    const itemIndex = updatedItems.findIndex(i => i.id === itemId);
                    if (itemIndex > -1) {
                        const prevStock = Number(updatedItems[itemIndex].quantityInStock) || 0;
                        const newStock = prevStock + diff;
                        updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: newStock };

                        newHistoryLogs.push(createStockLog(updatedItems[itemIndex].id, updatedItems[itemIndex].name, prevStock, newStock, 'Invoice Edited', updatedInvoice.invoiceNumber));
                    }
                }
            });
            updatedInvoices = updatedInvoices.map(inv => inv.id === updatedInvoice.id ? updatedInvoice : inv);
        } else {
            const newInvoiceData = invoiceData as Omit<Invoice, 'id' | 'status'>;
            const nextNumber = Number(activeCompany.details.nextInvoiceNumber || 1);
            const expectedInvoiceNumber = `${activeCompany.details.invoicePrefix || 'INV-'}${nextNumber.toString().padStart(3, '0')}`;

            newInvoiceData.items.forEach(soldItem => {
                const itemIndex = updatedItems.findIndex(i => i.id === soldItem.id);
                if (itemIndex > -1) {
                    const prevStock = Number(updatedItems[itemIndex].quantityInStock) || 0;
                    const newStock = prevStock - soldItem.quantity;
                    updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: newStock };
                    newHistoryLogs.push(createStockLog(updatedItems[itemIndex].id, updatedItems[itemIndex].name, prevStock, newStock, 'Invoice Created', newInvoiceData.invoiceNumber));
                }
            });
            const newInvoice: Invoice = { ...newInvoiceData, id: `inv_${Date.now()}`, status: 'Unpaid' };
            updatedInvoices.push(newInvoice);
            // Ensure we only increment if the invoice used the generated ID
            if (newInvoiceData.invoiceNumber === expectedInvoiceNumber) {
                updatedDetails.nextInvoiceNumber = nextNumber + 1;
            }
        }

        handleUpdateCompany({ ...activeCompany, items: updatedItems, invoices: updatedInvoices.sort((a,b) => b.invoiceNumber.localeCompare(a.invoiceNumber, undefined, {numeric: true})), details: updatedDetails, stockHistory: [...(activeCompany.stockHistory || []), ...newHistoryLogs] });
        setDraftInvoice(emptyDraftInvoice);
  };

    // ... (rest of the file remains largely similar with updated props) ...
    const handleDeleteInvoice = (invoiceId: string) => handleBulkDeleteInvoices([invoiceId]);
    const handleBulkDeleteInvoices = (ids: string[]) => {
        if (!activeCompany) return;
        let updatedItems = [...activeCompany.items];
        let newHistoryLogs: StockHistoryEntry[] = [];

        const invoicesToDelete = activeCompany.invoices.filter(inv => ids.includes(inv.id));
        invoicesToDelete.forEach(invoice => {
             invoice.items.forEach(soldItem => {
                const itemIndex = updatedItems.findIndex(i => i.id === soldItem.id);
                if (itemIndex > -1) {
                    const prevStock = Number(updatedItems[itemIndex].quantityInStock) || 0;
                    const newStock = prevStock + soldItem.quantity; 
                    updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: newStock };
                    newHistoryLogs.push(createStockLog(updatedItems[itemIndex].id, updatedItems[itemIndex].name, prevStock, newStock, 'Invoice Deleted', invoice.invoiceNumber));
                }
             });
        });
        const updatedInvoices = activeCompany.invoices.filter(inv => !ids.includes(inv.id));
        handleUpdateCompany({ ...activeCompany, items: updatedItems, invoices: updatedInvoices, stockHistory: [...(activeCompany.stockHistory || []), ...newHistoryLogs] });
    };

    const handleUpdateInvoiceStatus = (invoiceId: string, status: Invoice['status']) => handleBulkStatusChange([invoiceId], status);
    const handleBulkStatusChange = (ids: string[], status: Invoice['status']) => {
        if (!activeCompany) return;
        const updatedInvoices = activeCompany.invoices.map(inv => ids.includes(inv.id) ? { ...inv, status } : inv);
        handleUpdateCompany({ ...activeCompany, invoices: updatedInvoices });
    };
    const handleAddRecurring = (profile: Omit<RecurringInvoice, 'id'>) => { if (!activeCompany) return; handleUpdateCompany({ ...activeCompany, recurringInvoices: [...(activeCompany.recurringInvoices || []), { ...profile, id: `rec_${Date.now()}` }] }); };
    const handleUpdateRecurring = (updatedProfile: RecurringInvoice) => { if (!activeCompany) return; handleUpdateCompany({ ...activeCompany, recurringInvoices: activeCompany.recurringInvoices.map(r => r.id === updatedProfile.id ? updatedProfile : r) }); };
    const handleDeleteRecurring = (id: string) => { if (!activeCompany) return; handleUpdateCompany({ ...activeCompany, recurringInvoices: activeCompany.recurringInvoices.filter(r => r.id !== id) }); };
    const createCompanyDataUpdater = <T,>(dataType: keyof Omit<Company, 'id' | 'ownerId' | 'details' | 'invoices' | 'recurringInvoices' | 'stockHistory'>) => (data: T[]) => { if(!activeCompany) return; const updatedCompany = { ...activeCompany, [dataType]: data }; handleUpdateCompany(updatedCompany as Company); };
    const setClients = createCompanyDataUpdater<Client>('clients');
    const setItems = createCompanyDataUpdater<Item>('items');
    const setTransporters = createCompanyDataUpdater<Transporter>('transporters');
    const handleBulkStockUpdate = (updates: { itemId: string, newQuantity: number }[], actionType: StockHistoryEntry['action'] = 'Bulk Update') => { if (!activeCompany) return; const updatedItems = [...activeCompany.items]; const newHistoryLogs: StockHistoryEntry[] = []; updates.forEach(update => { const idx = updatedItems.findIndex(i => i.id === update.itemId); if (idx !== -1) { const prevQty = updatedItems[idx].quantityInStock; if (prevQty !== update.newQuantity) { updatedItems[idx] = { ...updatedItems[idx], quantityInStock: update.newQuantity }; newHistoryLogs.push(createStockLog(updatedItems[idx].id, updatedItems[idx].name, prevQty, update.newQuantity, actionType)); } } }); if (newHistoryLogs.length > 0) { handleUpdateCompany({ ...activeCompany, items: updatedItems, stockHistory: [...(activeCompany.stockHistory || []), ...newHistoryLogs] }); } };
    const handleBulkDeleteClients = (ids: string[]) => { if(!activeCompany) return; handleUpdateCompany({ ...activeCompany, clients: activeCompany.clients.filter(c => !ids.includes(c.id)) }); };
    const handleBulkDeleteItems = (ids: string[]) => { if(!activeCompany) return; handleUpdateCompany({ ...activeCompany, items: activeCompany.items.filter(i => !ids.includes(i.id)) }); };

  const handleEditInvoice = (invoiceId: string) => {
    const invoice = activeCompany?.invoices.find(inv => inv.id === invoiceId);
    if (invoice) {
      setInvoiceToEdit(invoice);
      // NOTE: We use the raw setter here to bypass the clearing logic in handleNavigate
      // because we WANT to set the state for editing.
      setActiveView('NewInvoice');
    }
  };

  if (!currentUser) return <div className="w-full h-screen bg-slate-100 dark:bg-secondary-dark flex items-center justify-center"><Auth onLogin={handleLogin} onSignup={handleSignup} onGoogleLogin={handleGoogleLogin} onCheckUserExists={handleCheckUser} onResetPassword={handleResetPassword} /></div>;
  if (!activeCompany) return <CompanyManager onAddCompany={handleAddCompany} onLogout={handleLogout}/>;

  const renderView = () => {
    switch (activeView) {
      case 'Dashboard': return <Dashboard invoices={activeCompany.invoices} items={activeCompany.items} company={activeCompany} setActiveView={handleNavigate} />;
      case 'NewInvoice': return <NewInvoice company={activeCompany} saveInvoice={handleSaveInvoice} setActiveView={handleNavigate} invoiceToEdit={invoiceToEdit} clearEditingInvoice={() => setInvoiceToEdit(null)} onUpdateCompany={handleUpdateCompany} draftInvoice={draftInvoice} setDraftInvoice={setDraftInvoice} />;
      case 'Invoices': return <Invoices invoices={activeCompany.invoices} company={activeCompany} setActiveView={handleNavigate} onEdit={handleEditInvoice} onDelete={handleDeleteInvoice} onStatusChange={handleUpdateInvoiceStatus} onBulkDelete={handleBulkDeleteInvoices} onBulkStatusChange={handleBulkStatusChange} onAddRecurring={handleAddRecurring} onUpdateRecurring={handleUpdateRecurring} onDeleteRecurring={handleDeleteRecurring} />;
      case 'Clients': return <Clients clients={activeCompany.clients} setClients={setClients} invoices={activeCompany.invoices} company={activeCompany} onEditInvoice={handleEditInvoice} onDeleteInvoice={handleDeleteInvoice} onStatusChange={handleUpdateInvoiceStatus} onBulkDelete={handleBulkDeleteClients} />;
      case 'Items': return <Items items={activeCompany.items} setItems={setItems} company={activeCompany} onBulkDelete={handleBulkDeleteItems} />;
      case 'Inventory': return <Inventory items={activeCompany.items} setItems={setItems} onBulkStockUpdate={handleBulkStockUpdate} stockHistory={activeCompany.stockHistory || []} />;
      case 'Transporters': return <Transporters transporters={activeCompany.transporters} setTransporters={setTransporters} />;
      case 'Settings': return <Settings activeCompany={activeCompany} updateCompany={handleUpdateCompany} />;
      default: return <Dashboard invoices={activeCompany.invoices} items={activeCompany.items} company={activeCompany} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-100 dark:bg-secondary-dark font-sans transition-colors relative">
      <Sidebar 
        activeView={activeView} setActiveView={handleNavigate} theme={theme} setTheme={setTheme} 
        userCompanies={userCompanies} activeCompany={activeCompany} 
        onSwitchCompany={handleSwitchCompany}
        onAddCompany={() => setIsAddCompanyModalOpen(true)}
        onLogout={handleLogout}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
        currentUser={currentUser}
        onOpenProfile={() => setIsProfileOpen(true)}
      />
      <main className="flex-1 p-4 lg:p-8 overflow-y-auto">
        <div className="md:hidden mb-4 flex justify-between items-center">
            <button onClick={() => setIsSidebarOpen(true)} className="p-2 rounded-xl text-slate-600 dark:text-light-text hover:bg-white dark:hover:bg-tertiary-dark shadow-sm">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" /></svg>
            </button>
            <div className="text-xs font-medium text-slate-400">Cmd+K</div>
        </div>
        {renderView()}
      </main>

      <CommandPalette 
        isOpen={isPaletteOpen} 
        onClose={() => setIsPaletteOpen(false)} 
        onNavigate={handleNavigate}
        toggleTheme={() => setTheme(theme === 'dark' ? 'light' : 'dark')}
        onNewInvoice={() => { handleNavigate('NewInvoice'); }}
      />

      <VoiceAssistant 
        onNavigate={handleNavigate} 
        currentView={activeView}
        onAddClient={handleVoiceAddClient}
        onAddItem={handleVoiceAddItem}
        onUpdateStock={handleVoiceUpdateStock}
        dataContext={{
            clients: activeCompany.clients,
            items: activeCompany.items,
            invoices: activeCompany.invoices
        }}
        onOpenEmailModal={handleVoiceOpenEmailModal}
        onDraftInvoice={handleVoiceDraftInvoice}
        onAddDraftItem={handleVoiceAddDraftItem}
        onUpdateInvoiceDetails={handleVoiceUpdateInvoiceDetails}
        onUpdateShippingDetails={handleVoiceUpdateShippingDetails}
        onRemoveInvoiceItem={handleVoiceRemoveInvoiceItem}
        onSaveDraftInvoice={handleVoiceSaveInvoice}
        onDeleteClient={handleVoiceDeleteClient}
        onDeleteInvoice={handleVoiceDeleteInvoice}
        onDeleteItem={handleVoiceDeleteItem}
        onUpdateInvoiceStatus={handleVoiceUpdateInvoiceStatus}
        onUpdateCompanyInfo={handleVoiceUpdateCompanyInfo}
      />

       <Modal isOpen={isAddCompanyModalOpen} onClose={() => setIsAddCompanyModalOpen(false)} title="Create New Company">
          <div className="p-6 space-y-4">
            <Input label="Company Name" id="new-company-name" value={newCompanyName} onChange={(e) => setNewCompanyName(e.target.value)} placeholder="Enter your new company's name" required />
          </div>
          <div className="p-6 pt-0 flex justify-end gap-4">
            <Button variant="secondary" onClick={() => { setIsAddCompanyModalOpen(false); setNewCompanyName(''); }}>Cancel</Button>
            <Button onClick={handleCreateNewCompany} disabled={!newCompanyName.trim()}>Create Company</Button>
          </div>
        </Modal>

        <Modal isOpen={isProfileOpen} onClose={() => setIsProfileOpen(false)} title="User Profile">
            {currentUser && <UserProfile user={currentUser} onUpdateProfile={handleUpdateProfile} onClose={() => setIsProfileOpen(false)} />}
        </Modal>

        {voiceInvoiceToEmail && (
            <Modal isOpen={true} onClose={() => setVoiceInvoiceToEmail(null)} title={`Email Invoice #${voiceInvoiceToEmail.invoiceNumber}`}>
                <div className="p-6 text-center">
                    <p className="text-slate-600 dark:text-slate-300 mb-4">The email functionality for <strong>{voiceInvoiceToEmail.invoiceNumber}</strong> has been triggered by your voice command.</p>
                    <p className="text-sm text-slate-500">(In a real app, this would pre-fill and send the email. For now, it opens this confirmation.)</p>
                    <div className="mt-6 flex justify-center gap-4">
                        <Button variant="secondary" onClick={() => setVoiceInvoiceToEmail(null)}>Close</Button>
                        <Button onClick={() => { alert(`Email sent to ${voiceInvoiceToEmail.client.email}`); setVoiceInvoiceToEmail(null); }}>Send Email Now</Button>
                    </div>
                </div>
            </Modal>
        )}
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import type { Company, BankAccount, CompanyDetails } from '../types';
import Input from './common/Input';
import Button from './common/Button';
import Modal from './common/Modal';
import { INDIAN_STATES } from '../constants';
import { validateGstin, validatePan, validateEmail, validateIfsc, validateRequired, fetchLocationByPincode } from '../utils/validation';

interface SettingsProps {
  activeCompany: Company;
  updateCompany: (updatedCompany: Company) => void;
}

type DetailsFormErrors = { [K in keyof Omit<CompanyDetails, 'logo' | 'invoicePrefix' | 'nextInvoiceNumber'>]?: string };
type BankFormErrors = { [K in keyof Omit<BankAccount, 'id' | 'isDefault'>]?: string };

const emptyBankAccount: Omit<BankAccount, 'id'> = { bankName: '', accountNumber: '', ifsc: '', isDefault: false };

const BankAccountForm: React.FC<{ 
    account: Omit<BankAccount, 'id'> | BankAccount; 
    setAccount: React.Dispatch<React.SetStateAction<Omit<BankAccount, 'id'> | BankAccount>>;
    errors: BankFormErrors;
}> = ({ account, setAccount, errors }) => {
    const handleChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setAccount(prev => ({ ...prev, [name]: value }));
    }, [setAccount]);

    return (
        <div className="p-6 space-y-4">
            <Input label="Bank Name" name="bankName" value={account.bankName} onChange={handleChange} required error={errors.bankName} placeholder="e.g. HDFC Bank"/>
            <Input label="Account Number" name="accountNumber" value={account.accountNumber} onChange={handleChange} required error={errors.accountNumber} placeholder="e.g. 502000..."/>
            <Input label="IFSC Code" name="ifsc" value={account.ifsc} onChange={handleChange} required error={errors.ifsc} placeholder="e.g. HDFC0001234"/>
        </div>
    );
};

const Settings: React.FC<SettingsProps> = ({ activeCompany, updateCompany }) => {
  const [details, setDetails] = useState(activeCompany.details);
  const [logoPreview, setLogoPreview] = useState<string | null>(activeCompany.details.logo);
  const [isBankModalOpen, setIsBankModalOpen] = useState(false);
  const [editingAccount, setEditingAccount] = useState<BankAccount | Omit<BankAccount, 'id'>>(emptyBankAccount);
  const [showSuccess, setShowSuccess] = useState(false);
  const [bankSuccessMessage, setBankSuccessMessage] = useState('');
  const [isBankDeleteConfirmOpen, setIsBankDeleteConfirmOpen] = useState(false);
  const [accountToDeleteId, setAccountToDeleteId] = useState<string | null>(null);

  const [detailErrors, setDetailErrors] = useState<DetailsFormErrors>({});
  const [bankErrors, setBankErrors] = useState<BankFormErrors>({});
  const [logoError, setLogoError] = useState<string|null>(null);
  const [isPincodeLoading, setIsPincodeLoading] = useState(false);

  useEffect(() => {
    setDetails(activeCompany.details);
    setLogoPreview(activeCompany.details.logo);
    setDetailErrors({});
  }, [activeCompany]);

    useEffect(() => {
    const pincode = details.zip;
    if (pincode && pincode.length === 6) {
      const timer = setTimeout(async () => {
        setIsPincodeLoading(true);
        const location = await fetchLocationByPincode(pincode);
        if (location) {
          setDetails(prev => ({ ...prev, city: location.city, state: location.state }));
          setDetailErrors(prev => ({...prev, zip: undefined}));
        } else if (location === null) {
           setDetailErrors(prev => ({...prev, zip: 'Invalid Pincode'}));
        } else {
           setDetailErrors(prev => ({...prev, zip: 'Lookup failed. Enter manually.'}));
        }
        setIsPincodeLoading(false);
      }, 500); // Debounce
      return () => clearTimeout(timer);
    }
  }, [details.zip]);

  const validateDetailsField = useCallback((name: string, value: string): string | null => {
    switch (name) {
      case 'name': return validateRequired(value);
      case 'gstin': return validateGstin(value);
      case 'pan': return validatePan(value);
      case 'email': return validateEmail(value);
      default: return null;
    }
  }, []);

  const handleChange = useCallback((e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target;
    setDetails(prev => ({ ...prev, [name]: type === 'number' ? (value === '' ? '' : parseInt(value)) : value }));
    const error = validateDetailsField(name, value);
    setDetailErrors(prev => ({...prev, [name]: error || undefined }));
  }, [validateDetailsField]);

  const handleLogoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setLogoError(null);
    if (e.target.files && e.target.files[0]) {
        const file = e.target.files[0];
        if (!file.type.startsWith('image/')) {
            setLogoError('Please select an image file.');
            return;
        }
        if (file.size > 2 * 1024 * 1024) { // 2MB limit
            setLogoError('Image size should be less than 2MB.');
            return;
        }
      const reader = new FileReader();
      reader.onloadend = () => {
        const result = reader.result as string;
        setLogoPreview(result);
        setDetails(prev => ({ ...prev, logo: result }));
      };
      reader.onerror = () => setLogoError('Failed to read file.');
      reader.readAsDataURL(file);
    }
  };

  const handleSaveDetails = () => {
    // Validate all required fields before saving
    const newErrors: DetailsFormErrors = {};
    if (!details.name) newErrors.name = validateRequired(details.name) || undefined;
    if (!details.phone) newErrors.phone = validateRequired(details.phone) || undefined;
    if (!details.address) newErrors.address = validateRequired(details.address) || undefined;
    if (!details.city) newErrors.city = validateRequired(details.city) || undefined;
    if (!details.state) newErrors.state = validateRequired(details.state) || undefined;
    if (!details.zip) newErrors.zip = validateRequired(details.zip) || undefined;

    // Check existing errors and new validations
    const hasErrors = Object.values(detailErrors).some(e => e) || Object.values(newErrors).some(e => e);

    if (hasErrors) {
        setDetailErrors(prev => ({ ...prev, ...newErrors }));
        return;
    }

    updateCompany({ ...activeCompany, details });
    setShowSuccess(true);
    setTimeout(() => setShowSuccess(false), 3000);
  };

  const handleOpenBankModal = (account?: BankAccount) => {
    setBankErrors({});
    setEditingAccount(account || emptyBankAccount);
    setIsBankModalOpen(true);
  };

  const validateBankAccount = (account: Omit<BankAccount, 'id'> | BankAccount): boolean => {
      const errors: BankFormErrors = {};
      if (validateRequired(account.bankName)) errors.bankName = "Bank Name is required.";
      if (validateRequired(account.accountNumber)) errors.accountNumber = "Account Number is required.";
      const ifscError = validateRequired(account.ifsc) || validateIfsc(account.ifsc);
      if (ifscError) errors.ifsc = ifscError;
      setBankErrors(errors);
      return Object.keys(errors).length === 0;
  }

  const handleSaveBankAccount = () => {
    if (!validateBankAccount(editingAccount)) return;

    let updatedAccounts: BankAccount[];
    const isNew = !('id' in editingAccount);

    if (editingAccount.isDefault) {
      activeCompany.bankAccounts.forEach(acc => acc.isDefault = false);
    }

    if (isNew) {
      updatedAccounts = [...activeCompany.bankAccounts, { ...editingAccount, id: Date.now().toString() }];
    } else {
      updatedAccounts = activeCompany.bankAccounts.map(acc => acc.id === (editingAccount as BankAccount).id ? (editingAccount as BankAccount) : acc);
    }

    // Auto-set default if it's the first and only account
    if (updatedAccounts.length === 1) {
        updatedAccounts[0].isDefault = true;
    } else if (updatedAccounts.length > 0 && !updatedAccounts.some(acc => acc.isDefault)) {
        updatedAccounts[0].isDefault = true;
    }

    updateCompany({ ...activeCompany, bankAccounts: updatedAccounts });
    setIsBankModalOpen(false);
    setBankSuccessMessage(`Bank account successfully ${isNew ? 'added' : 'updated'}.`);
    setTimeout(() => setBankSuccessMessage(''), 3000);
  };

  const handleDeleteBankAccount = (accountId: string) => {
    setAccountToDeleteId(accountId);
    setIsBankDeleteConfirmOpen(true);
  };

  const confirmDeleteBankAccount = () => {
    if (accountToDeleteId) {
      const updatedAccounts = activeCompany.bankAccounts.filter(acc => acc.id !== accountToDeleteId);
      if (updatedAccounts.length > 0 && !updatedAccounts.some(acc => acc.isDefault)) {
        updatedAccounts[0].isDefault = true;
      }
      updateCompany({ ...activeCompany, bankAccounts: updatedAccounts });
      setBankSuccessMessage('Bank account successfully deleted.');
      setTimeout(() => setBankSuccessMessage(''), 3000);
    }
    setIsBankDeleteConfirmOpen(false);
    setAccountToDeleteId(null);
  };

  const handleSetDefault = (accountId: string) => {
      const updatedAccounts = activeCompany.bankAccounts.map(acc => ({ ...acc, isDefault: acc.id === accountId }));
      updateCompany({ ...activeCompany, bankAccounts: updatedAccounts });
  };

  const inputClasses = "w-full bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white rounded-lg shadow-sm placeholder-slate-400 dark:placeholder-slate-500 focus:outline-none text-sm px-4 py-3 transition-all duration-200 ease-in-out border border-slate-300 dark:border-slate-700 hover:border-slate-400 dark:hover:border-slate-500 focus:ring-2 focus:ring-accent/20 focus:border-accent";

  return (
    <div className="max-w-7xl mx-auto space-y-8 pb-12">

      {/* Header */}
      <div className="flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-bold text-slate-900 dark:text-light-text tracking-tight">Settings</h1>
            <p className="text-slate-500 dark:text-slate-400 mt-1">Manage your company profile and preferences.</p>
          </div>
          {showSuccess && <div className="bg-green-100 text-green-700 px-4 py-2 rounded-lg text-sm font-semibold animate-fade-in">Settings Saved!</div>}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Left Column - Company Info */}
        <div className="lg:col-span-2 space-y-8">

            {/* Identity Card */}
            <div className="bg-white dark:bg-primary-dark p-8 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800">
                <h2 className="text-lg font-bold text-slate-900 dark:text-light-text mb-6 border-b border-slate-100 dark:border-slate-700 pb-4">Identity & Contact</h2>
                <div className="flex flex-col md:flex-row gap-8 mb-8">
                    <div className="flex-shrink-0">
                        <label className="block text-xs font-semibold uppercase text-slate-500 mb-2">Logo</label>
                        <div className="relative group w-32 h-32 bg-slate-50 dark:bg-slate-900 rounded-xl border-2 border-dashed border-slate-300 dark:border-slate-700 flex items-center justify-center overflow-hidden hover:border-accent transition-colors">
                            {logoPreview ? (
                                <img src={logoPreview} alt="Company Logo" className="w-full h-full object-contain p-2" />
                            ) : (
                                <span className="text-xs text-slate-400 text-center px-2">Upload<br/>Logo</span>
                            )}
                            <div className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer">
                                <span className="text-white text-xs font-bold">Change</span>
                            </div>
                            <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={handleLogoChange} accept="image/*" />
                        </div>
                        {logoError && <p className="text-xs text-red-500 mt-1">{logoError}</p>}
                    </div>
                    <div className="flex-grow space-y-6">
                        <Input label="Company Name" name="name" value={details.name} onChange={handleChange} required error={detailErrors.name} placeholder="e.g. Acme Corp" />
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <Input label="Phone" name="phone" type="tel" value={details.phone} onChange={handleChange} required error={detailErrors.phone} placeholder="e.g. +91 98765 43210"/>
                            <Input label="Email" name="email" type="email" value={details.email} onChange={handleChange} error={detailErrors.email} placeholder="e.g. contact@acme.com" />
                        </div>
                    </div>
                </div>

                <h3 className="text-sm font-bold text-slate-900 dark:text-white mb-4">Address</h3>
                <div className="space-y-6">
                    <textarea name="address" rows={2} value={details.address} onChange={handleChange} className={inputClasses} placeholder="Street Address, Area, Landmark" />
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <div className="relative">
                            <Input label="ZIP Code" name="zip" value={details.zip} onChange={handleChange} error={detailErrors.zip} maxLength={6} required placeholder="e.g. 400001" />
                            {isPincodeLoading && <div className="absolute top-9 right-3 h-4 w-4 border-2 border-slate-400 border-t-transparent rounded-full animate-spin"></div>}
                        </div>
                        <Input label="City" name="city" value={details.city} onChange={handleChange} required error={detailErrors.city} placeholder="e.g. Mumbai" />
                        <div>
                            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1.5">State</label>
                            <select id="state" name="state" value={details.state} onChange={handleChange} className={inputClasses}>
                                <option value="">Select State</option>
                                {INDIAN_STATES.map(state => <option key={state} value={state}>{state}</option>)}
                            </select>
                        </div>
                    </div>
                </div>
            </div>

            {/* Legal Card */}
            <div className="bg-white dark:bg-primary-dark p-8 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800">
                <h2 className="text-lg font-bold text-slate-900 dark:text-light-text mb-6 border-b border-slate-100 dark:border-slate-700 pb-4">Legal Information</h2>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <Input label="GSTIN" name="gstin" value={details.gstin} onChange={handleChange} error={detailErrors.gstin} placeholder="e.g. 27AAAAA0000A1Z5" />
                    <Input label="PAN" name="pan" value={details.pan} onChange={handleChange} error={detailErrors.pan} placeholder="e.g. ABCDE1234F" />
                    <Input label="UDYAM" name="udyam" value={details.udyam} onChange={handleChange} placeholder="Optional" />
                </div>
                <div className="mt-8 pt-6 border-t border-slate-100 dark:border-slate-800 flex justify-end">
                    <Button onClick={handleSaveDetails} className="px-8 !py-3 !text-base shadow-lg shadow-accent/20">Save Changes</Button>
                </div>
            </div>
        </div>

        {/* Right Column - Bank Accounts */}
        <div className="lg:col-span-1">
            <div className="bg-white dark:bg-primary-dark p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 sticky top-6">
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-lg font-bold text-slate-900 dark:text-light-text">Bank Accounts</h2>
                    <button onClick={() => handleOpenBankModal()} className="text-accent hover:text-accent-hover dark:text-indigo-400 font-bold text-sm bg-accent/10 dark:bg-accent/20 px-3 py-1.5 rounded-lg transition-colors">+ Add</button>
                </div>

                <div className="space-y-4">
                    {activeCompany.bankAccounts.map(account => (
                        <div key={account.id} className={`p-4 rounded-xl border transition-all ${account.isDefault ? 'border-accent bg-accent/5 dark:bg-accent/10' : 'border-slate-200 dark:border-slate-700 hover:border-slate-300 dark:hover:border-slate-600'}`}>
                            <div className="flex justify-between items-start mb-2">
                                <h3 className="font-bold text-slate-800 dark:text-white text-sm">{account.bankName}</h3>
                                {account.isDefault && <span className="text-[10px] font-bold uppercase tracking-wider bg-accent text-white px-2 py-0.5 rounded-full">Default</span>}
                            </div>
                            <p className="text-xs text-slate-500 dark:text-slate-400 font-mono mb-1">{account.accountNumber}</p>
                            <p className="text-xs text-slate-500 dark:text-slate-400">IFSC: {account.ifsc}</p>

                            <div className="flex justify-end gap-2 mt-4 pt-3 border-t border-slate-100 dark:border-slate-700/50">
                                {!account.isDefault && (
                                    <button onClick={() => handleSetDefault(account.id)} className="text-xs font-semibold text-slate-500 hover:text-slate-800 dark:hover:text-white">Make Default</button>
                                )}
                                <button onClick={() => handleOpenBankModal(account)} className="text-xs font-semibold text-accent hover:text-accent-hover dark:text-indigo-400">Edit</button>
                                <button onClick={() => handleDeleteBankAccount(account.id)} className="text-xs font-semibold text-red-500 hover:text-red-700">Delete</button>
                            </div>
                        </div>
                    ))}

                    {activeCompany.bankAccounts.length === 0 && (
                        <div className="text-center py-10 px-4 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-dashed border-slate-300 dark:border-slate-700">
                            <svg className="w-10 h-10 mx-auto text-slate-300 mb-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M17 9V7a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2m2 4h10a2 2 0 002-2v-6a2 2 0 00-2-2H9a2 2 0 00-2 2v6a2 2 0 002 2zm7-5a2 2 0 11-4 0 2 2 0 014 0z" /></svg>
                            <p className="text-sm text-slate-500 dark:text-slate-400 mb-4">No bank accounts added yet.</p>
                            <Button onClick={() => handleOpenBankModal()} variant="secondary" className="w-full text-xs">Add First Account</Button>
                        </div>
                    )}
                </div>

                {bankSuccessMessage && <div className="mt-4 text-center text-xs font-bold text-green-600 bg-green-50 dark:bg-green-900/20 py-2 rounded-lg animate-fade-in">{bankSuccessMessage}</div>}
            </div>
        </div>
      </div>

      <Modal isOpen={isBankModalOpen} onClose={() => setIsBankModalOpen(false)} title={'id' in editingAccount ? 'Edit Bank Account' : 'Add Bank Account'}>
          <BankAccountForm account={editingAccount} setAccount={setEditingAccount} errors={bankErrors} />
          <div className="p-6 pt-0 flex justify-end gap-4">
              <Button variant="secondary" onClick={() => setIsBankModalOpen(false)}>Cancel</Button>
              <Button onClick={handleSaveBankAccount}>Save Account</Button>
          </div>
      </Modal>

      <Modal isOpen={isBankDeleteConfirmOpen} onClose={() => setIsBankDeleteConfirmOpen(false)} title="Delete Bank Account">
          <div className="p-6">
            <p className="text-slate-600 dark:text-medium-text mb-6">Are you sure you want to delete this bank account? This action cannot be undone.</p>
            <div className="flex justify-end gap-4">
              <Button variant="secondary" onClick={() => setIsBankDeleteConfirmOpen(false)}>Cancel</Button>
              <Button onClick={confirmDeleteBankAccount} className="bg-red-600 hover:bg-red-700 focus:ring-red-500">Confirm Delete</Button>
            </div>
          </div>
      </Modal>

    </div>
  );
};

export default Settings;

export interface BankAccount {
  id: string;
  bankName: string;
  accountNumber: string;
  ifsc: string;
  isDefault: boolean;
}

export interface CompanyDetails {
  logo: string;
  name: string;
  gstin: string;
  pan: string;
  phone: string;
  email: string;
  website?: string;
  address: string;
  city: string;
  state: string;
  zip: string;
  udyam: string;
  invoicePrefix: string;
  nextInvoiceNumber: number;
  signature?: string;
}

export interface Client {
  id: string;
  name: string;
  gstin: string;
  email: string;
  phone: string;
  address: string;
  city: string;
  state: string;
  zip: string;
  shippingAddress?: string;
  shippingCity?: string;
  shippingState?: string;
  shippingZip?: string;
  tags?: string[];
}

export interface Item {
  id: string;
  name: string;
  hsn: string;
  price: number;
  gstRate: number; // in percentage
  unit: string;
  quantityInStock: number;
}

export interface Transporter {
  id: string;
  name: string;
  gstin: string;
}

export interface InvoiceItem extends Item {
  quantity: number;
}

export interface Invoice {
  id:string;
  invoiceNumber: string;
  client: Client;
  items: InvoiceItem[];
  issueDate: string;
  dueDate: string;
  notes: string;
  subTotal: number;
  cgst: number;
  sgst: number;
  igst: number;
  grandTotal: number;
  status: 'Paid' | 'Unpaid' | 'Overdue';
  selectedBankAccountId: string | null;

  // Shipping Details - Snapshot for this specific invoice
  shippingName?: string;
  shippingAddress?: string;
  shippingCity?: string;
  shippingState?: string;
  shippingZip?: string;
  shippingGstin?: string;

  // Transporter Details
  transporterName?: string;
  transporterGstin?: string;
  vehicleNumber?: string;
  ewayBillNumber?: string;
}

export interface Quotation extends Omit<Invoice, 'status' | 'invoiceNumber'> {
    quotationNumber: string;
    validUntil: string;
    status: 'Draft' | 'Sent' | 'Accepted' | 'Converted';
}

export type RecurringFrequency = 'Daily' | 'Weekly' | 'Monthly' | 'Quarterly' | 'Yearly';

export interface RecurringInvoice {
  id: string;
  clientId: string;
  items: InvoiceItem[];
  frequency: RecurringFrequency;
  startDate: string;
  endDate?: string;
  nextRunDate: string;
  lastRunDate?: string;
  status: 'Active' | 'Paused' | 'Completed';
  notes?: string;
}

export interface StockHistoryEntry {
    id: string;
    itemId: string;
    itemName: string;
    previousQuantity: number;
    newQuantity: number;
    action: 'Manual Update' | 'Bulk Update' | 'Invoice Created' | 'Invoice Edited' | 'Invoice Deleted' | 'Voice Update' | 'Initial' | 'Bill Scan';
    timestamp: string;
    referenceId?: string; // e.g., Invoice Number
}

export interface Company {
  id: string;
  ownerId: string;
  details: CompanyDetails;
  bankAccounts: BankAccount[];
  clients: Client[];
  items: Item[];
  transporters: Transporter[];
  invoices: Invoice[];
  quotations: Quotation[]; // Added quotations
  recurringInvoices: RecurringInvoice[];
  stockHistory: StockHistoryEntry[];
}

export interface User {
    id: string;
    email: string;
    name?: string;
    passwordHash: string; // In a real app, never store plain text passwords
}

export interface DraftInvoice {
    invoiceNumber: string;
    clientId: string;
    items: InvoiceItem[];
    issueDate: string;
    dueDate: string;
    notes: string;
    selectedBankAccountId: string | null;
    shippingDetails: {
        name: string;
        address: string;
        city: string;
        state: string;
        zip: string;
        gstin: string;
    };
    isShippingSameAsBilling: boolean;
    transporterId: string;
    vehicleNumber: string;
    ewayBillNumber: string;
    // Added for Quotation support
    type?: 'invoice' | 'quote';
    validUntil?: string;
}

