  const handleSignup = (email: string, pass: string, name: string): boolean => { if(users.some(u => u.email === email)) return false; const newUser: User = { id: Date.now().toString(), email, name, passwordHash: simpleHash(pass) }; setUsers([...users, newUser]); setCurrentUser(newUser); setActiveCompanyId(null); return true; };
  const handleLogout = () => { setCurrentUser(null); setActiveCompanyId(null); };
