  const handleVoiceAddClient = (client: Omit<Client, 'id'>) => { if (!activeCompany) return { success: false, message: 'No active company' }; const existing = activeCompany.clients.find(c => c.name.toLowerCase() === client.name.toLowerCase()); if (existing) return { success: false, message: `Client '${client.name}' already exists.` }; const newClient: Client = { gstin: '', email: '', phone: '', address: '', city: '', state: '', zip: '', tags: [], ...client, id: `c_${Date.now()}` }; handleUpdateCompany({ ...activeCompany, clients: [...activeCompany.clients, newClient] }); return { success: true, message: `Client ${client.name} added successfully.` }; };
  const handleVoiceAddItem = (item: Omit<Item, 'id'>) => { if (!activeCompany) return { success: false, message: 'No active company' }; const existing = activeCompany.items.find(i => i.name.toLowerCase() === item.name.toLowerCase()); if (existing) return { success: false, message: `Item '${item.name}' already exists.` }; const newItem: Item = { hsn: '', unit: 'pcs', quantityInStock: 0, ...item, id: `i_${Date.now()}` }; const log = createStockLog(newItem.id, newItem.name, 0, newItem.quantityInStock, 'Initial'); handleUpdateCompany({ ...activeCompany, items: [...activeCompany.items, newItem], stockHistory: [...(activeCompany.stockHistory || []), log] }); return { success: true, message: `Item ${item.name} added.` }; };
