  const handleVoiceOpenEmailModal = (invoiceNumberQuery: string) => { if(!activeCompany) return { success: false, message: 'No company' }; const invoice = activeCompany.invoices.find(inv => inv.invoiceNumber.toLowerCase().includes(invoiceNumberQuery.toLowerCase())); if(invoice) { setVoiceInvoiceToEmail(invoice); return { success: true, message: `Opening email for ${invoice.invoiceNumber}` }; } return { success: false, message: `Invoice ${invoiceNumberQuery} not found` }; };
  const handleVoiceDraftInvoice = (clientName: string) => { if (!activeCompany) return { success: false, message: 'No active company' }; const client = activeCompany.clients.find(c => c.name.toLowerCase().includes(clientName.toLowerCase())); setDraftInvoice(prev => ({ ...prev, clientId: client ? client.id : prev.clientId, items: [], shippingDetails: client ? { name: client.name, address: client.address, city: client.city, state: client.state, zip: client.zip, gstin: client.gstin } : prev.shippingDetails, isShippingSameAsBilling: true })); setActiveView('NewInvoice'); setInvoiceToEdit(null); if (!client) return { success: false, message: `Opened New Invoice. Client ${clientName} not found.` }; return { success: true, message: `Started invoice for ${client.name}.` }; };
  const handleVoiceAddDraftItem = (itemName: string, quantity: number) => { if (!activeCompany) return { success: false, message: 'No active company' }; const item = activeCompany.items.find(i => i.name.toLowerCase().includes(itemName.toLowerCase())); if (!item) return { success: false, message: `Item ${itemName} not found.` }; const newItem: InvoiceItem = { ...item, quantity }; setDraftInvoice(prev => ({ ...prev, items: [...prev.items, newItem] })); if (activeView !== 'NewInvoice') setActiveView('NewInvoice'); return { success: true, message: `Added ${quantity} ${item.name}(s).` }; };
  const handleVoiceUpdateInvoiceDetails = (details: any) => { if (activeView !== 'NewInvoice') setActiveView('NewInvoice'); setDraftInvoice(prev => ({ ...prev, ...details })); return { success: true, message: "Invoice details updated." }; };
  const handleVoiceUpdateShippingDetails = (details: any) => { if (activeView !== 'NewInvoice') setActiveView('NewInvoice'); setDraftInvoice(prev => ({ ...prev, isShippingSameAsBilling: false, shippingDetails: { ...prev.shippingDetails, ...details } })); return { success: true, message: "Shipping details updated." }; };
  const handleVoiceRemoveInvoiceItem = (itemName: string) => { if (activeView !== 'NewInvoice') return { success: false, message: "Not on invoice page" }; const index = draftInvoice.items.findIndex(i => i.name.toLowerCase().includes(itemName.toLowerCase())); if (index === -1) return { success: false, message: "Item not found" }; const newItems = draftInvoice.items.filter((_, i) => i !== index); setDraftInvoice(prev => ({ ...prev, items: newItems })); return { success: true, message: `Removed ${itemName}.` }; };
  const handleVoiceSaveInvoice = () => { if (activeView !== 'NewInvoice') return { success: false, message: "Not on invoice page" }; if (!draftInvoice.clientId || draftInvoice.items.length === 0) return { success: false, message: "Missing client or items." }; const client = activeCompany?.clients.find(c => c.id === draftInvoice.clientId); if(!client) return { success: false, message: "Client not found" }; let subTotal = 0, cgst = 0, sgst = 0, igst = 0; const isIntraState = !draftInvoice.shippingDetails.state || draftInvoice.shippingDetails.state === activeCompany?.details.state; draftInvoice.items.forEach(item => { const t = item.price * item.quantity; subTotal += t; const tax = (t * item.gstRate) / 100; if (isIntraState) { cgst += tax/2; sgst += tax/2; } else { igst += tax; } }); const commonData = { invoiceNumber: draftInvoice.invoiceNumber, client, items: draftInvoice.items, issueDate: draftInvoice.issueDate, dueDate: draftInvoice.dueDate, notes: draftInvoice.notes, selectedBankAccountId: draftInvoice.selectedBankAccountId, shippingName: draftInvoice.shippingDetails.name, shippingAddress: draftInvoice.shippingDetails.address, shippingCity: draftInvoice.shippingDetails.city, shippingState: draftInvoice.shippingDetails.state, shippingZip: draftInvoice.shippingDetails.zip, shippingGstin: draftInvoice.shippingDetails.gstin, vehicleNumber: draftInvoice.vehicleNumber, ewayBillNumber: draftInvoice.ewayBillNumber, subTotal, cgst, sgst, igst, grandTotal: subTotal + cgst + sgst + igst }; if (invoiceToEdit && 'invoiceNumber' in invoiceToEdit) { handleSaveInvoice({ ...commonData, id: invoiceToEdit.id, status: (invoiceToEdit as Invoice).status }); } else { handleSaveInvoice(commonData); } setActiveView('Invoices'); return { success: true, message: invoiceToEdit ? "Invoice updated." : "Invoice saved." }; };

  // Handlers for optional props
  const handleVoiceDeleteClient = (clientName: string) => { if(!activeCompany) return { success: false, message: 'No active company' }; const client = activeCompany.clients.find(c => c.name.toLowerCase().includes(clientName.toLowerCase())); if(client) { setActiveView('Clients'); const updatedClients = activeCompany.clients.filter(c => c.id !== client.id); handleUpdateCompany({ ...activeCompany, clients: updatedClients }); return { success: true, message: `Client ${client.name} deleted.` }; } return { success: false, message: `Client ${clientName} not found` }; };
  const handleVoiceDeleteInvoice = (invoiceNumber: string) => { if(!activeCompany) return { success: false, message: 'No active company' }; const invoice = activeCompany.invoices.find(i => i.invoiceNumber.toLowerCase().includes(invoiceNumber.toLowerCase())); if(invoice) { setActiveView('Invoices'); handleBulkDeleteInvoices([invoice.id]); return { success: true, message: `Invoice ${invoice.invoiceNumber} deleted.` }; } return { success: false, message: `Invoice ${invoiceNumber} not found` }; };
  const handleVoiceDeleteItem = (itemName: string) => { if(!activeCompany) return { success: false, message: 'No active company' }; const item = activeCompany.items.find(i => i.name.toLowerCase().includes(itemName.toLowerCase())); if(item) { setActiveView('Items'); handleBulkDeleteItems([item.id]); return { success: true, message: `Item ${item.name} deleted.` }; } return { success: false, message: `Item ${itemName} not found` }; };
  const handleVoiceUpdateInvoiceStatus = (invoiceNumber: string, status: string) => { if (!activeCompany) return { success: false, message: 'No company active' }; const inv = activeCompany.invoices.find(i => i.invoiceNumber.toLowerCase().includes(invoiceNumber.toLowerCase())); if (inv) { const validStatus = ['Paid', 'Unpaid', 'Overdue'].find(s => s.toLowerCase() === status.toLowerCase()); if (validStatus) { handleBulkStatusChange([inv.id], validStatus as Invoice['status']); return { success: true, message: `Invoice ${inv.invoiceNumber} marked as ${validStatus}` }; } return { success: false, message: 'Invalid status.' }; } return { success: false, message: 'Invoice not found' }; };
  const handleVoiceUpdateCompanyInfo = (field: string, value: string) => { if (!activeCompany) return { success: false, message: 'No company active' }; const validFields = ['name', 'phone', 'email', 'address', 'city', 'state', 'zip', 'gstin']; if (validFields.includes(field)) { const newDetails = { ...activeCompany.details, [field]: value }; handleUpdateCompany({ ...activeCompany, details: newDetails }); return { success: true, message: `Company ${field} updated.` }; } return { success: false, message: `Cannot update field ${field}.` }; };

  const handleSaveInvoice = (data: Omit<Invoice, 'id' | 'status'> | Invoice | Omit<Quotation, 'id' | 'status'>) => {
        if (!activeCompany) return;
        let updatedItems = [...activeCompany.items];
        let updatedInvoices = [...activeCompany.invoices];
        let updatedQuotations = [...(activeCompany.quotations || [])];
        let updatedDetails = { ...activeCompany.details };
        let newHistoryLogs: StockHistoryEntry[] = [];

        // Check if it's a Quotation
        if ('quotationNumber' in data) {
            const quotationData = data as Quotation | Omit<Quotation, 'id' | 'status'>;
            if ('id' in quotationData) {
                // Update existing quote
                updatedQuotations = updatedQuotations.map(q => q.id === quotationData.id ? { ...q, ...quotationData } as Quotation : q);
            } else {
                // New Quote
                const newQuote: Quotation = { 
                    ...quotationData, 
                    id: `qt_${Date.now()}`, 
                    status: 'Draft',
                    // Fallbacks for type safety if needed, though they should be present
                    selectedBankAccountId: quotationData.selectedBankAccountId || null
                } as Quotation;
                updatedQuotations.push(newQuote);
            }
            // Save logic
            handleUpdateCompany({ ...activeCompany, quotations: updatedQuotations });
            setDraftInvoice(emptyDraftInvoice);
            return;
        }

        // Invoice Logic (Same as before)
        const invoiceData = data as Invoice | Omit<Invoice, 'id' | 'status'>;
        if ('id' in invoiceData) {
            const updatedInvoice = invoiceData as Invoice;
            const originalInvoice = activeCompany.invoices.find(inv => inv.id === updatedInvoice.id);
            if (!originalInvoice) return; 

            const originalItemsMap = new Map<string, number>(originalInvoice.items.map(item => [item.id, item.quantity] as [string, number]));
            const updatedItemsMap = new Map<string, number>(updatedInvoice.items.map(item => [item.id, item.quantity] as [string, number]));
            const allItemIds = new Set([...originalItemsMap.keys(), ...updatedItemsMap.keys()]);

            allItemIds.forEach(itemId => {
                const originalQty = originalItemsMap.get(itemId) || 0;
                const updatedQty = updatedItemsMap.get(itemId) || 0;
                const diff = originalQty - updatedQty; 
                if (diff !== 0) {
                    const itemIndex = updatedItems.findIndex(i => i.id === itemId);
                    if (itemIndex > -1) {
                        const prevStock = Number(updatedItems[itemIndex].quantityInStock) || 0;
                        const newStock = prevStock + diff;
                        updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: newStock };
                        newHistoryLogs.push(createStockLog(updatedItems[itemIndex].id, updatedItems[itemIndex].name, prevStock, newStock, 'Invoice Edited', updatedInvoice.invoiceNumber));
                    }
                }
            });
            updatedInvoices = updatedInvoices.map(inv => inv.id === updatedInvoice.id ? updatedInvoice : inv);
        } else {
            const newInvoiceData = invoiceData as Omit<Invoice, 'id' | 'status'>;
            const nextNumber = Number(activeCompany.details.nextInvoiceNumber || 1);
            const expectedInvoiceNumber = `${activeCompany.details.invoicePrefix || 'INV-'}${nextNumber.toString().padStart(3, '0')}`;

            newInvoiceData.items.forEach(soldItem => {
                const itemIndex = updatedItems.findIndex(i => i.id === soldItem.id);
                if (itemIndex > -1) {
                    const prevStock = Number(updatedItems[itemIndex].quantityInStock) || 0;
                    const newStock = prevStock - soldItem.quantity;
                    updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: newStock };
                    newHistoryLogs.push(createStockLog(updatedItems[itemIndex].id, updatedItems[itemIndex].name, prevStock, newStock, 'Invoice Created', newInvoiceData.invoiceNumber));
                }
            });
            const newInvoice: Invoice = { ...newInvoiceData, id: `inv_${Date.now()}`, status: 'Unpaid' };
            updatedInvoices.push(newInvoice);
            if (newInvoiceData.invoiceNumber === expectedInvoiceNumber) updatedDetails.nextInvoiceNumber = nextNumber + 1;
        }

        handleUpdateCompany({ ...activeCompany, items: updatedItems, invoices: updatedInvoices.sort((a,b) => b.invoiceNumber.localeCompare(a.invoiceNumber, undefined, {numeric: true})), details: updatedDetails, stockHistory: [...(activeCompany.stockHistory || []), ...newHistoryLogs] });
        setDraftInvoice(emptyDraftInvoice);
  };

    const handleDeleteInvoice = (invoiceId: string) => handleBulkDeleteInvoices([invoiceId]);
    const handleBulkDeleteInvoices = (ids: string[]) => { if (!activeCompany) return; let updatedItems = [...activeCompany.items]; let newHistoryLogs: StockHistoryEntry[] = []; const invoicesToDelete = activeCompany.invoices.filter(inv => ids.includes(inv.id)); invoicesToDelete.forEach(invoice => { invoice.items.forEach(soldItem => { const itemIndex = updatedItems.findIndex(i => i.id === soldItem.id); if (itemIndex > -1) { const prevStock = Number(updatedItems[itemIndex].quantityInStock) || 0; const newStock = prevStock + soldItem.quantity; updatedItems[itemIndex] = { ...updatedItems[itemIndex], quantityInStock: newStock }; newHistoryLogs.push(createStockLog(updatedItems[itemIndex].id, updatedItems[itemIndex].name, prevStock, newStock, 'Invoice Deleted', invoice.invoiceNumber)); } }); }); const updatedInvoices = activeCompany.invoices.filter(inv => !ids.includes(inv.id)); handleUpdateCompany({ ...activeCompany, items: updatedItems, invoices: updatedInvoices, stockHistory: [...(activeCompany.stockHistory || []), ...newHistoryLogs] }); };
    const handleUpdateInvoiceStatus = (invoiceId: string, status: Invoice['status']) => handleBulkStatusChange([invoiceId], status);
    const handleBulkStatusChange = (ids: string[], status: Invoice['status']) => { if (!activeCompany) return; const updatedInvoices = activeCompany.invoices.map(inv => ids.includes(inv.id) ? { ...inv, status } : inv); handleUpdateCompany({ ...activeCompany, invoices: updatedInvoices }); };
    const handleAddRecurring = (profile: Omit<RecurringInvoice, 'id'>) => { if (!activeCompany) return; handleUpdateCompany({ ...activeCompany, recurringInvoices: [...(activeCompany.recurringInvoices || []), { ...profile, id: `rec_${Date.now()}` }] }); };
    const handleUpdateRecurring = (updatedProfile: RecurringInvoice) => { if (!activeCompany) return; handleUpdateCompany({ ...activeCompany, recurringInvoices: activeCompany.recurringInvoices.map(r => r.id === updatedProfile.id ? updatedProfile : r) }); };
    const handleDeleteRecurring = (id: string) => { if (!activeCompany) return; handleUpdateCompany({ ...activeCompany, recurringInvoices: activeCompany.recurringInvoices.filter(r => r.id !== id) }); };
    const createCompanyDataUpdater = <T,>(dataType: keyof Omit<Company, 'id' | 'ownerId' | 'details' | 'invoices' | 'recurringInvoices' | 'stockHistory' | 'quotations'>) => (data: T[]) => { if(!activeCompany) return; const updatedCompany = { ...activeCompany, [dataType]: data }; handleUpdateCompany(updatedCompany as Company); };
    const setClients = createCompanyDataUpdater<Client>('clients');
    const setItems = createCompanyDataUpdater<Item>('items');
    const setTransporters = createCompanyDataUpdater<Transporter>('transporters');
    const handleBulkStockUpdate = (updates: { itemId: string, newQuantity: number }[], actionType: StockHistoryEntry['action'] = 'Bulk Update') => { if (!activeCompany) return; const updatedItems = [...activeCompany.items]; const newHistoryLogs: StockHistoryEntry[] = []; updates.forEach(update => { const idx = updatedItems.findIndex(i => i.id === update.itemId); if (idx !== -1) { const prevQty = updatedItems[idx].quantityInStock; if (prevQty !== update.newQuantity) { updatedItems[idx] = { ...updatedItems[idx], quantityInStock: update.newQuantity }; newHistoryLogs.push(createStockLog(updatedItems[idx].id, updatedItems[idx].name, prevQty, update.newQuantity, actionType)); } } }); if (newHistoryLogs.length > 0) { handleUpdateCompany({ ...activeCompany, items: updatedItems, stockHistory: [...(activeCompany.stockHistory || []), ...newHistoryLogs] }); } };
    const handleBulkDeleteClients = (ids: string[]) => { if(!activeCompany) return; handleUpdateCompany({ ...activeCompany, clients: activeCompany.clients.filter(c => !ids.includes(c.id)) }); };
    const handleBulkDeleteItems = (ids: string[]) => { if(!activeCompany) return; handleUpdateCompany({ ...activeCompany, items: activeCompany.items.filter(i => !ids.includes(i.id)) }); };

  const handleEditInvoice = (invoiceId: string) => {
