export const InvoiceView: React.FC<{ invoice: Invoice; company: Company; onClose: () => void; documentTitle?: string }> = ({ invoice, company, onClose, documentTitle = 'Invoice' }) => {
  const printRef = useRef<HTMLDivElement>(null);

  const generatePdf = async () => { if (!printRef.current) return null; try { const canvas = await (window as any).html2canvas(printRef.current, { scale: 2, backgroundColor: '#ffffff' }); const imgData = canvas.toDataURL('image/png'); const pdf = new (window as any).jspdf.jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' }); const pdfWidth = pdf.internal.pageSize.getWidth(); const pdfHeight = pdf.internal.pageSize.getHeight(); const canvasWidth = canvas.width; const canvasHeight = canvas.height; const imgHeight = canvasHeight * pdfWidth / canvasWidth; let renderHeight = imgHeight; let renderWidth = pdfWidth; if (imgHeight > pdfHeight) { const ratio = pdfHeight / imgHeight; renderHeight = pdfHeight - 10; renderWidth = pdfWidth * ratio; } pdf.addImage(imgData, 'PNG', (pdfWidth - renderWidth) / 2, 0, renderWidth, renderHeight); return pdf; } catch(error) { console.error("Error generating PDF:", error); alert("Failed to generate PDF. Please try again."); return null; } };

  const handleDownloadPdf = async () => { 
      const pdf = await generatePdf(); 
      if (pdf) { 
          const num = invoice.invoiceNumber || (invoice as any).quotationNumber;
          pdf.save(`${documentTitle}-${num}.pdf`); 
      } 
  };

  const handlePrint = async () => { const pdf = await generatePdf(); if (pdf) { pdf.autoPrint(); window.open(pdf.output('bloburl'), '_blank'); } };

  const handleShareWhatsApp = () => { 
      const num = invoice.invoiceNumber || (invoice as any).quotationNumber;
      const text = `*${documentTitle} from ${company.details.name}*%0A%0AHello ${invoice.client.name},%0A%0AHere are the details for *${documentTitle} ${num}*:%0A%0A*Total Amount:* ₹${invoice.grandTotal.toFixed(2)}%0A*Date:* ${invoice.issueDate}%0A%0APlease review attached details.%0A%0AThank you.`; 
      window.open(`https://wa.me/?text=${text}`, '_blank'); 
  };

  return (
    <>
      <div className="max-h-[80vh] overflow-y-auto bg-slate-100 dark:bg-tertiary-dark p-4 flex justify-center">
        <div ref={printRef} className="w-[210mm] bg-white min-h-[297mm] shadow-2xl origin-top scale-[0.8] md:scale-100"> 
          <InvoiceContent invoice={invoice} company={company} documentTitle={documentTitle} />
        </div>
      </div>
      <div className="p-6 bg-white dark:bg-primary-dark flex justify-end gap-4 rounded-b-lg border-t border-slate-100 dark:border-slate-800 sticky bottom-0 z-10 shadow-[0_-4px_10px_rgba(0,0,0,0.05)]">
        <Button variant="secondary" onClick={onClose}>Close</Button>
        <button onClick={handleShareWhatsApp} className="px-4 py-2 text-sm font-semibold rounded-xl shadow-sm focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 bg-green-500 text-white hover:bg-green-600 flex items-center gap-2 transition-all active:scale-95"><WhatsAppIcon /> WhatsApp</button>
        <Button onClick={handleDownloadPdf}>Download PDF</Button>
        <Button onClick={handlePrint}>Print</Button>
      </div>
    </>
  );
};

