                            <div key={inv.id} className="bg-white dark:bg-primary-dark p-5 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800 active:scale-[0.98] transition-all" style={{ animationDelay: `${idx * 50}ms` }} onClick={() => setSelectedInvoice(inv)}>
