import Input from './common/Input';
import Modal from './common/Modal';
import { InvoiceView } from './Invoices';

interface QuotationsProps {
  quotations: Quotation[];
  company: Company;
  setActiveView: (view: string) => void;
  onEdit: (id: string) => void;
  onDelete: (id: string) => void;
  onConvert: (id: string) => void;
}

const Quotations: React.FC<QuotationsProps> = ({ 
    quotations, company, setActiveView, onEdit, onDelete, onConvert
}) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedQuotation, setSelectedQuotation] = useState<Quotation | null>(null);
  const currency = '₹';

  const filteredQuotations = useMemo(() => {
    let result = [...quotations];
    const lowercasedQuery = searchQuery.toLowerCase();
    if (lowercasedQuery) {
        result = result.filter(q => 
            q.quotationNumber.toLowerCase().includes(lowercasedQuery) ||
            q.client.name.toLowerCase().includes(lowercasedQuery)
        );
    }
    return result.sort((a,b) => new Date(b.issueDate).getTime() - new Date(a.issueDate).getTime());
  }, [quotations, searchQuery]);

  const getStatusBadge = (status: Quotation['status']) => {
    switch (status) {
        case 'Converted': return 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400';
        case 'Sent': return 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400';
        case 'Accepted': return 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400';
        default: return 'bg-slate-100 text-slate-600 dark:bg-slate-700 dark:text-slate-300';
    }
  };

  return (
    <div>
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold text-slate-900 dark:text-light-text tracking-tight">Quotations</h1>
        <div className="flex gap-3">
             <Button onClick={() => setActiveView('NewQuotation')} className="shadow-lg shadow-accent/20">+ New Quote</Button>
        </div>
      </div>

      <div className="mb-6 flex gap-4">
          <div className="flex-grow">
              <Input label="" placeholder="Search quotes..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="!py-2.5 !rounded-xl"/>
          </div>
      </div>

      {filteredQuotations.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 text-center animate-fade-in">
              <div className="w-16 h-16 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center text-slate-400 mb-4">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
              </div>
              <h3 className="text-xl font-bold text-slate-800 dark:text-white mt-2">No quotations yet</h3>
              <p className="text-slate-500 dark:text-slate-400 mt-2 max-w-sm">Create estimates for your clients and convert them to invoices later.</p>
              <Button className="mt-6" onClick={() => setActiveView('NewQuotation')}>Create First Quote</Button>
          </div>
      ) : (
          <div className="bg-white dark:bg-primary-dark shadow-sm border border-slate-200 dark:border-slate-800 rounded-2xl overflow-hidden animate-fade-in-up">
              <table className="w-full text-sm text-left text-slate-600 dark:text-slate-400">
                  <thead className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800">
                      <tr>
                          <th className="px-6 py-4">Number</th>
                          <th className="px-6 py-4">Client</th>
                          <th className="px-6 py-4">Date</th>
                          <th className="px-6 py-4 text-right">Amount</th>
                          <th className="px-6 py-4 text-center">Status</th>
                          <th className="px-6 py-4 text-right">Actions</th>
                      </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                      {filteredQuotations.map((quote) => (
                          <tr key={quote.id} className="group hover:bg-slate-50 dark:hover:bg-slate-800/30 transition-colors cursor-pointer" onClick={() => setSelectedQuotation(quote)}>
                              <td className="px-6 py-4 font-mono font-medium text-slate-900 dark:text-white">{quote.quotationNumber}</td>
                              <td className="px-6 py-4 font-semibold text-slate-800 dark:text-slate-200">{quote.client.name}</td>
                              <td className="px-6 py-4">{quote.issueDate}</td>
                              <td className="px-6 py-4 text-right font-bold text-slate-900 dark:text-white">{currency}{quote.grandTotal.toLocaleString()}</td>
                              <td className="px-6 py-4 text-center"><span className={`px-3 py-1 rounded-full text-xs font-bold ${getStatusBadge(quote.status)}`}>{quote.status}</span></td>
                              <td className="px-6 py-4 text-right space-x-2" onClick={e => e.stopPropagation()}>
                                  {quote.status !== 'Converted' && (
                                      <button onClick={() => onConvert(quote.id)} className="text-accent hover:text-accent-hover font-bold text-xs bg-accent/10 hover:bg-accent/20 px-3 py-1.5 rounded transition-all mr-2">Convert to Invoice</button>
                                  )}
                                  <button onClick={() => onEdit(quote.id)} className="text-slate-400 hover:text-slate-700 dark:hover:text-slate-200 p-1 transition-all"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg></button>
                                  <button onClick={() => onDelete(quote.id)} className="text-slate-400 hover:text-red-500 p-1 transition-all"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                              </td>
                          </tr>
                      ))}
                  </tbody>
              </table>
          </div>
      )}

      <Modal isOpen={!!selectedQuotation} onClose={() => setSelectedQuotation(null)} title={`Quotation #${selectedQuotation?.quotationNumber}`}>
          {selectedQuotation && (
              <div className="relative">
                  <div className="absolute top-2 left-1/2 -translate-x-1/2 bg-yellow-100 text-yellow-800 text-xs font-bold px-3 py-1 rounded-full z-20">PREVIEW MODE</div>
                  <InvoiceView 
                        invoice={selectedQuotation as unknown as any} 
                        company={company} 
                        onClose={() => setSelectedQuotation(null)} 
                        documentTitle="Quotation"
                  />
              </div>
          )}
      </Modal>
    </div>
  );
};

export default Quotations;

export interface BankAccount {
  id: string;
  bankName: string;
  accountNumber: string;
  ifsc: string;
  isDefault: boolean;
}

export interface CompanyDetails {
  logo: string;
  name: string;
  gstin: string;
  pan: string;
  phone: string;
  email: string;
  website?: string;
  address: string;
  city: string;
  state: string;
  zip: string;
  udyam: string;
  invoicePrefix: string;
  nextInvoiceNumber: number;
  signature?: string;
  brandColor?: string; // Added for visual customization
}

export interface Client {
  id: string;
  name: string;
  gstin: string;
  email: string;
  phone: string;
  address: string;
  city: string;
  state: string;
  zip: string;
  shippingAddress?: string;
  shippingCity?: string;
  shippingState?: string;
  shippingZip?: string;
  tags?: string[];
}

export interface Item {
  id: string;
  name: string;
  hsn: string;
  price: number;
  gstRate: number; // in percentage
  unit: string;
  quantityInStock: number;
}

export interface Transporter {
  id: string;
  name: string;
  gstin: string;
}

export interface InvoiceItem extends Item {
  quantity: number;
}

export interface Invoice {
  id:string;
  invoiceNumber: string;
  client: Client;
  items: InvoiceItem[];
  issueDate: string;
  dueDate: string;
  notes: string;
  subTotal: number;
  cgst: number;
  sgst: number;
  igst: number;
  grandTotal: number;
  status: 'Paid' | 'Unpaid' | 'Overdue';
  selectedBankAccountId: string | null;

  // Shipping Details - Snapshot for this specific invoice
  shippingName?: string;
  shippingAddress?: string;
  shippingCity?: string;
  shippingState?: string;
  shippingZip?: string;
  shippingGstin?: string;

  // Transporter Details
  transporterName?: string;
  transporterGstin?: string;
  vehicleNumber?: string;
  ewayBillNumber?: string;
}

export interface Quotation extends Omit<Invoice, 'status' | 'invoiceNumber'> {
    quotationNumber: string;
    validUntil: string;
    status: 'Draft' | 'Sent' | 'Accepted' | 'Converted';
}

export type RecurringFrequency = 'Daily' | 'Weekly' | 'Monthly' | 'Quarterly' | 'Yearly';

export interface RecurringInvoice {
  id: string;
  clientId: string;
  items: InvoiceItem[];
  frequency: RecurringFrequency;
  startDate: string;
  endDate?: string;
  nextRunDate: string;
  lastRunDate?: string;
  status: 'Active' | 'Paused' | 'Completed';
  notes?: string;
}

export interface StockHistoryEntry {
    id: string;
    itemId: string;
    itemName: string;
    previousQuantity: number;
    newQuantity: number;
    action: 'Manual Update' | 'Bulk Update' | 'Invoice Created' | 'Invoice Edited' | 'Invoice Deleted' | 'Voice Update' | 'Initial' | 'Bill Scan';
    timestamp: string;
    referenceId?: string; // e.g., Invoice Number
}

export interface Company {
  id: string;
  ownerId: string;
  details: CompanyDetails;
  bankAccounts: BankAccount[];
  clients: Client[];
  items: Item[];
  transporters: Transporter[];
  invoices: Invoice[];
  quotations: Quotation[]; // Added quotations
  recurringInvoices: RecurringInvoice[];
  stockHistory: StockHistoryEntry[];
}

export interface User {
    id: string;
    email: string;
    name?: string;
    passwordHash: string; // In a real app, never store plain text passwords
}

export interface DraftInvoice {
    invoiceNumber: string;
    clientId: string;
    items: InvoiceItem[];
    issueDate: string;
    dueDate: string;
    notes: string;
    selectedBankAccountId: string | null;
    shippingDetails: {
        name: string;
        address: string;
        city: string;
        state: string;
        zip: string;
        gstin: string;
    };
    isShippingSameAsBilling: boolean;
    transporterId: string;
    vehicleNumber: string;
    ewayBillNumber: string;
    // Added for Quotation support
    type?: 'invoice' | 'quote';
    validUntil?: string;
}

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import type { Company, BankAccount, CompanyDetails } from '../types';
import Input from './common/Input';
import Button from './common/Button';
import Modal from './common/Modal';
import { INDIAN_STATES } from '../constants';
import { validateGstin, validatePan, validateEmail, validateIfsc, validateRequired, fetchLocationByPincode } from '../utils/validation';

interface SettingsProps {
  activeCompany: Company;
  updateCompany: (updatedCompany: Company) => void;
}

type DetailsFormErrors = { [K in keyof Omit<CompanyDetails, 'logo' | 'invoicePrefix' | 'nextInvoiceNumber'>]?: string };
type BankFormErrors = { [K in keyof Omit<BankAccount, 'id' | 'isDefault'>]?: string };

const emptyBankAccount: Omit<BankAccount, 'id'> = { bankName: '', accountNumber: '', ifsc: '', isDefault: false };

const BankAccountForm: React.FC<{ 
    account: Omit<BankAccount, 'id'> | BankAccount; 
    setAccount: React.Dispatch<React.SetStateAction<Omit<BankAccount, 'id'> | BankAccount>>;
    errors: BankFormErrors;
}> = ({ account, setAccount, errors }) => {
    const handleChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setAccount(prev => ({ ...prev, [name]: value }));
    }, [setAccount]);

    return (
        <div className="p-6 space-y-4">
            <Input label="Bank Name" name="bankName" value={account.bankName} onChange={handleChange} required error={errors.bankName} placeholder="e.g. HDFC Bank"/>
            <Input label="Account Number" name="accountNumber" value={account.accountNumber} onChange={handleChange} required error={errors.accountNumber} placeholder="e.g. 502000..."/>
            <Input label="IFSC Code" name="ifsc" value={account.ifsc} onChange={handleChange} required error={errors.ifsc} placeholder="e.g. HDFC0001234"/>
        </div>
    );
};

const Settings: React.FC<SettingsProps> = ({ activeCompany, updateCompany }) => {
  const [details, setDetails] = useState(activeCompany.details);
  const [logoPreview, setLogoPreview] = useState<string | null>(activeCompany.details.logo);
  const [isBankModalOpen, setIsBankModalOpen] = useState(false);
  const [editingAccount, setEditingAccount] = useState<BankAccount | Omit<BankAccount, 'id'>>(emptyBankAccount);
  const [showSuccess, setShowSuccess] = useState(false);
  const [bankSuccessMessage, setBankSuccessMessage] = useState('');
  const [isBankDeleteConfirmOpen, setIsBankDeleteConfirmOpen] = useState(false);
  const [accountToDeleteId, setAccountToDeleteId] = useState<string | null>(null);

  const [detailErrors, setDetailErrors] = useState<DetailsFormErrors>({});
  const [bankErrors, setBankErrors] = useState<BankFormErrors>({});
  const [logoError, setLogoError] = useState<string|null>(null);
  const [isPincodeLoading, setIsPincodeLoading] = useState(false);

  useEffect(() => {
    setDetails(activeCompany.details);
    setLogoPreview(activeCompany.details.logo);
    setDetailErrors({});
  }, [activeCompany]);

    useEffect(() => {
    const pincode = details.zip;
    if (pincode && pincode.length === 6) {
      const timer = setTimeout(async () => {
        setIsPincodeLoading(true);
        const location = await fetchLocationByPincode(pincode);
        if (location) {
          setDetails(prev => ({ ...prev, city: location.city, state: location.state }));
          setDetailErrors(prev => ({...prev, zip: undefined}));
        } else if (location === null) {
           setDetailErrors(prev => ({...prev, zip: 'Invalid Pincode'}));
        } else {
           setDetailErrors(prev => ({...prev, zip: 'Lookup failed. Enter manually.'}));
        }
        setIsPincodeLoading(false);
      }, 500); // Debounce
      return () => clearTimeout(timer);
    }
  }, [details.zip]);

  const validateDetailsField = useCallback((name: string, value: string): string | null => {
    switch (name) {
      case 'name': return validateRequired(value);
      case 'gstin': return validateGstin(value);
      case 'pan': return validatePan(value);
      case 'email': return validateEmail(value);
      default: return null;
    }
  }, []);

  const handleChange = useCallback((e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target;
    setDetails(prev => ({ ...prev, [name]: type === 'number' ? (value === '' ? '' : parseInt(value)) : value }));
    const error = validateDetailsField(name, value);
    setDetailErrors(prev => ({...prev, [name]: error || undefined }));
  }, [validateDetailsField]);

  const handleLogoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setLogoError(null);
    if (e.target.files && e.target.files[0]) {
        const file = e.target.files[0];
        if (!file.type.startsWith('image/')) {
            setLogoError('Please select an image file.');
            return;
        }
        if (file.size > 2 * 1024 * 1024) { // 2MB limit
            setLogoError('Image size should be less than 2MB.');
            return;
        }
      const reader = new FileReader();
      reader.onloadend = () => {
        const result = reader.result as string;
        setLogoPreview(result);
        setDetails(prev => ({ ...prev, logo: result }));
      };
      reader.onerror = () => setLogoError('Failed to read file.');
      reader.readAsDataURL(file);
    }
  };

  const handleSaveDetails = () => {
    // Validate all required fields before saving
    const newErrors: DetailsFormErrors = {};
    if (!details.name) newErrors.name = validateRequired(details.name) || undefined;
    if (!details.phone) newErrors.phone = validateRequired(details.phone) || undefined;
    if (!details.address) newErrors.address = validateRequired(details.address) || undefined;
    if (!details.city) newErrors.city = validateRequired(details.city) || undefined;
    if (!details.state) newErrors.state = validateRequired(details.state) || undefined;
    if (!details.zip) newErrors.zip = validateRequired(details.zip) || undefined;

    // Check existing errors and new validations
    const hasErrors = Object.values(detailErrors).some(e => e) || Object.values(newErrors).some(e => e);

    if (hasErrors) {
        setDetailErrors(prev => ({ ...prev, ...newErrors }));
        return;
    }

    updateCompany({ ...activeCompany, details });
    setShowSuccess(true);
    setTimeout(() => setShowSuccess(false), 3000);
  };

  const handleOpenBankModal = (account?: BankAccount) => {
    setBankErrors({});
    setEditingAccount(account || emptyBankAccount);
    setIsBankModalOpen(true);
  };

  const validateBankAccount = (account: Omit<BankAccount, 'id'> | BankAccount): boolean => {
      const errors: BankFormErrors = {};
      if (validateRequired(account.bankName)) errors.bankName = "Bank Name is required.";
      if (validateRequired(account.accountNumber)) errors.accountNumber = "Account Number is required.";
      const ifscError = validateRequired(account.ifsc) || validateIfsc(account.ifsc);
      if (ifscError) errors.ifsc = ifscError;
      setBankErrors(errors);
      return Object.keys(errors).length === 0;
  }

  const handleSaveBankAccount = () => {
    if (!validateBankAccount(editingAccount)) return;

    let updatedAccounts: BankAccount[];
    const isNew = !('id' in editingAccount);

    if (editingAccount.isDefault) {
      activeCompany.bankAccounts.forEach(acc => acc.isDefault = false);
    }

    if (isNew) {
      updatedAccounts = [...activeCompany.bankAccounts, { ...editingAccount, id: Date.now().toString() }];
    } else {
      updatedAccounts = activeCompany.bankAccounts.map(acc => acc.id === (editingAccount as BankAccount).id ? (editingAccount as BankAccount) : acc);
    }

    // Auto-set default if it's the first and only account
    if (updatedAccounts.length === 1) {
        updatedAccounts[0].isDefault = true;
    } else if (updatedAccounts.length > 0 && !updatedAccounts.some(acc => acc.isDefault)) {
        updatedAccounts[0].isDefault = true;
    }

    updateCompany({ ...activeCompany, bankAccounts: updatedAccounts });
    setIsBankModalOpen(false);
    setBankSuccessMessage(`Bank account successfully ${isNew ? 'added' : 'updated'}.`);
    setTimeout(() => setBankSuccessMessage(''), 3000);
  };

  const handleDeleteBankAccount = (accountId: string) => {
    setAccountToDeleteId(accountId);
    setIsBankDeleteConfirmOpen(true);
  };

  const confirmDeleteBankAccount = () => {
    if (accountToDeleteId) {
      const updatedAccounts = activeCompany.bankAccounts.filter(acc => acc.id !== accountToDeleteId);
      if (updatedAccounts.length > 0 && !updatedAccounts.some(acc => acc.isDefault)) {
        updatedAccounts[0].isDefault = true;
      }
      updateCompany({ ...activeCompany, bankAccounts: updatedAccounts });
      setBankSuccessMessage('Bank account successfully deleted.');
      setTimeout(() => setBankSuccessMessage(''), 3000);
    }
    setIsBankDeleteConfirmOpen(false);
    setAccountToDeleteId(null);
  };

  const handleSetDefault = (accountId: string) => {
      const updatedAccounts = activeCompany.bankAccounts.map(acc => ({ ...acc, isDefault: acc.id === accountId }));
      updateCompany({ ...activeCompany, bankAccounts: updatedAccounts });
  };

  const inputClasses = "w-full bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white rounded-lg shadow-sm placeholder-slate-400 dark:placeholder-slate-500 focus:outline-none text-sm px-4 py-3 transition-all duration-200 ease-in-out border border-slate-300 dark:border-slate-700 hover:border-slate-400 dark:hover:border-slate-500 focus:ring-2 focus:ring-accent/20 focus:border-accent";

  return (
    <div className="max-w-7xl mx-auto space-y-8 pb-12">

      {/* Header */}
      <div className="flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-bold text-slate-900 dark:text-light-text tracking-tight">Settings</h1>
            <p className="text-slate-500 dark:text-slate-400 mt-1">Manage your company profile and preferences.</p>
          </div>
          {showSuccess && <div className="bg-green-100 text-green-700 px-4 py-2 rounded-lg text-sm font-semibold animate-fade-in">Settings Saved!</div>}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Left Column - Company Info */}
        <div className="lg:col-span-2 space-y-8">

            {/* Identity Card */}
            <div className="bg-white dark:bg-primary-dark p-8 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800">
                <h2 className="text-lg font-bold text-slate-900 dark:text-light-text mb-6 border-b border-slate-100 dark:border-slate-700 pb-4">Identity & Branding</h2>
                <div className="flex flex-col md:flex-row gap-8 mb-8">
                    <div className="flex-shrink-0">
                        <label className="block text-xs font-semibold uppercase text-slate-500 mb-2">Logo</label>
                        <div className="relative group w-32 h-32 bg-slate-50 dark:bg-slate-900 rounded-xl border-2 border-dashed border-slate-300 dark:border-slate-700 flex items-center justify-center overflow-hidden hover:border-accent transition-colors">
                            {logoPreview ? (
                                <img src={logoPreview} alt="Company Logo" className="w-full h-full object-contain p-2" />
                            ) : (
                                <span className="text-xs text-slate-400 text-center px-2">Upload<br/>Logo</span>
                            )}
                            <div className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer">
                                <span className="text-white text-xs font-bold">Change</span>
                            </div>
                            <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={handleLogoChange} accept="image/*" />
                        </div>
                        {logoError && <p className="text-xs text-red-500 mt-1">{logoError}</p>}
                    </div>
                    <div className="flex-grow space-y-6">
                        <Input label="Company Name" name="name" value={details.name} onChange={handleChange} required error={detailErrors.name} placeholder="e.g. Acme Corp" />
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <Input label="Phone" name="phone" type="tel" value={details.phone} onChange={handleChange} required error={detailErrors.phone} placeholder="e.g. +91 98765 43210"/>
                            <Input label="Email" name="email" type="email" value={details.email} onChange={handleChange} error={detailErrors.email} placeholder="e.g. contact@acme.com" />
                        </div>
                        <div>
                            <label className="block text-xs font-semibold uppercase text-slate-500 mb-2">Brand Color</label>
                            <div className="flex items-center gap-4">
                                <input 
                                    type="color" 
                                    name="brandColor"
                                    value={details.brandColor || '#4F46E5'} 
                                    onChange={handleChange}
                                    className="h-10 w-20 p-1 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-700 rounded cursor-pointer" 
                                />
                                <span className="text-sm text-slate-500 font-mono">{details.brandColor || '#4F46E5'}</span>
                            </div>
                            <p className="text-xs text-slate-400 mt-1">This color will be used for buttons, links, and invoice headers.</p>
                        </div>
                    </div>
                </div>

                <h3 className="text-sm font-bold text-slate-900 dark:text-white mb-4">Address</h3>
                <div className="space-y-6">
                    <textarea name="address" rows={2} value={details.address} onChange={handleChange} className={inputClasses} placeholder="Street Address, Area, Landmark" />
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <div className="relative">
                            <Input label="ZIP Code" name="zip" value={details.zip} onChange={handleChange} error={detailErrors.zip} maxLength={6} required placeholder="e.g. 400001" />
                            {isPincodeLoading && <div className="absolute top-9 right-3 h-4 w-4 border-2 border-slate-400 border-t-transparent rounded-full animate-spin"></div>}
                        </div>
                        <Input label="City" name="city" value={details.city} onChange={handleChange} required error={detailErrors.city} placeholder="e.g. Mumbai" />
                        <div>
                            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1.5">State</label>
                            <select id="state" name="state" value={details.state} onChange={handleChange} className={inputClasses}>
                                <option value="">Select State</option>
