                <StatCard title="Total Receivables" value={`${currency}${metrics.totalReceivables.toLocaleString()}`} icon={<ScaleIcon />} color="yellow" trend={{ value: metrics.trends.outstanding, label: 'vs last month' }} sparklineData={metrics.outstandingData} onClick={navigateToInvoices} delay={100} />
