                            {invoiceStatusCounts.overdue > 0 && <path className="text-red-500 transition-all duration-500" strokeDasharray={dashArray(invoiceStatusCounts.overdue)} strokeDashoffset={dashOffset([invoiceStatusCounts.paid, invoiceStatusCounts.pending])} d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="currentColor" strokeWidth="3" />}
