    useEffect(() => {
        if (isOpen) {
            setTimeout(() => inputRef.current?.focus(), 100);
        } else {
            setQuery('');
        }
    }, [isOpen]);

    const actions = [
        { id: 'new-inv', label: 'Create New Invoice', icon: '+', action: () => onNewInvoice() },
        { id: 'new-qt', label: 'Create New Quotation', icon: '📝', action: () => onNewQuote() },
