  const handleVoiceSaveInvoice = () => { if (activeView !== 'NewInvoice') return { success: false, message: "Not on invoice page" }; if (!draftInvoice.clientId || draftInvoice.items.length === 0) return { success: false, message: "Missing client or items." }; const client = activeCompany?.clients.find(c => c.id === draftInvoice.clientId); if(!client) return { success: false, message: "Client not found" }; let subTotal = 0, cgst = 0, sgst = 0, igst = 0; const isIntraState = !draftInvoice.shippingDetails.state || draftInvoice.shippingDetails.state === activeCompany?.details.state; draftInvoice.items.forEach(item => { const t = item.price * item.quantity; subTotal += t; const tax = (t * item.gstRate) / 100; if (isIntraState) { cgst += tax/2; sgst += tax/2; } else { igst += tax; } }); const commonData = { invoiceNumber: draftInvoice.invoiceNumber, client, items: draftInvoice.items, issueDate: draftInvoice.issueDate, dueDate: draftInvoice.dueDate, notes: draftInvoice.notes, selectedBankAccountId: draftInvoice.selectedBankAccountId, shippingName: draftInvoice.shippingDetails.name, shippingAddress: draftInvoice.shippingDetails.address, shippingCity: draftInvoice.shippingDetails.city, shippingState: draftInvoice.shippingDetails.state, shippingZip: draftInvoice.shippingDetails.zip, shippingGstin: draftInvoice.shippingDetails.gstin, vehicleNumber: draftInvoice.vehicleNumber, ewayBillNumber: draftInvoice.ewayBillNumber, subTotal, cgst, sgst, igst, grandTotal: subTotal + cgst + sgst + igst }; if (invoiceToEdit && 'invoiceNumber' in invoiceToEdit) { handleSaveInvoice({ ...commonData, id: invoiceToEdit.id, status: (invoiceToEdit as Invoice).status }); } else { handleSaveInvoice(commonData); } setActiveView('Invoices'); return { success: true, message: invoiceToEdit ? "Invoice updated." : "Invoice saved." }; };

