                            <p>{selectedBankAccount.bankName} • {selectedBankAccount.accountNumber} • {selectedBankAccount.ifsc}</p>
                        </div>
                    )}
                </div>
                <div className="w-72 shrink-0">
                    <div className="bg-slate-900 text-white p-6 rounded-2xl shadow-lg">
                        <div className="space-y-2 text-sm opacity-90">
                            <div className="flex justify-between"><span>Subtotal</span><span>{currency}{invoice.subTotal.toFixed(2)}</span></div>

                            {(invoice.cgst > 0 || invoice.sgst > 0) && (
                                <>
                                    <div className="flex justify-between text-slate-300"><span>CGST</span><span>{currency}{invoice.cgst.toFixed(2)}</span></div>
                                    <div className="flex justify-between text-slate-300"><span>SGST</span><span>{currency}{invoice.sgst.toFixed(2)}</span></div>
                                </>
                            )}

                            {invoice.igst > 0 && (
                                <div className="flex justify-between text-slate-300"><span>IGST</span><span>{currency}{invoice.igst.toFixed(2)}</span></div>
                            )}
                        </div>
                        <div className="border-t border-white/20 my-4"></div>
                        <div className="flex justify-between text-xl font-bold">
                            <span>Total</span>
                            <span>{currency}{invoice.grandTotal.toFixed(2)}</span>
                        </div>
                    </div>
                </div>
            </div>

            {/* Signature Area */}
            <div className="mt-12 flex justify-between items-end pt-8 border-t border-slate-100">
                <div className="text-xs text-slate-400 max-w-sm">
                    <p className="font-semibold text-slate-600 mb-1">Terms & Conditions:</p>
                    <p>{invoice.notes || (documentTitle === 'Quotation' ? 'Valid for 30 days.' : 'Payment due within 15 days.')}</p>
                </div>
                <div className="text-center">
                    {company.details.signature && <img src={company.details.signature} className="h-12 w-auto mx-auto mb-2 opacity-80" alt="Sign"/>}
                    <p className="font-bold text-slate-900 text-sm">{company.details.name}</p>
                    <p className="text-[10px] text-slate-500 uppercase tracking-widest mt-1">Authorized Signatory</p>
                </div>
            </div>
        </div>
    );
};

export const InvoiceView: React.FC<{ invoice: Invoice; company: Company; onClose: () => void; documentTitle?: string }> = ({ invoice, company, onClose, documentTitle = 'Invoice' }) => {
  const printRef = useRef<HTMLDivElement>(null);

  const generatePdf = async () => { if (!printRef.current) return null; try { const canvas = await (window as any).html2canvas(printRef.current, { scale: 2, backgroundColor: '#ffffff' }); const imgData = canvas.toDataURL('image/png'); const pdf = new (window as any).jspdf.jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' }); const pdfWidth = pdf.internal.pageSize.getWidth(); const pdfHeight = pdf.internal.pageSize.getHeight(); const canvasWidth = canvas.width; const canvasHeight = canvas.height; const imgHeight = canvasHeight * pdfWidth / canvasWidth; let renderHeight = imgHeight; let renderWidth = pdfWidth; if (imgHeight > pdfHeight) { const ratio = pdfHeight / imgHeight; renderHeight = pdfHeight - 10; renderWidth = pdfWidth * ratio; } pdf.addImage(imgData, 'PNG', (pdfWidth - renderWidth) / 2, 0, renderWidth, renderHeight); return pdf; } catch(error) { console.error("Error generating PDF:", error); alert("Failed to generate PDF. Please try again."); return null; } };

  const handleDownloadPdf = async () => { 
      const pdf = await generatePdf(); 
      if (pdf) { 
          const num = invoice.invoiceNumber || (invoice as any).quotationNumber;
          pdf.save(`${documentTitle}-${num}.pdf`); 
      } 
  };

  const handlePrint = async () => { const pdf = await generatePdf(); if (pdf) { pdf.autoPrint(); window.open(pdf.output('bloburl'), '_blank'); } };

  const handleShareWhatsApp = () => { 
      const num = invoice.invoiceNumber || (invoice as any).quotationNumber;
      const text = `*${documentTitle} from ${company.details.name}*%0A%0AHello ${invoice.client.name},%0A%0AHere are the details for *${documentTitle} ${num}*:%0A%0A*Total Amount:* ₹${invoice.grandTotal.toFixed(2)}%0A*Date:* ${invoice.issueDate}%0A%0APlease review attached details.%0A%0AThank you.`; 
      window.open(`https://wa.me/?text=${text}`, '_blank'); 
  };

  return (
    <>
      <div className="max-h-[80vh] overflow-y-auto bg-slate-100 dark:bg-tertiary-dark p-4 flex justify-center">
        <div ref={printRef} className="w-[210mm] bg-white min-h-[297mm] shadow-2xl origin-top scale-[0.8] md:scale-100"> 
          <InvoiceContent invoice={invoice} company={company} documentTitle={documentTitle} />
        </div>
      </div>
      <div className="p-6 bg-white dark:bg-primary-dark flex justify-end gap-4 rounded-b-lg border-t border-slate-100 dark:border-slate-800 sticky bottom-0 z-10 shadow-[0_-4px_10px_rgba(0,0,0,0.05)]">
        <Button variant="secondary" onClick={onClose}>Close</Button>
        <button onClick={handleShareWhatsApp} className="px-4 py-2 text-sm font-semibold rounded-xl shadow-sm focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 bg-green-500 text-white hover:bg-green-600 flex items-center gap-2 transition-all active:scale-95"><WhatsAppIcon /> WhatsApp</button>
        <Button onClick={handleDownloadPdf}>Download PDF</Button>
        <Button onClick={handlePrint}>Print</Button>
      </div>
    </>
  );
};

// --- Main Invoices Component ---
interface InvoicesProps {
  invoices: Invoice[];
  company: Company;
  setActiveView: (view: string) => void;
  onEdit: (invoiceId: string) => void;
  onDelete: (invoiceId: string) => void;
  onStatusChange: (invoiceId: string, status: Invoice['status']) => void;
  onBulkDelete: (invoiceIds: string[]) => void;
  onBulkStatusChange: (invoiceIds: string[], status: Invoice['status']) => void;
  onAddRecurring: (profile: Omit<RecurringInvoice, 'id'>) => void;
  onUpdateRecurring: (profile: RecurringInvoice) => void;
  onDeleteRecurring: (id: string) => void;
}

const Invoices: React.FC<InvoicesProps> = ({ 
    invoices, company, setActiveView, onEdit, onDelete, onStatusChange,
    onBulkDelete, onBulkStatusChange, onAddRecurring, onUpdateRecurring, onDeleteRecurring
}) => {
  const [activeTab, setActiveTab] = useState<'invoices' | 'recurring'>('invoices');
  const [searchQuery, setSearchQuery] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [filterStatus, setFilterStatus] = useState('');
  const [selectedInvoice, setSelectedInvoice] = useState<Invoice | null>(null);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const currency = '₹';

  const filteredInvoices = useMemo(() => {
    let result = [...invoices];
    const lowercasedQuery = searchQuery.toLowerCase();
    if (lowercasedQuery) {
        result = result.filter(invoice => 
            invoice.invoiceNumber.toLowerCase().includes(lowercasedQuery) ||
            invoice.client.name.toLowerCase().includes(lowercasedQuery)
        );
    }
    if (filterStatus) result = result.filter(invoice => invoice.status === filterStatus);
    return result;
  }, [invoices, searchQuery, filterStatus]);

  const handleSelectOne = (id: string) => {
      if (selectedIds.includes(id)) setSelectedIds(selectedIds.filter(sid => sid !== id));
      else setSelectedIds([...selectedIds, id]);
  };

  const getStatusBadge = (status: Invoice['status']) => {
    switch (status) {
        case 'Paid': return 'bg-green-100 text-green-700 ring-1 ring-green-600/20 dark:bg-green-900/30 dark:text-green-400';
        case 'Unpaid': return 'bg-yellow-100 text-yellow-700 ring-1 ring-yellow-600/20 dark:bg-yellow-900/30 dark:text-yellow-400';
        case 'Overdue': return 'bg-red-100 text-red-700 ring-1 ring-red-600/20 dark:bg-red-900/30 dark:text-red-400';
        default: return 'bg-slate-100 text-slate-600';
    }
  };

  return (
    <div>
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold text-slate-900 dark:text-light-text tracking-tight">Invoices</h1>
        <div className="flex gap-3">
             <Button onClick={() => setActiveView('NewInvoice')} className="shadow-lg shadow-accent/20">+ Create</Button>
        </div>
      </div>

      {activeTab === 'invoices' && (
        <>
            <div className="mb-6 flex gap-4">
                <div className="flex-grow">
                    <Input label="" placeholder="Search invoices..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="!py-2.5 !rounded-xl"/>
                </div>
            </div>

            {filteredInvoices.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-20 text-center animate-fade-in">
                    <EmptyStateIllustration />
                    <h3 className="text-xl font-bold text-slate-800 dark:text-white mt-6">No invoices found</h3>
                    <p className="text-slate-500 dark:text-slate-400 mt-2 max-w-sm">Create your first invoice to start getting paid faster. It only takes a minute.</p>
                    <Button className="mt-6" onClick={() => setActiveView('NewInvoice')}>Create First Invoice</Button>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-1 gap-4 animate-fade-in-up">
                    {/* Mobile Card View (and Tablet grid) */}
                    <div className="xl:hidden grid grid-cols-1 md:grid-cols-2 gap-4">
                        {filteredInvoices.map((inv, idx) => (
                            <div key={inv.id} className="bg-white dark:bg-primary-dark p-5 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800 active:scale-[0.98] transition-all" style={{ animationDelay: `${idx * 50}ms` }} onClick={() => setSelectedInvoice(inv)}>
                                <div className="flex justify-between items-start mb-4">
                                    <div>
                                        <h3 className="font-bold text-slate-900 dark:text-white">{inv.client.name}</h3>
                                        <p className="text-xs text-slate-500">{inv.invoiceNumber}</p>
                                    </div>
                                    <span className={`px-2.5 py-1 rounded-lg text-xs font-bold ${getStatusBadge(inv.status)}`}>{inv.status}</span>
                                </div>
                                <div className="flex justify-between items-end">
                                    <div className="text-xs text-slate-500">
                                        <p>Date: {inv.issueDate}</p>
                                        <p className="mt-0.5">Due: <span className={inv.status === 'Overdue' ? 'text-red-500 font-bold' : ''}>{inv.dueDate}</span></p>
                                    </div>
                                    <p className="text-xl font-black text-slate-900 dark:text-white">{currency}{inv.grandTotal.toLocaleString()}</p>
                                </div>
                            </div>
                        ))}
                    </div>

                    {/* Desktop Table View */}
                    <div className="hidden xl:block bg-white dark:bg-primary-dark shadow-sm border border-slate-200 dark:border-slate-800 rounded-2xl overflow-hidden">
                        <table className="w-full text-sm text-left text-slate-600 dark:text-slate-400">
                            <thead className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800">
                                <tr>
                                    <th className="px-6 py-4 w-10"><input type="checkbox" className="rounded border-slate-300 text-accent focus:ring-accent" /></th>
                                    <th className="px-6 py-4">Number</th>
                                    <th className="px-6 py-4">Client</th>
                                    <th className="px-6 py-4">Date</th>
                                    <th className="px-6 py-4 text-right">Amount</th>
                                    <th className="px-6 py-4 text-center">Status</th>
                                    <th className="px-6 py-4 text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                                {filteredInvoices.map((invoice, idx) => (
                                    <tr key={invoice.id} className="group hover:bg-slate-50 dark:hover:bg-slate-800/30 transition-colors cursor-pointer" onClick={() => setSelectedInvoice(invoice)}>
                                        <td className="px-6 py-4" onClick={e => e.stopPropagation()}><input type="checkbox" checked={selectedIds.includes(invoice.id)} onChange={() => handleSelectOne(invoice.id)} className="rounded border-slate-300 text-accent focus:ring-accent" /></td>
                                        <td className="px-6 py-4 font-mono font-medium text-slate-900 dark:text-white">{invoice.invoiceNumber}</td>
                                        <td className="px-6 py-4 font-semibold text-slate-800 dark:text-slate-200">{invoice.client.name}</td>
                                        <td className="px-6 py-4">{invoice.issueDate}</td>
                                        <td className="px-6 py-4 text-right font-bold text-slate-900 dark:text-white">{currency}{invoice.grandTotal.toLocaleString()}</td>
                                        <td className="px-6 py-4 text-center"><span className={`px-3 py-1 rounded-full text-xs font-bold ${getStatusBadge(invoice.status)}`}>{invoice.status}</span></td>
                                        <td className="px-6 py-4 text-right space-x-2" onClick={e => e.stopPropagation()}>
                                            <button onClick={() => onEdit(invoice.id)} className="text-slate-400 hover:text-accent p-2 hover:bg-accent/10 rounded-lg transition-all">Edit</button>
                                            <button onClick={() => onDelete(invoice.id)} className="text-slate-400 hover:text-red-500 p-2 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-all">Delete</button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}
        </>
      )}

      <Modal isOpen={!!selectedInvoice} onClose={() => setSelectedInvoice(null)} title={`Invoice #${selectedInvoice?.invoiceNumber}`}>
          {selectedInvoice && <InvoiceView invoice={selectedInvoice} company={company} onClose={() => setSelectedInvoice(null)} />}
      </Modal>
    </div>
  );
};

export default Invoices;
